import { Transaction, User } from '../types';

const STORAGE_KEY = 'finance_tracker_v3_local_data';
const USER_KEY = 'finance_tracker_v3_user';

export const storageService = {
  async login(email: string, password: string): Promise<User | null> {
    // Simple local auth simulation
    const user: User = { id: 'local-user', name: email.split('@')[0], email };
    localStorage.setItem(USER_KEY, JSON.stringify(user));
    return user;
  },

  async register(name: string, email: string, password: string): Promise<User | null> {
    const user: User = { id: 'local-user', name, email };
    localStorage.setItem(USER_KEY, JSON.stringify(user));
    return user;
  },

  async logout() {
    localStorage.removeItem(USER_KEY);
  },

  getCurrentUser(): User | null {
    const data = localStorage.getItem(USER_KEY);
    return data ? JSON.parse(data) : null;
  },

  async fetchTransactions(): Promise<Transaction[]> {
    const data = localStorage.getItem(STORAGE_KEY);
    return data ? JSON.parse(data) : [];
  },

  async addTransaction(transaction: Transaction): Promise<boolean> {
    const data = await this.fetchTransactions();
    const newTx = { ...transaction, id: crypto.randomUUID() };
    data.push(newTx);
    localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
    return true;
  },

  async updateTransaction(id: string, transaction: Transaction): Promise<boolean> {
    const data = await this.fetchTransactions();
    const index = data.findIndex(tx => tx.id === id);
    if (index !== -1) {
      data[index] = { ...transaction, id };
      localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
      return true;
    }
    return false;
  },

  async deleteTransaction(id: string): Promise<boolean> {
    const data = await this.fetchTransactions();
    const filtered = data.filter(tx => tx.id !== id);
    localStorage.setItem(STORAGE_KEY, JSON.stringify(filtered));
    return true;
  }
};

import React, { useState, useEffect, useCallback } from 'react';
import { Transaction, Language, User } from './types';
import { translations } from './translations';
import { storageService } from './services/googleSheets';
import Dashboard from './components/Dashboard';
import AuthForm from './components/AuthForm';
import { Globe, Wallet, LayoutDashboard, History, BarChart3, LogOut, User as UserIcon } from 'lucide-react';

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>('en');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'analytics' | 'history'>('dashboard');
  const [isLoading, setIsLoading] = useState(false);
  const [user, setUser] = useState<User | null>(storageService.getCurrentUser());

  const t = translations[lang];

  const loadData = useCallback(async () => {
    setIsLoading(true);
    try {
      const data = await storageService.fetchTransactions();
      setTransactions(data);
    } catch (err) {
      console.error("Failed to load data", err);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    if (user) {
      loadData();
    }
    const savedLang = localStorage.getItem('lang');
    if (savedLang) setLang(savedLang as Language);
  }, [loadData, user]);

  const toggleLanguage = () => {
    const newLang = lang === 'en' ? 'si' : 'en';
    setLang(newLang);
    localStorage.setItem('lang', newLang);
  };

  const onAddTransaction = async (data: Transaction) => {
    setIsLoading(true);
    await storageService.addTransaction(data);
    await loadData();
    setIsLoading(false);
  };

  const onUpdateTransaction = async (id: string, data: Transaction) => {
    setIsLoading(true);
    await storageService.updateTransaction(id, data);
    await loadData();
    setIsLoading(false);
  };

  const onDeleteTransaction = async (id: string) => {
    if(confirm(t.confirmDelete)) {
      setIsLoading(true);
      await storageService.deleteTransaction(id);
      await loadData();
      setIsLoading(false);
    }
  };

  const handleLogout = () => {
    storageService.logout();
    setUser(null);
  };

  if (!user) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4">
        <div className="w-full max-w-md">
          <div className="flex flex-col items-center mb-8">
            <div className="p-4 bg-indigo-600 rounded-2xl shadow-xl shadow-indigo-100 mb-4">
              <Wallet className="w-8 h-8 text-white" />
            </div>
            <h1 className="text-2xl font-black text-slate-800 tracking-tight">{t.title}</h1>
            <p className="text-slate-500 font-medium">Local Record Tracking</p>
          </div>
          <AuthForm t={t} onAuthSuccess={setUser} />
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 pb-20 md:pb-0 font-sans">
      {/* Sidebar / Desktop Nav */}
      <nav className="hidden md:flex flex-col fixed h-full w-64 bg-white border-r border-slate-200 p-6 z-20 no-print">
        <div className="flex items-center gap-3 mb-10">
          <div className="p-2 bg-indigo-600 rounded-xl">
            <Wallet className="w-6 h-6 text-white" />
          </div>
          <h1 className="font-bold text-lg text-slate-800 leading-tight">{t.title}</h1>
        </div>

        <div className="space-y-2 flex-grow">
          <button 
            onClick={() => setActiveTab('dashboard')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium transition-all ${activeTab === 'dashboard' ? 'bg-indigo-50 text-indigo-600 shadow-sm' : 'text-slate-500 hover:bg-slate-50 hover:text-slate-800'}`}
          >
            <LayoutDashboard className="w-5 h-5" />
            {t.dashboard}
          </button>
          <button 
            onClick={() => setActiveTab('analytics')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium transition-all ${activeTab === 'analytics' ? 'bg-indigo-50 text-indigo-600 shadow-sm' : 'text-slate-500 hover:bg-slate-50 hover:text-slate-800'}`}
          >
            <BarChart3 className="w-5 h-5" />
            {t.charts}
          </button>
          <button 
            onClick={() => setActiveTab('history')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium transition-all ${activeTab === 'history' ? 'bg-indigo-50 text-indigo-600 shadow-sm' : 'text-slate-500 hover:bg-slate-50 hover:text-slate-800'}`}
          >
            <History className="w-5 h-5" />
