          </button>
        </div>

        <div className="mt-auto space-y-2 border-t border-slate-100 pt-6">
          <div className="flex items-center gap-3 px-4 py-2 text-slate-700 bg-slate-50 rounded-xl mb-4">
             <UserIcon className="w-4 h-4" />
