import React from 'react';
import { Transaction } from '../types';
import { Edit2, Trash2, FileSpreadsheet, Download, Printer } from 'lucide-react';
import * as XLSX from 'xlsx';

interface HistoryTableProps {
  t: any;
  transactions: Transaction[];
  allTransactions?: Transaction[];
  onEdit: (tx: Transaction) => void;
  onDelete: (id: string) => void;
  isLoading: boolean;
}

const HistoryTable: React.FC<HistoryTableProps> = ({ t, transactions, allTransactions, onEdit, onDelete, isLoading }) => {

  const formatForExcel = (data: Transaction[]) => {
    return data.map(tx => ({
      [t.date]: tx.date,
      [t.dailyCash]: tx.dailyCash,
      [t.groceries]: tx.groceries,
      [t.vegetables]: tx.vegetables,
      [t.fishEgg]: tx.fishEgg,
      [t.chicken]: tx.chicken,
      [t.houseRent]: tx.houseRent,
      [t.travel]: tx.travel,
      [t.others]: tx.others,
      [t.totalExpenses]: tx.totalExpenses,
      [t.totalBalance]: tx.totalBalance,
    }));
  };

  const exportAllToExcel = () => {
    const dataToExport = allTransactions || transactions;
    if (dataToExport.length === 0) return;

    const workbook = XLSX.utils.book_new();
    const sortedData = [...dataToExport].sort((a,b) => a.date.localeCompare(b.date));

    // Detailed Sheet
    const fullData = formatForExcel(sortedData);
    const wsFull = XLSX.utils.json_to_sheet(fullData);

    // Add some styling (conceptual as basic XLSX doesn't support deep styling without more libs, but we organize the data)
    XLSX.utils.book_append_sheet(workbook, wsFull, "Transaction Details");

    // Summary Sheet
    const monthlySummary: any[] = [];
    const months = [...new Set(sortedData.map(tx => tx.month))];
    months.forEach(m => {
      const txs = sortedData.filter(tx => tx.month === m);
      monthlySummary.push({
        [t.month]: m,
        [t.totalIncome]: txs.reduce((acc, curr) => acc + (curr.dailyCash || 0), 0),
        [t.totalExpenses]: txs.reduce((acc, curr) => acc + (curr.totalExpenses || 0), 0),
        [t.totalBalance]: txs[txs.length-1]?.totalBalance || 0
      });
    });
    const wsSummary = XLSX.utils.json_to_sheet(monthlySummary);
    XLSX.utils.book_append_sheet(workbook, wsSummary, "Monthly Summary");

    XLSX.writeFile(workbook, `Finance_Report_${new Date().toISOString().split('T')[0]}.xlsx`);
  };

  const handlePrint = () => {
    window.print();
  };

  if (isLoading) {
    return <div className="p-12 text-center text-slate-400">Loading records...</div>;
  }

  if (transactions.length === 0) {
    return (
      <div className="p-12 text-center">
        <p className="text-slate-400 mb-4">{t.noData}</p>
      </div>
    );
  }

  const selectedMonth = transactions[0]?.month || '';
  const totalIn = transactions.reduce((s, tx) => s + tx.dailyCash, 0);
  const totalOut = transactions.reduce((s, tx) => s + tx.totalExpenses, 0);

  return (
    <div className="flex flex-col">
      {/* Action Buttons - Hidden in Print */}
      <div className="p-4 border-b border-slate-50 flex justify-end gap-2 flex-wrap no-print">
        <button 
          onClick={handlePrint}
          className="flex items-center gap-2 bg-slate-100 text-slate-700 font-bold text-sm hover:bg-slate-200 px-4 py-2 rounded-xl transition-colors"
        >
          <Printer className="w-4 h-4" />
          {t.printReport}
        </button>
        <button 
          onClick={exportAllToExcel}
          className="flex items-center gap-2 bg-indigo-600 text-white font-bold text-sm hover:bg-indigo-700 px-4 py-2 rounded-xl transition-colors shadow-sm"
        >
          <FileSpreadsheet className="w-4 h-4" />
          {t.exportExcel}
        </button>
      </div>

      {/* Print-Only Header */}
      <div className="print-only mb-6 text-center">
        <h1 className="text-2xl font-bold">{t.title}</h1>
        <h2 className="text-xl text-slate-600">{selectedMonth}</h2>
        <div className="flex justify-center gap-8 mt-4 border-y py-2">
           <div><span className="font-bold">{t.totalReceived}:</span> LKR {totalIn.toLocaleString()}</div>
           <div><span className="font-bold">{t.totalSpent}:</span> LKR {totalOut.toLocaleString()}</div>
           <div><span className="font-bold">{t.totalBalance}:</span> LKR {transactions[transactions.length - 1]?.totalBalance.toLocaleString()}</div>
        </div>
      </div>

      <div className="overflow-x-auto">
        <table className="w-full text-left min-w-[1000px] border-collapse">
          <thead>
            <tr className="bg-slate-50 text-slate-500 text-[10px] uppercase font-black tracking-widest border-b border-slate-200">
              <th className="px-6 py-4 border-r border-slate-100">{t.date}</th>
              <th className="px-6 py-4 border-r border-slate-100">{t.dailyCash}</th>
              <th className="px-6 py-4">{t.groceries}</th>
              <th className="px-6 py-4">{t.vegetables}</th>
              <th className="px-6 py-4">{t.fishEgg}</th>
              <th className="px-6 py-4">{t.chicken}</th>
              <th className="px-6 py-4">{t.houseRent}</th>
              <th className="px-6 py-4">{t.travel}</th>
              <th className="px-6 py-4">{t.others}</th>
              <th className="px-6 py-4 border-l border-slate-100">{t.totalExpenses}</th>
              <th className="px-6 py-4 bg-indigo-50/30 text-indigo-700 border-l border-slate-100">{t.totalBalance}</th>
              <th className="px-6 py-4 text-center no-print">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100 text-sm">
            {transactions.map((tx) => (
              <tr key={tx.id || tx.timestamp} className="hover:bg-slate-50/50 transition-colors">
                <td className="px-6 py-4 font-semibold text-slate-700 whitespace-nowrap border-r border-slate-50">{tx.date.split('-').reverse().join('/')}</td>
                <td className="px-6 py-4 font-bold text-emerald-600 border-r border-slate-50">LKR {tx.dailyCash?.toLocaleString()}</td>
                <td className="px-6 py-4 text-slate-600">{tx.groceries?.toLocaleString()}</td>
                <td className="px-6 py-4 text-slate-600">{tx.vegetables?.toLocaleString()}</td>
                <td className="px-6 py-4 text-slate-600">{tx.fishEgg?.toLocaleString()}</td>
                <td className="px-6 py-4 text-slate-600">{tx.chicken?.toLocaleString()}</td>
                <td className="px-6 py-4 text-slate-600">{tx.houseRent?.toLocaleString()}</td>
                <td className="px-6 py-4 text-slate-600">{tx.travel?.toLocaleString()}</td>
                <td className="px-6 py-4 text-slate-600">{tx.others?.toLocaleString()}</td>
                <td className="px-6 py-4 font-bold text-rose-500 border-l border-slate-50">LKR {tx.totalExpenses?.toLocaleString()}</td>
                <td className="px-6 py-4 font-black text-indigo-600 bg-indigo-50/20 border-l border-slate-50">LKR {tx.totalBalance?.toLocaleString()}</td>
                <td className="px-6 py-4 no-print">
                  <div className="flex items-center justify-center gap-2">
                    <button 
                      onClick={() => onEdit(tx)}
                      className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-all"
                    >
                      <Edit2 className="w-4 h-4" />
                    </button>
                    <button 
                      onClick={() => tx.id && onDelete(tx.id)}
                      className="p-2 text-slate-400 hover:text-rose-600 hover:bg-rose-50 rounded-lg transition-all"
                    >
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* Print-Only Footer */}
      <div className="print-only mt-12 text-xs text-slate-400 text-center border-t pt-4">
        Generated by Personal Account Tracker | {new Date().toLocaleString()}
      </div>
    </div>
  );
};

export default HistoryTable;

import React, { useState } from 'react';
import { User } from '../types';
// Corrected import to match storageService export in googleSheets.ts
import { storageService } from '../services/googleSheets';

interface AuthFormProps {
  t: any;
  onAuthSuccess: (user: User) => void;
}

const AuthForm: React.FC<AuthFormProps> = ({ t, onAuthSuccess }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    try {
      if (isLogin) {
        // Use storageService instead of googleSheetsService as per services/googleSheets.ts export
        const user = await storageService.login(email, password);
        if (user) onAuthSuccess(user);
        else setError('Invalid credentials');
      } else {
        // Use storageService instead of googleSheetsService as per services/googleSheets.ts export
        const user = await storageService.register(name, email, password);
        if (user) onAuthSuccess(user);
        else setError('Registration failed');
      }
    } catch (err) {
      setError('Something went wrong. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="bg-white p-8 rounded-3xl shadow-xl border border-slate-100">
      <form onSubmit={handleSubmit} className="space-y-4">
        {!isLogin && (
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-1">{t.name}</label>
            <input
              type="text"
              required
              className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all"
              value={name}
              onChange={(e) => setName(e.target.value)}
            />
          </div>
        )}
        <div>
          <label className="block text-sm font-semibold text-slate-700 mb-1">{t.email}</label>
          <input
            type="email"
            required
            className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
          />
        </div>
        <div>
          <label className="block text-sm font-semibold text-slate-700 mb-1">{t.password}</label>
          <input
            type="password"
            required
            minLength={4}
            className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
          />
        </div>

        {error && <p className="text-rose-500 text-sm font-medium">{error}</p>}

        <button
          type="submit"
          disabled={loading}
          className="w-full bg-indigo-600 text-white py-3 rounded-xl font-bold shadow-lg shadow-indigo-200 hover:bg-indigo-700 active:scale-[0.98] transition-all disabled:opacity-50"
        >
          {loading ? '...' : isLogin ? t.login : t.register}
        </button>
      </form>

      <div className="mt-6 text-center">
        <button
          onClick={() => setIsLogin(!isLogin)}
          className="text-sm font-semibold text-indigo-600 hover:underline"
        >
          {isLogin ? "Don't have an account? Register" : "Already have an account? Login"}
        </button>
      </div>
    </div>
  );
};

export default AuthForm;

import { Transaction } from '../types';

const STORAGE_KEY = 'finance_tracker_v3_local_data';

export const storageService = {
  async fetchTransactions(): Promise<Transaction[]> {
    const data = localStorage.getItem(STORAGE_KEY);
    return data ? JSON.parse(data) : [];
  },

  async addTransaction(transaction: Transaction): Promise<boolean> {
    const data = await this.fetchTransactions();
    const newTx = { ...transaction, id: crypto.randomUUID() };
    data.push(newTx);
    localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
    return true;
  },

  async updateTransaction(id: string, transaction: Transaction): Promise<boolean> {
    const data = await this.fetchTransactions();
    const index = data.findIndex(tx => tx.id === id);
    if (index !== -1) {
      data[index] = { ...transaction, id };
      localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
      return true;
    }
    return false;
  },

  async deleteTransaction(id: string): Promise<boolean> {
    const data = await this.fetchTransactions();
    const filtered = data.filter(tx => tx.id !== id);
    localStorage.setItem(STORAGE_KEY, JSON.stringify(filtered));
    return true;
  }
};

import React, { useState, useEffect, useCallback } from 'react';
import { Transaction, Language } from './types';
import { translations } from './translations';
import { storageService } from './services/googleSheets';
import Dashboard from './components/Dashboard';
import { Globe, Wallet, LayoutDashboard, History, BarChart3 } from 'lucide-react';

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>('en');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'analytics' | 'history'>('dashboard');
  const [isLoading, setIsLoading] = useState(false);

  const t = translations[lang];

  const loadData = useCallback(async () => {
    setIsLoading(true);
    try {
      const data = await storageService.fetchTransactions();
      setTransactions(data);
    } catch (err) {
      console.error("Failed to load data", err);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    loadData();
    const savedLang = localStorage.getItem('lang');
    if (savedLang) setLang(savedLang as Language);
  }, [loadData]);

  const toggleLanguage = () => {
    const newLang = lang === 'en' ? 'si' : 'en';
    setLang(newLang);
