                onClick={() => setShowBudgetForm(false)}
                className="p-2 hover:bg-slate-100 rounded-full transition-colors"
              >
                <X className="w-6 h-6 text-slate-400" />
              </button>
            </div>
            <div className="p-6">
              <BudgetManager 
                t={t} 
                month={selectedMonth} 
                initialLimits={activeBudget.limits} 
                onSubmit={handleSaveBudget} 
              />
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { MonthlyBudget } from '../types';

interface BudgetManagerProps {
  t: any;
  month: string;
  initialLimits: MonthlyBudget['limits'];
  onSubmit: (limits: MonthlyBudget['limits']) => void;
}

const BudgetManager: React.FC<BudgetManagerProps> = ({ t, month, initialLimits, onSubmit }) => {
  const [limits, setLimits] = useState(initialLimits);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setLimits(prev => ({
      ...prev,
      [name]: value === '' ? 0 : parseFloat(value)
    }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit(limits);
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-4">
      <div className="bg-indigo-50 p-4 rounded-2xl mb-4 text-center">
        <p className="text-xs font-black text-indigo-400 uppercase tracking-widest mb-1">{t.month}</p>
        <p className="font-bold text-indigo-700">{month}</p>
      </div>

      <div className="grid grid-cols-1 gap-3 max-h-[400px] overflow-y-auto px-1">
        {[
          { name: 'groceries', label: t.groceries },
          { name: 'vegetables', label: t.vegetables },
          { name: 'fishEgg', label: t.fishEgg },
          { name: 'chicken', label: t.chicken },
          { name: 'houseRent', label: t.houseRent },
          { name: 'travel', label: t.travel },
          { name: 'others', label: t.others },
        ].map(field => (
          <div key={field.name} className="flex items-center gap-4">
            <label className="flex-1 text-sm font-semibold text-slate-700">{field.label}</label>
            <input
              type="number"
              name={field.name}
              placeholder="0"
              className="w-32 px-3 py-2 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none transition-all text-right font-bold text-indigo-600"
              value={(limits as any)[field.name] || ''}
              onChange={handleChange}
            />
          </div>
        ))}
      </div>

      <button
        type="submit"
        className="w-full bg-indigo-600 text-white py-3.5 rounded-xl font-bold shadow-lg shadow-indigo-100 hover:bg-indigo-700 active:scale-95 transition-all mt-6"
      >
        {t.save}
      </button>
    </form>
  );
};

export default BudgetManager;

import React, { useState, useEffect, useCallback } from 'react';
import { Transaction, Language } from './types';
import { translations } from './translations';
import { storageService } from './services/googleSheets';
import Dashboard from './components/Dashboard';
import { Globe, Wallet, LayoutDashboard, History, BarChart3, Target } from 'lucide-react';

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>('en');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'analytics' | 'history' | 'budget'>('dashboard');
  const [isLoading, setIsLoading] = useState(false);

  const t = translations[lang];

  const loadData = useCallback(async () => {
    setIsLoading(true);
    try {
      const data = await storageService.fetchTransactions();
      setTransactions(data);
    } catch (err) {
      console.error("Failed to load data", err);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    loadData();
    const savedLang = localStorage.getItem('lang');
    if (savedLang) setLang(savedLang as Language);
  }, [loadData]);

  const toggleLanguage = () => {
    const newLang = lang === 'en' ? 'si' : 'en';
    setLang(newLang);
    localStorage.setItem('lang', newLang);
  };

  const onAddTransaction = async (data: Transaction) => {
    setIsLoading(true);
    await storageService.addTransaction(data);
    await loadData();
    setIsLoading(false);
  };

  const onUpdateTransaction = async (id: string, data: Transaction) => {
    setIsLoading(true);
    await storageService.updateTransaction(id, data);
    await loadData();
    setIsLoading(false);
  };

  const onDeleteTransaction = async (id: string) => {
    if(confirm(t.confirmDelete)) {
      setIsLoading(true);
      await storageService.deleteTransaction(id);
      await loadData();
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20 md:pb-0 font-sans">
      {/* Sidebar / Desktop Nav */}
