export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { Transaction, MonthlySummary, MonthlyBudget } from '../types';
import TransactionForm from './TransactionForm';
import StatsOverview from './StatsOverview';
import MonthlyCharts from './MonthlyCharts';
import HistoryTable from './HistoryTable';
import BudgetManager from './BudgetManager';
import BudgetPerformance from './BudgetPerformance';
import { Plus, X, Calendar, BarChart3, ClipboardList, ArrowRight, Target, AlertCircle } from 'lucide-react';
import { storageService } from '../services/googleSheets';

interface DashboardProps {
  activeTab: 'dashboard' | 'analytics' | 'history' | 'budget';
  setActiveTab?: (tab: 'dashboard' | 'analytics' | 'history' | 'budget') => void;
  t: any;
  transactions: Transaction[];
  onAdd: (data: Transaction) => void;
  onUpdate: (id: string, data: Transaction) => void;
  onDelete: (id: string) => void;
  onRefresh: () => void;
  isLoading: boolean;
}

const Dashboard: React.FC<DashboardProps> = ({ 
  activeTab, 
  setActiveTab,
  t, 
  transactions, 
  onAdd, 
  onUpdate,
  onDelete,
  onRefresh,
  isLoading 
}) => {
  const [showAddForm, setShowAddForm] = useState(false);
  const [showBudgetForm, setShowBudgetForm] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [budgets, setBudgets] = useState<MonthlyBudget[]>([]);

  useEffect(() => {
    const loadBudgets = async () => {
      const data = await storageService.fetchBudgets();
      setBudgets(data);
    };
    loadBudgets();
  }, [transactions]);

  const currentMonthName = useMemo(() => {
    return new Date().toLocaleString('en-US', { month: 'long', year: 'numeric' });
  }, []);

  const availableMonths = useMemo(() => {
    const monthsSet = new Set<string>();
    transactions.forEach(tx => {
      if (tx.month) monthsSet.add(tx.month.trim());
    });
    monthsSet.add(currentMonthName);
    return Array.from(monthsSet).sort((a, b) => {
      const dateA = new Date(a);
      const dateB = new Date(b);
      return dateB.getTime() - dateA.getTime();
    });
  }, [transactions, currentMonthName]);

  const [selectedMonth, setSelectedMonth] = useState<string>(availableMonths[0] || currentMonthName);

  const activeBudget = useMemo(() => {
    return budgets.find(b => b.month === selectedMonth) || {
      month: selectedMonth,
      limits: { groceries: 0, vegetables: 0, fishEgg: 0, chicken: 0, houseRent: 0, travel: 0, others: 0 }
    };
  }, [budgets, selectedMonth]);

  const currentMonthTransactions = useMemo(() => {
    return transactions.filter(tx => tx.month?.trim() === selectedMonth).sort((a, b) => a.date.localeCompare(b.date));
  }, [transactions, selectedMonth]);

  const categorySpending = useMemo(() => {
    const totals = { groceries: 0, vegetables: 0, fishEgg: 0, chicken: 0, houseRent: 0, travel: 0, others: 0 };
    currentMonthTransactions.forEach(tx => {
      totals.groceries += tx.groceries;
      totals.vegetables += tx.vegetables;
      totals.fishEgg += tx.fishEgg;
      totals.chicken += tx.chicken;
      totals.houseRent += tx.houseRent;
      totals.travel += tx.travel;
      totals.others += tx.others;
    });
    return totals;
  }, [currentMonthTransactions]);

  const filteredStats = useMemo(() => {
    const totalSpent = currentMonthTransactions.reduce((sum, tx) => sum + (Number(tx.totalExpenses) || 0), 0);
    const totalReceived = currentMonthTransactions.reduce((sum, tx) => sum + (Number(tx.dailyCash) || 0), 0);
    const lastBalance = currentMonthTransactions.length > 0 ? (Number(currentMonthTransactions[currentMonthTransactions.length - 1].totalBalance) || 0) : 0;
    return { totalSpent, totalReceived, lastBalance };
  }, [currentMonthTransactions]);

  const handleEdit = (tx: Transaction) => {
    setEditingTransaction(tx);
    setShowAddForm(true);
  };

  const handleSaveBudget = async (limits: MonthlyBudget['limits']) => {
    await storageService.saveBudget(selectedMonth, limits);
    const updated = await storageService.fetchBudgets();
    setBudgets(updated);
    setShowBudgetForm(false);
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row items-center justify-between gap-4 bg-white p-4 rounded-3xl border border-slate-100 shadow-sm no-print">
        <div className="flex items-center gap-3 w-full sm:w-auto">
          <div className="p-2 bg-indigo-50 rounded-xl">
            <Calendar className="w-5 h-5 text-indigo-600" />
          </div>
          <div className="flex-grow">
            <h2 className="text-[10px] font-bold text-slate-400 uppercase tracking-widest leading-none mb-1">{t.selectMonth}</h2>
            <select 
              value={selectedMonth}
              onChange={(e) => setSelectedMonth(e.target.value)}
              className="bg-transparent font-bold text-lg text-slate-800 outline-none cursor-pointer hover:text-indigo-600 transition-colors"
            >
              {availableMonths.map(m => (
                <option key={m} value={m}>{m}</option>
              ))}
            </select>
          </div>
        </div>

        <div className="flex items-center gap-3 w-full sm:w-auto">
          <button 
            onClick={() => setShowBudgetForm(true)}
            className="flex items-center gap-2 px-6 py-3 bg-white text-indigo-600 rounded-2xl font-bold hover:bg-indigo-50 transition-all border border-indigo-100 shadow-sm active:scale-95"
          >
            <Target className="w-5 h-5" />
            <span className="hidden sm:inline">{t.manageBudget}</span>
          </button>
          <button 
            onClick={() => setShowAddForm(true)}
            className="flex-grow sm:flex-grow-0 bg-indigo-600 text-white px-6 py-3 rounded-2xl font-bold flex items-center justify-center gap-2 shadow-lg shadow-indigo-200 hover:bg-indigo-700 active:scale-95 transition-all"
          >
            <Plus className="w-5 h-5" />
            {t.addRecord}
          </button>
        </div>
      </div>

      {activeTab === 'dashboard' && (
        <>
          <StatsOverview t={t} stats={filteredStats} />

          {/* Budget Tracking Section */}
          <div className="mt-8 bg-white p-6 rounded-3xl border border-slate-100 shadow-sm">
            <div className="flex items-center justify-between mb-6">
               <div className="flex items-center gap-3">
                 <div className="p-2 bg-emerald-50 rounded-xl text-emerald-600">
                    <Target className="w-6 h-6" />
                 </div>
                 <h2 className="text-xl font-bold text-slate-800">{t.budgetStatus}</h2>
               </div>
               <div className="text-xs text-slate-400 font-bold uppercase tracking-widest">{selectedMonth}</div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-x-8 gap-y-6">
              {[
                { key: 'groceries', label: t.groceries },
                { key: 'vegetables', label: t.vegetables },
                { key: 'fishEgg', label: t.fishEgg },
                { key: 'chicken', label: t.chicken },
                { key: 'houseRent', label: t.houseRent },
                { key: 'travel', label: t.travel },
                { key: 'others', label: t.others },
              ].map(({ key, label }) => {
                const limit = (activeBudget.limits as any)[key] || 0;
                const spent = (categorySpending as any)[key] || 0;
                const percent = limit > 0 ? (spent / limit) * 100 : 0;
                const remaining = limit - spent;

                let barColor = "bg-indigo-500";
                if (percent >= 100) barColor = "bg-rose-500";
                else if (percent >= 80) barColor = "bg-amber-500";

                return (
                  <div key={key} className="space-y-2">
                    <div className="flex justify-between items-end">
                      <span className="text-sm font-bold text-slate-700">{label}</span>
                      <div className="text-right">
                        <span className={`text-[10px] font-black uppercase ${percent > 100 ? 'text-rose-500' : 'text-slate-400'}`}>
                          {spent.toLocaleString()} / {limit > 0 ? limit.toLocaleString() : '---'}
                        </span>
                      </div>
                    </div>
                    <div className="h-2.5 w-full bg-slate-100 rounded-full overflow-hidden">
                      <div 
                        className={`h-full transition-all duration-500 ${barColor}`} 
                        style={{ width: `${Math.min(percent, 100)}%` }}
                      ></div>
                    </div>
                    <div className="flex justify-between text-[10px] font-bold">
                       {limit > 0 ? (
                         remaining >= 0 ? (
                           <span className="text-emerald-500">{t.remaining}: LKR {remaining.toLocaleString()}</span>
                         ) : (
                           <span className="text-rose-500 flex items-center gap-1">
                             <AlertCircle className="w-3 h-3" />
                             {t.overspent}: LKR {Math.abs(remaining).toLocaleString()}
                           </span>
                         )
                       ) : (
                         <span className="text-slate-300">Budget not set</span>
                       )}
                       <span className="text-slate-400">{Math.round(percent)}%</span>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>

          <div className="mt-8 bg-white rounded-3xl border border-slate-100 shadow-sm overflow-hidden">
            <div className="p-6 border-b border-slate-100 flex items-center justify-between">
              <div className="flex items-center gap-3">
                <ClipboardList className="w-6 h-6 text-indigo-600" />
                <h2 className="text-xl font-bold text-slate-800">{t.recentTransactions}</h2>
              </div>
              <button 
                onClick={() => setActiveTab?.('history')}
                className="flex items-center gap-1 text-sm font-bold text-indigo-600 hover:text-indigo-700 transition-colors"
              >
                {t.viewAll}
                <ArrowRight className="w-4 h-4" />
              </button>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full text-left min-w-[800px]">
                <thead>
                  <tr className="bg-slate-50 text-slate-500 text-[10px] uppercase font-black tracking-widest border-b border-slate-100">
                    <th className="px-6 py-4">{t.date}</th>
                    <th className="px-6 py-4">{t.month}</th>
                    <th className="px-6 py-4">{t.dailyCash}</th>
                    <th className="px-6 py-4">{t.totalExpenses}</th>
                    <th className="px-6 py-4 bg-indigo-50/30 text-indigo-700">{t.totalBalance}</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {transactions.slice().reverse().slice(0, 5).map((tx) => (
                    <tr key={tx.id || tx.timestamp} className="hover:bg-slate-50/50 transition-colors">
                      <td className="px-6 py-4 text-sm font-semibold text-slate-700">{tx.date.split('-').reverse().join('/')}</td>
                      <td className="px-6 py-4 text-xs font-medium text-slate-400">{tx.month}</td>
                      <td className="px-6 py-4 text-sm font-bold text-emerald-600">LKR {Number(tx.dailyCash)?.toLocaleString()}</td>
                      <td className="px-6 py-4 text-sm font-bold text-rose-500">LKR {Number(tx.totalExpenses)?.toLocaleString()}</td>
                      <td className="px-6 py-4 text-sm font-black text-indigo-600 bg-indigo-50/20">LKR {Number(tx.totalBalance)?.toLocaleString()}</td>
                    </tr>
                  ))}
                  {transactions.length === 0 && (
                    <tr>
                      <td colSpan={5} className="px-6 py-12 text-center text-slate-400 font-medium italic">{t.noData}</td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </>
      )}

      {activeTab === 'analytics' && (
        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div>
            <div className="flex items-center justify-between mb-6">
              <div className="flex items-center gap-3">
                <div className="p-2 bg-indigo-100 rounded-xl">
                  <BarChart3 className="w-6 h-6 text-indigo-700" />
                </div>
                <h2 className="text-2xl font-black text-slate-800">{t.charts} - {selectedMonth}</h2>
              </div>
            </div>
            <MonthlyCharts t={t} transactions={currentMonthTransactions} />
          </div>
        </div>
      )}

      {activeTab === 'budget' && (
        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
          <BudgetPerformance 
            t={t} 
            transactions={transactions} 
            budgets={budgets} 
          />
        </div>
      )}

      {activeTab === 'history' && (
        <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div className="p-6 border-b border-slate-100 flex items-center justify-between no-print">
            <h2 className="text-xl font-bold text-slate-800">{t.history} ({selectedMonth})</h2>
          </div>
          <HistoryTable 
            t={t} 
            transactions={transactions.filter(tx => tx.month?.trim() === selectedMonth)} 
            allTransactions={transactions}
            onEdit={handleEdit} 
            onDelete={onDelete} 
            isLoading={isLoading} 
          />
        </div>
      )}

      {showAddForm && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm no-print">
          <div className="bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden max-h-[90vh] flex flex-col scale-in-center">
            <div className="p-6 border-b border-slate-100 flex items-center justify-between">
              <h3 className="text-xl font-bold text-slate-800">
                {editingTransaction ? t.edit : t.addRecord}
              </h3>
              <button 
                onClick={() => { setShowAddForm(false); setEditingTransaction(null); }}
                className="p-2 hover:bg-slate-100 rounded-full transition-colors"
              >
                <X className="w-6 h-6 text-slate-400" />
              </button>
            </div>
            <div className="p-6 overflow-y-auto">
              <TransactionForm 
                t={t} 
                initialData={editingTransaction}
                onSubmit={(data) => {
                  if (editingTransaction?.id) {
                    onUpdate(editingTransaction.id, data);
                  } else {
                    onAdd(data);
                  }
                  setShowAddForm(false);
                  setEditingTransaction(null);
                }} 
              />
            </div>
          </div>
        </div>
      )}

      {showBudgetForm && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm no-print">
          <div className="bg-white w-full max-w-lg rounded-3xl shadow-2xl overflow-hidden flex flex-col scale-in-center">
            <div className="p-6 border-b border-slate-100 flex items-center justify-between">
              <h3 className="text-xl font-bold text-slate-800">{t.manageBudget}</h3>
              <button 
                onClick={() => setShowBudgetForm(false)}
                className="p-2 hover:bg-slate-100 rounded-full transition-colors"
              >
                <X className="w-6 h-6 text-slate-400" />
              </button>
            </div>
            <div className="p-6">
              <BudgetManager 
                t={t} 
                month={selectedMonth} 
                initialLimits={activeBudget.limits} 
                onSubmit={handleSaveBudget} 
              />
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Dashboard;

import React, { useMemo } from 'react';
