import React, { useState, useEffect, useCallback } from 'react';
import { Transaction, Language, CurrencySettings } from './types';
import { translations } from './translations';
import { storageService } from './services/googleSheets';
import Dashboard from './components/Dashboard';
import SettingsPage from './components/SettingsPage';
import { Globe, Wallet, LayoutDashboard, History, BarChart3, Target, Settings } from 'lucide-react';

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>('en');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'analytics' | 'history' | 'budget' | 'settings'>('dashboard');
  const [isLoading, setIsLoading] = useState(false);
  const [currencySettings, setCurrencySettings] = useState<CurrencySettings>({
    symbol: 'LKR',
    position: 'before'
  });

  const t = translations[lang];

  const formatCurrency = useCallback((amount: number) => {
    const formattedAmount = amount.toLocaleString();
    return currencySettings.position === 'before' 
      ? `${currencySettings.symbol} ${formattedAmount}`
      : `${formattedAmount} ${currencySettings.symbol}`;
  }, [currencySettings]);

  const loadData = useCallback(async () => {
    setIsLoading(true);
    try {
      const data = await storageService.fetchTransactions();
      setTransactions(data);

      const savedLang = localStorage.getItem('lang');
      if (savedLang) setLang(savedLang as Language);

      const savedCurrency = localStorage.getItem('currency_settings');
      if (savedCurrency) setCurrencySettings(JSON.parse(savedCurrency));
    } catch (err) {
      console.error("Failed to load data", err);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    loadData();
  }, [loadData]);

  const toggleLanguage = () => {
    const newLang = lang === 'en' ? 'si' : 'en';
    setLang(newLang);
    localStorage.setItem('lang', newLang);
  };

  const saveCurrencySettings = (settings: CurrencySettings) => {
    setCurrencySettings(settings);
    localStorage.setItem('currency_settings', JSON.stringify(settings));
  };

  const onAddTransaction = async (data: Transaction) => {
    setIsLoading(true);
    await storageService.addTransaction(data);
    await loadData();
    setIsLoading(false);
  };

  const onUpdateTransaction = async (id: string, data: Transaction) => {
    setIsLoading(true);
    await storageService.updateTransaction(id, data);
    await loadData();
    setIsLoading(false);
  };

  const onDeleteTransaction = async (id: string) => {
    if(confirm(t.confirmDelete)) {
      setIsLoading(true);
      await storageService.deleteTransaction(id);
      await loadData();
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20 md:pb-0 font-sans">
      {/* Sidebar / Desktop Nav */}
      <nav className="hidden md:flex flex-col fixed h-full w-64 bg-white border-r border-slate-200 p-6 z-20 no-print">
        <div className="flex items-center gap-3 mb-10">
          <div className="p-2 bg-indigo-600 rounded-xl">
            <Wallet className="w-6 h-6 text-white" />
          </div>
          <h1 className="font-bold text-lg text-slate-800 leading-tight">{t.title}</h1>
        </div>

        <div className="space-y-2 flex-grow">
          <button 
            onClick={() => setActiveTab('dashboard')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium transition-all ${activeTab === 'dashboard' ? 'bg-indigo-50 text-indigo-600 shadow-sm' : 'text-slate-500 hover:bg-slate-50 hover:text-slate-800'}`}
          >
            <LayoutDashboard className="w-5 h-5" />
            {t.dashboard}
          </button>
          <button 
            onClick={() => setActiveTab('analytics')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium transition-all ${activeTab === 'analytics' ? 'bg-indigo-50 text-indigo-600 shadow-sm' : 'text-slate-500 hover:bg-slate-50 hover:text-slate-800'}`}
          >
            <BarChart3 className="w-5 h-5" />
            {t.charts}
          </button>
          <button 
            onClick={() => setActiveTab('budget')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium transition-all ${activeTab === 'budget' ? 'bg-indigo-50 text-indigo-600 shadow-sm' : 'text-slate-500 hover:bg-slate-50 hover:text-slate-800'}`}
          >
            <Target className="w-5 h-5" />
            {t.budgetPerformance}
          </button>
          <button 
            onClick={() => setActiveTab('history')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium transition-all ${activeTab === 'history' ? 'bg-indigo-50 text-indigo-600 shadow-sm' : 'text-slate-500 hover:bg-slate-50 hover:text-slate-800'}`}
          >
            <History className="w-5 h-5" />
            {t.history}
          </button>
        </div>

        <div className="mt-auto space-y-2 border-t border-slate-100 pt-6">
          <button 
            onClick={() => setActiveTab('settings')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium transition-all ${activeTab === 'settings' ? 'bg-indigo-50 text-indigo-600 shadow-sm' : 'text-slate-500 hover:bg-slate-50 hover:text-slate-800'}`}
          >
            <Settings className="w-5 h-5" />
            {t.settings}
          </button>
          <button 
            onClick={toggleLanguage}
            className="w-full flex items-center gap-3 px-4 py-3 text-slate-500 hover:text-indigo-600 font-medium transition-colors"
          >
            <Globe className="w-5 h-5" />
            {t.language}
          </button>
        </div>
      </nav>

      {/* Mobile Top Nav */}
      <header className="md:hidden bg-white border-b border-slate-200 px-4 py-3 flex items-center justify-between sticky top-0 z-30 no-print">
        <div className="flex items-center gap-2">
          <Wallet className="w-6 h-6 text-indigo-600" />
          <h1 className="font-bold text-sm text-slate-800">{t.title}</h1>
        </div>
        <div className="flex items-center gap-2">
          <button onClick={() => setActiveTab('settings')} className="p-2 text-slate-500 hover:bg-slate-100 rounded-lg transition-colors">
            <Settings className="w-5 h-5"/>
          </button>
          <button onClick={toggleLanguage} className="p-2 text-slate-500 hover:bg-slate-100 rounded-lg transition-colors">
            <Globe className="w-5 h-5"/>
          </button>
        </div>
      </header>

      {/* Main Content */}
      <main className="md:pl-64 min-h-screen">
        <div className="max-w-6xl mx-auto p-4 md:p-8">
          {activeTab === 'settings' ? (
            <SettingsPage 
              t={t} 
              settings={currencySettings} 
              onSave={saveCurrencySettings} 
            />
          ) : (
            <Dashboard 
              activeTab={activeTab} 
              setActiveTab={setActiveTab}
              t={t} 
              transactions={transactions} 
              onAdd={onAddTransaction}
              onUpdate={onUpdateTransaction}
              onDelete={onDeleteTransaction}
              onRefresh={loadData}
