import { Transaction, MonthlyBudget, Bill } from '../types';

const STORAGE_KEY = 'finance_tracker_v3_local_data';
const BUDGET_KEY = 'finance_tracker_v3_budgets';
const BILLS_KEY = 'finance_tracker_v3_bills';

export const storageService = {
  async fetchTransactions(): Promise<Transaction[]> {
    const data = localStorage.getItem(STORAGE_KEY);
    return data ? JSON.parse(data) : [];
  },

  async addTransaction(transaction: Transaction): Promise<boolean> {
    const data = await this.fetchTransactions();
    const newTx = { ...transaction, id: crypto.randomUUID() };
    data.push(newTx);
    localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
    return true;
  },

  async updateTransaction(id: string, transaction: Transaction): Promise<boolean> {
    const data = await this.fetchTransactions();
    const index = data.findIndex(tx => tx.id === id);
    if (index !== -1) {
      data[index] = { ...transaction, id };
      localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
      return true;
    }
    return false;
  },

  async deleteTransaction(id: string): Promise<boolean> {
    const data = await this.fetchTransactions();
    const filtered = data.filter(tx => tx.id !== id);
    localStorage.setItem(STORAGE_KEY, JSON.stringify(filtered));
    return true;
  },

  async fetchBudgets(): Promise<MonthlyBudget[]> {
    const data = localStorage.getItem(BUDGET_KEY);
    return data ? JSON.parse(data) : [];
  },

  async saveBudget(month: string, limits: MonthlyBudget['limits']): Promise<boolean> {
    const budgets = await this.fetchBudgets();
    const index = budgets.findIndex(b => b.month === month);
    if (index !== -1) {
      budgets[index].limits = limits;
    } else {
      budgets.push({ month, limits });
    }
    localStorage.setItem(BUDGET_KEY, JSON.stringify(budgets));
    return true;
  },

  async fetchBills(): Promise<Bill[]> {
    const data = localStorage.getItem(BILLS_KEY);
    return data ? JSON.parse(data) : [];
  },

  async saveBill(bill: Bill): Promise<boolean> {
    const bills = await this.fetchBills();
    const index = bills.findIndex(b => b.id === bill.id);
    if (index !== -1) {
      bills[index] = bill;
    } else {
      bills.push(bill);
    }
    localStorage.setItem(BILLS_KEY, JSON.stringify(bills));
    return true;
  },

  async deleteBill(id: string): Promise<boolean> {
    const bills = await this.fetchBills();
    const filtered = bills.filter(b => b.id !== id);
    localStorage.setItem(BILLS_KEY, JSON.stringify(filtered));
    return true;
  }
};

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { Transaction, Language, CurrencySettings, Notification, MonthlyBudget, Bill } from './types';
import { translations } from './translations';
import { storageService } from './services/googleSheets';
import Dashboard from './components/Dashboard';
import SettingsPage from './components/SettingsPage';
import NotificationDrawer from './components/NotificationDrawer';
import BillManager from './components/BillManager';
import { Globe, Wallet, LayoutDashboard, History, BarChart3, Target, Settings, Bell, CreditCard } from 'lucide-react';

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>('en');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'analytics' | 'history' | 'budget' | 'settings' | 'bills'>('dashboard');
  const [isLoading, setIsLoading] = useState(false);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [isNotificationOpen, setIsNotificationOpen] = useState(false);
  const [currencySettings, setCurrencySettings] = useState<CurrencySettings>({
    symbol: 'LKR',
    position: 'before'
  });

  const t = translations[lang];

  const formatCurrency = useCallback((amount: number) => {
    const formattedAmount = amount.toLocaleString();
    return currencySettings.position === 'before' 
      ? `${currencySettings.symbol} ${formattedAmount}`
      : `${formattedAmount} ${currencySettings.symbol}`;
  }, [currencySettings]);

  const generateNotifications = useCallback(async (txs: Transaction[]) => {
    const budgets = await storageService.fetchBudgets();
    const bills = await storageService.fetchBills();
    const currentMonth = new Date().toLocaleString('en-US', { month: 'long', year: 'numeric' });
    const currentMonthTxs = txs.filter(tx => tx.month === currentMonth);
    const budget = budgets.find(b => b.month === currentMonth);
    const newNotifications: Notification[] = [];

    // 1. Check Low Budgets
    if (budget) {
      const categories = ['groceries', 'vegetables', 'fishEgg', 'chicken', 'houseRent', 'travel', 'others'];
      categories.forEach(cat => {
        const limit = (budget.limits as any)[cat];
        const spent = currentMonthTxs.reduce((sum, tx) => sum + ((tx as any)[cat] || 0), 0);
        if (limit > 0 && spent / limit >= 0.85) {
          newNotifications.push({
            id: `budget-${cat}-${currentMonth}`,
            type: 'budget',
            title: t.lowBudgetAlert,
            message: t.lowBudgetMsg.replace('{percent}', Math.round((spent/limit)*100).toString()).replace('{category}', (t as any)[cat]),
            timestamp: new Date().toISOString(),
            read: false,
            priority: spent >= limit ? 'high' : 'medium'
          });
        }
      });
    }

    // 2. Check Upcoming Bills
    const today = new Date().getDate();
    bills.forEach(bill => {
      const daysLeft = bill.dueDay - today;
      if (daysLeft >= 0 && daysLeft <= 3) {
        newNotifications.push({
          id: `bill-${bill.id}-${currentMonth}`,
          type: 'bill',
          title: bill.name,
          message: t.billDueIn.replace('{days}', daysLeft.toString()),
          timestamp: new Date().toISOString(),
          read: false,
          priority: daysLeft === 0 ? 'high' : 'medium'
        });
      }
    });

    // Simple deduplication based on ID
    setNotifications(prev => {
      const existingIds = new Set(prev.map(n => n.id));
      const added = newNotifications.filter(n => !existingIds.has(n.id));
      return [...added, ...prev].slice(0, 20);
    });
  }, [t]);

  const loadData = useCallback(async () => {
    setIsLoading(true);
    try {
      const data = await storageService.fetchTransactions();
      setTransactions(data);
      generateNotifications(data);

      const savedLang = localStorage.getItem('lang');
      if (savedLang) setLang(savedLang as Language);

      const savedCurrency = localStorage.getItem('currency_settings');
      if (savedCurrency) setCurrencySettings(JSON.parse(savedCurrency));
    } catch (err) {
      console.error("Failed to load data", err);
    } finally {
      setIsLoading(false);
    }
  }, [generateNotifications]);

  useEffect(() => {
    loadData();
  }, [loadData]);

  const unreadCount = useMemo(() => notifications.filter(n => !n.read).length, [notifications]);

  return (
    <div className="min-h-screen bg-slate-50 pb-20 md:pb-0 font-sans">
      <nav className="hidden md:flex flex-col fixed h-full w-64 bg-white border-r border-slate-200 p-6 z-20 no-print">
        <div className="flex items-center gap-3 mb-10">
          <div className="p-2 bg-indigo-600 rounded-xl shadow-lg shadow-indigo-200">
            <Wallet className="w-6 h-6 text-white" />
          </div>
          <h1 className="font-bold text-lg text-slate-800 leading-tight">{t.title}</h1>
        </div>

        <div className="space-y-2 flex-grow">
          {[
            { id: 'dashboard', label: t.dashboard, icon: LayoutDashboard },
            { id: 'analytics', label: t.charts, icon: BarChart3 },
            { id: 'budget', label: t.budgetPerformance, icon: Target },
            { id: 'bills', label: t.bills, icon: CreditCard },
            { id: 'history', label: t.history, icon: History },
          ].map(tab => (
            <button 
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium transition-all ${activeTab === tab.id ? 'bg-indigo-50 text-indigo-600 shadow-sm' : 'text-slate-500 hover:bg-slate-50 hover:text-slate-800'}`}
            >
              <tab.icon className="w-5 h-5" />
              {tab.label}
            </button>
          ))}
        </div>

        <div className="mt-auto space-y-2 border-t border-slate-100 pt-6">
          <button 
            onClick={() => setActiveTab('settings')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium transition-all ${activeTab === 'settings' ? 'bg-indigo-50 text-indigo-600 shadow-sm' : 'text-slate-500 hover:bg-slate-50 hover:text-slate-800'}`}
          >
            <Settings className="w-5 h-5" />
            {t.settings}
          </button>
          <button onClick={() => setLang(lang === 'en' ? 'si' : 'en')} className="w-full flex items-center gap-3 px-4 py-3 text-slate-500 hover:text-indigo-600 font-medium transition-colors">
            <Globe className="w-5 h-5" />
            {t.language}
          </button>
        </div>
      </nav>

      <header className="md:hidden bg-white border-b border-slate-200 px-4 py-3 flex items-center justify-between sticky top-0 z-30 no-print">
        <div className="flex items-center gap-2">
          <Wallet className="w-6 h-6 text-indigo-600" />
          <h1 className="font-bold text-sm text-slate-800">{t.title}</h1>
        </div>
        <div className="flex items-center gap-2">
          <button onClick={() => setIsNotificationOpen(true)} className="p-2 relative text-slate-500 hover:bg-slate-100 rounded-lg">
            <Bell className="w-5 h-5" />
            {unreadCount > 0 && <span className="absolute top-1 right-1 w-2 h-2 bg-rose-500 rounded-full"></span>}
          </button>
          <button onClick={() => setActiveTab('settings')} className="p-2 text-slate-500 hover:bg-slate-100 rounded-lg"><Settings className="w-5 h-5"/></button>
        </div>
      </header>

      <div className="hidden md:block fixed top-6 right-6 z-40 no-print">
        <button 
          onClick={() => setIsNotificationOpen(true)}
          className="bg-white p-3 rounded-2xl border border-slate-100 shadow-xl hover:bg-slate-50 transition-all relative group"
        >
          <Bell className="w-6 h-6 text-slate-600 group-hover:text-indigo-600" />
          {unreadCount > 0 && (
            <span className="absolute -top-1 -right-1 bg-rose-500 text-white text-[10px] font-black h-5 w-5 flex items-center justify-center rounded-full border-2 border-white">
              {unreadCount}
            </span>
          )}
        </button>
      </div>

      <main className="md:pl-64 min-h-screen">
        <div className="max-w-6xl mx-auto p-4 md:p-8">
          {activeTab === 'settings' && <SettingsPage t={t} settings={currencySettings} onSave={(s) => { setCurrencySettings(s); localStorage.setItem('currency_settings', JSON.stringify(s)); }} />}
          {activeTab === 'bills' && <BillManager t={t} formatCurrency={formatCurrency} />}
          {activeTab !== 'settings' && activeTab !== 'bills' && (
            <Dashboard 
              activeTab={activeTab} 
              setActiveTab={setActiveTab}
              t={t} 
              transactions={transactions} 
              onAdd={onAddTransaction}
              onUpdate={onUpdateTransaction}
              onDelete={onDeleteTransaction}
              onRefresh={loadData}
              isLoading={isLoading}
              formatCurrency={formatCurrency}
            />
          )}
        </div>
      </main>

      <NotificationDrawer 
        isOpen={isNotificationOpen} 
        onClose={() => setIsNotificationOpen(false)} 
        notifications={notifications}
        onRead={(id) => setNotifications(prev => prev.map(n => n.id === id ? {...n, read: true} : n))}
        onReadAll={() => setNotifications(prev => prev.map(n => ({...n, read: true})))}
        t={t}
      />

      <nav className="md:hidden fixed bottom-0 left-0 right-0 bg-white border-t border-slate-200 flex items-center justify-around p-3 z-30 shadow-[0_-4px_12px_rgba(0,0,0,0.05)] no-print">
        {[
          { id: 'dashboard', icon: LayoutDashboard },
          { id: 'analytics', icon: BarChart3 },
          { id: 'budget', icon: Target },
          { id: 'bills', icon: CreditCard },
          { id: 'history', icon: History },
        ].map(tab => (
          <button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`flex flex-col items-center gap-1 transition-colors ${activeTab === tab.id ? 'text-indigo-600' : 'text-slate-400'}`}>
            <tab.icon className="w-6 h-6" />
          </button>
        ))}
      </nav>
    </div>
  );
};

