import React, { useState, useMemo, useEffect } from 'react';
import { Transaction, MonthlyBudget } from '../types';
import TransactionForm from './TransactionForm';
import StatsOverview from './StatsOverview';
import MonthlyCharts from './MonthlyCharts';
import HistoryTable from './HistoryTable';
import BudgetManager from './BudgetManager';
import BudgetPerformance from './BudgetPerformance';
import { Plus, X, Calendar, BarChart3, ClipboardList, ArrowRight, Target, AlertCircle } from 'lucide-react';
import { storageService } from '../services/googleSheets';

interface DashboardProps {
  activeTab: 'dashboard' | 'analytics' | 'history' | 'budget';
  setActiveTab?: (tab: 'dashboard' | 'analytics' | 'history' | 'budget') => void;
  t: any;
  transactions: Transaction[];
  onAdd: (data: Transaction) => void;
  onUpdate: (id: string, data: Transaction) => void;
  onDelete: (id: string) => void;
  onRefresh: () => void;
  isLoading: boolean;
  formatCurrency: (amount: number) => string;
}

const Dashboard: React.FC<DashboardProps> = ({ 
  activeTab, 
  setActiveTab,
  t, 
  transactions, 
  onAdd, 
  onUpdate,
  onDelete,
  onRefresh,
  isLoading,
  formatCurrency
}) => {
  const [showAddForm, setShowAddForm] = useState(false);
  const [showBudgetForm, setShowBudgetForm] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [budgets, setBudgets] = useState<MonthlyBudget[]>([]);

  useEffect(() => {
    const loadBudgets = async () => {
      const data = await storageService.fetchBudgets();
      setBudgets(data);
    };
    loadBudgets();
  }, [transactions]);

  const currentMonthName = useMemo(() => {
    return new Date().toLocaleString('en-US', { month: 'long', year: 'numeric' });
  }, []);

  const availableMonths = useMemo(() => {
    const monthsSet = new Set<string>();
    transactions.forEach(tx => {
      if (tx.month) monthsSet.add(tx.month.trim());
    });
    monthsSet.add(currentMonthName);
    return Array.from(monthsSet).sort((a, b) => {
      const dateA = new Date(a);
      const dateB = new Date(b);
      return dateB.getTime() - dateA.getTime();
    });
  }, [transactions, currentMonthName]);

  const [selectedMonth, setSelectedMonth] = useState<string>(availableMonths[0] || currentMonthName);

  const activeBudget = useMemo(() => {
    return budgets.find(b => b.month === selectedMonth) || {
      month: selectedMonth,
      limits: { groceries: 0, vegetables: 0, fishEgg: 0, chicken: 0, houseRent: 0, electricity: 0, water: 0, travel: 0, others: 0 }
    };
  }, [budgets, selectedMonth]);

  const currentMonthTransactions = useMemo(() => {
    return transactions.filter(tx => tx.month?.trim() === selectedMonth).sort((a, b) => a.date.localeCompare(b.date));
  }, [transactions, selectedMonth]);

  const categorySpending = useMemo(() => {
    const totals = { groceries: 0, vegetables: 0, fishEgg: 0, chicken: 0, houseRent: 0, electricity: 0, water: 0, travel: 0, others: 0 };
    currentMonthTransactions.forEach(tx => {
      totals.groceries += tx.groceries;
      totals.vegetables += tx.vegetables;
      totals.fishEgg += tx.fishEgg;
      totals.chicken += tx.chicken;
      totals.houseRent += tx.houseRent;
      totals.electricity += tx.electricity;
      totals.water += tx.water;
      totals.travel += tx.travel;
      totals.others += tx.others;
    });
    return totals;
  }, [currentMonthTransactions]);

  const filteredStats = useMemo(() => {
    const totalSpent = currentMonthTransactions.reduce((sum, tx) => sum + (Number(tx.totalExpenses) || 0), 0);
    const totalReceived = currentMonthTransactions.reduce((sum, tx) => sum + (Number(tx.dailyCash) || 0), 0);
    const lastBalance = currentMonthTransactions.length > 0 ? (Number(currentMonthTransactions[currentMonthTransactions.length - 1].totalBalance) || 0) : 0;
    return { totalSpent, totalReceived, lastBalance };
  }, [currentMonthTransactions]);

  const handleEdit = (tx: Transaction) => {
    setEditingTransaction(tx);
    setShowAddForm(true);
