import React, { useState } from 'react';
import { MonthlyBudget } from '../types';

interface BudgetManagerProps {
  t: any;
  month: string;
  initialLimits: MonthlyBudget['limits'];
  onSubmit: (limits: MonthlyBudget['limits']) => void;
}

const BudgetManager: React.FC<BudgetManagerProps> = ({ t, month, initialLimits, onSubmit }) => {
  const [limits, setLimits] = useState(initialLimits);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setLimits(prev => ({
      ...prev,
      [name]: value === '' ? 0 : parseFloat(value)
    }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit(limits);
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-4">
      <div className="bg-indigo-50 p-4 rounded-2xl mb-4 text-center">
        <p className="text-xs font-black text-indigo-400 uppercase tracking-widest mb-1">{t.month}</p>
        <p className="font-bold text-indigo-700">{month}</p>
      </div>

      <div className="grid grid-cols-1 gap-3 max-h-[400px] overflow-y-auto px-1">
        {[
          { name: 'groceries', label: t.groceries },
          { name: 'vegetables', label: t.vegetables },
          { name: 'fishEgg', label: t.fishEgg },
          { name: 'chicken', label: t.chicken },
          { name: 'houseRent', label: t.houseRent },
          { name: 'electricity', label: t.electricity },
          { name: 'water', label: t.water },
          { name: 'travel', label: t.travel },
          { name: 'others', label: t.others },
        ].map(field => (
          <div key={field.name} className="flex items-center gap-4">
            <label className="flex-1 text-sm font-semibold text-slate-700">{field.label}</label>
            <input
              type="number"
              name={field.name}
              placeholder="0"
              className="w-32 px-3 py-2 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none transition-all text-right font-bold text-indigo-600"
              value={(limits as any)[field.name] || ''}
