      <button
        type="submit"
        className="w-full bg-indigo-600 text-white py-3.5 rounded-xl font-bold shadow-lg shadow-indigo-100 hover:bg-indigo-700 active:scale-95 transition-all mt-6"
      >
        {t.save}
      </button>
    </form>
  );
};

