          <h1 className="font-bold text-sm text-slate-800">{t.title}</h1>
        </div>
        <div className="flex items-center gap-2">
          <button onClick={() => setIsNotificationOpen(true)} className="p-2 relative text-slate-500 hover:bg-slate-100 rounded-lg">
            <Bell className="w-5 h-5" />
            {unreadCount > 0 && <span className="absolute top-1 right-1 w-2 h-2 bg-rose-500 rounded-full"></span>}
          </button>
          <button onClick={() => setActiveTab('settings')} className="p-2 text-slate-500 hover:bg-slate-100 rounded-lg"><Settings className="w-5 h-5"/></button>
        </div>
      </header>

      <div className="hidden md:block fixed top-6 right-6 z-40 no-print">
        <button 
          onClick={() => setIsNotificationOpen(true)}
          className="bg-white p-3 rounded-2xl border border-slate-100 shadow-xl hover:bg-slate-50 transition-all relative group"
        >
          <Bell className="w-6 h-6 text-slate-600 group-hover:text-indigo-600" />
          {unreadCount > 0 && (
            <span className="absolute -top-1 -right-1 bg-rose-500 text-white text-[10px] font-black h-5 w-5 flex items-center justify-center rounded-full border-2 border-white">
