import React, { useState, useEffect } from 'react';
import { Bill } from '../types';
import { storageService } from '../services/googleSheets';
import { Plus, CreditCard, Trash2, Calendar, DollarSign, X } from 'lucide-react';

interface BillManagerProps {
  t: any;
  formatCurrency: (amount: number) => string;
}

const BillManager: React.FC<BillManagerProps> = ({ t, formatCurrency }) => {
  const [bills, setBills] = useState<Bill[]>([]);
  const [showAdd, setShowAdd] = useState(false);
  const [newBill, setNewBill] = useState<Partial<Bill>>({ dueDay: 1, category: 'others' });

  useEffect(() => {
    storageService.fetchBills().then(setBills);
  }, []);

  const handleSave = async () => {
    if (!newBill.name || !newBill.amount) return;
    const bill: Bill = {
      id: crypto.randomUUID(),
      name: newBill.name,
      amount: Number(newBill.amount),
      dueDay: Number(newBill.dueDay),
      category: newBill.category || 'others'
    };
    await storageService.saveBill(bill);
    setBills([...bills, bill]);
    setShowAdd(false);
    setNewBill({ dueDay: 1, category: 'others' });
  };

  const handleDelete = async (id: string) => {
    await storageService.deleteBill(id);
    setBills(bills.filter(b => b.id !== id));
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-indigo-100 rounded-xl">
            <CreditCard className="w-6 h-6 text-indigo-700" />
          </div>
          <h2 className="text-2xl font-black text-slate-800">{t.bills}</h2>
        </div>
        <button 
          onClick={() => setShowAdd(true)}
          className="flex items-center gap-2 px-6 py-3 bg-indigo-600 text-white rounded-2xl font-bold shadow-lg shadow-indigo-200 hover:bg-indigo-700 active:scale-95 transition-all"
        >
          <Plus className="w-5 h-5" />
          {t.addBill}
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {bills.map(bill => (
          <div key={bill.id} className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm relative group overflow-hidden">
            <div className="absolute top-0 left-0 w-2 h-full bg-indigo-500 opacity-20 group-hover:opacity-100 transition-all" />
            <div className="flex justify-between items-start mb-4 pl-2">
              <div>
                <h3 className="font-black text-slate-800 text-lg uppercase tracking-tight">{bill.name}</h3>
