                className="p-2 text-slate-300 hover:text-rose-500 hover:bg-rose-50 rounded-xl transition-all"
              >
                <Trash2 className="w-4 h-4" />
              </button>
            </div>

            <div className="flex items-center gap-6 pl-2">
              <div className="flex flex-col">
                <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{t.date}</span>
                <div className="flex items-center gap-2 text-indigo-600 font-black">
                  <Calendar className="w-4 h-4" />
                  <span>{bill.dueDay}st / Month</span>
                </div>
              </div>
              <div className="flex flex-col">
                <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Amount</span>
                <div className="flex items-center gap-2 text-slate-800 font-black">
                  <DollarSign className="w-4 h-4 text-slate-300" />
                  <span>{formatCurrency(bill.amount)}</span>
                </div>
              </div>
            </div>
          </div>
        ))}

        {bills.length === 0 && (
          <div className="col-span-full py-20 bg-slate-50/50 rounded-3xl border-2 border-dashed border-slate-200 flex flex-col items-center justify-center text-slate-400 gap-4">
             <CreditCard className="w-12 h-12 opacity-10" />
             <p className="font-bold italic">{t.noData}</p>
          </div>
        )}
      </div>

      {showAdd && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white w-full max-w-md rounded-3xl shadow-2xl overflow-hidden animate-in zoom-in-95 duration-200">
            <div className="p-6 border-b border-slate-100 flex items-center justify-between">
              <h3 className="text-xl font-bold text-slate-800">{t.addBill}</h3>
              <button onClick={() => setShowAdd(false)} className="p-2 hover:bg-slate-100 rounded-full transition-colors">
                <X className="w-6 h-6 text-slate-400" />
              </button>
            </div>
            <div className="p-6 space-y-4">
              <div>
                <label className="block text-xs font-black text-slate-400 uppercase mb-2">Bill Name</label>
                <input 
                  type="text" 
                  className="w-full px-4 py-3 rounded-2xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none font-bold"
                  value={newBill.name || ''}
                  onChange={e => setNewBill({...newBill, name: e.target.value})}
                  placeholder="e.g. Internet Bill"
                />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-black text-slate-400 uppercase mb-2">Amount</label>
                  <input 
                    type="number" 
                    className="w-full px-4 py-3 rounded-2xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none font-bold"
                    value={newBill.amount || ''}
                    onChange={e => setNewBill({...newBill, amount: e.target.value})}
                  />
                </div>
                <div>
                  <label className="block text-xs font-black text-slate-400 uppercase mb-2">Due Day (1-31)</label>
                  <input 
                    type="number" 
                    min="1" max="31"
                    className="w-full px-4 py-3 rounded-2xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none font-bold"
                    value={newBill.dueDay || ''}
                    onChange={e => setNewBill({...newBill, dueDay: e.target.value})}
                  />
                </div>
              </div>
              <div>
                <label className="block text-xs font-black text-slate-400 uppercase mb-2">Category</label>
                <select 
                  className="w-full px-4 py-3 rounded-2xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none font-bold"
                  value={newBill.category || 'others'}
                  onChange={e => setNewBill({...newBill, category: e.target.value})}
                >
                  <option value="groceries">{t.groceries}</option>
                  <option value="houseRent">{t.houseRent}</option>
                  <option value="electricity">{t.electricity}</option>
                  <option value="water">{t.water}</option>
                  <option value="travel">{t.travel}</option>
                  <option value="others">{t.others}</option>
                </select>
              </div>
              <button 
                onClick={handleSave}
                className="w-full bg-indigo-600 text-white py-4 rounded-2xl font-bold shadow-lg shadow-indigo-200 hover:bg-indigo-700 mt-4 transition-all"
              >
                {t.save}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
