interface BudgetPerformanceProps {
  t: any;
  transactions: Transaction[];
  budgets: MonthlyBudget[];
  formatCurrency: (amount: number) => string;
}

const BudgetPerformance: React.FC<BudgetPerformanceProps> = ({ t, transactions, budgets, formatCurrency }) => {
  const performanceData = useMemo(() => {
    const months = Array.from(new Set([
      ...transactions.map(tx => tx.month.trim()),
      ...budgets.map(b => b.month.trim())
    ])).sort((a, b) => new Date(a).getTime() - new Date(b).getTime());

    return months.map(month => {
      const monthTxs = transactions.filter(tx => tx.month.trim() === month);
      const monthBudget = budgets.find(b => b.month.trim() === month);

      // Fix: Use generic type parameter <number> for reduce to ensure the result is correctly inferred as number
      const actual: number = monthTxs.reduce<number>((sum, tx) => sum + (Number(tx.totalExpenses) || 0), 0);
      const budget: number = monthBudget ? Object.values(monthBudget.limits).reduce<number>((sum, limit) => sum + (Number(limit) || 0), 0) : 0;

      return {
        month,
        actual,
        budget,
        difference: budget - actual,
        status: (budget > 0) ? (actual <= budget ? 'under' : 'over') : 'no-budget'
      };
    }).filter(d => d.budget > 0 || d.actual > 0);
  }, [transactions, budgets]);

  if (performanceData.length === 0) {
    return (
      <div className="bg-white p-12 rounded-3xl border border-slate-100 text-center">
        <p className="text-slate-400">{t.noData}</p>
      </div>
    );
  }

  const latestPerformance = performanceData[performanceData.length - 1];

  return (
    <div className="space-y-6">
      <div className="flex items-center gap-3">
        <div className="p-2 bg-indigo-100 rounded-xl">
          <Target className="w-6 h-6 text-indigo-700" />
        </div>
        <h2 className="text-2xl font-black text-slate-800">{t.historicalBudgetPerformance}</h2>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm">
          <h3 className="font-bold text-slate-700 mb-6">{t.budgetVsActual}</h3>
          <div className="h-[350px]">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={performanceData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="month" fontSize={10} tickLine={false} axisLine={false} />
                <YAxis fontSize={12} tickLine={false} axisLine={false} />
                <Tooltip 
                  cursor={{fill: '#f8fafc'}}
                  contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 12px rgba(0,0,0,0.1)' }}
                />
                <Legend iconType="circle" />
                <Bar name={t.budgetLimit} dataKey="budget" fill="#6366f1" radius={[4, 4, 0, 0]} />
                <Bar name={t.actualSpending} dataKey="actual" fill="#10b981" radius={[4, 4, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="space-y-4">
          <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm">
             <div className="flex justify-between items-start mb-4">
               <h3 className="font-bold text-slate-700">{t.budgetStatus} - {latestPerformance.month}</h3>
               {latestPerformance.status === 'under' ? (
                 <span className="flex items-center gap-1 text-[10px] font-black uppercase text-emerald-500 bg-emerald-50 px-2 py-1 rounded-lg">
                   <CheckCircle2 className="w-3 h-3" /> Safe
                 </span>
               ) : latestPerformance.status === 'over' ? (
                 <span className="flex items-center gap-1 text-[10px] font-black uppercase text-rose-500 bg-rose-50 px-2 py-1 rounded-lg">
                   <AlertCircle className="w-3 h-3" /> Over Budget
                 </span>
               ) : null}
             </div>

             <div className="flex items-center gap-4 mb-6">
                <div className={`p-4 rounded-2xl ${latestPerformance.status === 'under' ? 'bg-emerald-50' : 'bg-rose-50'}`}>
                  {latestPerformance.status === 'under' ? (
                    <TrendingDown className="w-8 h-8 text-emerald-500" />
                  ) : (
                    <TrendingUp className="w-8 h-8 text-rose-500" />
                  )}
                </div>
                <div>
                   <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">{latestPerformance.status === 'under' ? t.remaining : t.overspent}</p>
                   <p className={`text-2xl font-black ${latestPerformance.status === 'under' ? 'text-emerald-600' : 'text-rose-600'}`}>
                      {formatCurrency(Math.abs(latestPerformance.difference))}
                   </p>
                </div>
             </div>

             <div className="space-y-3">
                <div className="flex justify-between text-sm">
                  <span className="text-slate-500">{t.budgetLimit}</span>
                  <span className="font-bold">{formatCurrency(latestPerformance.budget)}</span>
                </div>
                <div className="flex justify-between text-sm">
                  <span className="text-slate-500">{t.actualSpending}</span>
                  <span className="font-bold">{formatCurrency(latestPerformance.actual)}</span>
                </div>
                <div className="h-2 w-full bg-slate-100 rounded-full overflow-hidden">
                  <div 
                    className={`h-full ${latestPerformance.status === 'under' ? 'bg-indigo-500' : 'bg-rose-500'}`}
                    style={{ width: `${Math.min((latestPerformance.actual / latestPerformance.budget) * 100, 100)}%` }}
                  />
                </div>
             </div>
          </div>

          <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm overflow-hidden">
             <h3 className="font-bold text-slate-700 mb-4">{t.historicalBudgetPerformance}</h3>
             <div className="space-y-3 max-h-[150px] overflow-y-auto pr-2">
                {performanceData.slice().reverse().map((data, idx) => (
                  <div key={idx} className="flex items-center justify-between p-3 bg-slate-50 rounded-xl hover:bg-slate-100 transition-colors">
                     <div>
                       <p className="text-xs font-bold text-slate-700">{data.month}</p>
                       <p className="text-[10px] text-slate-400 uppercase font-black">{data.status === 'under' ? 'Saved' : 'Exceeded'}</p>
                     </div>
                     <div className="text-right">
                       <p className={`text-sm font-black ${data.status === 'under' ? 'text-emerald-600' : 'text-rose-600'}`}>
                         {formatCurrency(Math.abs(data.difference))}
                       </p>
                     </div>
                  </div>
                ))}
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default BudgetPerformance;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { Transaction, Language, CurrencySettings, Notification, MonthlyBudget, Bill } from './types';
import { translations } from './translations';
import { storageService } from './services/googleSheets';
import Dashboard from './components/Dashboard';
import SettingsPage from './components/SettingsPage';
import NotificationDrawer from './components/NotificationDrawer';
import BillManager from './components/BillManager';
import { Globe, Wallet, LayoutDashboard, History, BarChart3, Target, Settings, Bell, CreditCard, Sun, Moon } from 'lucide-react';

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>('en');
  const [isDark, setIsDark] = useState(() => localStorage.getItem('theme') === 'dark');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'analytics' | 'history' | 'budget' | 'settings' | 'bills'>('dashboard');
  const [isLoading, setIsLoading] = useState(false);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [isNotificationOpen, setIsNotificationOpen] = useState(false);
  const [currencySettings, setCurrencySettings] = useState<CurrencySettings>({
    symbol: 'LKR',
    position: 'before'
  });

  const t = translations[lang];

  useEffect(() => {
    if (isDark) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [isDark]);

  const formatCurrency = useCallback((amount: number) => {
    const formattedAmount = amount.toLocaleString();
    return currencySettings.position === 'before' 
      ? `${currencySettings.symbol} ${formattedAmount}`
      : `${formattedAmount} ${currencySettings.symbol}`;
  }, [currencySettings]);

  const generateNotifications = useCallback(async (txs: Transaction[]) => {
    const budgets = await storageService.fetchBudgets();
    const bills = await storageService.fetchBills();
    const currentMonth = new Date().toLocaleString('en-US', { month: 'long', year: 'numeric' });
    const currentMonthTxs = txs.filter(tx => tx.month === currentMonth);
    const budget = budgets.find(b => b.month === currentMonth);
    const newNotifications: Notification[] = [];

    if (budget) {
      const categories = ['groceries', 'vegetables', 'fishEgg', 'chicken', 'houseRent', 'electricity', 'water', 'travel', 'others'];
      categories.forEach(cat => {
        const limit = (budget.limits as any)[cat];
        const spent = currentMonthTxs.reduce((sum, tx) => sum + ((tx as any)[cat] || 0), 0);
        if (limit > 0 && spent / limit >= 0.85) {
          newNotifications.push({
            id: `budget-${cat}-${currentMonth}`,
            type: 'budget',
            title: t.lowBudgetAlert,
            message: t.lowBudgetMsg.replace('{percent}', Math.round((spent/limit)*100).toString()).replace('{category}', (t as any)[cat]),
            timestamp: new Date().toISOString(),
            read: false,
            priority: spent >= limit ? 'high' : 'medium'
          });
        }
      });
    }

    const today = new Date().getDate();
    bills.forEach(bill => {
      const daysLeft = bill.dueDay - today;
      if (daysLeft >= 0 && daysLeft <= 3) {
        newNotifications.push({
          id: `bill-${bill.id}-${currentMonth}`,
          type: 'bill',
          title: bill.name,
          message: t.billDueIn.replace('{days}', daysLeft.toString()),
          timestamp: new Date().toISOString(),
          read: false,
          priority: daysLeft === 0 ? 'high' : 'medium'
        });
      }
    });

    setNotifications(prev => {
      const existingIds = new Set(prev.map(n => n.id));
      const added = newNotifications.filter(n => !existingIds.has(n.id));
      return [...added, ...prev].slice(0, 20);
    });
  }, [t]);

  const loadData = useCallback(async () => {
    setIsLoading(true);
    try {
      const data = await storageService.fetchTransactions();
      setTransactions(data);
      generateNotifications(data);

      const savedLang = localStorage.getItem('lang');
      if (savedLang) setLang(savedLang as Language);

      const savedCurrency = localStorage.getItem('currency_settings');
      if (savedCurrency) setCurrencySettings(JSON.parse(savedCurrency));
    } catch (err) {
      console.error("Failed to load data", err);
    } finally {
      setIsLoading(false);
    }
  }, [generateNotifications]);

  const onAddTransaction = useCallback(async (data: Transaction) => {
    await storageService.addTransaction(data);
    loadData();
  }, [loadData]);

  const onUpdateTransaction = useCallback(async (id: string, data: Transaction) => {
    await storageService.updateTransaction(id, data);
    loadData();
  }, [loadData]);

  const onDeleteTransaction = useCallback(async (id: string) => {
    if (window.confirm(t.confirmDelete)) {
      await storageService.deleteTransaction(id);
      loadData();
    }
  }, [loadData, t.confirmDelete]);

  useEffect(() => {
    loadData();
  }, [loadData]);

  const unreadCount = useMemo(() => notifications.filter(n => !n.read).length, [notifications]);

  return (
    <div className="min-h-screen bg-slate-50 dark:bg-slate-950 pb-20 md:pb-0 font-sans transition-colors duration-300">
      <nav className="hidden md:flex flex-col fixed h-full w-64 bg-white dark:bg-slate-900 border-r border-slate-200 dark:border-slate-800 p-6 z-20 no-print transition-colors">
        <div className="flex items-center gap-3 mb-10">
          <div className="p-2 bg-indigo-600 rounded-xl shadow-lg shadow-indigo-200 dark:shadow-none">
            <Wallet className="w-6 h-6 text-white" />
          </div>
          <h1 className="font-bold text-lg text-slate-800 dark:text-slate-100 leading-tight">{t.title}</h1>
        </div>

        <div className="space-y-2 flex-grow">
          {[
            { id: 'dashboard', label: t.dashboard, icon: LayoutDashboard },
            { id: 'analytics', label: t.charts, icon: BarChart3 },
            { id: 'budget', label: t.budgetPerformance, icon: Target },
            { id: 'bills', label: t.bills, icon: CreditCard },
            { id: 'history', label: t.history, icon: History },
          ].map(tab => (
            <button 
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium transition-all ${activeTab === tab.id ? 'bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400 shadow-sm' : 'text-slate-500 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800 hover:text-slate-800 dark:hover:text-slate-200'}`}
            >
              <tab.icon className="w-5 h-5" />
              {tab.label}
            </button>
          ))}
        </div>

        <div className="mt-auto space-y-2 border-t border-slate-100 dark:border-slate-800 pt-6">
          <button 
            onClick={() => setIsDark(!isDark)}
            className="w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium text-slate-500 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800 transition-all"
          >
            {isDark ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
            {isDark ? t.lightMode : t.darkMode}
          </button>
          <button 
            onClick={() => setActiveTab('settings')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium transition-all ${activeTab === 'settings' ? 'bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400 shadow-sm' : 'text-slate-500 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800 hover:text-slate-800 dark:hover:text-slate-200'}`}
          >
            <Settings className="w-5 h-5" />
            {t.settings}
          </button>
          <button onClick={() => setLang(lang === 'en' ? 'si' : 'en')} className="w-full flex items-center gap-3 px-4 py-3 text-slate-500 dark:text-slate-400 hover:text-indigo-600 dark:hover:text-indigo-400 font-medium transition-colors">
            <Globe className="w-5 h-5" />
            {t.language}
          </button>
        </div>
      </nav>

      <header className="md:hidden bg-white dark:bg-slate-900 border-b border-slate-200 dark:border-slate-800 px-4 py-3 flex items-center justify-between sticky top-0 z-30 no-print transition-colors">
        <div className="flex items-center gap-2">
          <Wallet className="w-6 h-6 text-indigo-600 dark:text-indigo-400" />
          <h1 className="font-bold text-sm text-slate-800 dark:text-slate-100">{t.title}</h1>
        </div>
        <div className="flex items-center gap-2">
          <button onClick={() => setIsNotificationOpen(true)} className="p-2 relative text-slate-500 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-lg">
            <Bell className="w-5 h-5" />
            {unreadCount > 0 && <span className="absolute top-1 right-1 w-2 h-2 bg-rose-500 rounded-full"></span>}
          </button>
          <button onClick={() => setIsDark(!isDark)} className="p-2 text-slate-500 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-lg">
            {isDark ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
          </button>
          <button onClick={() => setActiveTab('settings')} className="p-2 text-slate-500 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-lg"><Settings className="w-5 h-5"/></button>
        </div>
      </header>

      <div className="hidden md:block fixed top-6 right-6 z-40 no-print">
        <button 
          onClick={() => setIsNotificationOpen(true)}
          className="bg-white dark:bg-slate-900 p-3 rounded-2xl border border-slate-100 dark:border-slate-800 shadow-xl dark:shadow-none hover:bg-slate-50 dark:hover:bg-slate-800 transition-all relative group"
        >
          <Bell className="w-6 h-6 text-slate-600 dark:text-slate-300 group-hover:text-indigo-600 dark:group-hover:text-indigo-400" />
          {unreadCount > 0 && (
            <span className="absolute -top-1 -right-1 bg-rose-500 text-white text-[10px] font-black h-5 w-5 flex items-center justify-center rounded-full border-2 border-white dark:border-slate-900">
              {unreadCount}
            </span>
          )}
        </button>
      </div>

      <main className="md:pl-64 min-h-screen">
        <div className="max-w-6xl mx-auto p-4 md:p-8">
          {activeTab === 'settings' && (
            <SettingsPage 
              t={t} 
              settings={currencySettings} 
              isDark={isDark}
              onToggleDark={() => setIsDark(!isDark)}
              onSave={(s) => { setCurrencySettings(s); localStorage.setItem('currency_settings', JSON.stringify(s)); }} 
            />
          )}
          {activeTab === 'bills' && <BillManager t={t} formatCurrency={formatCurrency} />}
          {activeTab !== 'settings' && activeTab !== 'bills' && (
            <Dashboard 
              activeTab={activeTab} 
              setActiveTab={setActiveTab}
              t={t} 
              transactions={transactions} 
              onAdd={onAddTransaction}
              onUpdate={onUpdateTransaction}
              onDelete={onDeleteTransaction}
              onRefresh={loadData}
              isLoading={isLoading}
              formatCurrency={formatCurrency}
            />
          )}
        </div>
      </main>

      <NotificationDrawer 
        isOpen={isNotificationOpen} 
        onClose={() => setIsNotificationOpen(false)} 
        notifications={notifications}
        onRead={(id) => setNotifications(prev => prev.map(n => n.id === id ? {...n, read: true} : n))}
        onReadAll={() => setNotifications(prev => prev.map(n => ({...n, read: true})))}
        t={t}
      />

      <nav className="md:hidden fixed bottom-0 left-0 right-0 bg-white dark:bg-slate-900 border-t border-slate-200 dark:border-slate-800 flex items-center justify-around p-3 z-30 shadow-[0_-4px_12px_rgba(0,0,0,0.05)] no-print transition-colors">
        {[
          { id: 'dashboard', icon: LayoutDashboard },
          { id: 'analytics', icon: BarChart3 },
          { id: 'budget', icon: Target },
          { id: 'bills', icon: CreditCard },
          { id: 'history', icon: History },
        ].map(tab => (
          <button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`flex flex-col items-center gap-1 transition-colors ${activeTab === tab.id ? 'text-indigo-600 dark:text-indigo-400' : 'text-slate-400 dark:text-slate-600'}`}>
            <tab.icon className="w-6 h-6" />
          </button>
        ))}
      </nav>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { CurrencySettings } from '../types';
import { Settings, Save, CheckCircle, Moon, Sun, Monitor } from 'lucide-react';

interface SettingsPageProps {
  t: any;
  settings: CurrencySettings;
  isDark: boolean;
  onToggleDark: () => void;
  onSave: (settings: CurrencySettings) => void;
}

const SettingsPage: React.FC<SettingsPageProps> = ({ t, settings, isDark, onToggleDark, onSave }) => {
  const [localSettings, setLocalSettings] = useState<CurrencySettings>(settings);
  const [showToast, setShowToast] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave(localSettings);
    setShowToast(true);
    setTimeout(() => setShowToast(false), 3000);
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="flex items-center gap-3">
        <div className="p-2 bg-indigo-100 dark:bg-indigo-900/30 rounded-xl">
          <Settings className="w-6 h-6 text-indigo-700 dark:text-indigo-400" />
        </div>
        <h2 className="text-2xl font-black text-slate-800 dark:text-slate-100">{t.settings}</h2>
      </div>

      <div className="bg-white dark:bg-slate-900 p-8 rounded-3xl border border-slate-100 dark:border-slate-800 shadow-sm max-w-2xl transition-colors">
        <form onSubmit={handleSubmit} className="space-y-8">

          <div className="space-y-4">
            <label className="block text-sm font-bold text-slate-700 dark:text-slate-300">{t.appearance}</label>
            <div className="grid grid-cols-2 gap-4">
              <button
                type="button"
                onClick={() => !isDark && onToggleDark()}
                className={`flex items-center justify-center gap-3 p-4 rounded-2xl border transition-all ${isDark ? 'bg-indigo-50 dark:bg-indigo-900/30 border-indigo-200 dark:border-indigo-800 text-indigo-700 dark:text-indigo-400' : 'bg-white dark:bg-slate-900 border-slate-100 dark:border-slate-800 text-slate-400'}`}
              >
                <Moon className="w-5 h-5" />
                <span className="font-bold">{t.darkMode}</span>
              </button>
              <button
                type="button"
                onClick={() => isDark && onToggleDark()}
                className={`flex items-center justify-center gap-3 p-4 rounded-2xl border transition-all ${!isDark ? 'bg-indigo-50 dark:bg-indigo-900/30 border-indigo-200 dark:border-indigo-800 text-indigo-700 dark:text-indigo-400' : 'bg-white dark:bg-slate-900 border-slate-100 dark:border-slate-800 text-slate-400'}`}
              >
                <Sun className="w-5 h-5" />
                <span className="font-bold">{t.lightMode}</span>
              </button>
            </div>
          </div>

          <div>
            <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2">{t.currencySymbol}</label>
            <input
              type="text"
              className="w-full px-4 py-3 rounded-xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 focus:ring-2 focus:ring-indigo-500 outline-none transition-all font-bold text-indigo-600 dark:text-indigo-400"
              value={localSettings.symbol}
              onChange={(e) => setLocalSettings({ ...localSettings, symbol: e.target.value })}
              placeholder="e.g. $, LKR, Rs."
            />
          </div>

          <div>
            <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-4">{t.currencyPosition}</label>
            <div className="space-y-3">
              <label className="flex items-center gap-3 p-4 rounded-2xl border border-slate-100 dark:border-slate-800 hover:bg-slate-50 dark:hover:bg-slate-800 cursor-pointer transition-colors">
                <input
                  type="radio"
                  className="w-5 h-5 text-indigo-600 dark:text-indigo-400 focus:ring-indigo-500"
                  name="position"
                  checked={localSettings.position === 'before'}
                  onChange={() => setLocalSettings({ ...localSettings, position: 'before' })}
                />
                <span className="font-semibold text-slate-700 dark:text-slate-300">{t.positionBefore}</span>
              </label>

              <label className="flex items-center gap-3 p-4 rounded-2xl border border-slate-100 dark:border-slate-800 hover:bg-slate-50 dark:hover:bg-slate-800 cursor-pointer transition-colors">
                <input
                  type="radio"
                  className="w-5 h-5 text-indigo-600 dark:text-indigo-400 focus:ring-indigo-500"
                  name="position"
                  checked={localSettings.position === 'after'}
                  onChange={() => setLocalSettings({ ...localSettings, position: 'after' })}
                />
                <span className="font-semibold text-slate-700 dark:text-slate-300">{t.positionAfter}</span>
              </label>
            </div>
          </div>

          <button
            type="submit"
            className="w-full flex items-center justify-center gap-2 bg-indigo-600 text-white py-4 rounded-2xl font-bold shadow-lg shadow-indigo-200 dark:shadow-none hover:bg-indigo-700 active:scale-95 transition-all"
          >
            <Save className="w-5 h-5" />
            {t.saveSettings}
          </button>
        </form>
      </div>

      {showToast && (
        <div className="fixed bottom-10 left-1/2 -translate-x-1/2 flex items-center gap-2 bg-emerald-600 text-white px-6 py-3 rounded-2xl shadow-xl animate-in fade-in slide-in-from-bottom-4">
          <CheckCircle className="w-5 h-5" />
          <span className="font-bold">{t.settingsSaved}</span>
        </div>
      )}
    </div>
  );
};

export default SettingsPage;

import React, { useState, useMemo, useEffect } from 'react';
import { Transaction, MonthlyBudget } from '../types';
import TransactionForm from './TransactionForm';
import StatsOverview from './StatsOverview';
import MonthlyCharts from './MonthlyCharts';
import HistoryTable from './HistoryTable';
import BudgetManager from './BudgetManager';
import BudgetPerformance from './BudgetPerformance';
import { Plus, X, Calendar, BarChart3, ClipboardList, ArrowRight, Target, AlertCircle } from 'lucide-react';
import { storageService } from '../services/googleSheets';

interface DashboardProps {
  activeTab: 'dashboard' | 'analytics' | 'history' | 'budget';
  setActiveTab?: (tab: 'dashboard' | 'analytics' | 'history' | 'budget') => void;
  t: any;
  transactions: Transaction[];
  onAdd: (data: Transaction) => void;
  onUpdate: (id: string, data: Transaction) => void;
  onDelete: (id: string) => void;
  onRefresh: () => void;
  isLoading: boolean;
  formatCurrency: (amount: number) => string;
}

const Dashboard: React.FC<DashboardProps> = ({ 
  activeTab, 
  setActiveTab,
  t, 
  transactions, 
  onAdd, 
  onUpdate,
  onDelete,
  onRefresh,
  isLoading,
  formatCurrency
}) => {
  const [showAddForm, setShowAddForm] = useState(false);
  const [showBudgetForm, setShowBudgetForm] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [budgets, setBudgets] = useState<MonthlyBudget[]>([]);

  useEffect(() => {
    const loadBudgets = async () => {
      const data = await storageService.fetchBudgets();
      setBudgets(data);
    };
    loadBudgets();
  }, [transactions]);

  const currentMonthName = useMemo(() => {
    return new Date().toLocaleString('en-US', { month: 'long', year: 'numeric' });
  }, []);

  const availableMonths = useMemo(() => {
    const monthsSet = new Set<string>();
    transactions.forEach(tx => {
      if (tx.month) monthsSet.add(tx.month.trim());
    });
    monthsSet.add(currentMonthName);
    return Array.from(monthsSet).sort((a, b) => {
      const dateA = new Date(a);
      const dateB = new Date(b);
      return dateB.getTime() - dateA.getTime();
    });
  }, [transactions, currentMonthName]);

  const [selectedMonth, setSelectedMonth] = useState<string>(availableMonths[0] || currentMonthName);

  const activeBudget = useMemo(() => {
    return budgets.find(b => b.month === selectedMonth) || {
      month: selectedMonth,
      limits: { groceries: 0, vegetables: 0, fishEgg: 0, chicken: 0, houseRent: 0, electricity: 0, water: 0, travel: 0, others: 0 }
    };
  }, [budgets, selectedMonth]);

  const currentMonthTransactions = useMemo(() => {
    return transactions.filter(tx => tx.month?.trim() === selectedMonth).sort((a, b) => a.date.localeCompare(b.date));
  }, [transactions, selectedMonth]);

  const categorySpending = useMemo(() => {
    const totals = { groceries: 0, vegetables: 0, fishEgg: 0, chicken: 0, houseRent: 0, electricity: 0, water: 0, travel: 0, others: 0 };
    currentMonthTransactions.forEach(tx => {
      totals.groceries += tx.groceries;
      totals.vegetables += tx.vegetables;
      totals.fishEgg += tx.fishEgg;
      totals.chicken += tx.chicken;
      totals.houseRent += tx.houseRent;
      totals.electricity += tx.electricity;
      totals.water += tx.water;
      totals.travel += tx.travel;
      totals.others += tx.others;
    });
    return totals;
  }, [currentMonthTransactions]);

  const filteredStats = useMemo(() => {
    const totalSpent = currentMonthTransactions.reduce((sum, tx) => sum + (Number(tx.totalExpenses) || 0), 0);
    const totalReceived = currentMonthTransactions.reduce((sum, tx) => sum + (Number(tx.dailyCash) || 0), 0);
    const lastBalance = currentMonthTransactions.length > 0 ? (Number(currentMonthTransactions[currentMonthTransactions.length - 1].totalBalance) || 0) : 0;
    return { totalSpent, totalReceived, lastBalance };
  }, [currentMonthTransactions]);

  const handleEdit = (tx: Transaction) => {
    setEditingTransaction(tx);
    setShowAddForm(true);
  };

  const handleSaveBudget = async (limits: MonthlyBudget['limits']) => {
    await storageService.saveBudget(selectedMonth, limits);
    const updated = await storageService.fetchBudgets();
    setBudgets(updated);
    setShowBudgetForm(false);
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row items-center justify-between gap-4 bg-white dark:bg-slate-900 p-4 rounded-3xl border border-slate-100 dark:border-slate-800 shadow-sm no-print transition-colors">
        <div className="flex items-center gap-3 w-full sm:w-auto">
          <div className="p-2 bg-indigo-50 dark:bg-indigo-900/30 rounded-xl">
            <Calendar className="w-5 h-5 text-indigo-600 dark:text-indigo-400" />
          </div>
          <div className="flex-grow">
            <h2 className="text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest leading-none mb-1">{t.selectMonth}</h2>
            <select 
              value={selectedMonth}
              onChange={(e) => setSelectedMonth(e.target.value)}
              className="bg-transparent font-bold text-lg text-slate-800 dark:text-slate-100 outline-none cursor-pointer hover:text-indigo-600 dark:hover:text-indigo-400 transition-colors"
            >
              {availableMonths.map(m => (
                <option key={m} value={m} className="bg-white dark:bg-slate-900">{m}</option>
              ))}
            </select>
          </div>
        </div>

        <div className="flex items-center gap-3 w-full sm:w-auto">
          <button 
            onClick={() => setShowBudgetForm(true)}
            className="flex items-center gap-2 px-6 py-3 bg-white dark:bg-slate-900 text-indigo-600 dark:text-indigo-400 rounded-2xl font-bold hover:bg-indigo-50 dark:hover:bg-indigo-900/20 transition-all border border-indigo-100 dark:border-indigo-900 shadow-sm active:scale-95"
          >
            <Target className="w-5 h-5" />
            <span className="hidden sm:inline">{t.manageBudget}</span>
          </button>
          <button 
            onClick={() => setShowAddForm(true)}
            className="flex-grow sm:flex-grow-0 bg-indigo-600 text-white px-6 py-3 rounded-2xl font-bold flex items-center justify-center gap-2 shadow-lg shadow-indigo-200 dark:shadow-none hover:bg-indigo-700 active:scale-95 transition-all"
          >
            <Plus className="w-5 h-5" />
            {t.addRecord}
          </button>
        </div>
      </div>

      {activeTab === 'dashboard' && (
        <>
          <StatsOverview t={t} stats={filteredStats} formatCurrency={formatCurrency} />

          <div className="mt-8 bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-100 dark:border-slate-800 shadow-sm transition-colors">
            <div className="flex items-center justify-between mb-6">
               <div className="flex items-center gap-3">
                 <div className="p-2 bg-emerald-50 dark:bg-emerald-900/20 rounded-xl text-emerald-600 dark:text-emerald-400">
                    <Target className="w-6 h-6" />
                 </div>
                 <h2 className="text-xl font-bold text-slate-800 dark:text-slate-100">{t.budgetStatus}</h2>
               </div>
               <div className="text-xs text-slate-400 dark:text-slate-500 font-bold uppercase tracking-widest">{selectedMonth}</div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-x-8 gap-y-6">
              {[
                { key: 'groceries', label: t.groceries },
                { key: 'vegetables', label: t.vegetables },
                { key: 'fishEgg', label: t.fishEgg },
                { key: 'chicken', label: t.chicken },
                { key: 'houseRent', label: t.houseRent },
                { key: 'electricity', label: t.electricity },
                { key: 'water', label: t.water },
                { key: 'travel', label: t.travel },
                { key: 'others', label: t.others },
              ].map(({ key, label }) => {
                const limit = (activeBudget.limits as any)[key] || 0;
                const spent = (categorySpending as any)[key] || 0;
                const percent = limit > 0 ? (spent / limit) * 100 : 0;
                const remaining = limit - spent;

                let barColor = "bg-indigo-500";
                if (percent >= 100) barColor = "bg-rose-500";
                else if (percent >= 80) barColor = "bg-amber-500";

                return (
                  <div key={key} className="space-y-2">
                    <div className="flex justify-between items-end">
                      <span className="text-sm font-bold text-slate-700 dark:text-slate-300">{label}</span>
                      <div className="text-right">
                        <span className={`text-[10px] font-black uppercase ${percent > 100 ? 'text-rose-500' : 'text-slate-400 dark:text-slate-500'}`}>
                          {formatCurrency(spent)} / {limit > 0 ? formatCurrency(limit) : '---'}
                        </span>
                      </div>
                    </div>
                    <div className="h-2.5 w-full bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden transition-colors">
                      <div 
                        className={`h-full transition-all duration-500 ${barColor}`} 
                        style={{ width: `${Math.min(percent, 100)}%` }}
                      ></div>
                    </div>
                    <div className="flex justify-between text-[10px] font-bold">
                       {limit > 0 ? (
                         remaining >= 0 ? (
                           <span className="text-emerald-500 dark:text-emerald-400">{t.remaining}: {formatCurrency(remaining)}</span>
                         ) : (
                           <span className="text-rose-500 flex items-center gap-1">
                             <AlertCircle className="w-3 h-3" />
                             {t.overspent}: {formatCurrency(Math.abs(remaining))}
                           </span>
                         )
                       ) : (
                         <span className="text-slate-300 dark:text-slate-700">Budget not set</span>
                       )}
                       <span className="text-slate-400 dark:text-slate-500">{Math.round(percent)}%</span>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>

          <div className="mt-8 bg-white dark:bg-slate-900 rounded-3xl border border-slate-100 dark:border-slate-800 shadow-sm overflow-hidden transition-colors">
            <div className="p-6 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between">
              <div className="flex items-center gap-3">
                <ClipboardList className="w-6 h-6 text-indigo-600 dark:text-indigo-400" />
                <h2 className="text-xl font-bold text-slate-800 dark:text-slate-100">{t.recentTransactions}</h2>
              </div>
              <button 
                onClick={() => setActiveTab?.('history')}
                className="flex items-center gap-1 text-sm font-bold text-indigo-600 dark:text-indigo-400 hover:text-indigo-700 dark:hover:text-indigo-300 transition-colors"
              >
                {t.viewAll}
                <ArrowRight className="w-4 h-4" />
              </button>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full text-left min-w-[800px]">
                <thead>
                  <tr className="bg-slate-50 dark:bg-slate-800/50 text-slate-500 dark:text-slate-400 text-[10px] uppercase font-black tracking-widest border-b border-slate-100 dark:border-slate-800">
                    <th className="px-6 py-4">{t.date}</th>
                    <th className="px-6 py-4">{t.month}</th>
                    <th className="px-6 py-4">{t.dailyCash}</th>
                    <th className="px-6 py-4">{t.totalExpenses}</th>
                    <th className="px-6 py-4 bg-indigo-50/30 dark:bg-indigo-900/10 text-indigo-700 dark:text-indigo-400">{t.totalBalance}</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                  {transactions.slice().reverse().slice(0, 5).map((tx) => (
                    <tr key={tx.id || tx.timestamp} className="hover:bg-slate-50/50 dark:hover:bg-slate-800/50 transition-colors">
                      <td className="px-6 py-4 text-sm font-semibold text-slate-700 dark:text-slate-300">{tx.date.split('-').reverse().join('/')}</td>
                      <td className="px-6 py-4 text-xs font-medium text-slate-400 dark:text-slate-500">{tx.month}</td>
                      <td className="px-6 py-4 text-sm font-bold text-emerald-600 dark:text-emerald-400">{formatCurrency(Number(tx.dailyCash))}</td>
                      <td className="px-6 py-4 text-sm font-bold text-rose-500 dark:text-rose-400">{formatCurrency(Number(tx.totalExpenses))}</td>
                      <td className="px-6 py-4 text-sm font-black text-indigo-600 dark:text-indigo-400 bg-indigo-50/20 dark:bg-indigo-900/5">{formatCurrency(Number(tx.totalBalance))}</td>
                    </tr>
                  ))}
                  {transactions.length === 0 && (
                    <tr>
                      <td colSpan={5} className="px-6 py-12 text-center text-slate-400 dark:text-slate-600 font-medium italic">{t.noData}</td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </>
      )}

      {activeTab === 'analytics' && (
        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div>
            <div className="flex items-center justify-between mb-6">
              <div className="flex items-center gap-3">
                <div className="p-2 bg-indigo-100 dark:bg-indigo-900/30 rounded-xl">
                  <BarChart3 className="w-6 h-6 text-indigo-700 dark:text-indigo-400" />
                </div>
                <h2 className="text-2xl font-black text-slate-800 dark:text-slate-100">{t.charts} - {selectedMonth}</h2>
              </div>
            </div>
            <MonthlyCharts t={t} transactions={currentMonthTransactions} />
          </div>
        </div>
      )}

      {activeTab === 'budget' && (
        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
          <BudgetPerformance 
            t={t} 
            transactions={transactions} 
            budgets={budgets} 
            formatCurrency={formatCurrency}
          />
        </div>
      )}

      {activeTab === 'history' && (
        <div className="bg-white dark:bg-slate-900 rounded-3xl shadow-sm border border-slate-100 dark:border-slate-800 overflow-hidden animate-in fade-in slide-in-from-bottom-4 duration-500 transition-colors">
          <div className="p-6 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between no-print">
            <h2 className="text-xl font-bold text-slate-800 dark:text-slate-100">{t.history} ({selectedMonth})</h2>
          </div>
          <HistoryTable 
            t={t} 
            transactions={transactions.filter(tx => tx.month?.trim() === selectedMonth)} 
            allTransactions={transactions}
            onEdit={handleEdit} 
            onDelete={onDelete} 
            isLoading={isLoading} 
            formatCurrency={formatCurrency}
          />
        </div>
      )}

      {showAddForm && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 dark:bg-black/70 backdrop-blur-sm no-print">
          <div className="bg-white dark:bg-slate-900 w-full max-w-2xl rounded-3xl shadow-2xl dark:shadow-none overflow-hidden max-h-[90vh] flex flex-col scale-in-center transition-colors">
            <div className="p-6 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between">
              <h3 className="text-xl font-bold text-slate-800 dark:text-slate-100">
                {editingTransaction ? t.edit : t.addRecord}
              </h3>
              <button 
                onClick={() => { setShowAddForm(false); setEditingTransaction(null); }}
                className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full transition-colors"
              >
                <X className="w-6 h-6 text-slate-400 dark:text-slate-500" />
              </button>
            </div>
            <div className="p-6 overflow-y-auto">
              <TransactionForm 
                t={t} 
                initialData={editingTransaction}
                formatCurrency={formatCurrency}
                onSubmit={(data) => {
                  if (editingTransaction?.id) {
                    onUpdate(editingTransaction.id, data);
                  } else {
                    onAdd(data);
                  }
                  setShowAddForm(false);
                  setEditingTransaction(null);
                }} 
              />
            </div>
          </div>
        </div>
      )}

      {showBudgetForm && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 dark:bg-black/70 backdrop-blur-sm no-print">
          <div className="bg-white dark:bg-slate-900 w-full max-w-lg rounded-3xl shadow-2xl dark:shadow-none overflow-hidden flex flex-col scale-in-center transition-colors">
            <div className="p-6 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between">
              <h3 className="text-xl font-bold text-slate-800 dark:text-slate-100">{t.manageBudget}</h3>
              <button 
                onClick={() => setShowBudgetForm(false)}
                className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full transition-colors"
              >
                <X className="w-6 h-6 text-slate-400 dark:text-slate-500" />
              </button>
            </div>
            <div className="p-6">
              <BudgetManager 
                t={t} 
                month={selectedMonth} 
                initialLimits={activeBudget.limits} 
                onSubmit={handleSaveBudget} 
              />
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { Transaction } from '../types';

interface TransactionFormProps {
  t: any;
  initialData?: Transaction | null;
  onSubmit: (data: Transaction) => void;
  formatCurrency: (amount: number) => string;
}

const TransactionForm: React.FC<TransactionFormProps> = ({ t, initialData, onSubmit, formatCurrency }) => {
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    groceries: '' as any,
    vegetables: '' as any,
    fishEgg: '' as any,
    chicken: '' as any,
    houseRent: '' as any,
    electricity: '' as any,
    water: '' as any,
    travel: '' as any,
    others: '' as any,
    dailyCash: '' as any,
    broughtForward: '' as any,
  });

  useEffect(() => {
    if (initialData) {
      setFormData({
        date: initialData.date,
        groceries: initialData.groceries || '',
        vegetables: initialData.vegetables || '',
        fishEgg: initialData.fishEgg || '',
        chicken: initialData.chicken || '',
        houseRent: initialData.houseRent || '',
        electricity: initialData.electricity || '',
        water: initialData.water || '',
        travel: initialData.travel || '',
        others: initialData.others || '',
        dailyCash: initialData.dailyCash || '',
        broughtForward: initialData.broughtForward || '',
      });
    }
  }, [initialData]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value, type } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: type === 'number' ? (value === '' ? '' : parseFloat(value)) : value
    }));
  };

  const val = (v: any) => {
    const n = parseFloat(v);
    return isNaN(n) ? 0 : n;
  };

  const totalExpenses = 
    val(formData.groceries) + 
    val(formData.vegetables) + 
    val(formData.fishEgg) + 
    val(formData.chicken) + 
    val(formData.houseRent) +
    val(formData.electricity) +
    val(formData.water) +
    val(formData.travel) +
    val(formData.others);

  const totalBalance = val(formData.broughtForward) + val(formData.dailyCash) - totalExpenses;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const dateObj = new Date(formData.date);
    const monthName = dateObj.toLocaleString('en-US', { month: 'long', year: 'numeric' });

    onSubmit({
      ...formData,
      groceries: val(formData.groceries),
      vegetables: val(formData.vegetables),
      fishEgg: val(formData.fishEgg),
      chicken: val(formData.chicken),
      houseRent: val(formData.houseRent),
      electricity: val(formData.electricity),
      water: val(formData.water),
      travel: val(formData.travel),
      others: val(formData.others),
      dailyCash: val(formData.dailyCash),
      broughtForward: val(formData.broughtForward),
      month: monthName,
      totalExpenses: totalExpenses,
      totalBalance: totalBalance,
      timestamp: new Date().toISOString()
    });
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-6">
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
        <div>
          <label className="block text-sm font-semibold text-slate-700 dark:text-slate-300 mb-1">{t.date}</label>
          <input
            type="date"
            name="date"
            required
            className="w-full px-4 py-2.5 rounded-xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
            value={formData.date}
            onChange={handleChange}
          />
        </div>
        <div>
          <label className="block text-sm font-semibold text-slate-700 dark:text-slate-300 mb-1">{t.broughtForward}</label>
          <input
            type="number"
            name="broughtForward"
            placeholder="0"
            className="w-full px-4 py-2.5 rounded-xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
            value={formData.broughtForward}
            onChange={handleChange}
          />
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
        <div>
          <label className="block text-sm font-semibold mb-1 text-indigo-700 dark:text-indigo-400">{t.dailyCash}</label>
          <input
            type="number"
            name="dailyCash"
            placeholder="0"
            className="w-full px-4 py-2.5 rounded-xl border border-indigo-200 dark:border-indigo-900 bg-indigo-50 dark:bg-indigo-900/10 font-bold transition-all focus:ring-2 focus:ring-indigo-500 outline-none text-slate-800 dark:text-slate-100"
            value={formData.dailyCash}
            onChange={handleChange}
          />
        </div>
        {[
          { name: 'groceries', label: t.groceries },
          { name: 'vegetables', label: t.vegetables },
          { name: 'fishEgg', label: t.fishEgg },
          { name: 'chicken', label: t.chicken },
          { name: 'houseRent', label: t.houseRent },
          { name: 'electricity', label: t.electricity },
          { name: 'water', label: t.water },
          { name: 'travel', label: t.travel },
          { name: 'others', label: t.others },
        ].map(field => (
          <div key={field.name}>
            <label className="block text-sm font-semibold mb-1 text-slate-700 dark:text-slate-300">{field.label}</label>
            <input
              type="number"
              name={field.name}
              placeholder="0"
              className="w-full px-4 py-2.5 rounded-xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 transition-all focus:ring-2 focus:ring-indigo-500 outline-none"
              value={(formData as any)[field.name]}
              onChange={handleChange}
            />
          </div>
        ))}
      </div>

      <div className="p-6 bg-slate-50 dark:bg-slate-800/50 rounded-2xl flex flex-wrap gap-8 items-center justify-center border border-slate-100 dark:border-slate-800 transition-colors">
        <div className="text-center">
          <p className="text-xs text-slate-400 dark:text-slate-500 uppercase tracking-wider font-bold">{t.totalExpenses}</p>
          <p className="text-2xl font-black text-rose-600 dark:text-rose-400">{formatCurrency(totalExpenses)}</p>
        </div>
        <div className="text-center">
