import React from 'react';
import { Transaction } from '../types';
import { Edit2, Trash2, FileSpreadsheet, Download, Printer } from 'lucide-react';
import * as XLSX from 'xlsx';

interface HistoryTableProps {
  t: any;
  transactions: Transaction[];
  allTransactions?: Transaction[];
  onEdit: (tx: Transaction) => void;
  onDelete: (id: string) => void;
  isLoading: boolean;
  formatCurrency: (amount: number) => string;
}

const HistoryTable: React.FC<HistoryTableProps> = ({ t, transactions, allTransactions, onEdit, onDelete, isLoading, formatCurrency }) => {

  const formatForExcel = (data: Transaction[]) => {
    return data.map(tx => ({
      [t.date]: tx.date,
      [t.dailyCash]: tx.dailyCash,
      [t.groceries]: tx.groceries,
      [t.vegetables]: tx.vegetables,
      [t.fishEgg]: tx.fishEgg,
      [t.chicken]: tx.chicken,
      [t.houseRent]: tx.houseRent,
      [t.electricity]: tx.electricity,
      [t.water]: tx.water,
      [t.travel]: tx.travel,
      [t.others]: tx.others,
      [t.totalExpenses]: tx.totalExpenses,
      [t.totalBalance]: tx.totalBalance,
    }));
  };

  const exportAllToExcel = () => {
    const dataToExport = allTransactions || transactions;
    if (dataToExport.length === 0) return;

    const workbook = XLSX.utils.book_new();
    const sortedData = [...dataToExport].sort((a,b) => a.date.localeCompare(b.date));

    const fullData = formatForExcel(sortedData);
    const wsFull = XLSX.utils.json_to_sheet(fullData);
    XLSX.utils.book_append_sheet(workbook, wsFull, "Transaction Details");

    const monthlySummary: any[] = [];
    const months = [...new Set(sortedData.map(tx => tx.month))];
    months.forEach(m => {
      const txs = sortedData.filter(tx => tx.month === m);
      monthlySummary.push({
        [t.month]: m,
        [t.totalIncome]: txs.reduce((acc, curr) => acc + (curr.dailyCash || 0), 0),
        [t.totalExpenses]: txs.reduce((acc, curr) => acc + (curr.totalExpenses || 0), 0),
        [t.totalBalance]: txs[txs.length-1]?.totalBalance || 0
      });
    });
    const wsSummary = XLSX.utils.json_to_sheet(monthlySummary);
    XLSX.utils.book_append_sheet(workbook, wsSummary, "Monthly Summary");

    XLSX.writeFile(workbook, `Finance_Report_${new Date().toISOString().split('T')[0]}.xlsx`);
  };

  const handlePrint = () => {
    window.print();
  };

  if (isLoading) {
    return <div className="p-12 text-center text-slate-400">Loading records...</div>;
  }

  if (transactions.length === 0) {
    return (
      <div className="p-12 text-center">
        <p className="text-slate-400 dark:text-slate-600 mb-4">{t.noData}</p>
      </div>
    );
  }

  const selectedMonth = transactions[0]?.month || '';
  const totalIn = transactions.reduce((s, tx) => s + tx.dailyCash, 0);
  const totalOut = transactions.reduce((s, tx) => s + tx.totalExpenses, 0);

  return (
    <div className="flex flex-col">
      <div className="p-4 border-b border-slate-50 dark:border-slate-800 flex justify-end gap-2 flex-wrap no-print transition-colors">
        <button 
          onClick={handlePrint}
          className="flex items-center gap-2 bg-slate-100 dark:bg-slate-800 text-slate-700 dark:text-slate-300 font-bold text-sm hover:bg-slate-200 dark:hover:bg-slate-700 px-4 py-2 rounded-xl transition-colors"
        >
          <Printer className="w-4 h-4" />
          {t.printReport}
        </button>
        <button 
          onClick={exportAllToExcel}
          className="flex items-center gap-2 bg-indigo-600 text-white font-bold text-sm hover:bg-indigo-700 px-4 py-2 rounded-xl transition-colors shadow-sm"
        >
          <FileSpreadsheet className="w-4 h-4" />
          {t.exportExcel}
        </button>
      </div>

      <div className="print-only mb-6 text-center">
        <h1 className="text-2xl font-bold">{t.title}</h1>
        <h2 className="text-xl text-slate-600">{selectedMonth}</h2>
        <div className="flex justify-center gap-8 mt-4 border-y py-2">
           <div><span className="font-bold">{t.totalReceived}:</span> {formatCurrency(totalIn)}</div>
           <div><span className="font-bold">{t.totalSpent}:</span> {formatCurrency(totalOut)}</div>
           <div><span className="font-bold">{t.totalBalance}:</span> {formatCurrency(transactions[transactions.length - 1]?.totalBalance)}</div>
        </div>
      </div>

      <div className="overflow-x-auto transition-colors">
        <table className="w-full text-left min-w-[1200px] border-collapse">
          <thead>
            <tr className="bg-slate-50 dark:bg-slate-800/50 text-slate-500 dark:text-slate-400 text-[10px] uppercase font-black tracking-widest border-b border-slate-200 dark:border-slate-800">
              <th className="px-6 py-4 border-r border-slate-100 dark:border-slate-800">{t.date}</th>
              <th className="px-6 py-4 border-r border-slate-100 dark:border-slate-800">{t.dailyCash}</th>
              <th className="px-6 py-4">{t.groceries}</th>
              <th className="px-6 py-4">{t.vegetables}</th>
              <th className="px-6 py-4">{t.fishEgg}</th>
              <th className="px-6 py-4">{t.chicken}</th>
              <th className="px-6 py-4">{t.houseRent}</th>
              <th className="px-6 py-4">{t.electricity}</th>
              <th className="px-6 py-4">{t.water}</th>
              <th className="px-6 py-4">{t.travel}</th>
              <th className="px-6 py-4">{t.others}</th>
              <th className="px-6 py-4 border-l border-slate-100 dark:border-slate-800">{t.totalExpenses}</th>
              <th className="px-6 py-4 bg-indigo-50/30 dark:bg-indigo-900/10 text-indigo-700 dark:text-indigo-400 border-l border-slate-100 dark:border-slate-800">{t.totalBalance}</th>
              <th className="px-6 py-4 text-center no-print">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100 dark:divide-slate-800 text-sm">
            {transactions.map((tx) => (
              <tr key={tx.id || tx.timestamp} className="hover:bg-slate-50/50 dark:hover:bg-slate-800/50 transition-colors">
                <td className="px-6 py-4 font-semibold text-slate-700 dark:text-slate-300 whitespace-nowrap border-r border-slate-50 dark:border-slate-800">{tx.date.split('-').reverse().join('/')}</td>
                <td className="px-6 py-4 font-bold text-emerald-600 dark:text-emerald-400 border-r border-slate-50 dark:border-slate-800">{formatCurrency(tx.dailyCash)}</td>
                <td className="px-6 py-4 text-slate-600 dark:text-slate-400">{tx.groceries?.toLocaleString()}</td>
                <td className="px-6 py-4 text-slate-600 dark:text-slate-400">{tx.vegetables?.toLocaleString()}</td>
                <td className="px-6 py-4 text-slate-600 dark:text-slate-400">{tx.fishEgg?.toLocaleString()}</td>
                <td className="px-6 py-4 text-slate-600 dark:text-slate-400">{tx.chicken?.toLocaleString()}</td>
                <td className="px-6 py-4 text-slate-600 dark:text-slate-400">{tx.houseRent?.toLocaleString()}</td>
                <td className="px-6 py-4 text-slate-600 dark:text-slate-400">{tx.electricity?.toLocaleString()}</td>
                <td className="px-6 py-4 text-slate-600 dark:text-slate-400">{tx.water?.toLocaleString()}</td>
                <td className="px-6 py-4 text-slate-600 dark:text-slate-400">{tx.travel?.toLocaleString()}</td>
                <td className="px-6 py-4 text-slate-600 dark:text-slate-400">{tx.others?.toLocaleString()}</td>
                <td className="px-6 py-4 font-bold text-rose-500 dark:text-rose-400 border-l border-slate-50 dark:border-slate-800">{formatCurrency(tx.totalExpenses)}</td>
                <td className="px-6 py-4 font-black text-indigo-600 dark:text-indigo-400 bg-indigo-50/20 dark:bg-indigo-900/5 border-l border-slate-50 dark:border-slate-800">{formatCurrency(tx.totalBalance)}</td>
                <td className="px-6 py-4 no-print whitespace-nowrap">
                  <div className="flex items-center justify-center gap-2">
                    <button 
                      onClick={() => onEdit(tx)}
                      className="p-2 text-slate-400 dark:text-slate-500 hover:text-indigo-600 dark:hover:text-indigo-400 hover:bg-indigo-50 dark:hover:bg-indigo-900/30 rounded-lg transition-all"
                    >
                      <Edit2 className="w-4 h-4" />
                    </button>
                    <button 
                      onClick={() => tx.id && onDelete(tx.id)}
                      className="p-2 text-slate-400 dark:text-slate-500 hover:text-rose-600 dark:hover:text-rose-400 hover:bg-rose-50 dark:hover:bg-rose-900/30 rounded-lg transition-all"
                    >
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      <div className="print-only mt-12 text-xs text-slate-400 text-center border-t pt-4">
        Generated by Personal Account Tracker | {new Date().toLocaleString()}
      </div>
    </div>
  );
};

export default HistoryTable;

import React, { useMemo } from 'react';
import { Transaction } from '../types';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer,
  PieChart, Pie, Cell 
} from 'recharts';

interface MonthlyChartsProps {
  t: any;
  transactions: Transaction[];
}

const COLORS = ['#6366f1', '#10b981', '#f43f5e', '#f59e0b', '#8b5cf6', '#06b6d4', '#ec4899', '#f97316', '#3b82f6'];

const MonthlyCharts: React.FC<MonthlyChartsProps> = ({ t, transactions }) => {
  const isDark = document.documentElement.classList.contains('dark');

  const categoryData = useMemo(() => {
    const data = [
      { name: t.groceries, value: 0 },
      { name: t.vegetables, value: 0 },
      { name: t.fishEgg, value: 0 },
      { name: t.chicken, value: 0 },
      { name: t.houseRent, value: 0 },
      { name: t.electricity, value: 0 },
      { name: t.water, value: 0 },
      { name: t.travel, value: 0 },
      { name: t.others, value: 0 },
    ];

    transactions.forEach(tx => {
      data[0].value += tx.groceries || 0;
      data[1].value += tx.vegetables || 0;
      data[2].value += tx.fishEgg || 0;
      data[3].value += tx.chicken || 0;
      data[4].value += tx.houseRent || 0;
      data[5].value += tx.electricity || 0;
      data[6].value += tx.water || 0;
      data[7].value += tx.travel || 0;
      data[8].value += tx.others || 0;
    });

    return data.filter(d => d.value > 0);
  }, [transactions, t]);

  if (transactions.length === 0) {
    return (
      <div className="bg-white dark:bg-slate-900 p-12 rounded-3xl border border-slate-100 dark:border-slate-800 text-center transition-colors">
        <p className="text-slate-400 dark:text-slate-600">{t.noData}</p>
      </div>
    );
  }

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
      <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-100 dark:border-slate-800 shadow-sm transition-colors">
        <h3 className="font-bold text-slate-700 dark:text-slate-300 mb-6">{t.expensesByCategory}</h3>
        <div className="h-[300px]">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={categoryData}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke={isDark ? "#1e293b" : "#f1f5f9"} />
              <XAxis dataKey="name" fontSize={10} tickLine={false} axisLine={false} stroke={isDark ? "#64748b" : "#94a3b8"} />
              <YAxis fontSize={12} tickLine={false} axisLine={false} stroke={isDark ? "#64748b" : "#94a3b8"} />
              <Tooltip 
                cursor={{fill: isDark ? '#1e293b' : '#f8fafc'}}
                contentStyle={{ 
                  backgroundColor: isDark ? '#0f172a' : '#ffffff', 
                  borderRadius: '12px', 
                  border: isDark ? '1px solid #1e293b' : 'none', 
                  boxShadow: '0 4px 12px rgba(0,0,0,0.1)',
                  color: isDark ? '#f1f5f9' : '#1e293b'
                }}
              />
              <Bar dataKey="value" fill="#6366f1" radius={[4, 4, 0, 0]} />
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>

      <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-100 dark:border-slate-800 shadow-sm transition-colors">
        <h3 className="font-bold text-slate-700 dark:text-slate-300 mb-6">{t.expenseDistribution}</h3>
        <div className="h-[300px] flex flex-col items-center">
          <ResponsiveContainer width="100%" height="100%">
            <PieChart>
              <Pie
                data={categoryData}
                cx="50%"
                cy="50%"
                innerRadius={60}
                outerRadius={100}
                paddingAngle={5}
                dataKey="value"
                stroke={isDark ? "#0f172a" : "#fff"}
              >
                {categoryData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                ))}
              </Pie>
              <Tooltip 
                contentStyle={{ 
                  backgroundColor: isDark ? '#0f172a' : '#ffffff', 
                  borderRadius: '12px', 
                  border: isDark ? '1px solid #1e293b' : 'none',
                  color: isDark ? '#f1f5f9' : '#1e293b'
                }}
              />
              <Legend layout="horizontal" align="center" verticalAlign="bottom" />
            </PieChart>
          </ResponsiveContainer>
        </div>
      </div>
    </div>
  );
};

export default MonthlyCharts;

import React, { useState, useEffect } from 'react';
import { Bill } from '../types';
import { storageService } from '../services/googleSheets';
import { Plus, CreditCard, Trash2, Calendar, DollarSign, X } from 'lucide-react';

interface BillManagerProps {
  t: any;
  formatCurrency: (amount: number) => string;
}

const BillManager: React.FC<BillManagerProps> = ({ t, formatCurrency }) => {
  const [bills, setBills] = useState<Bill[]>([]);
  const [showAdd, setShowAdd] = useState(false);
  const [newBill, setNewBill] = useState<Partial<Bill>>({ dueDay: 1, category: 'others' });

  useEffect(() => {
    storageService.fetchBills().then(setBills);
  }, []);

  const handleSave = async () => {
    if (!newBill.name || !newBill.amount) return;
    const bill: Bill = {
      id: crypto.randomUUID(),
      name: newBill.name,
      amount: Number(newBill.amount),
      dueDay: Number(newBill.dueDay),
      category: newBill.category || 'others'
    };
    await storageService.saveBill(bill);
    setBills([...bills, bill]);
    setShowAdd(false);
    setNewBill({ dueDay: 1, category: 'others' });
  };

  const handleDelete = async (id: string) => {
    await storageService.deleteBill(id);
    setBills(bills.filter(b => b.id !== id));
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-indigo-100 dark:bg-indigo-900/30 rounded-xl">
            <CreditCard className="w-6 h-6 text-indigo-700 dark:text-indigo-400" />
          </div>
          <h2 className="text-2xl font-black text-slate-800 dark:text-slate-100">{t.bills}</h2>
        </div>
        <button 
          onClick={() => setShowAdd(true)}
          className="flex items-center gap-2 px-6 py-3 bg-indigo-600 text-white rounded-2xl font-bold shadow-lg shadow-indigo-200 dark:shadow-none hover:bg-indigo-700 active:scale-95 transition-all"
        >
          <Plus className="w-5 h-5" />
          {t.addBill}
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {bills.map(bill => (
          <div key={bill.id} className="bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-100 dark:border-slate-800 shadow-sm relative group overflow-hidden transition-colors">
            <div className="absolute top-0 left-0 w-2 h-full bg-indigo-500 opacity-20 group-hover:opacity-100 transition-all" />
            <div className="flex justify-between items-start mb-4 pl-2">
              <div>
                <h3 className="font-black text-slate-800 dark:text-slate-100 text-lg uppercase tracking-tight">{bill.name}</h3>
                <p className="text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest">{t[bill.category as keyof typeof t] || bill.category}</p>
              </div>
              <button 
                onClick={() => handleDelete(bill.id)}
                className="p-2 text-slate-300 dark:text-slate-600 hover:text-rose-500 dark:hover:text-rose-400 hover:bg-rose-50 dark:hover:bg-rose-900/30 rounded-xl transition-all"
              >
                <Trash2 className="w-4 h-4" />
              </button>
            </div>

            <div className="flex items-center gap-6 pl-2">
              <div className="flex flex-col">
                <span className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-1">{t.date}</span>
                <div className="flex items-center gap-2 text-indigo-600 dark:text-indigo-400 font-black">
                  <Calendar className="w-4 h-4" />
                  <span>{bill.dueDay}st / Month</span>
                </div>
              </div>
              <div className="flex flex-col">
                <span className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-1">Amount</span>
                <div className="flex items-center gap-2 text-slate-800 dark:text-slate-100 font-black">
                  <DollarSign className="w-4 h-4 text-slate-300 dark:text-slate-700" />
                  <span>{formatCurrency(bill.amount)}</span>
                </div>
              </div>
            </div>
          </div>
        ))}

        {bills.length === 0 && (
          <div className="col-span-full py-20 bg-slate-50/50 dark:bg-slate-900/50 rounded-3xl border-2 border-dashed border-slate-200 dark:border-slate-800 flex flex-col items-center justify-center text-slate-400 dark:text-slate-600 gap-4 transition-colors">
