                    value={newBill.amount || ''}
                    onChange={e => setNewBill({...newBill, amount: e.target.value})}
                  />
                </div>
                <div>
                  <label className="block text-xs font-black text-slate-400 dark:text-slate-500 uppercase mb-2">Due Day (1-31)</label>
                  <input 
                    type="number" 
                    min="1" max="31"
