                  value={newBill.category || 'others'}
                  onChange={e => setNewBill({...newBill, category: e.target.value})}
                >
                  <option value="groceries" className="bg-white dark:bg-slate-900">{t.groceries}</option>
                  <option value="vegetables" className="bg-white dark:bg-slate-900">{t.vegetables}</option>
                  <option value="fishEgg" className="bg-white dark:bg-slate-900">{t.fishEgg}</option>
                  <option value="chicken" className="bg-white dark:bg-slate-900">{t.chicken}</option>
                  <option value="houseRent" className="bg-white dark:bg-slate-900">{t.houseRent}</option>
                  <option value="electricity" className="bg-white dark:bg-slate-900">{t.electricity}</option>
                  <option value="water" className="bg-white dark:bg-slate-900">{t.water}</option>
                  <option value="travel" className="bg-white dark:bg-slate-900">{t.travel}</option>
                  <option value="others" className="bg-white dark:bg-slate-900">{t.others}</option>
                </select>
              </div>
              <button 
                onClick={handleSave}
                className="w-full bg-indigo-600 text-white py-4 rounded-2xl font-bold shadow-lg shadow-indigo-200 dark:shadow-none hover:bg-indigo-700 mt-4 transition-all"
              >
                {t.save}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

