import React, { useState, useMemo } from 'react';
import { Transaction } from '../types';
import { Edit2, Trash2, FileSpreadsheet, Printer, Search, X, Calendar as CalendarIcon, Filter } from 'lucide-react';
import * as XLSX from 'xlsx';

interface HistoryTableProps {
  t: any;
  transactions: Transaction[];
  allTransactions?: Transaction[];
  onEdit: (tx: Transaction) => void;
  onDelete: (id: string) => void;
  isLoading: boolean;
  formatCurrency: (amount: number) => string;
}

const HistoryTable: React.FC<HistoryTableProps> = ({ t, transactions, allTransactions, onEdit, onDelete, isLoading, formatCurrency }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');

  const filteredTransactions = useMemo(() => {
    return transactions.filter(tx => {
      // Date range filter
      if (startDate && tx.date < startDate) return false;
      if (endDate && tx.date > endDate) return false;

      // Search term filter
      if (searchTerm) {
        const lowerSearch = searchTerm.toLowerCase();

        // Search in date
        if (tx.date.includes(searchTerm)) return true;

        // Check if search matches any category label where expense > 0
        const categories = [
          { key: 'groceries', label: t.groceries },
          { key: 'vegetables', label: t.vegetables },
          { key: 'fishEgg', label: t.fishEgg },
          { key: 'chicken', label: t.chicken },
          { key: 'houseRent', label: t.houseRent },
          { key: 'electricity', label: t.electricity },
          { key: 'water', label: t.water },
          { key: 'travel', label: t.travel },
          { key: 'others', label: t.others },
        ];

        const matchesCategory = categories.some(cat => 
          cat.label.toLowerCase().includes(lowerSearch) && (tx as any)[cat.key] > 0
        );

        if (matchesCategory) return true;

        // Search in total expenses or daily cash
        if (tx.totalExpenses.toString().includes(searchTerm)) return true;
        if (tx.dailyCash.toString().includes(searchTerm)) return true;

        return false;
      }

      return true;
    });
  }, [transactions, searchTerm, startDate, endDate, t]);

  const formatForExcel = (data: Transaction[]) => {
    return data.map(tx => ({
      [t.date]: tx.date,
      [t.dailyCash]: tx.dailyCash,
      [t.groceries]: tx.groceries,
      [t.vegetables]: tx.vegetables,
      [t.fishEgg]: tx.fishEgg,
      [t.chicken]: tx.chicken,
      [t.houseRent]: tx.houseRent,
      [t.electricity]: tx.electricity,
      [t.water]: tx.water,
      [t.travel]: tx.travel,
      [t.others]: tx.others,
      [t.totalExpenses]: tx.totalExpenses,
      [t.totalBalance]: tx.totalBalance,
    }));
  };

  const exportAllToExcel = () => {
    const dataToExport = allTransactions || transactions;
    if (dataToExport.length === 0) return;

    const workbook = XLSX.utils.book_new();
    const sortedData = [...dataToExport].sort((a,b) => a.date.localeCompare(b.date));

    const fullData = formatForExcel(sortedData);
    const wsFull = XLSX.utils.json_to_sheet(fullData);
    XLSX.utils.book_append_sheet(workbook, wsFull, "Transaction Details");

    const monthlySummary: any[] = [];
    const months = [...new Set(sortedData.map(tx => tx.month))];
    months.forEach(m => {
      const txs = sortedData.filter(tx => tx.month === m);
      monthlySummary.push({
        [t.month]: m,
        [t.totalIncome]: txs.reduce((acc, curr) => acc + (curr.dailyCash || 0), 0),
        [t.totalExpenses]: txs.reduce((acc, curr) => acc + (curr.totalExpenses || 0), 0),
        [t.totalBalance]: txs[txs.length-1]?.totalBalance || 0
      });
    });
    const wsSummary = XLSX.utils.json_to_sheet(monthlySummary);
    XLSX.utils.book_append_sheet(workbook, wsSummary, "Monthly Summary");

    XLSX.writeFile(workbook, `Finance_Report_${new Date().toISOString().split('T')[0]}.xlsx`);
  };

  const handlePrint = () => {
    window.print();
  };

  const clearFilters = () => {
    setSearchTerm('');
    setStartDate('');
    setEndDate('');
  };

  if (isLoading) {
    return <div className="p-12 text-center text-slate-400 dark:text-slate-600">Loading records...</div>;
  }

  const selectedMonth = transactions[0]?.month || '';
  const totalIn = filteredTransactions.reduce((s, tx) => s + tx.dailyCash, 0);
  const totalOut = filteredTransactions.reduce((s, tx) => s + tx.totalExpenses, 0);

  return (
    <div className="flex flex-col">
      {/* Search and Filters Header */}
      <div className="p-4 md:p-6 border-b border-slate-100 dark:border-slate-800 space-y-4 no-print transition-colors">
        <div className="flex flex-col lg:flex-row gap-4">
          <div className="flex-grow relative">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
            <input
              type="text"
              placeholder={t.search}
              className="w-full pl-11 pr-4 py-2.5 rounded-xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 focus:ring-2 focus:ring-indigo-500 outline-none transition-all font-medium text-sm"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
            {searchTerm && (
              <button 
                onClick={() => setSearchTerm('')}
                className="absolute right-4 top-1/2 -translate-y-1/2 p-1 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-full transition-colors"
              >
                <X className="w-3 h-3 text-slate-400" />
              </button>
            )}
          </div>

          <div className="flex flex-wrap items-center gap-4">
            <div className="flex items-center gap-2 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl px-3 py-1">
              <CalendarIcon className="w-4 h-4 text-slate-400" />
              <input
                type="date"
                className="bg-transparent border-none text-xs font-bold text-slate-600 dark:text-slate-300 outline-none p-1"
                value={startDate}
                onChange={(e) => setStartDate(e.target.value)}
                title={t.startDate}
              />
              <span className="text-slate-300 dark:text-slate-600">→</span>
              <input
                type="date"
                className="bg-transparent border-none text-xs font-bold text-slate-600 dark:text-slate-300 outline-none p-1"
                value={endDate}
                onChange={(e) => setEndDate(e.target.value)}
                title={t.endDate}
              />
            </div>

            <div className="flex gap-2">
              {(searchTerm || startDate || endDate) && (
                <button 
                  onClick={clearFilters}
                  className="px-4 py-2 text-xs font-bold text-rose-500 hover:bg-rose-50 dark:hover:bg-rose-900/20 rounded-xl transition-all flex items-center gap-2"
                >
                  <X className="w-3.5 h-3.5" />
                  {t.clearFilters}
                </button>
              )}

              <button 
                onClick={handlePrint}
                className="flex items-center gap-2 bg-slate-100 dark:bg-slate-800 text-slate-700 dark:text-slate-300 font-bold text-xs hover:bg-slate-200 dark:hover:bg-slate-700 px-4 py-2 rounded-xl transition-colors"
              >
                <Printer className="w-3.5 h-3.5" />
                {t.printReport}
              </button>
              <button 
                onClick={exportAllToExcel}
                className="flex items-center gap-2 bg-indigo-600 text-white font-bold text-xs hover:bg-indigo-700 px-4 py-2 rounded-xl transition-colors shadow-sm"
              >
                <FileSpreadsheet className="w-3.5 h-3.5" />
                {t.exportExcel}
              </button>
            </div>
          </div>
        </div>
      </div>

      <div className="print-only mb-6 text-center">
        <h1 className="text-2xl font-bold">{t.title}</h1>
        <h2 className="text-xl text-slate-600">{selectedMonth}</h2>
        <div className="flex justify-center gap-8 mt-4 border-y py-2">
           <div><span className="font-bold">{t.totalReceived}:</span> {formatCurrency(totalIn)}</div>
           <div><span className="font-bold">{t.totalSpent}:</span> {formatCurrency(totalOut)}</div>
           <div><span className="font-bold">{t.totalBalance}:</span> {formatCurrency(filteredTransactions[filteredTransactions.length - 1]?.totalBalance || 0)}</div>
        </div>
      </div>

      <div className="overflow-x-auto transition-colors">
        <table className="w-full text-left min-w-[1200px] border-collapse">
          <thead>
            <tr className="bg-slate-50 dark:bg-slate-800/50 text-slate-500 dark:text-slate-400 text-[10px] uppercase font-black tracking-widest border-b border-slate-200 dark:border-slate-800">
              <th className="px-6 py-4 border-r border-slate-100 dark:border-slate-800">{t.date}</th>
              <th className="px-6 py-4 border-r border-slate-100 dark:border-slate-800">{t.dailyCash}</th>
              <th className="px-6 py-4">{t.groceries}</th>
              <th className="px-6 py-4">{t.vegetables}</th>
              <th className="px-6 py-4">{t.fishEgg}</th>
              <th className="px-6 py-4">{t.chicken}</th>
              <th className="px-6 py-4">{t.houseRent}</th>
              <th className="px-6 py-4">{t.electricity}</th>
              <th className="px-6 py-4">{t.water}</th>
              <th className="px-6 py-4">{t.travel}</th>
              <th className="px-6 py-4">{t.others}</th>
              <th className="px-6 py-4 border-l border-slate-100 dark:border-slate-800">{t.totalExpenses}</th>
              <th className="px-6 py-4 bg-indigo-50/30 dark:bg-indigo-900/10 text-indigo-700 dark:text-indigo-400 border-l border-slate-100 dark:border-slate-800">{t.totalBalance}</th>
              <th className="px-6 py-4 text-center no-print">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100 dark:divide-slate-800 text-sm">
            {filteredTransactions.map((tx) => (
              <tr key={tx.id || tx.timestamp} className="hover:bg-slate-50/50 dark:hover:bg-slate-800/50 transition-colors">
                <td className="px-6 py-4 font-semibold text-slate-700 dark:text-slate-300 whitespace-nowrap border-r border-slate-50 dark:border-slate-800">{tx.date.split('-').reverse().join('/')}</td>
                <td className="px-6 py-4 font-bold text-emerald-600 dark:text-emerald-400 border-r border-slate-50 dark:border-slate-800">{formatCurrency(tx.dailyCash)}</td>
                <td className="px-6 py-4 text-slate-600 dark:text-slate-400">{tx.groceries?.toLocaleString()}</td>
                <td className="px-6 py-4 text-slate-600 dark:text-slate-400">{tx.vegetables?.toLocaleString()}</td>
                <td className="px-6 py-4 text-slate-600 dark:text-slate-400">{tx.fishEgg?.toLocaleString()}</td>
                <td className="px-6 py-4 text-slate-600 dark:text-slate-400">{tx.chicken?.toLocaleString()}</td>
                <td className="px-6 py-4 text-slate-600 dark:text-slate-400">{tx.houseRent?.toLocaleString()}</td>
                <td className="px-6 py-4 text-slate-600 dark:text-slate-400">{tx.electricity?.toLocaleString()}</td>
                <td className="px-6 py-4 text-slate-600 dark:text-slate-400">{tx.water?.toLocaleString()}</td>
                <td className="px-6 py-4 text-slate-600 dark:text-slate-400">{tx.travel?.toLocaleString()}</td>
                <td className="px-6 py-4 text-slate-600 dark:text-slate-400">{tx.others?.toLocaleString()}</td>
                <td className="px-6 py-4 font-bold text-rose-500 dark:text-rose-400 border-l border-slate-50 dark:border-slate-800">{formatCurrency(tx.totalExpenses)}</td>
                <td className="px-6 py-4 font-black text-indigo-600 dark:text-indigo-400 bg-indigo-50/20 dark:bg-indigo-900/5 border-l border-slate-50 dark:border-slate-800">{formatCurrency(tx.totalBalance)}</td>
                <td className="px-6 py-4 no-print whitespace-nowrap">
                  <div className="flex items-center justify-center gap-2">
                    <button 
                      onClick={() => onEdit(tx)}
                      className="p-2 text-slate-400 dark:text-slate-500 hover:text-indigo-600 dark:hover:text-indigo-400 hover:bg-indigo-50 dark:hover:bg-indigo-900/30 rounded-lg transition-all"
                    >
                      <Edit2 className="w-4 h-4" />
                    </button>
                    <button 
                      onClick={() => tx.id && onDelete(tx.id)}
                      className="p-2 text-slate-400 dark:text-slate-500 hover:text-rose-600 dark:hover:text-rose-400 hover:bg-rose-50 dark:hover:bg-rose-900/30 rounded-lg transition-all"
                    >
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>

        {filteredTransactions.length === 0 && (
          <div className="p-20 text-center flex flex-col items-center gap-3">
             <Filter className="w-12 h-12 text-slate-200 dark:text-slate-800" />
             <p className="text-slate-400 dark:text-slate-600 font-bold italic">{t.noResults}</p>
             <button 
              onClick={clearFilters}
              className="text-indigo-600 dark:text-indigo-400 font-bold text-sm hover:underline"
             >
               {t.clearFilters}
             </button>
          </div>
        )}
      </div>

      <div className="print-only mt-12 text-xs text-slate-400 text-center border-t pt-4">
        Generated by Personal Account Tracker | {new Date().toLocaleString()}
      </div>
    </div>
  );
};

