interface BillManagerProps {
  t: any;
  formatCurrency: (amount: number) => string;
  onRefresh?: () => void;
}

const BillManager: React.FC<BillManagerProps> = ({ t, formatCurrency, onRefresh }) => {
  const [bills, setBills] = useState<Bill[]>([]);
  const [showAdd, setShowAdd] = useState(false);
  const [newBill, setNewBill] = useState<Partial<Bill>>({ dueDay: 1, category: 'others' });

  useEffect(() => {
    storageService.fetchBills().then(setBills);
  }, []);

  const handleSave = async () => {
    if (!newBill.name || !newBill.amount) return;
    const bill: Bill = {
      id: crypto.randomUUID(),
      name: newBill.name,
      amount: Number(newBill.amount),
      dueDay: Number(newBill.dueDay),
      category: newBill.category || 'others'
    };
    await storageService.saveBill(bill);
    setBills([...bills, bill]);
    setShowAdd(false);
    setNewBill({ dueDay: 1, category: 'others' });
    if (onRefresh) onRefresh();
  };

  const handleDelete = async (id: string) => {
    if (window.confirm(t.confirmDelete)) {
      await storageService.deleteBill(id);
      setBills(bills.filter(b => b.id !== id));
      if (onRefresh) onRefresh();
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
