import React, { useState, useMemo } from 'react';
import { Transaction } from '../types';
import { Edit2, Trash2, FileSpreadsheet, Printer, Search, X, Calendar as CalendarIcon, Filter, CheckCircle } from 'lucide-react';
import * as XLSX from 'xlsx';

interface HistoryTableProps {
  t: any;
  transactions: Transaction[];
  allTransactions?: Transaction[];
  onEdit: (tx: Transaction) => void;
  onDelete: (id: string) => void;
  isLoading: boolean;
  formatCurrency: (amount: number) => string;
}

const HistoryTable: React.FC<HistoryTableProps> = ({ t, transactions, allTransactions, onEdit, onDelete, isLoading, formatCurrency }) => {
  // Staged filter state (what the user sees in the inputs)
  const [stagedSearch, setStagedSearch] = useState('');
  const [stagedStart, setStagedStart] = useState('');
  const [stagedEnd, setStagedEnd] = useState('');

  // Active filter state (what is actually applied to the table)
  const [activeSearch, setActiveSearch] = useState('');
  const [activeStart, setActiveStart] = useState('');
  const [activeEnd, setActiveEnd] = useState('');

  const filteredTransactions = useMemo(() => {
    return transactions.filter(tx => {
      // Date range filter
      if (activeStart && tx.date < activeStart) return false;
      if (activeEnd && tx.date > activeEnd) return false;

      // Search term filter
      if (activeSearch) {
        const lowerSearch = activeSearch.toLowerCase();

        // Search in date
        if (tx.date.includes(activeSearch)) return true;

        // Check if search matches any category label where expense > 0
        const categories = [
          { key: 'groceries', label: t.groceries },
          { key: 'vegetables', label: t.vegetables },
          { key: 'fishEgg', label: t.fishEgg },
          { key: 'chicken', label: t.chicken },
          { key: 'houseRent', label: t.houseRent },
          { key: 'electricity', label: t.electricity },
          { key: 'water', label: t.water },
          { key: 'travel', label: t.travel },
          { key: 'others', label: t.others },
        ];

        const matchesCategory = categories.some(cat => 
          cat.label.toLowerCase().includes(lowerSearch) && (tx as any)[cat.key] > 0
        );

        if (matchesCategory) return true;

        // Search in total expenses or daily cash
        if (tx.totalExpenses.toString().includes(activeSearch)) return true;
        if (tx.dailyCash.toString().includes(activeSearch)) return true;

        return false;
      }

      return true;
    });
  }, [transactions, activeSearch, activeStart, activeEnd, t]);

  const formatForExcel = (data: Transaction[]) => {
    return data.map(tx => ({
      [t.date]: tx.date,
      [t.dailyCash]: tx.dailyCash,
      [t.groceries]: tx.groceries,
      [t.vegetables]: tx.vegetables,
      [t.fishEgg]: tx.fishEgg,
      [t.chicken]: tx.chicken,
      [t.houseRent]: tx.houseRent,
      [t.electricity]: tx.electricity,
      [t.water]: tx.water,
      [t.travel]: tx.travel,
      [t.others]: tx.others,
      [t.totalExpenses]: tx.totalExpenses,
      [t.totalBalance]: tx.totalBalance,
    }));
  };

  const exportAllToExcel = () => {
    const dataToExport = allTransactions || transactions;
    if (dataToExport.length === 0) return;

    const workbook = XLSX.utils.book_new();
    const sortedData = [...dataToExport].sort((a,b) => a.date.localeCompare(b.date));

    const fullData = formatForExcel(sortedData);
    const wsFull = XLSX.utils.json_to_sheet(fullData);
    XLSX.utils.book_append_sheet(workbook, wsFull, "Transaction Details");

    const monthlySummary: any[] = [];
    const months = [...new Set(sortedData.map(tx => tx.month))];
    months.forEach(m => {
      const txs = sortedData.filter(tx => tx.month === m);
      monthlySummary.push({
        [t.month]: m,
        [t.totalIncome]: txs.reduce((acc, curr) => acc + (curr.dailyCash || 0), 0),
        [t.totalExpenses]: txs.reduce((acc, curr) => acc + (curr.totalExpenses || 0), 0),
        [t.totalBalance]: txs[txs.length-1]?.totalBalance || 0
      });
    });
    const wsSummary = XLSX.utils.json_to_sheet(monthlySummary);
    XLSX.utils.book_append_sheet(workbook, wsSummary, "Monthly Summary");

    XLSX.writeFile(workbook, `Finance_Report_${new Date().toISOString().split('T')[0]}.xlsx`);
  };

  const handlePrint = () => {
    window.print();
  };

  const applyFilters = () => {
    setActiveSearch(stagedSearch);
    setActiveStart(stagedStart);
    setActiveEnd(stagedEnd);
  };

  const clearFilters = () => {
    setStagedSearch('');
    setStagedStart('');
    setStagedEnd('');
    setActiveSearch('');
    setActiveStart('');
    setActiveEnd('');
  };

  if (isLoading) {
    return <div className="p-12 text-center text-slate-400 dark:text-slate-600">Loading records...</div>;
  }

  const selectedMonth = transactions[0]?.month || '';
  const totalIn = filteredTransactions.reduce((s, tx) => s + tx.dailyCash, 0);
  const totalOut = filteredTransactions.reduce((s, tx) => s + tx.totalExpenses, 0);

  return (
    <div className="flex flex-col">
      {/* Search and Filters Header */}
      <div className="p-4 md:p-6 border-b border-slate-100 dark:border-slate-800 space-y-4 no-print transition-colors">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">
          {/* Keyword Search */}
          <div className="lg:col-span-4">
            <label className="block text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-2 px-1">
              Keyword Search
            </label>
            <div className="relative group">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 group-focus-within:text-indigo-500 transition-colors" />
              <input
                type="text"
                placeholder={t.search}
                className="w-full pl-11 pr-4 py-3 rounded-2xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 focus:ring-2 focus:ring-indigo-500 outline-none transition-all font-medium text-sm shadow-sm"
                value={stagedSearch}
                onChange={(e) => setStagedSearch(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && applyFilters()}
              />
              {stagedSearch && (
                <button 
                  onClick={() => setStagedSearch('')}
                  className="absolute right-4 top-1/2 -translate-y-1/2 p-1.5 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-full transition-colors"
                >
                  <X className="w-3.5 h-3.5 text-slate-400" />
                </button>
              )}
            </div>
          </div>

          {/* Date Range Selection */}
          <div className="lg:col-span-5">
            <label className="block text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-2 px-1">
              {t.date} Range
            </label>
            <div className="flex items-center gap-2 bg-slate-50 dark:bg-slate-900/50 border border-slate-200 dark:border-slate-700 rounded-2xl p-1 shadow-sm">
              <div className="flex-1 relative flex items-center bg-white dark:bg-slate-800 rounded-xl px-3 py-2 border border-slate-100 dark:border-slate-700/50">
                <span className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase absolute -top-2 left-2 bg-white dark:bg-slate-800 px-1">From</span>
                <CalendarIcon className="w-3.5 h-3.5 text-slate-300 mr-2" />
                <input
                  type="date"
                  className="bg-transparent border-none text-xs font-bold text-slate-700 dark:text-slate-200 outline-none w-full"
                  value={stagedStart}
                  onChange={(e) => setStagedStart(e.target.value)}
                />
              </div>
              <span className="text-slate-400 font-bold px-1">→</span>
              <div className="flex-1 relative flex items-center bg-white dark:bg-slate-800 rounded-xl px-3 py-2 border border-slate-100 dark:border-slate-700/50">
                <span className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase absolute -top-2 left-2 bg-white dark:bg-slate-800 px-1">To</span>
                <CalendarIcon className="w-3.5 h-3.5 text-slate-300 mr-2" />
                <input
                  type="date"
                  className="bg-transparent border-none text-xs font-bold text-slate-700 dark:text-slate-200 outline-none w-full"
                  value={stagedEnd}
                  onChange={(e) => setStagedEnd(e.target.value)}
                />
              </div>
            </div>
          </div>

          {/* Action Buttons */}
          <div className="lg:col-span-3 flex items-end gap-3 h-full">
            <button 
              onClick={applyFilters}
              className="flex-1 flex items-center justify-center gap-2 bg-indigo-600 text-white font-bold text-sm hover:bg-indigo-700 py-3 rounded-2xl transition-all shadow-lg shadow-indigo-100 dark:shadow-none active:scale-95"
            >
              <Filter className="w-4 h-4" />
              {t.applyFilters}
            </button>

            <button 
              onClick={clearFilters}
              disabled={!stagedSearch && !stagedStart && !stagedEnd && !activeSearch && !activeStart && !activeEnd}
              className="p-3 text-slate-400 hover:text-rose-500 hover:bg-rose-50 dark:hover:bg-rose-900/20 rounded-2xl transition-all disabled:opacity-30 disabled:cursor-not-allowed border border-slate-200 dark:border-slate-700"
              title={t.clearFilters}
            >
              <X className="w-5 h-5" />
            </button>
          </div>
        </div>

        {/* Report Controls (Lower Row) */}
        <div className="flex flex-wrap items-center justify-between gap-4 pt-2">
          <div className="flex gap-2">
            {(activeSearch || activeStart || activeEnd) && (
              <div className="flex items-center gap-2 px-3 py-1.5 bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400 rounded-full text-[10px] font-black uppercase tracking-widest border border-indigo-100 dark:border-indigo-800 animate-in fade-in zoom-in-95">
                <CheckCircle className="w-3 h-3" />
                Filters Applied
              </div>
            )}
          </div>

          <div className="flex gap-3">
            <button 
              onClick={handlePrint}
              className="flex items-center gap-2 bg-white dark:bg-slate-800 text-slate-600 dark:text-slate-300 font-bold text-xs hover:bg-slate-50 dark:hover:bg-slate-700 border border-slate-200 dark:border-slate-700 px-5 py-2.5 rounded-xl transition-all shadow-sm active:scale-95"
            >
              <Printer className="w-3.5 h-3.5" />
              {t.printReport}
            </button>
            <button 
              onClick={exportAllToExcel}
              className="flex items-center gap-2 bg-emerald-600 text-white font-bold text-xs hover:bg-emerald-700 px-5 py-2.5 rounded-xl transition-all shadow-lg shadow-emerald-100 dark:shadow-none active:scale-95"
            >
              <FileSpreadsheet className="w-3.5 h-3.5" />
              {t.exportExcel}
            </button>
          </div>
        </div>
      </div>

      <div className="print-only mb-6 text-center">
        <h1 className="text-2xl font-bold">{t.title}</h1>
        <h2 className="text-xl text-slate-600">{selectedMonth}</h2>
        <div className="flex justify-center gap-8 mt-4 border-y py-2">
           <div><span className="font-bold">{t.totalReceived}:</span> {formatCurrency(totalIn)}</div>
           <div><span className="font-bold">{t.totalSpent}:</span> {formatCurrency(totalOut)}</div>
           <div><span className="font-bold">{t.totalBalance}:</span> {formatCurrency(filteredTransactions[filteredTransactions.length - 1]?.totalBalance || 0)}</div>
        </div>
      </div>

      <div className="overflow-x-auto transition-colors">
        <table className="w-full text-left min-w-[1200px] border-collapse">
          <thead>
            <tr className="bg-slate-50 dark:bg-slate-800/50 text-slate-500 dark:text-slate-400 text-[10px] uppercase font-black tracking-widest border-b border-slate-200 dark:border-slate-800">
              <th className="px-6 py-4 border-r border-slate-100 dark:border-slate-800">{t.date}</th>
              <th className="px-6 py-4 border-r border-slate-100 dark:border-slate-800">{t.dailyCash}</th>
              <th className="px-6 py-4">{t.groceries}</th>
              <th className="px-6 py-4">{t.vegetables}</th>
              <th className="px-6 py-4">{t.fishEgg}</th>
              <th className="px-6 py-4">{t.chicken}</th>
              <th className="px-6 py-4">{t.houseRent}</th>
              <th className="px-6 py-4">{t.electricity}</th>
              <th className="px-6 py-4">{t.water}</th>
              <th className="px-6 py-4">{t.travel}</th>
              <th className="px-6 py-4">{t.others}</th>
              <th className="px-6 py-4 border-l border-slate-100 dark:border-slate-800">{t.totalExpenses}</th>
              <th className="px-6 py-4 bg-indigo-50/30 dark:bg-indigo-900/10 text-indigo-700 dark:text-indigo-400 border-l border-slate-100 dark:border-slate-800">{t.totalBalance}</th>
              <th className="px-6 py-4 text-center no-print">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100 dark:divide-slate-800 text-sm">
            {filteredTransactions.map((tx) => (
              <tr key={tx.id || tx.timestamp} className="hover:bg-slate-50/50 dark:hover:bg-slate-800/50 transition-colors">
                <td className="px-6 py-4 font-semibold text-slate-700 dark:text-slate-300 whitespace-nowrap border-r border-slate-50 dark:border-slate-800">{tx.date.split('-').reverse().join('/')}</td>
                <td className="px-6 py-4 font-bold text-emerald-600 dark:text-emerald-400 border-r border-slate-50 dark:border-slate-800">{formatCurrency(tx.dailyCash)}</td>
                <td className="px-6 py-4 text-slate-600 dark:text-slate-400">{tx.groceries?.toLocaleString()}</td>
                <td className="px-6 py-4 text-slate-600 dark:text-slate-400">{tx.vegetables?.toLocaleString()}</td>
                <td className="px-6 py-4 text-slate-600 dark:text-slate-400">{tx.fishEgg?.toLocaleString()}</td>
                <td className="px-6 py-4 text-slate-600 dark:text-slate-400">{tx.chicken?.toLocaleString()}</td>
                <td className="px-6 py-4 text-slate-600 dark:text-slate-400">{tx.houseRent?.toLocaleString()}</td>
                <td className="px-6 py-4 text-slate-600 dark:text-slate-400">{tx.electricity?.toLocaleString()}</td>
                <td className="px-6 py-4 text-slate-600 dark:text-slate-400">{tx.water?.toLocaleString()}</td>
                <td className="px-6 py-4 text-slate-600 dark:text-slate-400">{tx.travel?.toLocaleString()}</td>
                <td className="px-6 py-4 text-slate-600 dark:text-slate-400">{tx.others?.toLocaleString()}</td>
                <td className="px-6 py-4 font-bold text-rose-500 dark:text-rose-400 border-l border-slate-50 dark:border-slate-800">{formatCurrency(tx.totalExpenses)}</td>
                <td className="px-6 py-4 font-black text-indigo-600 dark:text-indigo-400 bg-indigo-50/20 dark:bg-indigo-900/5 border-l border-slate-50 dark:border-slate-800">{formatCurrency(tx.totalBalance)}</td>
                <td className="px-6 py-4 no-print whitespace-nowrap">
                  <div className="flex items-center justify-center gap-2">
                    <button 
                      onClick={() => onEdit(tx)}
                      className="p-2 text-slate-400 dark:text-slate-500 hover:text-indigo-600 dark:hover:text-indigo-400 hover:bg-indigo-50 dark:hover:bg-indigo-900/30 rounded-lg transition-all"
                    >
                      <Edit2 className="w-4 h-4" />
                    </button>
                    <button 
                      onClick={() => tx.id && onDelete(tx.id)}
                      className="p-2 text-slate-400 dark:text-slate-500 hover:text-rose-600 dark:hover:text-rose-400 hover:bg-rose-50 dark:hover:bg-rose-900/30 rounded-lg transition-all"
                    >
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>

        {filteredTransactions.length === 0 && (
          <div className="p-20 text-center flex flex-col items-center gap-3">
             <Filter className="w-12 h-12 text-slate-200 dark:text-slate-800" />
             <p className="text-slate-400 dark:text-slate-600 font-bold italic">{t.noResults}</p>
             <button 
              onClick={clearFilters}
              className="text-indigo-600 dark:text-indigo-400 font-bold text-sm hover:underline"
             >
               {t.clearFilters}
             </button>
          </div>
        )}
      </div>

      <div className="print-only mt-12 text-xs text-slate-400 text-center border-t pt-4">
        Generated by Personal Account Tracker | {new Date().toLocaleString()}
      </div>
    </div>
  );
};

export default HistoryTable;

import React, { useState, useEffect } from 'react';
import { Bill } from '../types';
import { storageService } from '../services/googleSheets';
import { Plus, CreditCard, Trash2, Calendar, DollarSign, X } from 'lucide-react';

interface BillManagerProps {
  t: any;
  formatCurrency: (amount: number) => string;
  onRefresh?: () => void;
}

const BillManager: React.FC<BillManagerProps> = ({ t, formatCurrency, onRefresh }) => {
  const [bills, setBills] = useState<Bill[]>([]);
  const [showAdd, setShowAdd] = useState(false);
  const [newBill, setNewBill] = useState<Partial<Bill>>({ dueDay: new Date().getDate(), category: 'others' });
  const [isNameManuallyEdited, setIsNameManuallyEdited] = useState(false);

  useEffect(() => {
    storageService.fetchBills().then(setBills);
  }, []);

  const handleCategoryChange = (category: string) => {
    const updates: Partial<Bill> = { category };

    // Auto-fill name if not manually edited or if name is empty
    if (!isNameManuallyEdited || !newBill.name) {
      updates.name = t[category as keyof typeof t] || category;
    }

    setNewBill(prev => ({ ...prev, ...updates }));
  };

  const handleSave = async () => {
    if (!newBill.name || !newBill.amount) return;
    const bill: Bill = {
      id: crypto.randomUUID(),
      name: newBill.name,
      amount: Number(newBill.amount),
      dueDay: Number(newBill.dueDay),
      category: newBill.category || 'others'
    };
    await storageService.saveBill(bill);
    setBills([...bills, bill]);
    setShowAdd(false);
    resetForm();
    if (onRefresh) onRefresh();
  };

  const resetForm = () => {
    setNewBill({ dueDay: new Date().getDate(), category: 'others' });
    setIsNameManuallyEdited(false);
  };

  const handleDelete = async (id: string) => {
    if (window.confirm(t.confirmDelete)) {
      await storageService.deleteBill(id);
      setBills(bills.filter(b => b.id !== id));
      if (onRefresh) onRefresh();
    }
  };

  // Helper to format the current month's "due date" for the date picker input
  const getDummyDateString = (day: number = 1) => {
    const now = new Date();
    const date = new Date(now.getFullYear(), now.getMonth(), day);
    return date.toISOString().split('T')[0];
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-indigo-100 dark:bg-indigo-900/30 rounded-xl">
            <CreditCard className="w-6 h-6 text-indigo-700 dark:text-indigo-400" />
          </div>
          <h2 className="text-2xl font-black text-slate-800 dark:text-slate-100">{t.bills}</h2>
        </div>
        <button 
          onClick={() => setShowAdd(true)}
          className="flex items-center gap-2 px-6 py-3 bg-indigo-600 text-white rounded-2xl font-bold shadow-lg shadow-indigo-200 dark:shadow-none hover:bg-indigo-700 active:scale-95 transition-all"
        >
          <Plus className="w-5 h-5" />
          {t.addBill}
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {bills.map(bill => (
          <div key={bill.id} className="bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-100 dark:border-slate-800 shadow-sm relative group overflow-hidden transition-colors">
            <div className="absolute top-0 left-0 w-2 h-full bg-indigo-500 opacity-20 group-hover:opacity-100 transition-all" />
            <div className="flex justify-between items-start mb-4 pl-2">
              <div>
                <h3 className="font-black text-slate-800 dark:text-slate-100 text-lg uppercase tracking-tight">{bill.name}</h3>
                <p className="text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest">{t[bill.category as keyof typeof t] || bill.category}</p>
              </div>
              <button 
                onClick={() => handleDelete(bill.id)}
                className="p-2 text-slate-300 dark:text-slate-600 hover:text-rose-500 dark:hover:text-rose-400 hover:bg-rose-50 dark:hover:bg-rose-900/30 rounded-xl transition-all"
              >
                <Trash2 className="w-4 h-4" />
              </button>
            </div>

            <div className="flex items-center gap-6 pl-2">
              <div className="flex flex-col">
                <span className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-1">{t.date}</span>
                <div className="flex items-center gap-2 text-indigo-600 dark:text-indigo-400 font-black">
                  <Calendar className="w-4 h-4" />
                  <span>Day {bill.dueDay} / Month</span>
                </div>
              </div>
              <div className="flex flex-col">
                <span className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-1">Amount</span>
                <div className="flex items-center gap-2 text-slate-800 dark:text-slate-100 font-black">
                  <DollarSign className="w-4 h-4 text-slate-300 dark:text-slate-700" />
                  <span>{formatCurrency(bill.amount)}</span>
                </div>
              </div>
            </div>
          </div>
        ))}

        {bills.length === 0 && (
          <div className="col-span-full py-20 bg-slate-50/50 dark:bg-slate-900/50 rounded-3xl border-2 border-dashed border-slate-200 dark:border-slate-800 flex flex-col items-center justify-center text-slate-400 dark:text-slate-600 gap-4 transition-colors">
             <CreditCard className="w-12 h-12 opacity-10" />
             <p className="font-bold italic">{t.noData}</p>
          </div>
        )}
      </div>

      {showAdd && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 dark:bg-black/70 backdrop-blur-sm">
          <div className="bg-white dark:bg-slate-900 w-full max-w-md rounded-3xl shadow-2xl dark:shadow-none overflow-hidden animate-in zoom-in-95 duration-200 transition-colors">
            <div className="p-6 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between">
              <h3 className="text-xl font-bold text-slate-800 dark:text-slate-100">{t.addBill}</h3>
              <button onClick={() => { setShowAdd(false); resetForm(); }} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full transition-colors">
                <X className="w-6 h-6 text-slate-400 dark:text-slate-500" />
              </button>
            </div>
            <div className="p-6 space-y-4">
              <div>
                <label className="block text-xs font-black text-slate-400 dark:text-slate-500 uppercase mb-2">Category</label>
                <select 
                  className="w-full px-4 py-3 rounded-2xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 focus:ring-2 focus:ring-indigo-500 outline-none font-bold"
                  value={newBill.category || 'others'}
                  onChange={e => handleCategoryChange(e.target.value)}
                >
                  <option value="groceries">{t.groceries}</option>
                  <option value="vegetables">{t.vegetables}</option>
                  <option value="fishEgg">{t.fishEgg}</option>
                  <option value="chicken">{t.chicken}</option>
                  <option value="houseRent">{t.houseRent}</option>
                  <option value="electricity">{t.electricity}</option>
                  <option value="water">{t.water}</option>
                  <option value="travel">{t.travel}</option>
                  <option value="others">{t.others}</option>
                </select>
              </div>

              <div>
                <label className="block text-xs font-black text-slate-400 dark:text-slate-500 uppercase mb-2">Bill Name</label>
                <input 
                  type="text" 
                  className="w-full px-4 py-3 rounded-2xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 focus:ring-2 focus:ring-indigo-500 outline-none font-bold"
                  value={newBill.name || ''}
                  onChange={e => {
                    setNewBill({...newBill, name: e.target.value});
                    setIsNameManuallyEdited(true);
                  }}
                  placeholder="e.g. Internet Bill"
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-black text-slate-400 dark:text-slate-500 uppercase mb-2">Amount</label>
                  <input 
                    type="number" 
                    className="w-full px-4 py-3 rounded-2xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 focus:ring-2 focus:ring-indigo-500 outline-none font-bold"
                    value={newBill.amount ?? ''}
                    onChange={e => setNewBill({...newBill, amount: e.target.value === '' ? undefined : Number(e.target.value)})}
                  />
                </div>
                <div>
                  <label className="block text-xs font-black text-slate-400 dark:text-slate-500 uppercase mb-2">Recurring Due Day</label>
                  <div className="relative">
                    <input 
                      type="date" 
                      className="w-full px-4 py-3 rounded-2xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 focus:ring-2 focus:ring-indigo-500 outline-none font-bold text-sm"
                      value={getDummyDateString(newBill.dueDay)}
                      onChange={e => {
                        const date = new Date(e.target.value);
                        if (!isNaN(date.getTime())) {
                          setNewBill({...newBill, dueDay: date.getDate()});
                        }
                      }}
                    />
                    <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-indigo-500">
                       <span className="text-xs font-black">Day {newBill.dueDay}</span>
                    </div>
                  </div>
                </div>
              </div>

              <button 
                onClick={handleSave}
                className="w-full bg-indigo-600 text-white py-4 rounded-2xl font-bold shadow-lg shadow-indigo-200 dark:shadow-none hover:bg-indigo-700 mt-4 transition-all"
              >
                {t.save}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default BillManager;

import React, { useState } from 'react';
import { MonthlyBudget } from '../types';

interface BudgetManagerProps {
  t: any;
  month: string;
  initialLimits: MonthlyBudget['limits'];
  onSubmit: (limits: MonthlyBudget['limits']) => void;
}

const BudgetManager: React.FC<BudgetManagerProps> = ({ t, month, initialLimits, onSubmit }) => {
  const [limits, setLimits] = useState(initialLimits);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setLimits(prev => ({
      ...prev,
      [name]: value === '' ? 0 : parseFloat(value)
    }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit(limits);
  };

  const fields = [
    { name: 'groceries', label: t.groceries },
    { name: 'vegetables', label: t.vegetables },
    { name: 'fishEgg', label: t.fishEgg },
    { name: 'chicken', label: t.chicken },
    { name: 'houseRent', label: t.houseRent },
    { name: 'electricity', label: t.electricity },
    { name: 'water', label: t.water },
    { name: 'travel', label: t.travel },
    { name: 'others', label: t.others },
  ];

  return (
    <form onSubmit={handleSubmit} className="flex flex-col h-full">
      <div className="bg-indigo-50 dark:bg-indigo-900/20 p-4 rounded-2xl mb-6 text-center transition-colors">
        <p className="text-[10px] font-black text-indigo-400 dark:text-indigo-500 uppercase tracking-widest mb-1">{t.month}</p>
        <p className="font-bold text-indigo-700 dark:text-indigo-300">{month}</p>
      </div>

      <div className="flex-grow space-y-2 overflow-y-auto pr-1 -mr-1 custom-scrollbar" style={{ maxHeight: 'calc(80vh - 250px)' }}>
        {fields.map(field => (
          <div key={field.name} className="flex items-center justify-between p-3 rounded-2xl bg-slate-50 dark:bg-slate-800/40 border border-slate-100/50 dark:border-slate-700/30 transition-colors">
            <label className="text-xs font-bold text-slate-600 dark:text-slate-400 flex-grow pr-2">
              {field.label}
            </label>
            <div className="relative">
              <input
                type="number"
                name={field.name}
                placeholder="0"
                className="w-24 sm:w-28 px-3 py-2 rounded-xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 focus:ring-2 focus:ring-indigo-500 outline-none transition-all text-right font-black text-indigo-600 dark:text-indigo-400 text-sm"
                value={(limits as any)[field.name] || ''}
                onChange={handleChange}
              />
            </div>
          </div>
        ))}
      </div>

      <div className="pt-6 mt-auto">
        <button
          type="submit"
          className="w-full bg-indigo-600 text-white py-4 rounded-2xl font-bold shadow-lg shadow-indigo-100 dark:shadow-none hover:bg-indigo-700 active:scale-95 transition-all"
        >
          {t.save}
        </button>
      </div>
    </form>
  );
};

export default BudgetManager;

import React, { useState, useMemo, useEffect } from 'react';
import { Transaction, MonthlyBudget, Notification } from '../types';
import TransactionForm from './TransactionForm';
import StatsOverview from './StatsOverview';
import MonthlyCharts from './MonthlyCharts';
import HistoryTable from './HistoryTable';
import BudgetManager from './BudgetManager';
import BudgetPerformance from './BudgetPerformance';
import { Plus, X, Calendar, BarChart3, ClipboardList, ArrowRight, Target, AlertCircle, Clock } from 'lucide-react';
import { storageService } from '../services/googleSheets';

// Fix: Updated activeTab and setActiveTab types to match App.tsx definitions (added 'bills' and 'settings')
interface DashboardProps {
  activeTab: 'dashboard' | 'analytics' | 'history' | 'budget' | 'bills' | 'settings';
  setActiveTab?: (tab: 'dashboard' | 'analytics' | 'history' | 'budget' | 'bills' | 'settings') => void;
  t: any;
  transactions: Transaction[];
  onAdd: (data: Transaction) => void;
  onUpdate: (id: string, data: Transaction) => void;
  onDelete: (id: string) => void;
  onRefresh: () => void;
  isLoading: boolean;
  formatCurrency: (amount: number) => string;
  notifications?: Notification[];
}

const Dashboard: React.FC<DashboardProps> = ({ 
  activeTab, 
  setActiveTab,
  t, 
  transactions, 
  onAdd, 
  onUpdate,
  onDelete,
  onRefresh,
  isLoading,
  formatCurrency,
  notifications = []
}) => {
  const [showAddForm, setShowAddForm] = useState(false);
  const [showBudgetForm, setShowBudgetForm] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [budgets, setBudgets] = useState<MonthlyBudget[]>([]);

  useEffect(() => {
    const loadBudgets = async () => {
      const data = await storageService.fetchBudgets();
      setBudgets(data);
    };
    loadBudgets();
  }, [transactions]);

  const currentMonthName = useMemo(() => {
    return new Date().toLocaleString('en-US', { month: 'long', year: 'numeric' });
  }, []);

  const availableMonths = useMemo(() => {
    const monthsSet = new Set<string>();
    transactions.forEach(tx => {
      if (tx.month) monthsSet.add(tx.month.trim());
    });
    monthsSet.add(currentMonthName);
    return Array.from(monthsSet).sort((a, b) => {
      const dateA = new Date(a);
      const dateB = new Date(b);
      return dateB.getTime() - dateA.getTime();
    });
  }, [transactions, currentMonthName]);

  const [selectedMonth, setSelectedMonth] = useState<string>(availableMonths[0] || currentMonthName);

  const activeBudget = useMemo(() => {
    return budgets.find(b => b.month === selectedMonth) || {
      month: selectedMonth,
      limits: { groceries: 0, vegetables: 0, fishEgg: 0, chicken: 0, houseRent: 0, electricity: 0, water: 0, travel: 0, others: 0 }
    };
  }, [budgets, selectedMonth]);

  const currentMonthTransactions = useMemo(() => {
    return transactions.filter(tx => tx.month?.trim() === selectedMonth).sort((a, b) => a.date.localeCompare(b.date));
  }, [transactions, selectedMonth]);

  const upcomingBillAlerts = useMemo(() => {
    return notifications
      .filter(n => n.type === 'bill' && !n.read)
      .sort((a, b) => {
        const priorityMap = { high: 0, medium: 1, low: 2 };
        return (priorityMap[a.priority] || 3) - (priorityMap[b.priority] || 3);
      })
      .slice(0, 3);
  }, [notifications]);

  const categorySpending = useMemo(() => {
    const totals = { groceries: 0, vegetables: 0, fishEgg: 0, chicken: 0, houseRent: 0, electricity: 0, water: 0, travel: 0, others: 0 };
    currentMonthTransactions.forEach(tx => {
      totals.groceries += tx.groceries;
      totals.vegetables += tx.vegetables;
      totals.fishEgg += tx.fishEgg;
      totals.chicken += tx.chicken;
      totals.houseRent += tx.houseRent;
      totals.electricity += tx.electricity;
      totals.water += tx.water;
      totals.travel += tx.travel;
      totals.others += tx.others;
    });
    return totals;
  }, [currentMonthTransactions]);

  const filteredStats = useMemo(() => {
    const totalSpent = currentMonthTransactions.reduce((sum, tx) => sum + (Number(tx.totalExpenses) || 0), 0);
    const totalReceived = currentMonthTransactions.reduce((sum, tx) => sum + (Number(tx.dailyCash) || 0), 0);
    const lastBalance = currentMonthTransactions.length > 0 ? (Number(currentMonthTransactions[currentMonthTransactions.length - 1].totalBalance) || 0) : 0;
    return { totalSpent, totalReceived, lastBalance };
  }, [currentMonthTransactions]);

  const handleEdit = (tx: Transaction) => {
    setEditingTransaction(tx);
    setShowAddForm(true);
  };

  const handleSaveBudget = async (limits: MonthlyBudget['limits']) => {
    await storageService.saveBudget(selectedMonth, limits);
    const updated = await storageService.fetchBudgets();
    setBudgets(updated);
    setShowBudgetForm(false);
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row items-center justify-between gap-4 bg-white dark:bg-slate-900 p-4 rounded-3xl border border-slate-100 dark:border-slate-800 shadow-sm no-print transition-colors">
        <div className="flex items-center gap-3 w-full sm:w-auto">
          <div className="p-2 bg-indigo-50 dark:bg-indigo-900/30 rounded-xl">
            <Calendar className="w-5 h-5 text-indigo-600 dark:text-indigo-400" />
          </div>
          <div className="flex-grow">
            <h2 className="text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest leading-none mb-1">{t.selectMonth}</h2>
            <select 
              value={selectedMonth}
              onChange={(e) => setSelectedMonth(e.target.value)}
              className="bg-transparent font-bold text-lg text-slate-800 dark:text-slate-100 outline-none cursor-pointer hover:text-indigo-600 dark:hover:text-indigo-400 transition-colors"
            >
              {availableMonths.map(m => (
                <option key={m} value={m} className="bg-white dark:bg-slate-900">{m}</option>
              ))}
            </select>
          </div>
        </div>

        <div className="flex items-center gap-2 w-full sm:w-auto">
          <button 
            onClick={() => setShowBudgetForm(true)}
            className="flex-1 sm:flex-none flex items-center justify-center gap-2 px-4 py-3 bg-white dark:bg-slate-900 text-indigo-600 dark:text-indigo-400 rounded-2xl font-bold hover:bg-indigo-50 dark:hover:bg-indigo-900/20 transition-all border border-indigo-100 dark:border-indigo-900 shadow-sm active:scale-95"
          >
            <Target className="w-5 h-5" />
            <span className="sm:inline">{t.manageBudget}</span>
          </button>
          <button 
            onClick={() => setShowAddForm(true)}
            className="flex-1 sm:flex-none bg-indigo-600 text-white px-6 py-3 rounded-2xl font-bold flex items-center justify-center gap-2 shadow-lg shadow-indigo-200 dark:shadow-none hover:bg-indigo-700 active:scale-95 transition-all"
          >
            <Plus className="w-5 h-5" />
            <span className="sm:inline">{t.addRecord}</span>
          </button>
        </div>
      </div>

      {activeTab === 'dashboard' && (
        <>
          {/* Upcoming Bills Alert Bar */}
          {upcomingBillAlerts.length > 0 && (
            <div className="animate-in slide-in-from-top-4 duration-500">
              <div className="bg-indigo-600 text-white p-4 rounded-3xl shadow-xl shadow-indigo-200 dark:shadow-none flex flex-col md:flex-row items-center justify-between gap-4 overflow-hidden relative">
                <div className="absolute top-0 right-0 p-4 opacity-10">
                  <Clock className="w-24 h-24 rotate-12" />
                </div>
                <div className="flex items-center gap-4 relative z-10">
                  <div className="p-3 bg-white/20 rounded-2xl">
                    <Calendar className="w-6 h-6" />
                  </div>
                  <div>
                    <h3 className="font-black text-lg leading-tight uppercase tracking-tight">{t.dueSoon}</h3>
                    <div className="flex flex-wrap gap-x-4 gap-y-1">
                      {upcomingBillAlerts.map((n, i) => (
                        <span key={n.id} className="text-sm font-medium flex items-center gap-1.5 text-white/90">
                          <span className={`w-2 h-2 rounded-full ${n.priority === 'high' ? 'bg-rose-400 animate-pulse' : (n.priority === 'medium' ? 'bg-amber-400' : 'bg-sky-400')}`} />
                          {n.title}: {n.message}
                        </span>
                      ))}
                    </div>
                  </div>
                </div>
                <button 
                   onClick={() => setActiveTab?.('bills')}
                   className="relative z-10 bg-white/20 hover:bg-white/30 text-white px-4 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all backdrop-blur-sm"
                >
                  Manage Bills
                </button>
              </div>
            </div>
          )}

          <StatsOverview t={t} stats={filteredStats} formatCurrency={formatCurrency} />

          <div className="mt-8 bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-100 dark:border-slate-800 shadow-sm transition-colors">
            <div className="flex items-center justify-between mb-6">
               <div className="flex items-center gap-3">
                 <div className="p-2 bg-emerald-50 dark:bg-emerald-900/20 rounded-xl text-emerald-600 dark:text-emerald-400">
                    <Target className="w-6 h-6" />
                 </div>
                 <h2 className="text-xl font-bold text-slate-800 dark:text-slate-100">{t.budgetStatus}</h2>
               </div>
               <div className="text-[10px] text-slate-400 dark:text-slate-500 font-black uppercase tracking-widest">{selectedMonth}</div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-x-8 gap-y-6">
              {[
                { key: 'groceries', label: t.groceries },
                { key: 'vegetables', label: t.vegetables },
                { key: 'fishEgg', label: t.fishEgg },
                { key: 'chicken', label: t.chicken },
                { key: 'houseRent', label: t.houseRent },
                { key: 'electricity', label: t.electricity },
                { key: 'water', label: t.water },
                { key: 'travel', label: t.travel },
                { key: 'others', label: t.others },
              ].map(({ key, label }) => {
                const limit = (activeBudget.limits as any)[key] || 0;
                const spent = (categorySpending as any)[key] || 0;
                const percent = limit > 0 ? (spent / limit) * 100 : 0;
                const remaining = limit - spent;

                let barColor = "bg-indigo-500";
                if (percent >= 100) barColor = "bg-rose-500";
                else if (percent >= 80) barColor = "bg-amber-500";

                return (
                  <div key={key} className="space-y-2">
                    <div className="flex justify-between items-end gap-2">
                      <span className="text-xs font-bold text-slate-700 dark:text-slate-300 truncate">{label}</span>
                      <div className="text-right shrink-0">
                        <span className={`text-[10px] font-black uppercase tracking-tighter ${percent > 100 ? 'text-rose-500' : 'text-slate-400 dark:text-slate-500'}`}>
                          {formatCurrency(spent)} / {limit > 0 ? formatCurrency(limit) : '---'}
                        </span>
                      </div>
                    </div>
                    <div className="h-2 w-full bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden transition-colors">
                      <div 
                        className={`h-full transition-all duration-500 ${barColor}`} 
                        style={{ width: `${Math.min(percent, 100)}%` }}
                      ></div>
                    </div>
                    <div className="flex justify-between text-[10px] font-black uppercase tracking-tight">
                       {limit > 0 ? (
                         remaining >= 0 ? (
                           <span className="text-emerald-500 dark:text-emerald-400 truncate">{t.remaining}: {formatCurrency(remaining)}</span>
                         ) : (
                           <span className="text-rose-500 flex items-center gap-1 truncate">
                             <AlertCircle className="w-3 h-3" />
                             {t.overspent}: {formatCurrency(Math.abs(remaining))}
                           </span>
                         )
                       ) : (
                         <span className="text-slate-300 dark:text-slate-700">Not set</span>
                       )}
                       <span className="text-slate-400 dark:text-slate-500 ml-2">{Math.round(percent)}%</span>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>

          <div className="mt-8 bg-white dark:bg-slate-900 rounded-3xl border border-slate-100 dark:border-slate-800 shadow-sm overflow-hidden transition-colors">
            <div className="p-6 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between">
              <div className="flex items-center gap-3">
                <ClipboardList className="w-6 h-6 text-indigo-600 dark:text-indigo-400" />
                <h2 className="text-xl font-bold text-slate-800 dark:text-slate-100">{t.recentTransactions}</h2>
              </div>
              <button 
                onClick={() => setActiveTab?.('history')}
                className="flex items-center gap-1 text-sm font-bold text-indigo-600 dark:text-indigo-400 hover:text-indigo-700 dark:hover:text-indigo-300 transition-colors"
              >
                {t.viewAll}
                <ArrowRight className="w-4 h-4" />
              </button>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full text-left min-w-[800px]">
                <thead>
                  <tr className="bg-slate-50 dark:bg-slate-800/50 text-slate-500 dark:text-slate-400 text-[10px] uppercase font-black tracking-widest border-b border-slate-100 dark:border-slate-800">
                    <th className="px-6 py-4">{t.date}</th>
                    <th className="px-6 py-4">{t.month}</th>
                    <th className="px-6 py-4">{t.dailyCash}</th>
                    <th className="px-6 py-4">{t.totalExpenses}</th>
                    <th className="px-6 py-4 bg-indigo-50/30 dark:bg-indigo-900/10 text-indigo-700 dark:text-indigo-400">{t.totalBalance}</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                  {transactions.slice().reverse().slice(0, 5).map((tx) => (
                    <tr key={tx.id || tx.timestamp} className="hover:bg-slate-50/50 dark:hover:bg-slate-800/50 transition-colors">
                      <td className="px-6 py-4 text-sm font-semibold text-slate-700 dark:text-slate-300">{tx.date.split('-').reverse().join('/')}</td>
                      <td className="px-6 py-4 text-xs font-medium text-slate-400 dark:text-slate-500">{tx.month}</td>
                      <td className="px-6 py-4 text-sm font-bold text-emerald-600 dark:text-emerald-400">{formatCurrency(Number(tx.dailyCash))}</td>
                      <td className="px-6 py-4 text-sm font-bold text-rose-500 dark:text-rose-400">{formatCurrency(Number(tx.totalExpenses))}</td>
                      <td className="px-6 py-4 text-sm font-black text-indigo-600 dark:text-indigo-400 bg-indigo-50/20 dark:bg-indigo-900/5">{formatCurrency(Number(tx.totalBalance))}</td>
                    </tr>
                  ))}
                  {transactions.length === 0 && (
                    <tr>
                      <td colSpan={5} className="px-6 py-12 text-center text-slate-400 dark:text-slate-600 font-medium italic">{t.noData}</td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </>
      )}

      {activeTab === 'analytics' && (
        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div>
            <div className="flex items-center justify-between mb-6">
              <div className="flex items-center gap-3">
                <div className="p-2 bg-indigo-100 dark:bg-indigo-900/30 rounded-xl">
                  <BarChart3 className="w-6 h-6 text-indigo-700 dark:text-indigo-400" />
                </div>
                <h2 className="text-2xl font-black text-slate-800 dark:text-slate-100">{t.charts} - {selectedMonth}</h2>
              </div>
            </div>
            <MonthlyCharts t={t} transactions={currentMonthTransactions} />
          </div>
        </div>
      )}

      {activeTab === 'budget' && (
        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
          <BudgetPerformance 
            t={t} 
            transactions={transactions} 
            budgets={budgets} 
            formatCurrency={formatCurrency}
          />
        </div>
      )}

      {activeTab === 'history' && (
        <div className="bg-white dark:bg-slate-900 rounded-3xl shadow-sm border border-slate-100 dark:border-slate-800 overflow-hidden animate-in fade-in slide-in-from-bottom-4 duration-500 transition-colors">
          <div className="p-6 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between no-print">
            <h2 className="text-xl font-bold text-slate-800 dark:text-slate-100">{t.history} ({selectedMonth})</h2>
          </div>
          <HistoryTable 
            t={t} 
            transactions={transactions.filter(tx => tx.month?.trim() === selectedMonth)} 
            allTransactions={transactions}
            onEdit={handleEdit} 
            onDelete={onDelete} 
            isLoading={isLoading} 
            formatCurrency={formatCurrency}
          />
        </div>
      )}

      {showAddForm && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 dark:bg-black/70 backdrop-blur-sm no-print">
          <div className="bg-white dark:bg-slate-900 w-full max-w-2xl rounded-3xl shadow-2xl dark:shadow-none overflow-hidden max-h-[90vh] flex flex-col scale-in-center transition-colors">
            <div className="p-6 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between">
              <h3 className="text-xl font-bold text-slate-800 dark:text-slate-100">
                {editingTransaction ? t.edit : t.addRecord}
              </h3>
              <button 
                onClick={() => { setShowAddForm(false); setEditingTransaction(null); }}
                className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full transition-colors"
              >
                <X className="w-6 h-6 text-slate-400 dark:text-slate-500" />
              </button>
            </div>
            <div className="p-6 overflow-y-auto">
              <TransactionForm 
                t={t} 
                initialData={editingTransaction}
                formatCurrency={formatCurrency}
                onSubmit={(data) => {
                  if (editingTransaction?.id) {
                    onUpdate(editingTransaction.id, data);
                  } else {
                    onAdd(data);
                  }
                  setShowAddForm(false);
                  setEditingTransaction(null);
                }} 
              />
            </div>
          </div>
        </div>
      )}

      {showBudgetForm && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 dark:bg-black/70 backdrop-blur-sm no-print">
          <div className="bg-white dark:bg-slate-900 w-full max-w-lg rounded-3xl shadow-2xl dark:shadow-none overflow-hidden flex flex-col scale-in-center transition-colors max-h-[95vh]">
            <div className="p-6 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between shrink-0">
              <h3 className="text-xl font-bold text-slate-800 dark:text-slate-100">{t.manageBudget}</h3>
              <button 
                onClick={() => setShowBudgetForm(false)}
                className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full transition-colors"
              >
                <X className="w-6 h-6 text-slate-400 dark:text-slate-500" />
              </button>
            </div>
            <div className="p-4 md:p-6 overflow-y-auto">
              <BudgetManager 
                t={t} 
                month={selectedMonth} 
                initialLimits={activeBudget.limits} 
                onSubmit={handleSaveBudget} 
              />
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { Transaction, Language, CurrencySettings, Notification, MonthlyBudget, Bill } from './types';
import { translations } from './translations';
import { storageService } from './services/googleSheets';
import Dashboard from './components/Dashboard';
import SettingsPage from './components/SettingsPage';
import NotificationDrawer from './components/NotificationDrawer';
import BillManager from './components/BillManager';
import { Globe, Wallet, LayoutDashboard, History, BarChart3, Target, Settings, Bell, CreditCard, Sun, Moon } from 'lucide-react';

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>('en');
  const [isDark, setIsDark] = useState(() => localStorage.getItem('theme') === 'dark');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'analytics' | 'history' | 'budget' | 'settings' | 'bills'>('dashboard');
  const [isLoading, setIsLoading] = useState(false);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [isNotificationOpen, setIsNotificationOpen] = useState(false);
  const [currencySettings, setCurrencySettings] = useState<CurrencySettings>({
    symbol: 'LKR',
    position: 'before'
  });

  const t = translations[lang];

  useEffect(() => {
    if (isDark) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [isDark]);

  const formatCurrency = useCallback((amount: number) => {
    const formattedAmount = amount.toLocaleString();
    return currencySettings.position === 'before' 
      ? `${currencySettings.symbol} ${formattedAmount}`
      : `${formattedAmount} ${currencySettings.symbol}`;
  }, [currencySettings]);

  const generateNotifications = useCallback(async (txs: Transaction[]) => {
    const budgets = await storageService.fetchBudgets();
    const bills = await storageService.fetchBills();
    const now = new Date();
    const currentMonthLabel = now.toLocaleString('en-US', { month: 'long', year: 'numeric' });
    const currentMonthTxs = txs.filter(tx => tx.month === currentMonthLabel);
    const budget = budgets.find(b => b.month === currentMonthLabel);
    const newNotifications: Notification[] = [];

    // 1. Budget Alerts
    if (budget) {
      const categories = ['groceries', 'vegetables', 'fishEgg', 'chicken', 'houseRent', 'electricity', 'water', 'travel', 'others'];
      categories.forEach(cat => {
        const limit = (budget.limits as any)[cat];
        const spent = currentMonthTxs.reduce((sum, tx) => sum + ((tx as any)[cat] || 0), 0);
        if (limit > 0 && spent / limit >= 0.85) {
          newNotifications.push({
            id: `budget-${cat}-${currentMonthLabel}`,
            type: 'budget',
            title: t.lowBudgetAlert,
            message: t.lowBudgetMsg.replace('{percent}', Math.round((spent/limit)*100).toString()).replace('{category}', (t as any)[cat]),
            timestamp: now.toISOString(),
            read: false,
            priority: spent >= limit ? 'high' : 'medium'
          });
        }
      });
    }

    // 2. Bill Due Date System (7-Day Prioritized Lookahead)
    bills.forEach(bill => {
      const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
      let dueDate = new Date(now.getFullYear(), now.getMonth(), bill.dueDay);

      // Target next month if day has passed
      if (dueDate < today) {
        dueDate = new Date(now.getFullYear(), now.getMonth() + 1, bill.dueDay);
      }

      const diffTime = dueDate.getTime() - today.getTime();
      const daysLeft = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

      if (daysLeft >= 0 && daysLeft <= 7) {
        newNotifications.push({
          id: `bill-${bill.id}-${dueDate.toISOString().split('T')[0]}`,
          type: 'bill',
          title: bill.name,
          message: daysLeft === 0 ? t.dueToday : t.billDueIn.replace('{days}', daysLeft.toString()),
          timestamp: now.toISOString(),
          read: false,
          priority: daysLeft === 0 ? 'high' : (daysLeft <= 3 ? 'medium' : 'low')
        });
      }
    });

    setNotifications(prev => {
      const existingIds = new Set(prev.map(n => n.id));
      const added = newNotifications.filter(n => !existingIds.has(n.id));
      // Sort: highest priority and newest first
      return [...added, ...prev]
        .filter(n => {
          // Cleanup logic: If it's a bill notification, ensure it's still relevant
          if (n.type === 'bill') {
            const billId = n.id.split('-')[1];
            return bills.some(b => b.id === billId);
          }
          return true;
        })
        .slice(0, 30);
    });
  }, [t]);

  const loadData = useCallback(async () => {
    setIsLoading(true);
    try {
      const data = await storageService.fetchTransactions();
      setTransactions(data);
      await generateNotifications(data);

      const savedLang = localStorage.getItem('lang');
      if (savedLang) setLang(savedLang as Language);

      const savedCurrency = localStorage.getItem('currency_settings');
      if (savedCurrency) setCurrencySettings(JSON.parse(savedCurrency));
    } catch (err) {
      console.error("Failed to load data", err);
    } finally {
      setIsLoading(false);
    }
  }, [generateNotifications]);

  const onAddTransaction = useCallback(async (data: Transaction) => {
    await storageService.addTransaction(data);
    loadData();
  }, [loadData]);

  const onUpdateTransaction = useCallback(async (id: string, data: Transaction) => {
    await storageService.updateTransaction(id, data);
    loadData();
  }, [loadData]);

  const onDeleteTransaction = useCallback(async (id: string) => {
    if (window.confirm(t.confirmDelete)) {
      await storageService.deleteTransaction(id);
      loadData();
    }
  }, [loadData, t.confirmDelete]);

  useEffect(() => {
    loadData();
  }, [loadData]);

  const unreadCount = useMemo(() => notifications.filter(n => !n.read).length, [notifications]);

  return (
    <div className="min-h-screen bg-slate-50 dark:bg-slate-950 pb-20 md:pb-0 font-sans transition-colors duration-300">
      <nav className="hidden md:flex flex-col fixed h-full w-64 bg-white dark:bg-slate-900 border-r border-slate-200 dark:border-slate-800 p-6 z-20 no-print transition-colors">
        <div className="flex items-center gap-3 mb-10">
          <div className="p-2 bg-indigo-600 rounded-xl shadow-lg shadow-indigo-200 dark:shadow-none">
            <Wallet className="w-6 h-6 text-white" />
          </div>
          <h1 className="font-bold text-lg text-slate-800 dark:text-slate-100 leading-tight">{t.title}</h1>
        </div>

        <div className="space-y-2 flex-grow">
          {[
            { id: 'dashboard', label: t.dashboard, icon: LayoutDashboard },
            { id: 'analytics', label: t.charts, icon: BarChart3 },
            { id: 'budget', label: t.budgetPerformance, icon: Target },
            { id: 'bills', label: t.bills, icon: CreditCard },
            { id: 'history', label: t.history, icon: History },
          ].map(tab => (
            <button 
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium transition-all ${activeTab === tab.id ? 'bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400 shadow-sm' : 'text-slate-500 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800 hover:text-slate-800 dark:hover:text-slate-200'}`}
            >
              <tab.icon className="w-5 h-5" />
              {tab.label}
            </button>
          ))}
        </div>

        <div className="mt-auto space-y-2 border-t border-slate-100 dark:border-slate-800 pt-6">
          <button 
            onClick={() => setIsDark(!isDark)}
            className="w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium text-slate-500 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800 transition-all"
          >
            {isDark ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
            {isDark ? t.lightMode : t.darkMode}
          </button>
          <button 
            onClick={() => setActiveTab('settings')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium transition-all ${activeTab === 'settings' ? 'bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400 shadow-sm' : 'text-slate-500 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800 hover:text-slate-800 dark:hover:text-slate-200'}`}
          >
            <Settings className="w-5 h-5" />
            {t.settings}
          </button>
          <button onClick={() => setLang(lang === 'en' ? 'si' : 'en')} className="w-full flex items-center gap-3 px-4 py-3 text-slate-500 dark:text-slate-400 hover:text-indigo-600 dark:hover:text-indigo-400 font-medium transition-colors">
            <Globe className="w-5 h-5" />
            {t.language}
          </button>
        </div>
      </nav>

      <header className="md:hidden bg-white dark:bg-slate-900 border-b border-slate-200 dark:border-slate-800 px-4 py-3 flex items-center justify-between sticky top-0 z-30 no-print transition-colors">
        <div className="flex items-center gap-2">
          <Wallet className="w-6 h-6 text-indigo-600 dark:text-indigo-400" />
          <h1 className="font-bold text-sm text-slate-800 dark:text-slate-100">{t.title}</h1>
        </div>
        <div className="flex items-center gap-2">
          <button onClick={() => setIsNotificationOpen(true)} className="p-2 relative text-slate-500 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-lg">
            <Bell className="w-5 h-5" />
            {unreadCount > 0 && <span className="absolute top-1 right-1 w-2 h-2 bg-rose-500 rounded-full"></span>}
          </button>
          <button onClick={() => setIsDark(!isDark)} className="p-2 text-slate-500 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-lg">
            {isDark ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
          </button>
          <button onClick={() => setActiveTab('settings')} className="p-2 text-slate-500 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-lg"><Settings className="w-5 h-5"/></button>
        </div>
      </header>

      <div className="hidden md:block fixed top-6 right-6 z-40 no-print">
        <button 
          onClick={() => setIsNotificationOpen(true)}
          className="bg-white dark:bg-slate-900 p-3 rounded-2xl border border-slate-100 dark:border-slate-800 shadow-xl dark:shadow-none hover:bg-slate-50 dark:hover:bg-slate-800 transition-all relative group"
        >
          <Bell className="w-6 h-6 text-slate-600 dark:text-slate-300 group-hover:text-indigo-600 dark:group-hover:text-indigo-400" />
          {unreadCount > 0 && (
            <span className="absolute -top-1 -right-1 bg-rose-500 text-white text-[10px] font-black h-5 w-5 flex items-center justify-center rounded-full border-2 border-white dark:border-slate-900">
              {unreadCount}
            </span>
          )}
        </button>
      </div>

      <main className="md:pl-64 min-h-screen">
        <div className="max-w-6xl mx-auto p-4 md:p-8">
          {activeTab === 'settings' && (
            <SettingsPage 
              t={t} 
              settings={currencySettings} 
              isDark={isDark}
              onToggleDark={() => setIsDark(!isDark)}
              onSave={(s) => { setCurrencySettings(s); localStorage.setItem('currency_settings', JSON.stringify(s)); }} 
            />
          )}
          {activeTab === 'bills' && <BillManager t={t} formatCurrency={formatCurrency} transactions={transactions} onRefresh={loadData} />}
          {activeTab !== 'settings' && activeTab !== 'bills' && (
            <Dashboard 
              activeTab={activeTab} 
              setActiveTab={setActiveTab}
              t={t} 
              transactions={transactions} 
              onAdd={onAddTransaction}
              onUpdate={onUpdateTransaction}
              onDelete={onDeleteTransaction}
              onRefresh={loadData}
              isLoading={isLoading}
              formatCurrency={formatCurrency}
              notifications={notifications}
            />
          )}
        </div>
      </main>

      <NotificationDrawer 
        isOpen={isNotificationOpen} 
        onClose={() => setIsNotificationOpen(false)} 
        notifications={notifications}
        onRead={(id) => setNotifications(prev => prev.map(n => n.id === id ? {...n, read: true} : n))}
        onReadAll={() => setNotifications(prev => prev.map(n => ({...n, read: true})))}
        t={t}
      />

      <nav className="md:hidden fixed bottom-0 left-0 right-0 bg-white dark:bg-slate-900 border-t border-slate-200 dark:border-slate-800 flex items-center justify-around p-3 z-30 shadow-[0_-4px_12px_rgba(0,0,0,0.05)] no-print transition-colors">
        {[
          { id: 'dashboard', icon: LayoutDashboard },
          { id: 'analytics', icon: BarChart3 },
          { id: 'budget', icon: Target },
          { id: 'bills', icon: CreditCard },
          { id: 'history', icon: History },
        ].map(tab => (
          <button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`flex flex-col items-center gap-1 transition-colors ${activeTab === tab.id ? 'text-indigo-600 dark:text-indigo-400' : 'text-slate-400 dark:text-slate-600'}`}>
            <tab.icon className="w-6 h-6" />
          </button>
        ))}
      </nav>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { Bill, Transaction } from '../types';
import { storageService } from '../services/googleSheets';
import { Plus, CreditCard, Trash2, Calendar, DollarSign, X, TrendingUp, ReceiptText } from 'lucide-react';

interface BillManagerProps {
  t: any;
  formatCurrency: (amount: number) => string;
  transactions: Transaction[];
  onRefresh?: () => void;
}

const BillManager: React.FC<BillManagerProps> = ({ t, formatCurrency, transactions, onRefresh }) => {
  const [bills, setBills] = useState<Bill[]>([]);
  const [showAdd, setShowAdd] = useState(false);
  const [newBill, setNewBill] = useState<Partial<Bill>>({ dueDay: new Date().getDate(), category: 'others' });
  const [isNameManuallyEdited, setIsNameManuallyEdited] = useState(false);

  useEffect(() => {
    storageService.fetchBills().then(setBills);
  }, []);

  const currentMonthLabel = useMemo(() => {
    return new Date().toLocaleString('en-US', { month: 'long', year: 'numeric' });
  }, []);

  const monthlySpendingSummary = useMemo(() => {
    const currentMonthTxs = transactions.filter(tx => tx.month === currentMonthLabel);

    // Aggregating actual spending by category
    const actualByCategory: Record<string, number> = {
      groceries: 0, vegetables: 0, fishEgg: 0, chicken: 0,
      houseRent: 0, electricity: 0, water: 0, travel: 0, others: 0
    };

    currentMonthTxs.forEach(tx => {
      Object.keys(actualByCategory).forEach(cat => {
        actualByCategory[cat] += (tx as any)[cat] || 0;
      });
    });

    // Aggregating bill estimates by category
    const billEstimatesByCategory: Record<string, number> = {
      groceries: 0, vegetables: 0, fishEgg: 0, chicken: 0,
      houseRent: 0, electricity: 0, water: 0, travel: 0, others: 0
    };

    bills.forEach(bill => {
      if (billEstimatesByCategory[bill.category] !== undefined) {
        billEstimatesByCategory[bill.category] += bill.amount;
      } else {
        billEstimatesByCategory.others += bill.amount;
      }
    });

    return Object.keys(actualByCategory)
      .map(cat => ({
        category: cat,
        label: t[cat as keyof typeof t] || cat,
        actual: actualByCategory[cat],
        estimate: billEstimatesByCategory[cat]
      }))
      .filter(item => item.actual > 0 || item.estimate > 0)
      .sort((a, b) => b.actual - a.actual);
  }, [transactions, bills, currentMonthLabel, t]);

  const handleCategoryChange = (category: string) => {
    const updates: Partial<Bill> = { category };

    // Auto-fill name if not manually edited or if name is empty
    if (!isNameManuallyEdited || !newBill.name) {
      updates.name = t[category as keyof typeof t] || category;
    }

    setNewBill(prev => ({ ...prev, ...updates }));
  };

  const handleSave = async () => {
    if (!newBill.name || !newBill.amount) return;
    const bill: Bill = {
      id: crypto.randomUUID(),
      name: newBill.name,
      amount: Number(newBill.amount),
      dueDay: Number(newBill.dueDay),
      category: newBill.category || 'others'
    };
    await storageService.saveBill(bill);
    setBills([...bills, bill]);
    setShowAdd(false);
    resetForm();
    if (onRefresh) onRefresh();
  };

  const resetForm = () => {
    setNewBill({ dueDay: new Date().getDate(), category: 'others' });
    setIsNameManuallyEdited(false);
  };

  const handleDelete = async (id: string) => {
    if (window.confirm(t.confirmDelete)) {
      await storageService.deleteBill(id);
      setBills(bills.filter(b => b.id !== id));
      if (onRefresh) onRefresh();
    }
  };

  // Helper to format the current month's "due date" for the date picker input
  const getDummyDateString = (day: number = 1) => {
    const now = new Date();
    const date = new Date(now.getFullYear(), now.getMonth(), day);
    return date.toISOString().split('T')[0];
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      {/* Page Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-indigo-100 dark:bg-indigo-900/30 rounded-xl">
            <CreditCard className="w-6 h-6 text-indigo-700 dark:text-indigo-400" />
          </div>
          <h2 className="text-2xl font-black text-slate-800 dark:text-slate-100">{t.bills}</h2>
        </div>
        <button 
          onClick={() => setShowAdd(true)}
          className="flex items-center gap-2 px-6 py-3 bg-indigo-600 text-white rounded-2xl font-bold shadow-lg shadow-indigo-200 dark:shadow-none hover:bg-indigo-700 active:scale-95 transition-all"
        >
          <Plus className="w-5 h-5" />
          {t.addBill}
        </button>
      </div>

      {/* Monthly Spending Section */}
      <div className="bg-white dark:bg-slate-900 rounded-3xl border border-slate-100 dark:border-slate-800 p-6 shadow-sm overflow-hidden transition-colors">
        <div className="flex items-center gap-3 mb-6">
          <div className="p-2 bg-emerald-100 dark:bg-emerald-900/30 rounded-xl">
            <TrendingUp className="w-5 h-5 text-emerald-600 dark:text-emerald-400" />
          </div>
          <div>
            <h3 className="text-lg font-bold text-slate-800 dark:text-slate-100">Monthly Spending Summary</h3>
            <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">{currentMonthLabel}</p>
          </div>
        </div>

        {monthlySpendingSummary.length > 0 ? (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
            {monthlySpendingSummary.map(item => (
              <div key={item.category} className="p-4 bg-slate-50 dark:bg-slate-800/40 rounded-2xl border border-slate-100 dark:border-slate-700/30">
                <div className="flex justify-between items-start mb-2">
                  <span className="text-xs font-black uppercase text-slate-400 tracking-wider">{item.label}</span>
                  {item.estimate > 0 && item.actual > item.estimate && (
                    <span className="text-[10px] font-black text-rose-500 bg-rose-50 dark:bg-rose-950/30 px-2 py-0.5 rounded-full">Exceeded Bill</span>
                  )}
                </div>
                <div className="flex items-baseline gap-2 mb-3">
                  <span className="text-xl font-black text-slate-800 dark:text-slate-100">{formatCurrency(item.actual)}</span>
                  {item.estimate > 0 && (
                    <span className="text-xs text-slate-400 font-bold">/ {formatCurrency(item.estimate)}</span>
                  )}
                </div>
                {item.estimate > 0 && (
                  <div className="w-full h-1.5 bg-slate-200 dark:bg-slate-700 rounded-full overflow-hidden">
                    <div 
                      className={`h-full transition-all duration-700 ${item.actual > item.estimate ? 'bg-rose-500' : 'bg-emerald-500'}`}
                      style={{ width: `${Math.min((item.actual / item.estimate) * 100, 100)}%` }}
                    />
                  </div>
                )}
              </div>
            ))}
          </div>
        ) : (
          <div className="py-10 text-center text-slate-400 italic flex flex-col items-center gap-2">
            <ReceiptText className="w-8 h-8 opacity-20" />
            <p>No spending recorded for this month yet.</p>
          </div>
        )}
      </div>

      {/* Bill List Section */}
      <div className="space-y-4">
        <h3 className="text-lg font-bold text-slate-800 dark:text-slate-100 flex items-center gap-2">
          <ReceiptText className="w-5 h-5 text-indigo-600" />
          Scheduled & Recurring
        </h3>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {bills.map(bill => (
            <div key={bill.id} className="bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-100 dark:border-slate-800 shadow-sm relative group overflow-hidden transition-colors">
              <div className="absolute top-0 left-0 w-2 h-full bg-indigo-500 opacity-20 group-hover:opacity-100 transition-all" />
              <div className="flex justify-between items-start mb-4 pl-2">
                <div>
                  <h3 className="font-black text-slate-800 dark:text-slate-100 text-lg uppercase tracking-tight">{bill.name}</h3>
                  <p className="text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest">{t[bill.category as keyof typeof t] || bill.category}</p>
                </div>
                <button 
                  onClick={() => handleDelete(bill.id)}
                  className="p-2 text-slate-300 dark:text-slate-600 hover:text-rose-500 dark:hover:text-rose-400 hover:bg-rose-50 dark:hover:bg-rose-900/30 rounded-xl transition-all"
                >
                  <Trash2 className="w-4 h-4" />
                </button>
              </div>

              <div className="flex items-center gap-6 pl-2">
                <div className="flex flex-col">
                  <span className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-1">{t.date}</span>
                  <div className="flex items-center gap-2 text-indigo-600 dark:text-indigo-400 font-black">
                    <Calendar className="w-4 h-4" />
                    <span>Day {bill.dueDay} / Month</span>
                  </div>
                </div>
                <div className="flex flex-col">
                  <span className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-1">Amount</span>
                  <div className="flex items-center gap-2 text-slate-800 dark:text-slate-100 font-black">
                    <DollarSign className="w-4 h-4 text-slate-300 dark:text-slate-700" />
                    <span>{formatCurrency(bill.amount)}</span>
                  </div>
                </div>
              </div>
            </div>
          ))}

          {bills.length === 0 && (
            <div className="col-span-full py-20 bg-slate-50/50 dark:bg-slate-900/50 rounded-3xl border-2 border-dashed border-slate-200 dark:border-slate-800 flex flex-col items-center justify-center text-slate-400 dark:text-slate-600 gap-4 transition-colors">
               <CreditCard className="w-12 h-12 opacity-10" />
               <p className="font-bold italic">{t.noData}</p>
            </div>
          )}
        </div>
      </div>

      {showAdd && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 dark:bg-black/70 backdrop-blur-sm">
          <div className="bg-white dark:bg-slate-900 w-full max-w-md rounded-3xl shadow-2xl dark:shadow-none overflow-hidden animate-in zoom-in-95 duration-200 transition-colors">
            <div className="p-6 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between">
              <h3 className="text-xl font-bold text-slate-800 dark:text-slate-100">{t.addBill}</h3>
              <button onClick={() => { setShowAdd(false); resetForm(); }} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full transition-colors">
                <X className="w-6 h-6 text-slate-400 dark:text-slate-500" />
              </button>
            </div>
            <div className="p-6 space-y-4">
              <div>
                <label className="block text-xs font-black text-slate-400 dark:text-slate-500 uppercase mb-2">Category</label>
                <select 
                  className="w-full px-4 py-3 rounded-2xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 focus:ring-2 focus:ring-indigo-500 outline-none font-bold"
                  value={newBill.category || 'others'}
                  onChange={e => handleCategoryChange(e.target.value)}
                >
                  <option value="groceries">{t.groceries}</option>
                  <option value="vegetables">{t.vegetables}</option>
                  <option value="fishEgg">{t.fishEgg}</option>
                  <option value="chicken">{t.chicken}</option>
                  <option value="houseRent">{t.houseRent}</option>
                  <option value="electricity">{t.electricity}</option>
                  <option value="water">{t.water}</option>
                  <option value="travel">{t.travel}</option>
                  <option value="others">{t.others}</option>
                </select>
              </div>

              <div>
                <label className="block text-xs font-black text-slate-400 dark:text-slate-500 uppercase mb-2">Bill Name</label>
                <input 
                  type="text" 
                  className="w-full px-4 py-3 rounded-2xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 focus:ring-2 focus:ring-indigo-500 outline-none font-bold"
                  value={newBill.name || ''}
                  onChange={e => {
                    setNewBill({...newBill, name: e.target.value});
                    setIsNameManuallyEdited(true);
                  }}
                  placeholder="e.g. Internet Bill"
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-black text-slate-400 dark:text-slate-500 uppercase mb-2">Amount</label>
                  <input 
                    type="number" 
                    className="w-full px-4 py-3 rounded-2xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 focus:ring-2 focus:ring-indigo-500 outline-none font-bold"
                    value={newBill.amount ?? ''}
                    onChange={e => setNewBill({...newBill, amount: e.target.value === '' ? undefined : Number(e.target.value)})}
                  />
                </div>
                <div>
                  <label className="block text-xs font-black text-slate-400 dark:text-slate-500 uppercase mb-2">Recurring Due Day</label>
                  <div className="relative">
                    <input 
                      type="date" 
                      className="w-full px-4 py-3 rounded-2xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 focus:ring-2 focus:ring-indigo-500 outline-none font-bold text-sm"
                      value={getDummyDateString(newBill.dueDay)}
                      onChange={e => {
                        const date = new Date(e.target.value);
                        if (!isNaN(date.getTime())) {
                          setNewBill({...newBill, dueDay: date.getDate()});
                        }
                      }}
                    />
                    <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-indigo-500">
                       <span className="text-xs font-black">Day {newBill.dueDay}</span>
                    </div>
                  </div>
                </div>
              </div>

              <button 
                onClick={handleSave}
                className="w-full bg-indigo-600 text-white py-4 rounded-2xl font-bold shadow-lg shadow-indigo-200 dark:shadow-none hover:bg-indigo-700 mt-4 transition-all"
              >
                {t.save}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default BillManager;

import React, { useState, useMemo, useEffect } from 'react';
import { Transaction, MonthlyBudget, Notification } from '../types';
import TransactionForm from './TransactionForm';
import StatsOverview from './StatsOverview';
import MonthlyCharts from './MonthlyCharts';
import HistoryTable from './HistoryTable';
import BudgetManager from './BudgetManager';
import BudgetPerformance from './BudgetPerformance';
import { Plus, X, Calendar, BarChart3, ClipboardList, ArrowRight, Target, AlertCircle, Clock } from 'lucide-react';
import { storageService } from '../services/googleSheets';

interface DashboardProps {
  activeTab: 'dashboard' | 'analytics' | 'history' | 'budget' | 'bills' | 'settings';
  setActiveTab?: (tab: 'dashboard' | 'analytics' | 'history' | 'budget' | 'bills' | 'settings') => void;
  t: any;
  transactions: Transaction[];
  onAdd: (data: Transaction) => void;
  onUpdate: (id: string, data: Transaction) => void;
  onDelete: (id: string) => void;
  onRefresh: () => void;
  isLoading: boolean;
  formatCurrency: (amount: number) => string;
  notifications?: Notification[];
}

const Dashboard: React.FC<DashboardProps> = ({ 
  activeTab, 
  setActiveTab,
  t, 
  transactions, 
  onAdd, 
  onUpdate,
  onDelete,
  onRefresh,
  isLoading,
  formatCurrency,
  notifications = []
}) => {
  const [showAddForm, setShowAddForm] = useState(false);
  const [showBudgetForm, setShowBudgetForm] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [budgets, setBudgets] = useState<MonthlyBudget[]>([]);

  useEffect(() => {
    const loadBudgets = async () => {
      const data = await storageService.fetchBudgets();
      setBudgets(data);
    };
    loadBudgets();
  }, [transactions]);

  const currentMonthName = useMemo(() => {
    return new Date().toLocaleString('en-US', { month: 'long', year: 'numeric' });
  }, []);

  const availableMonths = useMemo(() => {
    const monthsSet = new Set<string>();
    transactions.forEach(tx => {
      if (tx.month) monthsSet.add(tx.month.trim());
    });
    monthsSet.add(currentMonthName);
    return Array.from(monthsSet).sort((a, b) => {
      const dateA = new Date(a);
      const dateB = new Date(b);
      return dateB.getTime() - dateA.getTime();
    });
  }, [transactions, currentMonthName]);

  const [selectedMonth, setSelectedMonth] = useState<string>(availableMonths[0] || currentMonthName);

  const activeBudget = useMemo(() => {
    return budgets.find(b => b.month === selectedMonth) || {
      month: selectedMonth,
      limits: { groceries: 0, vegetables: 0, fishEgg: 0, chicken: 0, houseRent: 0, electricity: 0, water: 0, travel: 0, others: 0 }
    };
  }, [budgets, selectedMonth]);

  const currentMonthTransactions = useMemo(() => {
    return transactions.filter(tx => tx.month?.trim() === selectedMonth).sort((a, b) => a.date.localeCompare(b.date));
  }, [transactions, selectedMonth]);

  const categorySpending = useMemo(() => {
    const totals = { groceries: 0, vegetables: 0, fishEgg: 0, chicken: 0, houseRent: 0, electricity: 0, water: 0, travel: 0, others: 0 };
    currentMonthTransactions.forEach(tx => {
      totals.groceries += Number(tx.groceries) || 0;
      totals.vegetables += Number(tx.vegetables) || 0;
      totals.fishEgg += Number(tx.fishEgg) || 0;
      totals.chicken += Number(tx.chicken) || 0;
      totals.houseRent += Number(tx.houseRent) || 0;
      totals.electricity += Number(tx.electricity) || 0;
      totals.water += Number(tx.water) || 0;
      totals.travel += Number(tx.travel) || 0;
      totals.others += Number(tx.others) || 0;
    });
    return totals;
  }, [currentMonthTransactions]);

  const filteredStats = useMemo(() => {
    // Sort transactions by date to correctly identify the starting record of the month
    const sorted = [...currentMonthTransactions].sort((a, b) => a.date.localeCompare(b.date));

    // Total Expenses: Simple sum of the totalExpenses column
    const totalSpent = currentMonthTransactions.reduce((sum, tx) => sum + (Number(tx.totalExpenses) || 0), 0);

    // Total Income: Initial Brought Forward + sum of all Daily Cash received this month
    const firstTx = sorted[0];
    const initialBF = firstTx ? (Number(firstTx.broughtForward) || 0) : 0;
    const totalDailyCash = currentMonthTransactions.reduce((sum, tx) => sum + (Number(tx.dailyCash) || 0), 0);
    const totalIncome = initialBF + totalDailyCash;

    // Current Balance: The balance field from the most recent transaction
    const lastBalance = sorted.length > 0 ? (Number(sorted[sorted.length - 1].totalBalance) || 0) : 0;

    return { totalSpent, totalReceived: totalIncome, lastBalance };
  }, [currentMonthTransactions]);

  const handleEdit = (tx: Transaction) => {
    setEditingTransaction(tx);
    setShowAddForm(true);
  };

  const handleSaveBudget = async (limits: MonthlyBudget['limits']) => {
    await storageService.saveBudget(selectedMonth, limits);
    const updated = await storageService.fetchBudgets();
    setBudgets(updated);
    setShowBudgetForm(false);
  };

  const upcomingBillAlerts = useMemo(() => {
    return notifications
      .filter(n => n.type === 'bill' && !n.read)
      .sort((a, b) => {
        const priorityMap = { high: 0, medium: 1, low: 2 };
        return (priorityMap[a.priority] || 3) - (priorityMap[b.priority] || 3);
      })
      .slice(0, 3);
  }, [notifications]);

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row items-center justify-between gap-4 bg-white dark:bg-slate-900 p-4 rounded-3xl border border-slate-100 dark:border-slate-800 shadow-sm no-print transition-colors">
        <div className="flex items-center gap-3 w-full sm:w-auto">
          <div className="p-2 bg-indigo-50 dark:bg-indigo-900/30 rounded-xl">
            <Calendar className="w-5 h-5 text-indigo-600 dark:text-indigo-400" />
          </div>
          <div className="flex-grow">
            <h2 className="text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest leading-none mb-1">{t.selectMonth}</h2>
            <select 
              value={selectedMonth}
              onChange={(e) => setSelectedMonth(e.target.value)}
              className="bg-transparent font-bold text-lg text-slate-800 dark:text-slate-100 outline-none cursor-pointer hover:text-indigo-600 dark:hover:text-indigo-400 transition-colors"
            >
              {availableMonths.map(m => (
                <option key={m} value={m} className="bg-white dark:bg-slate-900">{m}</option>
              ))}
            </select>
          </div>
        </div>

        <div className="flex items-center gap-2 w-full sm:w-auto">
          <button 
            onClick={() => setShowBudgetForm(true)}
            className="flex-1 sm:flex-none flex items-center justify-center gap-2 px-4 py-3 bg-white dark:bg-slate-900 text-indigo-600 dark:text-indigo-400 rounded-2xl font-bold hover:bg-indigo-50 dark:hover:bg-indigo-900/20 transition-all border border-indigo-100 dark:border-indigo-900 shadow-sm active:scale-95"
          >
            <Target className="w-5 h-5" />
            <span className="sm:inline">{t.manageBudget}</span>
          </button>
          <button 
            onClick={() => setShowAddForm(true)}
            className="flex-1 sm:flex-none bg-indigo-600 text-white px-6 py-3 rounded-2xl font-bold flex items-center justify-center gap-2 shadow-lg shadow-indigo-200 dark:shadow-none hover:bg-indigo-700 active:scale-95 transition-all"
          >
            <Plus className="w-5 h-5" />
            <span className="sm:inline">{t.addRecord}</span>
          </button>
        </div>
      </div>

      {activeTab === 'dashboard' && (
        <>
          {upcomingBillAlerts.length > 0 && (
            <div className="animate-in slide-in-from-top-4 duration-500">
              <div className="bg-indigo-600 text-white p-4 rounded-3xl shadow-xl shadow-indigo-200 dark:shadow-none flex flex-col md:flex-row items-center justify-between gap-4 overflow-hidden relative">
                <div className="absolute top-0 right-0 p-4 opacity-10">
                  <Clock className="w-24 h-24 rotate-12" />
                </div>
                <div className="flex items-center gap-4 relative z-10">
                  <div className="p-3 bg-white/20 rounded-2xl">
                    <Calendar className="w-6 h-6" />
                  </div>
                  <div>
                    <h3 className="font-black text-lg leading-tight uppercase tracking-tight">{t.dueSoon}</h3>
                    <div className="flex flex-wrap gap-x-4 gap-y-1">
                      {upcomingBillAlerts.map((n, i) => (
                        <span key={n.id} className="text-sm font-medium flex items-center gap-1.5 text-white/90">
                          <span className={`w-2 h-2 rounded-full ${n.priority === 'high' ? 'bg-rose-400 animate-pulse' : (n.priority === 'medium' ? 'bg-amber-400' : 'bg-sky-400')}`} />
                          {n.title}: {n.message}
                        </span>
                      ))}
                    </div>
                  </div>
                </div>
                <button 
                   onClick={() => setActiveTab?.('bills')}
                   className="relative z-10 bg-white/20 hover:bg-white/30 text-white px-4 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all backdrop-blur-sm"
                >
                  Manage Bills
                </button>
              </div>
            </div>
          )}

          <StatsOverview t={t} stats={filteredStats} formatCurrency={formatCurrency} />

          <div className="mt-8 bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-100 dark:border-slate-800 shadow-sm transition-colors">
            <div className="flex items-center justify-between mb-6">
               <div className="flex items-center gap-3">
                 <div className="p-2 bg-emerald-50 dark:bg-emerald-900/20 rounded-xl text-emerald-600 dark:text-emerald-400">
                    <Target className="w-6 h-6" />
                 </div>
                 <h2 className="text-xl font-bold text-slate-800 dark:text-slate-100">{t.budgetStatus}</h2>
               </div>
               <div className="text-[10px] text-slate-400 dark:text-slate-500 font-black uppercase tracking-widest">{selectedMonth}</div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-x-8 gap-y-6">
              {[
                { key: 'groceries', label: t.groceries },
                { key: 'vegetables', label: t.vegetables },
                { key: 'fishEgg', label: t.fishEgg },
                { key: 'chicken', label: t.chicken },
                { key: 'houseRent', label: t.houseRent },
                { key: 'electricity', label: t.electricity },
                { key: 'water', label: t.water },
                { key: 'travel', label: t.travel },
                { key: 'others', label: t.others },
              ].map(({ key, label }) => {
                const limit = (activeBudget.limits as any)[key] || 0;
                const spent = (categorySpending as any)[key] || 0;
                const percent = limit > 0 ? (spent / limit) * 100 : 0;
                const remaining = limit - spent;

                let barColor = "bg-indigo-500";
                if (percent >= 100) barColor = "bg-rose-500";
                else if (percent >= 80) barColor = "bg-amber-500";

                return (
                  <div key={key} className="space-y-2">
                    <div className="flex justify-between items-end gap-2">
                      <span className="text-xs font-bold text-slate-700 dark:text-slate-300 truncate">{label}</span>
                      <div className="text-right shrink-0">
                        <span className={`text-[10px] font-black uppercase tracking-tighter ${percent > 100 ? 'text-rose-500' : 'text-slate-400 dark:text-slate-500'}`}>
                          {formatCurrency(spent)} / {limit > 0 ? formatCurrency(limit) : '---'}
                        </span>
                      </div>
                    </div>
                    <div className="h-2 w-full bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden transition-colors">
                      <div 
                        className={`h-full transition-all duration-500 ${barColor}`} 
                        style={{ width: `${Math.min(percent, 100)}%` }}
                      ></div>
                    </div>
                    <div className="flex justify-between text-[10px] font-black uppercase tracking-tight">
                       {limit > 0 ? (
                         remaining >= 0 ? (
                           <span className="text-emerald-500 dark:text-emerald-400 truncate">{t.remaining}: {formatCurrency(remaining)}</span>
                         ) : (
                           <span className="text-rose-500 flex items-center gap-1 truncate">
                             <AlertCircle className="w-3 h-3" />
                             {t.overspent}: {formatCurrency(Math.abs(remaining))}
                           </span>
                         )
                       ) : (
                         <span className="text-slate-300 dark:text-slate-700">Not set</span>
                       )}
                       <span className="text-slate-400 dark:text-slate-500 ml-2">{Math.round(percent)}%</span>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>

          <div className="mt-8 bg-white dark:bg-slate-900 rounded-3xl border border-slate-100 dark:border-slate-800 shadow-sm overflow-hidden transition-colors">
            <div className="p-6 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between">
              <div className="flex items-center gap-3">
                <ClipboardList className="w-6 h-6 text-indigo-600 dark:text-indigo-400" />
                <h2 className="text-xl font-bold text-slate-800 dark:text-slate-100">{t.recentTransactions}</h2>
              </div>
              <button 
                onClick={() => setActiveTab?.('history')}
                className="flex items-center gap-1 text-sm font-bold text-indigo-600 dark:text-indigo-400 hover:text-indigo-700 dark:hover:text-indigo-300 transition-colors"
              >
                {t.viewAll}
                <ArrowRight className="w-4 h-4" />
              </button>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full text-left min-w-[800px]">
                <thead>
                  <tr className="bg-slate-50 dark:bg-slate-800/50 text-slate-500 dark:text-slate-400 text-[10px] uppercase font-black tracking-widest border-b border-slate-100 dark:border-slate-800">
                    <th className="px-6 py-4">{t.date}</th>
                    <th className="px-6 py-4">{t.month}</th>
                    <th className="px-6 py-4">{t.dailyCash}</th>
                    <th className="px-6 py-4">{t.totalExpenses}</th>
                    <th className="px-6 py-4 bg-indigo-50/30 dark:bg-indigo-900/10 text-indigo-700 dark:text-indigo-400">{t.totalBalance}</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                  {transactions.slice().reverse().slice(0, 5).map((tx) => (
                    <tr key={tx.id || tx.timestamp} className="hover:bg-slate-50/50 dark:hover:bg-slate-800/50 transition-colors">
                      <td className="px-6 py-4 text-sm font-semibold text-slate-700 dark:text-slate-300">{tx.date.split('-').reverse().join('/')}</td>
                      <td className="px-6 py-4 text-xs font-medium text-slate-400 dark:text-slate-500">{tx.month}</td>
                      <td className="px-6 py-4 text-sm font-bold text-emerald-600 dark:text-emerald-400">{formatCurrency(Number(tx.dailyCash))}</td>
                      <td className="px-6 py-4 text-sm font-bold text-rose-500 dark:text-rose-400">{formatCurrency(Number(tx.totalExpenses))}</td>
                      <td className="px-6 py-4 text-sm font-black text-indigo-600 dark:text-indigo-400 bg-indigo-50/20 dark:bg-indigo-900/5">{formatCurrency(Number(tx.totalBalance))}</td>
                    </tr>
                  ))}
                  {transactions.length === 0 && (
                    <tr>
                      <td colSpan={5} className="px-6 py-12 text-center text-slate-400 dark:text-slate-600 font-medium italic">{t.noData}</td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </>
      )}

      {activeTab === 'analytics' && (
        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div>
            <div className="flex items-center justify-between mb-6">
              <div className="flex items-center gap-3">
                <div className="p-2 bg-indigo-100 dark:bg-indigo-900/30 rounded-xl">
                  <BarChart3 className="w-6 h-6 text-indigo-700 dark:text-indigo-400" />
                </div>
                <h2 className="text-2xl font-black text-slate-800 dark:text-slate-100">{t.charts} - {selectedMonth}</h2>
              </div>
            </div>
            <MonthlyCharts t={t} transactions={currentMonthTransactions} />
          </div>
        </div>
      )}

      {activeTab === 'budget' && (
        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
          <BudgetPerformance 
            t={t} 
            transactions={transactions} 
            budgets={budgets} 
            formatCurrency={formatCurrency}
          />
        </div>
      )}

      {activeTab === 'history' && (
        <div className="bg-white dark:bg-slate-900 rounded-3xl shadow-sm border border-slate-100 dark:border-slate-800 overflow-hidden animate-in fade-in slide-in-from-bottom-4 duration-500 transition-colors">
          <div className="p-6 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between no-print">
            <h2 className="text-xl font-bold text-slate-800 dark:text-slate-100">{t.history} ({selectedMonth})</h2>
          </div>
          <HistoryTable 
            t={t} 
            transactions={transactions.filter(tx => tx.month?.trim() === selectedMonth)} 
            allTransactions={transactions}
            onEdit={handleEdit} 
            onDelete={onDelete} 
            isLoading={isLoading} 
            formatCurrency={formatCurrency}
          />
        </div>
      )}

      {showAddForm && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 dark:bg-black/70 backdrop-blur-sm no-print">
          <div className="bg-white dark:bg-slate-900 w-full max-w-2xl rounded-3xl shadow-2xl dark:shadow-none overflow-hidden max-h-[90vh] flex flex-col scale-in-center transition-colors">
            <div className="p-6 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between">
              <h3 className="text-xl font-bold text-slate-800 dark:text-slate-100">
                {editingTransaction ? t.edit : t.addRecord}
              </h3>
              <button 
                onClick={() => { setShowAddForm(false); setEditingTransaction(null); }}
                className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full transition-colors"
              >
                <X className="w-6 h-6 text-slate-400 dark:text-slate-500" />
              </button>
            </div>
            <div className="p-6 overflow-y-auto">
              <TransactionForm 
                t={t} 
                initialData={editingTransaction}
                formatCurrency={formatCurrency}
                onSubmit={(data) => {
                  if (editingTransaction?.id) {
                    onUpdate(editingTransaction.id, data);
                  } else {
                    onAdd(data);
                  }
                  setShowAddForm(false);
                  setEditingTransaction(null);
                }} 
              />
            </div>
          </div>
        </div>
      )}

      {showBudgetForm && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 dark:bg-black/70 backdrop-blur-sm no-print">
          <div className="bg-white dark:bg-slate-900 w-full max-w-lg rounded-3xl shadow-2xl dark:shadow-none overflow-hidden flex flex-col scale-in-center transition-colors max-h-[95vh]">
            <div className="p-6 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between shrink-0">
              <h3 className="text-xl font-bold text-slate-800 dark:text-slate-100">{t.manageBudget}</h3>
              <button 
                onClick={() => setShowBudgetForm(false)}
                className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full transition-colors"
              >
                <X className="w-6 h-6 text-slate-400 dark:text-slate-500" />
              </button>
            </div>
            <div className="p-4 md:p-6 overflow-y-auto">
              <BudgetManager 
                t={t} 
                month={selectedMonth} 
                initialLimits={activeBudget.limits} 
                onSubmit={handleSaveBudget} 
              />
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Dashboard;

import React, { useState, useMemo } from 'react';
import { Transaction } from '../types';
import { Edit2, Trash2, FileSpreadsheet, Printer, Search, X, Calendar as CalendarIcon, Filter, CheckCircle } from 'lucide-react';
import * as XLSX from 'xlsx';

interface HistoryTableProps {
  t: any;
  transactions: Transaction[];
  allTransactions?: Transaction[];
  onEdit: (tx: Transaction) => void;
  onDelete: (id: string) => void;
  isLoading: boolean;
  formatCurrency: (amount: number) => string;
}

const HistoryTable: React.FC<HistoryTableProps> = ({ t, transactions, allTransactions, onEdit, onDelete, isLoading, formatCurrency }) => {
  const [stagedSearch, setStagedSearch] = useState('');
  const [stagedStart, setStagedStart] = useState('');
  const [stagedEnd, setStagedEnd] = useState('');
  const [activeSearch, setActiveSearch] = useState('');
  const [activeStart, setActiveStart] = useState('');
  const [activeEnd, setActiveEnd] = useState('');

  const filteredTransactions = useMemo(() => {
    return transactions.filter(tx => {
      if (activeStart && tx.date < activeStart) return false;
      if (activeEnd && tx.date > activeEnd) return false;
      if (activeSearch) {
        const lowerSearch = activeSearch.toLowerCase();
        if (tx.date.includes(activeSearch)) return true;
        const categories = [
          { key: 'groceries', label: t.groceries },
          { key: 'vegetables', label: t.vegetables },
          { key: 'fishEgg', label: t.fishEgg },
          { key: 'chicken', label: t.chicken },
          { key: 'houseRent', label: t.houseRent },
          { key: 'electricity', label: t.electricity },
          { key: 'water', label: t.water },
          { key: 'travel', label: t.travel },
          { key: 'others', label: t.others },
        ];
        const matchesCategory = categories.some(cat => 
          cat.label.toLowerCase().includes(lowerSearch) && Number((tx as any)[cat.key]) > 0
        );
        if (matchesCategory) return true;
        if (tx.totalExpenses.toString().includes(activeSearch)) return true;
        if (tx.dailyCash.toString().includes(activeSearch)) return true;
        return false;
      }
      return true;
    });
  }, [transactions, activeSearch, activeStart, activeEnd, t]);

  const formatForExcel = (data: Transaction[]) => {
    return data.map(tx => ({
      [t.date]: tx.date,
      [t.dailyCash]: tx.dailyCash,
      [t.groceries]: tx.groceries,
      [t.vegetables]: tx.vegetables,
      [t.fishEgg]: tx.fishEgg,
      [t.chicken]: tx.chicken,
      [t.houseRent]: tx.houseRent,
      [t.electricity]: tx.electricity,
      [t.water]: tx.water,
      [t.travel]: tx.travel,
      [t.others]: tx.others,
      [t.totalExpenses]: tx.totalExpenses,
      [t.totalBalance]: tx.totalBalance,
    }));
  };

  const exportAllToExcel = () => {
    const dataToExport = allTransactions || transactions;
    if (dataToExport.length === 0) return;
    const workbook = XLSX.utils.book_new();
    const sortedData = [...dataToExport].sort((a,b) => a.date.localeCompare(b.date));
    const fullData = formatForExcel(sortedData);
    const wsFull = XLSX.utils.json_to_sheet(fullData);
    XLSX.utils.book_append_sheet(workbook, wsFull, "Transaction Details");
    const monthlySummary: any[] = [];
    const months = [...new Set(sortedData.map(tx => tx.month))];
    months.forEach(m => {
      const txs = sortedData.filter(tx => tx.month === m);
      const firstInMonth = txs[0];
      const monthBF = firstInMonth ? Number(firstInMonth.broughtForward) : 0;
      const monthIncome = txs.reduce((acc, curr) => acc + (Number(curr.dailyCash) || 0), 0) + monthBF;
      monthlySummary.push({
        [t.month]: m,
        [t.totalIncome]: monthIncome,
        [t.totalExpenses]: txs.reduce((acc, curr) => acc + (Number(curr.totalExpenses) || 0), 0),
        [t.totalBalance]: Number(txs[txs.length-1]?.totalBalance) || 0
      });
    });
    const wsSummary = XLSX.utils.json_to_sheet(monthlySummary);
    XLSX.utils.book_append_sheet(workbook, wsSummary, "Monthly Summary");
    XLSX.writeFile(workbook, `Finance_Report_${new Date().toISOString().split('T')[0]}.xlsx`);
  };

  const handlePrint = () => { window.print(); };
  const applyFilters = () => {
    setActiveSearch(stagedSearch);
    setActiveStart(stagedStart);
    setActiveEnd(stagedEnd);
  };
  const clearFilters = () => {
    setStagedSearch(''); setStagedStart(''); setStagedEnd('');
    setActiveSearch(''); setActiveStart(''); setActiveEnd('');
  };

  if (isLoading) return <div className="p-12 text-center text-slate-400 dark:text-slate-600">Loading records...</div>;

  const sortedFiltered = [...filteredTransactions].sort((a, b) => a.date.localeCompare(b.date));
  const firstTx = sortedFiltered[0];
  const initialBF = firstTx ? (Number(firstTx.broughtForward) || 0) : 0;
  const totalCashIn = filteredTransactions.reduce((s, tx) => s + (Number(tx.dailyCash) || 0), 0);
  const totalIncome = initialBF + totalCashIn;
  const totalOut = filteredTransactions.reduce((s, tx) => s + (Number(tx.totalExpenses) || 0), 0);
  const selectedMonth = transactions[0]?.month || '';

  return (
    <div className="flex flex-col">
      <div className="p-4 md:p-6 border-b border-slate-100 dark:border-slate-800 space-y-4 no-print transition-colors">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">
          <div className="lg:col-span-4">
            <label className="block text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-2 px-1">Keyword Search</label>
            <div className="relative group">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 group-focus-within:text-indigo-500 transition-colors" />
              <input type="text" placeholder={t.search} className="w-full pl-11 pr-4 py-3 rounded-2xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 focus:ring-2 focus:ring-indigo-500 outline-none transition-all font-medium text-sm shadow-sm" value={stagedSearch} onChange={(e) => setStagedSearch(e.target.value)} onKeyDown={(e) => e.key === 'Enter' && applyFilters()} />
              {stagedSearch && <button onClick={() => setStagedSearch('')} className="absolute right-4 top-1/2 -translate-y-1/2 p-1.5 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-full transition-colors"><X className="w-3.5 h-3.5 text-slate-400" /></button>}
            </div>
          </div>
          <div className="lg:col-span-5">
            <label className="block text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-2 px-1">{t.date} Range</label>
            <div className="flex items-center gap-2 bg-slate-50 dark:bg-slate-900/50 border border-slate-200 dark:border-slate-700 rounded-2xl p-1 shadow-sm">
              <div className="flex-1 relative flex items-center bg-white dark:bg-slate-800 rounded-xl px-3 py-2 border border-slate-100 dark:border-slate-700/50">
                <span className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase absolute -top-2 left-2 bg-white dark:bg-slate-800 px-1">From</span>
                <CalendarIcon className="w-3.5 h-3.5 text-slate-300 mr-2" />
                <input type="date" className="bg-transparent border-none text-xs font-bold text-slate-700 dark:text-slate-200 outline-none w-full" value={stagedStart} onChange={(e) => setStagedStart(e.target.value)} />
              </div>
              <span className="text-slate-400 font-bold px-1">→</span>
              <div className="flex-1 relative flex items-center bg-white dark:bg-slate-800 rounded-xl px-3 py-2 border border-slate-100 dark:border-slate-700/50">
                <span className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase absolute -top-2 left-2 bg-white dark:bg-slate-800 px-1">To</span>
                <CalendarIcon className="w-3.5 h-3.5 text-slate-300 mr-2" />
                <input type="date" className="bg-transparent border-none text-xs font-bold text-slate-700 dark:text-slate-200 outline-none w-full" value={stagedEnd} onChange={(e) => setStagedEnd(e.target.value)} />
              </div>
            </div>
          </div>
          <div className="lg:col-span-3 flex items-end gap-3 h-full">
            <button onClick={applyFilters} className="flex-1 flex items-center justify-center gap-2 bg-indigo-600 text-white font-bold text-sm hover:bg-indigo-700 py-3 rounded-2xl transition-all shadow-lg shadow-indigo-100 dark:shadow-none active:scale-95"><Filter className="w-4 h-4" />{t.applyFilters}</button>
            <button onClick={clearFilters} disabled={!stagedSearch && !stagedStart && !stagedEnd && !activeSearch && !activeStart && !activeEnd} className="p-3 text-slate-400 hover:text-rose-500 hover:bg-rose-50 dark:hover:bg-rose-900/20 rounded-2xl transition-all disabled:opacity-30 disabled:cursor-not-allowed border border-slate-200 dark:border-slate-700" title={t.clearFilters}><X className="w-5 h-5" /></button>
          </div>
        </div>
        <div className="flex flex-wrap items-center justify-between gap-4 pt-2">
          <div className="flex gap-2">
            {(activeSearch || activeStart || activeEnd) && <div className="flex items-center gap-2 px-3 py-1.5 bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400 rounded-full text-[10px] font-black uppercase tracking-widest border border-indigo-100 dark:border-indigo-800 animate-in fade-in zoom-in-95"><CheckCircle className="w-3 h-3" />Filters Applied</div>}
          </div>
          <div className="flex gap-3">
            <button onClick={handlePrint} className="flex items-center gap-2 bg-white dark:bg-slate-800 text-slate-600 dark:text-slate-300 font-bold text-xs hover:bg-slate-50 dark:hover:bg-slate-700 border border-slate-200 dark:border-slate-700 px-5 py-2.5 rounded-xl transition-all shadow-sm active:scale-95"><Printer className="w-3.5 h-3.5" />{t.printReport}</button>
            <button onClick={exportAllToExcel} className="flex items-center gap-2 bg-emerald-600 text-white font-bold text-xs hover:bg-emerald-700 px-5 py-2.5 rounded-xl transition-all shadow-lg shadow-emerald-100 dark:shadow-none active:scale-95"><FileSpreadsheet className="w-3.5 h-3.5" />{t.exportExcel}</button>
          </div>
        </div>
      </div>

      <div className="print-only mb-6 text-center">
        <h1 className="text-2xl font-bold">{t.title}</h1>
        <h2 className="text-xl text-slate-600">{selectedMonth}</h2>
        <div className="flex justify-center gap-8 mt-4 border-y py-2">
           <div><span className="font-bold">{t.totalIncome}:</span> {formatCurrency(totalIncome)}</div>
           <div><span className="font-bold">{t.totalSpent}:</span> {formatCurrency(totalOut)}</div>
           <div><span className="font-bold">{t.totalBalance}:</span> {formatCurrency(sortedFiltered.length > 0 ? Number(sortedFiltered[sortedFiltered.length-1].totalBalance) : 0)}</div>
        </div>
      </div>

      <div className="overflow-x-auto transition-colors">
        <table className="w-full text-left min-w-[1200px] border-collapse">
          <thead>
            <tr className="bg-slate-50 dark:bg-slate-800/50 text-slate-500 dark:text-slate-400 text-[10px] uppercase font-black tracking-widest border-b border-slate-200 dark:border-slate-800">
              <th className="px-6 py-4 border-r border-slate-100 dark:border-slate-800">{t.date}</th>
              <th className="px-6 py-4 border-r border-slate-100 dark:border-slate-800">{t.dailyCash}</th>
              <th className="px-6 py-4">{t.groceries}</th>
              <th className="px-6 py-4">{t.vegetables}</th>
              <th className="px-6 py-4">{t.fishEgg}</th>
              <th className="px-6 py-4">{t.chicken}</th>
              <th className="px-6 py-4">{t.houseRent}</th>
              <th className="px-6 py-4">{t.electricity}</th>
              <th className="px-6 py-4">{t.water}</th>
              <th className="px-6 py-4">{t.travel}</th>
              <th className="px-6 py-4">{t.others}</th>
              <th className="px-6 py-4 border-l border-slate-100 dark:border-slate-800">{t.totalExpenses}</th>
              <th className="px-6 py-4 bg-indigo-50/30 dark:bg-indigo-900/10 text-indigo-700 dark:text-indigo-400 border-l border-slate-100 dark:border-slate-800">{t.totalBalance}</th>
              <th className="px-6 py-4 text-center no-print">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100 dark:divide-slate-800 text-sm">
            {sortedFiltered.map((tx) => (
              <tr key={tx.id || tx.timestamp} className="hover:bg-slate-50/50 dark:hover:bg-slate-800/50 transition-colors">
                <td className="px-6 py-4 font-semibold text-slate-700 dark:text-slate-300 whitespace-nowrap border-r border-slate-50 dark:border-slate-800">{tx.date.split('-').reverse().join('/')}</td>
                <td className="px-6 py-4 font-bold text-emerald-600 dark:text-emerald-400 border-r border-slate-50 dark:border-slate-800">{formatCurrency(Number(tx.dailyCash))}</td>
                <td className="px-6 py-4 text-slate-600 dark:text-slate-400">{Number(tx.groceries || 0).toLocaleString()}</td>
                <td className="px-6 py-4 text-slate-600 dark:text-slate-400">{Number(tx.vegetables || 0).toLocaleString()}</td>
                <td className="px-6 py-4 text-slate-600 dark:text-slate-400">{Number(tx.fishEgg || 0).toLocaleString()}</td>
                <td className="px-6 py-4 text-slate-600 dark:text-slate-400">{Number(tx.chicken || 0).toLocaleString()}</td>
                <td className="px-6 py-4 text-slate-600 dark:text-slate-400">{Number(tx.houseRent || 0).toLocaleString()}</td>
                <td className="px-6 py-4 text-slate-600 dark:text-slate-400">{Number(tx.electricity || 0).toLocaleString()}</td>
                <td className="px-6 py-4 text-slate-600 dark:text-slate-400">{Number(tx.water || 0).toLocaleString()}</td>
                <td className="px-6 py-4 text-slate-600 dark:text-slate-400">{Number(tx.travel || 0).toLocaleString()}</td>
                <td className="px-6 py-4 text-slate-600 dark:text-slate-400">{Number(tx.others || 0).toLocaleString()}</td>
                <td className="px-6 py-4 font-bold text-rose-500 dark:text-rose-400 border-l border-slate-50 dark:border-slate-800">{formatCurrency(Number(tx.totalExpenses))}</td>
                <td className="px-6 py-4 font-black text-indigo-600 dark:text-indigo-400 bg-indigo-50/20 dark:bg-indigo-900/5 border-l border-slate-50 dark:border-slate-800">{formatCurrency(Number(tx.totalBalance))}</td>
                <td className="px-6 py-4 no-print whitespace-nowrap">
                  <div className="flex items-center justify-center gap-2">
                    <button onClick={() => onEdit(tx)} className="p-2 text-slate-400 dark:text-slate-500 hover:text-indigo-600 dark:hover:text-indigo-400 hover:bg-indigo-50 dark:hover:bg-indigo-900/30 rounded-lg transition-all"><Edit2 className="w-4 h-4" /></button>
                    <button onClick={() => tx.id && onDelete(tx.id)} className="p-2 text-slate-400 dark:text-slate-500 hover:text-rose-600 dark:hover:text-rose-400 hover:bg-rose-50 dark:hover:bg-rose-900/30 rounded-lg transition-all"><Trash2 className="w-4 h-4" /></button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        {sortedFiltered.length === 0 && (
          <div className="p-20 text-center flex flex-col items-center gap-3">
             <Filter className="w-12 h-12 text-slate-200 dark:text-slate-800" />
             <p className="text-slate-400 dark:text-slate-600 font-bold italic">{t.noResults}</p>
             <button onClick={clearFilters} className="text-indigo-600 dark:text-indigo-400 font-bold text-sm hover:underline">{t.clearFilters}</button>
          </div>
        )}
      </div>
    </div>
  );
};

export default HistoryTable;

import React, { useState, useMemo, useEffect } from 'react';
import { Transaction, MonthlyBudget, Notification } from '../types';
import TransactionForm from './TransactionForm';
import StatsOverview from './StatsOverview';
import MonthlyCharts from './MonthlyCharts';
import HistoryTable from './HistoryTable';
import BudgetManager from './BudgetManager';
import BudgetPerformance from './BudgetPerformance';
import { Plus, X, Calendar, BarChart3, ClipboardList, ArrowRight, Target, AlertCircle, Clock } from 'lucide-react';
import { storageService } from '../services/googleSheets';

interface DashboardProps {
  activeTab: 'dashboard' | 'analytics' | 'history' | 'budget' | 'bills' | 'settings';
  setActiveTab?: (tab: 'dashboard' | 'analytics' | 'history' | 'budget' | 'bills' | 'settings') => void;
  t: any;
  transactions: Transaction[];
  onAdd: (data: Transaction) => void;
  onUpdate: (id: string, data: Transaction) => void;
  onDelete: (id: string) => void;
  onRefresh: () => void;
  isLoading: boolean;
  formatCurrency: (amount: number) => string;
  notifications?: Notification[];
}

const Dashboard: React.FC<DashboardProps> = ({ 
  activeTab, 
  setActiveTab,
  t, 
  transactions, 
  onAdd, 
  onUpdate,
  onDelete,
  onRefresh,
  isLoading,
  formatCurrency,
  notifications = []
}) => {
  const [showAddForm, setShowAddForm] = useState(false);
  const [showBudgetForm, setShowBudgetForm] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [budgets, setBudgets] = useState<MonthlyBudget[]>([]);

  useEffect(() => {
    const loadBudgets = async () => {
      const data = await storageService.fetchBudgets();
      setBudgets(data);
    };
    loadBudgets();
  }, [transactions]);

  const currentMonthName = useMemo(() => {
    return new Date().toLocaleString('en-US', { month: 'long', year: 'numeric' });
  }, []);

  const availableMonths = useMemo(() => {
    const monthsSet = new Set<string>();
    transactions.forEach(tx => {
      if (tx.month) monthsSet.add(tx.month.trim());
    });
    monthsSet.add(currentMonthName);
    return Array.from(monthsSet).sort((a, b) => {
      const dateA = new Date(a);
      const dateB = new Date(b);
      return dateB.getTime() - dateA.getTime();
    });
  }, [transactions, currentMonthName]);

  const [selectedMonth, setSelectedMonth] = useState<string>(availableMonths[0] || currentMonthName);

  const activeBudget = useMemo(() => {
    return budgets.find(b => b.month === selectedMonth) || {
      month: selectedMonth,
      limits: { groceries: 0, vegetables: 0, fishEgg: 0, chicken: 0, houseRent: 0, electricity: 0, water: 0, travel: 0, others: 0 }
    };
  }, [budgets, selectedMonth]);

  const currentMonthTransactions = useMemo(() => {
    return transactions.filter(tx => tx.month?.trim() === selectedMonth).sort((a, b) => a.date.localeCompare(b.date));
  }, [transactions, selectedMonth]);

  const categorySpending = useMemo(() => {
    const totals = { groceries: 0, vegetables: 0, fishEgg: 0, chicken: 0, houseRent: 0, electricity: 0, water: 0, travel: 0, others: 0 };
    currentMonthTransactions.forEach(tx => {
      totals.groceries += Number(tx.groceries) || 0;
      totals.vegetables += Number(tx.vegetables) || 0;
      totals.fishEgg += Number(tx.fishEgg) || 0;
      totals.chicken += Number(tx.chicken) || 0;
      totals.houseRent += Number(tx.houseRent) || 0;
      totals.electricity += Number(tx.electricity) || 0;
      totals.water += Number(tx.water) || 0;
      totals.travel += Number(tx.travel) || 0;
      totals.others += Number(tx.others) || 0;
    });
    return totals;
  }, [currentMonthTransactions]);

  const filteredStats = useMemo(() => {
    const sorted = [...currentMonthTransactions].sort((a, b) => a.date.localeCompare(b.date));

    // 1. Total Expenses: Sum of all category fields across all transactions of the month
    const totalSpent = currentMonthTransactions.reduce((sum, tx) => {
      const txExp = Number(tx.groceries || 0) + Number(tx.vegetables || 0) + Number(tx.fishEgg || 0) + 
                    Number(tx.chicken || 0) + Number(tx.houseRent || 0) + Number(tx.electricity || 0) + 
                    Number(tx.water || 0) + Number(tx.travel || 0) + Number(tx.others || 0);
      return sum + txExp;
    }, 0);

    // 2. Total Cash Received + Brought Forward
    const firstTx = sorted[0];
    const initialBF = firstTx ? (Number(firstTx.broughtForward) || 0) : 0;
    const totalDailyCash = currentMonthTransactions.reduce((sum, tx) => sum + (Number(tx.dailyCash) || 0), 0);
    const totalAvailableFunds = initialBF + totalDailyCash;

    // 3. Net Balance = (Initial BF + Sum Daily Cash) - Total Monthly Expenses
    const currentNetBalance = totalAvailableFunds - totalSpent;

    return { totalSpent, totalReceived: totalAvailableFunds, lastBalance: currentNetBalance };
  }, [currentMonthTransactions]);

  const handleEdit = (tx: Transaction) => {
    setEditingTransaction(tx);
    setShowAddForm(true);
  };

  const handleSaveBudget = async (limits: MonthlyBudget['limits']) => {
    await storageService.saveBudget(selectedMonth, limits);
    const updated = await storageService.fetchBudgets();
    setBudgets(updated);
    setShowBudgetForm(false);
  };

  const upcomingBillAlerts = useMemo(() => {
    return notifications
      .filter(n => n.type === 'bill' && !n.read)
      .sort((a, b) => {
        const priorityMap = { high: 0, medium: 1, low: 2 };
        return (priorityMap[a.priority] || 3) - (priorityMap[b.priority] || 3);
      })
      .slice(0, 3);
  }, [notifications]);

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row items-center justify-between gap-4 bg-white dark:bg-slate-900 p-4 rounded-3xl border border-slate-100 dark:border-slate-800 shadow-sm no-print transition-colors">
        <div className="flex items-center gap-3 w-full sm:w-auto">
          <div className="p-2 bg-indigo-50 dark:bg-indigo-900/30 rounded-xl">
            <Calendar className="w-5 h-5 text-indigo-600 dark:text-indigo-400" />
          </div>
          <div className="flex-grow">
            <h2 className="text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest leading-none mb-1">{t.selectMonth}</h2>
            <select 
              value={selectedMonth}
              onChange={(e) => setSelectedMonth(e.target.value)}
              className="bg-transparent font-bold text-lg text-slate-800 dark:text-slate-100 outline-none cursor-pointer hover:text-indigo-600 dark:hover:text-indigo-400 transition-colors"
            >
              {availableMonths.map(m => (
                <option key={m} value={m} className="bg-white dark:bg-slate-900">{m}</option>
              ))}
            </select>
          </div>
        </div>

        <div className="flex items-center gap-2 w-full sm:w-auto">
          <button 
            onClick={() => setShowBudgetForm(true)}
            className="flex-1 sm:flex-none flex items-center justify-center gap-2 px-4 py-3 bg-white dark:bg-slate-900 text-indigo-600 dark:text-indigo-400 rounded-2xl font-bold hover:bg-indigo-50 dark:hover:bg-indigo-900/20 transition-all border border-indigo-100 dark:border-indigo-900 shadow-sm active:scale-95"
          >
            <Target className="w-5 h-5" />
            <span className="sm:inline">{t.manageBudget}</span>
          </button>
          <button 
            onClick={() => setShowAddForm(true)}
            className="flex-1 sm:flex-none bg-indigo-600 text-white px-6 py-3 rounded-2xl font-bold flex items-center justify-center gap-2 shadow-lg shadow-indigo-200 dark:shadow-none hover:bg-indigo-700 active:scale-95 transition-all"
          >
            <Plus className="w-5 h-5" />
            <span className="sm:inline">{t.addRecord}</span>
          </button>
        </div>
      </div>

      {activeTab === 'dashboard' && (
        <>
          {upcomingBillAlerts.length > 0 && (
            <div className="animate-in slide-in-from-top-4 duration-500">
              <div className="bg-indigo-600 text-white p-4 rounded-3xl shadow-xl shadow-indigo-200 dark:shadow-none flex flex-col md:flex-row items-center justify-between gap-4 overflow-hidden relative">
                <div className="absolute top-0 right-0 p-4 opacity-10">
                  <Clock className="w-24 h-24 rotate-12" />
                </div>
                <div className="flex items-center gap-4 relative z-10">
                  <div className="p-3 bg-white/20 rounded-2xl">
