import React, { useState, useEffect, useMemo } from 'react';
import { Bill, Transaction } from '../types';
import { storageService } from '../services/googleSheets';
import { Plus, CreditCard, Trash2, Calendar, DollarSign, X, TrendingUp, ReceiptText, CheckCircle2 } from 'lucide-react';

interface BillManagerProps {
  t: any;
  formatCurrency: (amount: number) => string;
  transactions: Transaction[];
  onRefresh?: () => void;
}

const BillManager: React.FC<BillManagerProps> = ({ t, formatCurrency, transactions, onRefresh }) => {
  const [bills, setBills] = useState<Bill[]>([]);
  const [showAdd, setShowAdd] = useState(false);
  const [newBill, setNewBill] = useState<Partial<Bill>>({ dueDay: new Date().getDate(), category: 'others' });
  const [isNameManuallyEdited, setIsNameManuallyEdited] = useState(false);

  useEffect(() => {
    storageService.fetchBills().then(setBills);
  }, []);

  const currentMonthLabel = useMemo(() => {
    return new Date().toLocaleString('en-US', { month: 'long', year: 'numeric' });
  }, []);

  const monthlySpendingSummary = useMemo(() => {
    const currentMonthTxs = transactions.filter(tx => tx.month === currentMonthLabel);

    // Aggregating actual spending by category
    const actualByCategory: Record<string, number> = {
      groceries: 0, vegetables: 0, fishEgg: 0, chicken: 0,
      houseRent: 0, electricity: 0, water: 0, travel: 0, others: 0
    };

    currentMonthTxs.forEach(tx => {
      Object.keys(actualByCategory).forEach(cat => {
        actualByCategory[cat] += (tx as any)[cat] || 0;
      });
    });

    // Aggregating bill estimates by category
    const billEstimatesByCategory: Record<string, number> = {
      groceries: 0, vegetables: 0, fishEgg: 0, chicken: 0,
      houseRent: 0, electricity: 0, water: 0, travel: 0, others: 0
    };

    bills.forEach(bill => {
      if (billEstimatesByCategory[bill.category] !== undefined) {
        billEstimatesByCategory[bill.category] += bill.amount;
      } else {
        billEstimatesByCategory.others += bill.amount;
      }
    });

    return Object.keys(actualByCategory)
      .map(cat => ({
        category: cat,
        label: t[cat as keyof typeof t] || cat,
        actual: actualByCategory[cat],
        estimate: billEstimatesByCategory[cat]
      }))
      .filter(item => item.actual > 0 || item.estimate > 0)
      .sort((a, b) => b.actual - a.actual);
  }, [transactions, bills, currentMonthLabel, t]);

  const handleCategoryChange = (category: string) => {
    const updates: Partial<Bill> = { category };

    // Auto-fill name if not manually edited or if name is empty
    if (!isNameManuallyEdited || !newBill.name) {
      updates.name = t[category as keyof typeof t] || category;
    }

    setNewBill(prev => ({ ...prev, ...updates }));
  };

  const handleSave = async () => {
    if (!newBill.name || !newBill.amount) return;
    const bill: Bill = {
      id: crypto.randomUUID(),
      name: newBill.name,
      amount: Number(newBill.amount),
      dueDay: Number(newBill.dueDay),
      category: newBill.category || 'others'
    };
    await storageService.saveBill(bill);
    setBills([...bills, bill]);
    setShowAdd(false);
    resetForm();
    if (onRefresh) onRefresh();
  };

  const resetForm = () => {
    setNewBill({ dueDay: new Date().getDate(), category: 'others' });
    setIsNameManuallyEdited(false);
  };

  const handleDelete = async (id: string) => {
    if (window.confirm(t.confirmDelete)) {
      await storageService.deleteBill(id);
      setBills(bills.filter(b => b.id !== id));
      if (onRefresh) onRefresh();
    }
  };

  const handlePayBill = async (bill: Bill) => {
    const updatedBill: Bill = {
      ...bill,
      lastPaidMonth: currentMonthLabel
    };
    await storageService.saveBill(updatedBill);
    setBills(prev => prev.map(b => b.id === bill.id ? updatedBill : b));
    if (onRefresh) onRefresh();
  };

  // Helper to format the current month's "due date" for the date picker input
  const getDummyDateString = (day: number = 1) => {
    const now = new Date();
    const date = new Date(now.getFullYear(), now.getMonth(), day);
    return date.toISOString().split('T')[0];
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      {/* Page Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-indigo-100 dark:bg-indigo-900/30 rounded-xl">
            <CreditCard className="w-6 h-6 text-indigo-700 dark:text-indigo-400" />
          </div>
          <h2 className="text-2xl font-black text-slate-800 dark:text-slate-100">{t.bills}</h2>
        </div>
        <button 
          onClick={() => setShowAdd(true)}
          className="flex items-center gap-2 px-6 py-3 bg-indigo-600 text-white rounded-2xl font-bold shadow-lg shadow-indigo-200 dark:shadow-none hover:bg-indigo-700 active:scale-95 transition-all"
        >
          <Plus className="w-5 h-5" />
          {t.addBill}
        </button>
      </div>

      {/* Monthly Spending Section */}
      <div className="bg-white dark:bg-slate-900 rounded-3xl border border-slate-100 dark:border-slate-800 p-6 shadow-sm overflow-hidden transition-colors">
        <div className="flex items-center gap-3 mb-6">
          <div className="p-2 bg-emerald-100 dark:bg-emerald-900/30 rounded-xl">
            <TrendingUp className="w-5 h-5 text-emerald-600 dark:text-emerald-400" />
          </div>
          <div>
            <h3 className="text-lg font-bold text-slate-800 dark:text-slate-100">Monthly Spending Summary</h3>
            <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">{currentMonthLabel}</p>
          </div>
        </div>

        {monthlySpendingSummary.length > 0 ? (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
            {monthlySpendingSummary.map(item => (
              <div key={item.category} className="p-4 bg-slate-50 dark:bg-slate-800/40 rounded-2xl border border-slate-100 dark:border-slate-700/30">
                <div className="flex justify-between items-start mb-2">
                  <span className="text-xs font-black uppercase text-slate-400 tracking-wider">{item.label}</span>
                  {item.estimate > 0 && item.actual > item.estimate && (
                    <span className="text-[10px] font-black text-rose-500 bg-rose-50 dark:bg-rose-950/30 px-2 py-0.5 rounded-full">Exceeded Bill</span>
                  )}
                </div>
                <div className="flex items-baseline gap-2 mb-3">
                  <span className="text-xl font-black text-slate-800 dark:text-slate-100">{formatCurrency(item.actual)}</span>
                  {item.estimate > 0 && (
                    <span className="text-xs text-slate-400 font-bold">/ {formatCurrency(item.estimate)}</span>
                  )}
                </div>
                {item.estimate > 0 && (
                  <div className="w-full h-1.5 bg-slate-200 dark:bg-slate-700 rounded-full overflow-hidden">
                    <div 
                      className={`h-full transition-all duration-700 ${item.actual > item.estimate ? 'bg-rose-500' : 'bg-emerald-500'}`}
                      style={{ width: `${Math.min((item.actual / item.estimate) * 100, 100)}%` }}
                    />
                  </div>
                )}
              </div>
            ))}
          </div>
        ) : (
          <div className="py-10 text-center text-slate-400 italic flex flex-col items-center gap-2">
            <ReceiptText className="w-8 h-8 opacity-20" />
            <p>No spending recorded for this month yet.</p>
          </div>
        )}
      </div>

      {/* Bill List Section */}
      <div className="space-y-4">
        <h3 className="text-lg font-bold text-slate-800 dark:text-slate-100 flex items-center gap-2">
          <ReceiptText className="w-5 h-5 text-indigo-600" />
          Scheduled & Recurring
        </h3>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {bills.map(bill => {
            const isPaidThisMonth = bill.lastPaidMonth === currentMonthLabel;
            return (
              <div 
                key={bill.id} 
                className={`bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-100 dark:border-slate-800 shadow-sm relative group overflow-hidden transition-all duration-300 ${isPaidThisMonth ? 'opacity-60 bg-slate-50 dark:bg-slate-800/20' : ''}`}
              >
                <div className={`absolute top-0 left-0 w-2 h-full transition-all ${isPaidThisMonth ? 'bg-emerald-500' : 'bg-indigo-500 opacity-20 group-hover:opacity-100'}`} />
                <div className="flex justify-between items-start mb-4 pl-2">
                  <div>
                    <h3 className={`font-black text-slate-800 dark:text-slate-100 text-lg uppercase tracking-tight ${isPaidThisMonth ? 'line-through decoration-slate-400' : ''}`}>{bill.name}</h3>
                    <p className="text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest">{t[bill.category as keyof typeof t] || bill.category}</p>
                  </div>
                  <button 
                    onClick={() => handleDelete(bill.id)}
                    className="p-2 text-slate-300 dark:text-slate-600 hover:text-rose-500 dark:hover:text-rose-400 hover:bg-rose-50 dark:hover:bg-rose-900/30 rounded-xl transition-all"
                  >
                    <Trash2 className="w-4 h-4" />
                  </button>
                </div>

                <div className="flex items-center gap-6 pl-2 mb-6">
                  <div className="flex flex-col">
                    <span className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-1">{t.date}</span>
                    <div className={`flex items-center gap-2 font-black ${isPaidThisMonth ? 'text-slate-400' : 'text-indigo-600 dark:text-indigo-400'}`}>
                      <Calendar className="w-4 h-4" />
                      <span>Day {bill.dueDay} / Month</span>
                    </div>
                  </div>
                  <div className="flex flex-col">
                    <span className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-1">Amount</span>
                    <div className={`flex items-center gap-2 font-black ${isPaidThisMonth ? 'text-slate-400' : 'text-slate-800 dark:text-slate-100'}`}>
                      <DollarSign className="w-4 h-4 text-slate-300 dark:text-slate-700" />
                      <span>{formatCurrency(bill.amount)}</span>
                    </div>
                  </div>
                </div>

                <div className="pl-2">
                  {isPaidThisMonth ? (
                    <div className="flex items-center gap-2 text-emerald-600 dark:text-emerald-400 font-black text-sm uppercase tracking-widest bg-emerald-50 dark:bg-emerald-950/30 py-2 px-4 rounded-xl w-fit">
                      <CheckCircle2 className="w-4 h-4" />
                      {t.paid}
                    </div>
                  ) : (
                    <button 
                      onClick={() => handlePayBill(bill)}
                      className="w-full flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-700 text-white font-bold text-xs uppercase tracking-widest py-3 rounded-xl transition-all shadow-md active:scale-95"
                    >
                      <CheckCircle2 className="w-4 h-4" />
                      {t.payBill}
                    </button>
                  )}
                </div>
              </div>
            );
          })}

          {bills.length === 0 && (
            <div className="col-span-full py-20 bg-slate-50/50 dark:bg-slate-900/50 rounded-3xl border-2 border-dashed border-slate-200 dark:border-slate-800 flex flex-col items-center justify-center text-slate-400 dark:text-slate-600 gap-4 transition-colors">
               <CreditCard className="w-12 h-12 opacity-10" />
               <p className="font-bold italic">{t.noData}</p>
            </div>
          )}
        </div>
      </div>

      {showAdd && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 dark:bg-black/70 backdrop-blur-sm">
          <div className="bg-white dark:bg-slate-900 w-full max-w-md rounded-3xl shadow-2xl dark:shadow-none overflow-hidden animate-in zoom-in-95 duration-200 transition-colors">
            <div className="p-6 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between">
              <h3 className="text-xl font-bold text-slate-800 dark:text-slate-100">{t.addBill}</h3>
              <button onClick={() => { setShowAdd(false); resetForm(); }} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full transition-colors">
                <X className="w-6 h-6 text-slate-400 dark:text-slate-500" />
              </button>
            </div>
            <div className="p-6 space-y-4">
              <div>
                <label className="block text-xs font-black text-slate-400 dark:text-slate-500 uppercase mb-2">Category</label>
                <select 
                  className="w-full px-4 py-3 rounded-2xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 focus:ring-2 focus:ring-indigo-500 outline-none font-bold"
                  value={newBill.category || 'others'}
                  onChange={e => handleCategoryChange(e.target.value)}
                >
                  <option value="groceries">{t.groceries}</option>
                  <option value="vegetables">{t.vegetables}</option>
                  <option value="fishEgg">{t.fishEgg}</option>
                  <option value="chicken">{t.chicken}</option>
                  <option value="houseRent">{t.houseRent}</option>
                  <option value="electricity">{t.electricity}</option>
                  <option value="water">{t.water}</option>
                  <option value="travel">{t.travel}</option>
                  <option value="others">{t.others}</option>
                </select>
              </div>

              <div>
                <label className="block text-xs font-black text-slate-400 dark:text-slate-500 uppercase mb-2">Bill Name</label>
                <input 
                  type="text" 
                  className="w-full px-4 py-3 rounded-2xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 focus:ring-2 focus:ring-indigo-500 outline-none font-bold"
                  value={newBill.name || ''}
                  onChange={e => {
                    setNewBill({...newBill, name: e.target.value});
                    setIsNameManuallyEdited(true);
                  }}
                  placeholder="e.g. Internet Bill"
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-black text-slate-400 dark:text-slate-500 uppercase mb-2">Amount</label>
                  <input 
                    type="number" 
                    className="w-full px-4 py-3 rounded-2xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 focus:ring-2 focus:ring-indigo-500 outline-none font-bold"
                    value={newBill.amount ?? ''}
                    onChange={e => setNewBill({...newBill, amount: e.target.value === '' ? undefined : Number(e.target.value)})}
                  />
                </div>
                <div>
                  <label className="block text-xs font-black text-slate-400 dark:text-slate-500 uppercase mb-2">Recurring Due Day</label>
                  <div className="relative">
                    <input 
                      type="date" 
                      className="w-full px-4 py-3 rounded-2xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 focus:ring-2 focus:ring-indigo-500 outline-none font-bold text-sm"
                      value={getDummyDateString(newBill.dueDay)}
                      onChange={e => {
                        const date = new Date(e.target.value);
                        if (!isNaN(date.getTime())) {
                          setNewBill({...newBill, dueDay: date.getDate()});
                        }
                      }}
                    />
                    <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-indigo-500">
                       <span className="text-xs font-black">Day {newBill.dueDay}</span>
                    </div>
                  </div>
                </div>
              </div>

              <button 
                onClick={handleSave}
                className="w-full bg-indigo-600 text-white py-4 rounded-2xl font-bold shadow-lg shadow-indigo-200 dark:shadow-none hover:bg-indigo-700 mt-4 transition-all"
              >
                {t.save}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default BillManager;

import React, { useState, useMemo, useEffect } from 'react';
import { Transaction, MonthlyBudget, Notification } from '../types';
import TransactionForm from './TransactionForm';
import StatsOverview from './StatsOverview';
import MonthlyCharts from './MonthlyCharts';
import HistoryTable from './HistoryTable';
import BudgetManager from './BudgetManager';
import BudgetPerformance from './BudgetPerformance';
import { Plus, X, Calendar, BarChart3, ClipboardList, ArrowRight, Target, AlertCircle, Clock } from 'lucide-react';
import { storageService } from '../services/googleSheets';

interface DashboardProps {
  activeTab: 'dashboard' | 'analytics' | 'history' | 'budget' | 'bills' | 'settings';
  setActiveTab?: (tab: 'dashboard' | 'analytics' | 'history' | 'budget' | 'bills' | 'settings') => void;
  t: any;
  transactions: Transaction[];
  onAdd: (data: Transaction) => void;
  onUpdate: (id: string, data: Transaction) => void;
  onDelete: (id: string) => void;
  onRefresh: () => void;
  isLoading: boolean;
  formatCurrency: (amount: number) => string;
  notifications?: Notification[];
  latestBalance?: number;
}

const Dashboard: React.FC<DashboardProps> = ({ 
  activeTab, 
  setActiveTab,
  t, 
  transactions, 
  onAdd, 
  onUpdate,
  onDelete,
  onRefresh,
  isLoading,
  formatCurrency,
  notifications = [],
  latestBalance = 0
}) => {
  const [showAddForm, setShowAddForm] = useState(false);
  const [showBudgetForm, setShowBudgetForm] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [budgets, setBudgets] = useState<MonthlyBudget[]>([]);

  useEffect(() => {
    const loadBudgets = async () => {
      const data = await storageService.fetchBudgets();
      setBudgets(data);
    };
    loadBudgets();
  }, [transactions]);

  const currentMonthName = useMemo(() => {
    return new Date().toLocaleString('en-US', { month: 'long', year: 'numeric' });
  }, []);

  const availableMonths = useMemo(() => {
    const monthsSet = new Set<string>();
    transactions.forEach(tx => {
      if (tx.month) monthsSet.add(tx.month.trim());
    });
    monthsSet.add(currentMonthName);
    return Array.from(monthsSet).sort((a, b) => {
      const dateA = new Date(a);
      const dateB = new Date(b);
      return dateB.getTime() - dateA.getTime();
    });
  }, [transactions, currentMonthName]);

  const [selectedMonth, setSelectedMonth] = useState<string>(availableMonths[0] || currentMonthName);

  const activeBudget = useMemo(() => {
    return budgets.find(b => b.month === selectedMonth) || {
      month: selectedMonth,
      limits: { groceries: 0, vegetables: 0, fishEgg: 0, chicken: 0, houseRent: 0, electricity: 0, water: 0, travel: 0, others: 0 }
    };
  }, [budgets, selectedMonth]);

  const currentMonthTransactions = useMemo(() => {
    return transactions
      .filter(tx => tx.month?.trim() === selectedMonth)
      .sort((a, b) => a.date.localeCompare(b.date) || a.timestamp.localeCompare(b.timestamp));
  }, [transactions, selectedMonth]);

  const categorySpending = useMemo(() => {
    const totals = { groceries: 0, vegetables: 0, fishEgg: 0, chicken: 0, houseRent: 0, electricity: 0, water: 0, travel: 0, others: 0 };
    currentMonthTransactions.forEach(tx => {
      totals.groceries += Number(tx.groceries) || 0;
      totals.vegetables += Number(tx.vegetables) || 0;
      totals.fishEgg += Number(tx.fishEgg) || 0;
      totals.chicken += Number(tx.chicken) || 0;
      totals.houseRent += Number(tx.houseRent) || 0;
      totals.electricity += Number(tx.electricity) || 0;
      totals.water += Number(tx.water) || 0;
      totals.travel += Number(tx.travel) || 0;
      totals.others += Number(tx.others) || 0;
    });
    return totals;
  }, [currentMonthTransactions]);

  const filteredStats = useMemo(() => {
    const sorted = [...currentMonthTransactions].sort((a, b) => a.date.localeCompare(b.date) || a.timestamp.localeCompare(b.timestamp));
    const totalSpent = currentMonthTransactions.reduce((sum, tx) => {
      const txExp = Number(tx.groceries || 0) + Number(tx.vegetables || 0) + Number(tx.fishEgg || 0) + 
                    Number(tx.chicken || 0) + Number(tx.houseRent || 0) + Number(tx.electricity || 0) + 
                    Number(tx.water || 0) + Number(tx.travel || 0) + Number(tx.others || 0);
      return sum + txExp;
    }, 0);
    const firstTx = sorted[0];
    const initialBF = firstTx ? (Number(firstTx.broughtForward) || 0) : 0;
    const totalDailyCash = currentMonthTransactions.reduce((sum, tx) => sum + (Number(tx.dailyCash) || 0), 0);
    const totalAvailableFunds = initialBF + totalDailyCash;
    const currentNetBalance = totalAvailableFunds - totalSpent;
    return { totalSpent, totalReceived: totalAvailableFunds, lastBalance: currentNetBalance };
  }, [currentMonthTransactions]);

  const handleEdit = (tx: Transaction) => {
    setEditingTransaction(tx);
    setShowAddForm(true);
  };

  const handleSaveBudget = async (limits: MonthlyBudget['limits']) => {
    await storageService.saveBudget(selectedMonth, limits);
    const updated = await storageService.fetchBudgets();
    setBudgets(updated);
    setShowBudgetForm(false);
  };

  const upcomingBillAlerts = useMemo(() => {
    return notifications
      .filter(n => n.type === 'bill' && !n.read)
      .sort((a, b) => {
        const priorityMap = { high: 0, medium: 1, low: 2 };
        return (priorityMap[a.priority] || 3) - (priorityMap[b.priority] || 3);
      })
      .slice(0, 3);
  }, [notifications]);

  // Determine true recent transactions (latest dates/times across entire history)
  const recentTransactions = useMemo(() => {
    return [...transactions]
      .sort((a, b) => b.date.localeCompare(a.date) || b.timestamp.localeCompare(a.timestamp))
      .slice(0, 5);
  }, [transactions]);

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row items-center justify-between gap-4 bg-white dark:bg-slate-900 p-4 rounded-3xl border border-slate-100 dark:border-slate-800 shadow-sm no-print transition-colors">
        <div className="flex items-center gap-3 w-full sm:w-auto">
          <div className="p-2 bg-indigo-50 dark:bg-indigo-900/30 rounded-xl">
            <Calendar className="w-5 h-5 text-indigo-600 dark:text-indigo-400" />
          </div>
          <div className="flex-grow">
            <h2 className="text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest leading-none mb-1">{t.selectMonth}</h2>
            <select 
              value={selectedMonth}
              onChange={(e) => setSelectedMonth(e.target.value)}
              className="bg-transparent font-bold text-lg text-slate-800 dark:text-slate-100 outline-none cursor-pointer hover:text-indigo-600 dark:hover:text-indigo-400 transition-colors"
            >
              {availableMonths.map(m => (
                <option key={m} value={m} className="bg-white dark:bg-slate-900">{m}</option>
              ))}
            </select>
          </div>
        </div>

        <div className="flex items-center gap-2 w-full sm:w-auto">
          <button 
            onClick={() => setShowBudgetForm(true)}
            className="flex-1 sm:flex-none flex items-center justify-center gap-2 px-4 py-3 bg-white dark:bg-slate-900 text-indigo-600 dark:text-indigo-400 rounded-2xl font-bold hover:bg-indigo-50 dark:hover:bg-indigo-900/20 transition-all border border-indigo-100 dark:border-indigo-900 shadow-sm active:scale-95"
          >
            <Target className="w-5 h-5" />
            <span className="sm:inline">{t.manageBudget}</span>
          </button>
          <button 
            onClick={() => setShowAddForm(true)}
            className="flex-1 sm:flex-none bg-indigo-600 text-white px-6 py-3 rounded-2xl font-bold flex items-center justify-center gap-2 shadow-lg shadow-indigo-200 dark:shadow-none hover:bg-indigo-700 active:scale-95 transition-all"
          >
            <Plus className="w-5 h-5" />
            <span className="sm:inline">{t.addRecord}</span>
          </button>
        </div>
      </div>

      {activeTab === 'dashboard' && (
        <>
          {upcomingBillAlerts.length > 0 && (
            <div className="animate-in slide-in-from-top-4 duration-500">
              <div className="bg-indigo-600 text-white p-4 rounded-3xl shadow-xl shadow-indigo-200 dark:shadow-none flex flex-col md:flex-row items-center justify-between gap-4 overflow-hidden relative">
                <div className="absolute top-0 right-0 p-4 opacity-10">
                  <Clock className="w-24 h-24 rotate-12" />
                </div>
                <div className="flex items-center gap-4 relative z-10">
                  <div className="p-3 bg-white/20 rounded-2xl">
                    <Calendar className="w-6 h-6" />
                  </div>
                  <div>
                    <h3 className="font-black text-lg leading-tight uppercase tracking-tight">{t.dueSoon}</h3>
                    <div className="flex flex-wrap gap-x-4 gap-y-1">
                      {upcomingBillAlerts.map((n, i) => (
                        <span key={n.id} className="text-sm font-medium flex items-center gap-1.5 text-white/90">
                          <span className={`w-2 h-2 rounded-full ${n.priority === 'high' ? 'bg-rose-400 animate-pulse' : (n.priority === 'medium' ? 'bg-amber-400' : 'bg-sky-400')}`} />
                          {n.title}: {n.message}
                        </span>
                      ))}
                    </div>
                  </div>
                </div>
                <button 
                   onClick={() => setActiveTab?.('bills')}
                   className="relative z-10 bg-white/20 hover:bg-white/30 text-white px-4 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all backdrop-blur-sm"
                >
                  Manage Bills
                </button>
              </div>
            </div>
          )}

          <StatsOverview t={t} stats={filteredStats} formatCurrency={formatCurrency} />

          <div className="mt-8 bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-100 dark:border-slate-800 shadow-sm transition-colors">
            <div className="flex items-center justify-between mb-6">
               <div className="flex items-center gap-3">
                 <div className="p-2 bg-emerald-50 dark:bg-emerald-900/20 rounded-xl text-emerald-600 dark:text-emerald-400">
                    <Target className="w-6 h-6" />
                 </div>
                 <h2 className="text-xl font-bold text-slate-800 dark:text-slate-100">{t.budgetStatus}</h2>
               </div>
               <div className="text-[10px] text-slate-400 dark:text-slate-500 font-black uppercase tracking-widest">{selectedMonth}</div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-x-8 gap-y-6">
              {[
                { key: 'groceries', label: t.groceries },
                { key: 'vegetables', label: t.vegetables },
                { key: 'fishEgg', label: t.fishEgg },
                { key: 'chicken', label: t.chicken },
                { key: 'houseRent', label: t.houseRent },
                { key: 'electricity', label: t.electricity },
                { key: 'water', label: t.water },
                { key: 'travel', label: t.travel },
                { key: 'others', label: t.others },
              ].map(({ key, label }) => {
                const limit = (activeBudget.limits as any)[key] || 0;
                const spent = (categorySpending as any)[key] || 0;
                const percent = limit > 0 ? (spent / limit) * 100 : 0;
                const remaining = limit - spent;

                let barColor = "bg-indigo-500";
                if (percent >= 100) barColor = "bg-rose-500";
                else if (percent >= 80) barColor = "bg-amber-500";

                return (
                  <div key={key} className="space-y-2">
                    <div className="flex justify-between items-end gap-2">
                      <span className="text-xs font-bold text-slate-700 dark:text-slate-300 truncate">{label}</span>
                      <div className="text-right shrink-0">
                        <span className={`text-[10px] font-black uppercase tracking-tighter ${percent > 100 ? 'text-rose-500' : 'text-slate-400 dark:text-slate-500'}`}>
                          {formatCurrency(spent)} / {limit > 0 ? formatCurrency(limit) : '---'}
                        </span>
                      </div>
                    </div>
                    <div className="h-2 w-full bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden transition-colors">
                      <div 
                        className={`h-full transition-all duration-500 ${barColor}`} 
                        style={{ width: `${Math.min(percent, 100)}%` }}
                      ></div>
                    </div>
                    <div className="flex justify-between text-[10px] font-black uppercase tracking-tight">
                       {limit > 0 ? (
                         remaining >= 0 ? (
                           <span className="text-emerald-500 dark:text-emerald-400 truncate">{t.remaining}: {formatCurrency(remaining)}</span>
                         ) : (
                           <span className="text-rose-500 flex items-center gap-1 truncate">
                             <AlertCircle className="w-3 h-3" />
                             {t.overspent}: {formatCurrency(Math.abs(remaining))}
                           </span>
                         )
                       ) : (
                         <span className="text-slate-300 dark:text-slate-700">Not set</span>
                       )}
                       <span className="text-slate-400 dark:text-slate-500 ml-2">{Math.round(percent)}%</span>
                    </div>
                  </div>
                );
              })}
            </div>
