                <td className="px-3 py-4 text-center tabular-nums text-slate-500">{tx.groceries || '-'}</td>
                <td className="px-3 py-4 text-center tabular-nums text-slate-500">{tx.vegetables || '-'}</td>
                <td className="px-3 py-4 text-center tabular-nums text-slate-500">{tx.fishEgg || '-'}</td>
                <td className="px-3 py-4 text-center tabular-nums text-slate-500">{tx.chicken || '-'}</td>
                <td className="px-3 py-4 text-center tabular-nums text-slate-500">{tx.houseRent || '-'}</td>
                <td className="px-3 py-4 text-center tabular-nums text-slate-500">{tx.electricity || '-'}</td>
                <td className="px-3 py-4 text-center tabular-nums text-slate-500">{tx.water || '-'}</td>
                <td className="px-3 py-4 text-center tabular-nums text-slate-500">{tx.travel || '-'}</td>
                <td className="px-3 py-4 text-center tabular-nums text-slate-500">{tx.others || '-'}</td>

                <td className="px-6 py-4 text-center tabular-nums text-rose-500 font-bold bg-rose-50/10 dark:bg-rose-950/5">
                  {formatCurrency(Number(tx.totalExpenses))}
                </td>
                <td className="px-6 py-4 text-center tabular-nums text-indigo-600 dark:text-indigo-400 font-black bg-indigo-50/10 dark:bg-indigo-900/5">
