export default Dashboard;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { Transaction, Language, CurrencySettings, Notification, MonthlyBudget, Bill } from './types';
import { translations } from './translations';
import { storageService } from './services/googleSheets';
import Dashboard from './components/Dashboard';
import SettingsPage from './components/SettingsPage';
import NotificationDrawer from './components/NotificationDrawer';
import BillManager from './components/BillManager';
import { Globe, Wallet, LayoutDashboard, History, BarChart3, Target, Settings, Bell, CreditCard, Sun, Moon } from 'lucide-react';

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>('en');
  const [isDark, setIsDark] = useState(() => localStorage.getItem('theme') === 'dark');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'analytics' | 'history' | 'budget' | 'settings' | 'bills'>('dashboard');
  const [isLoading, setIsLoading] = useState(false);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [isNotificationOpen, setIsNotificationOpen] = useState(false);
  const [currencySettings, setCurrencySettings] = useState<CurrencySettings>({
    symbol: 'LKR',
    position: 'before'
  });

  const t = translations[lang];

  useEffect(() => {
    if (isDark) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [isDark]);

  const formatCurrency = useCallback((amount: number) => {
    const formattedAmount = amount.toLocaleString();
    return currencySettings.position === 'before' 
      ? `${currencySettings.symbol} ${formattedAmount}`
      : `${formattedAmount} ${currencySettings.symbol}`;
  }, [currencySettings]);

  // Calculate the absolute latest balance from all transactions
  const latestBalance = useMemo(() => {
    if (transactions.length === 0) return 0;
    // Sort by date and then by timestamp to find the actual last record
    const sorted = [...transactions].sort((a, b) => {
      const dateDiff = a.date.localeCompare(b.date);
      if (dateDiff !== 0) return dateDiff;
      return a.timestamp.localeCompare(b.timestamp);
    });
    return Number(sorted[sorted.length - 1].totalBalance) || 0;
  }, [transactions]);

  const generateNotifications = useCallback(async (txs: Transaction[]) => {
    const budgets = await storageService.fetchBudgets();
    const bills = await storageService.fetchBills();
    const now = new Date();
    const currentMonthLabel = now.toLocaleString('en-US', { month: 'long', year: 'numeric' });
    const currentMonthTxs = txs.filter(tx => tx.month === currentMonthLabel);
    const budget = budgets.find(b => b.month === currentMonthLabel);
    const newNotifications: Notification[] = [];

    // 1. Budget Alerts
    if (budget) {
      const categories = ['groceries', 'vegetables', 'fishEgg', 'chicken', 'houseRent', 'electricity', 'water', 'travel', 'others'];
      categories.forEach(cat => {
        const limit = (budget.limits as any)[cat];
        const spent = currentMonthTxs.reduce((sum, tx) => sum + ((tx as any)[cat] || 0), 0);
        if (limit > 0 && spent / limit >= 0.85) {
          newNotifications.push({
            id: `budget-${cat}-${currentMonthLabel}`,
            type: 'budget',
            title: t.lowBudgetAlert,
            message: t.lowBudgetMsg.replace('{percent}', Math.round((spent/limit)*100).toString()).replace('{category}', (t as any)[cat]),
            timestamp: now.toISOString(),
            read: false,
            priority: spent >= limit ? 'high' : 'medium'
          });
        }
      });
    }

    // 2. Bill Due Date System
    bills.forEach(bill => {
      const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
      let dueDate = new Date(now.getFullYear(), now.getMonth(), bill.dueDay);
      if (dueDate < today) {
        dueDate = new Date(now.getFullYear(), now.getMonth() + 1, bill.dueDay);
      }
      const diffTime = dueDate.getTime() - today.getTime();
      const daysLeft = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

      if (daysLeft >= 0 && daysLeft <= 7) {
        newNotifications.push({
          id: `bill-${bill.id}-${dueDate.toISOString().split('T')[0]}`,
          type: 'bill',
          title: bill.name,
          message: daysLeft === 0 ? t.dueToday : t.billDueIn.replace('{days}', daysLeft.toString()),
          timestamp: now.toISOString(),
          read: false,
          priority: daysLeft === 0 ? 'high' : (daysLeft <= 3 ? 'medium' : 'low')
        });
      }
    });

    setNotifications(prev => {
      const existingIds = new Set(prev.map(n => n.id));
      const added = newNotifications.filter(n => !existingIds.has(n.id));
      return [...added, ...prev].slice(0, 30);
    });
  }, [t]);

  const loadData = useCallback(async () => {
    setIsLoading(true);
    try {
      const data = await storageService.fetchTransactions();
      setTransactions(data);
      await generateNotifications(data);

      const savedLang = localStorage.getItem('lang');
      if (savedLang) setLang(savedLang as Language);

      const savedCurrency = localStorage.getItem('currency_settings');
      if (savedCurrency) setCurrencySettings(JSON.parse(savedCurrency));
    } catch (err) {
      console.error("Failed to load data", err);
    } finally {
      setIsLoading(false);
    }
  }, [generateNotifications]);

  const onAddTransaction = useCallback(async (data: Transaction) => {
    // Check if a transaction for this date already exists
    const existing = transactions.find(tx => tx.date === data.date);

    if (existing && existing.id) {
      // Aggregate logic: merge the data into the existing record
      const merged: Transaction = {
        ...existing,
        groceries: (existing.groceries || 0) + (data.groceries || 0),
        vegetables: (existing.vegetables || 0) + (data.vegetables || 0),
        fishEgg: (existing.fishEgg || 0) + (data.fishEgg || 0),
        chicken: (existing.chicken || 0) + (data.chicken || 0),
        houseRent: (existing.houseRent || 0) + (data.houseRent || 0),
        electricity: (existing.electricity || 0) + (data.electricity || 0),
        water: (existing.water || 0) + (data.water || 0),
        travel: (existing.travel || 0) + (data.travel || 0),
        others: (existing.others || 0) + (data.others || 0),
        dailyCash: (existing.dailyCash || 0) + (data.dailyCash || 0),
        // Keep original Brought Forward for the day
        broughtForward: existing.broughtForward,
        timestamp: new Date().toISOString()
      };

      // Recalculate totals for the merged record
      const totalExpenses = 
        merged.groceries + merged.vegetables + merged.fishEgg + merged.chicken + 
        merged.houseRent + merged.electricity + merged.water + merged.travel + merged.others;

      merged.totalExpenses = totalExpenses;
      merged.totalBalance = (merged.broughtForward || 0) + (merged.dailyCash || 0) - totalExpenses;

      await storageService.updateTransaction(existing.id, merged);
    } else {
      // Proceed with normal addition
      await storageService.addTransaction(data);
    }

    loadData();
  }, [transactions, loadData]);

  const onUpdateTransaction = useCallback(async (id: string, data: Transaction) => {
    await storageService.updateTransaction(id, data);
    loadData();
  }, [loadData]);

  const onDeleteTransaction = useCallback(async (id: string) => {
    if (window.confirm(t.confirmDelete)) {
      await storageService.deleteTransaction(id);
      loadData();
    }
  }, [loadData, t.confirmDelete]);

  useEffect(() => {
    loadData();
  }, [loadData]);

  return (
    <div className="min-h-screen bg-slate-50 dark:bg-slate-950 pb-20 md:pb-0 font-sans transition-colors duration-300">
      <nav className="hidden md:flex flex-col fixed h-full w-64 bg-white dark:bg-slate-900 border-r border-slate-200 dark:border-slate-800 p-6 z-20 no-print transition-colors">
        <div className="flex items-center gap-3 mb-10">
          <div className="p-2 bg-indigo-600 rounded-xl shadow-lg shadow-indigo-200 dark:shadow-none">
            <Wallet className="w-6 h-6 text-white" />
          </div>
          <h1 className="font-bold text-lg text-slate-800 dark:text-slate-100 leading-tight">{t.title}</h1>
        </div>

        <div className="space-y-2 flex-grow">
          {[
            { id: 'dashboard', label: t.dashboard, icon: LayoutDashboard },
            { id: 'analytics', label: t.charts, icon: BarChart3 },
            { id: 'budget', label: t.budgetPerformance, icon: Target },
            { id: 'bills', label: t.bills, icon: CreditCard },
            { id: 'history', label: t.history, icon: History },
          ].map(tab => (
            <button 
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium transition-all ${activeTab === tab.id ? 'bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400 shadow-sm' : 'text-slate-500 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800 hover:text-slate-800 dark:hover:text-slate-200'}`}
            >
              <tab.icon className="w-5 h-5" />
              {tab.label}
            </button>
          ))}
        </div>

        <div className="mt-auto space-y-2 border-t border-slate-100 dark:border-slate-800 pt-6">
          <button onClick={() => setIsDark(!isDark)} className="w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium text-slate-500 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800 transition-all">
            {isDark ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
            {isDark ? t.lightMode : t.darkMode}
          </button>
          <button onClick={() => setActiveTab('settings')} className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium transition-all ${activeTab === 'settings' ? 'bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400 shadow-sm' : 'text-slate-500 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800 hover:text-slate-800 dark:hover:text-slate-200'}`}>
            <Settings className="w-5 h-5" />
            {t.settings}
          </button>
          <button onClick={() => setLang(lang === 'en' ? 'si' : 'en')} className="w-full flex items-center gap-3 px-4 py-3 text-slate-500 dark:text-slate-400 hover:text-indigo-600 dark:hover:text-indigo-400 font-medium transition-colors">
            <Globe className="w-5 h-5" />
            {t.language}
          </button>
        </div>
      </nav>

      <header className="md:hidden bg-white dark:bg-slate-900 border-b border-slate-200 dark:border-slate-800 px-4 py-3 flex items-center justify-between sticky top-0 z-30 no-print transition-colors">
        <div className="flex items-center gap-2">
          <Wallet className="w-6 h-6 text-indigo-600 dark:text-indigo-400" />
          <h1 className="font-bold text-sm text-slate-800 dark:text-slate-100">{t.title}</h1>
        </div>
        <div className="flex items-center gap-2">
          <button onClick={() => setIsNotificationOpen(true)} className="p-2 relative text-slate-500 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-lg">
            <Bell className="w-5 h-5" />
            {notifications.filter(n => !n.read).length > 0 && <span className="absolute top-1 right-1 w-2 h-2 bg-rose-500 rounded-full"></span>}
          </button>
          <button onClick={() => setIsDark(!isDark)} className="p-2 text-slate-500 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-lg">
            {isDark ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
          </button>
        </div>
      </header>

      <main className="md:pl-64 min-h-screen">
        <div className="max-w-6xl mx-auto p-4 md:p-8">
          {activeTab === 'settings' && (
            <SettingsPage 
              t={t} 
              settings={currencySettings} 
              isDark={isDark}
              onToggleDark={() => setIsDark(!isDark)}
              onSave={(s) => { setCurrencySettings(s); localStorage.setItem('currency_settings', JSON.stringify(s)); }} 
            />
          )}
          {activeTab === 'bills' && <BillManager t={t} formatCurrency={formatCurrency} transactions={transactions} onRefresh={loadData} />}
          {activeTab !== 'settings' && activeTab !== 'bills' && (
            <Dashboard 
              activeTab={activeTab} 
              setActiveTab={setActiveTab}
              t={t} 
              transactions={transactions} 
              onAdd={onAddTransaction}
              onUpdate={onUpdateTransaction}
              onDelete={onDeleteTransaction}
              onRefresh={loadData}
              isLoading={isLoading}
              formatCurrency={formatCurrency}
              notifications={notifications}
              latestBalance={latestBalance}
            />
          )}
        </div>
      </main>

      <NotificationDrawer 
        isOpen={isNotificationOpen} 
        onClose={() => setIsNotificationOpen(false)} 
        notifications={notifications}
        onRead={(id) => setNotifications(prev => prev.map(n => n.id === id ? {...n, read: true} : n))}
        onReadAll={() => setNotifications(prev => prev.map(n => ({...n, read: true})))}
        t={t}
      />
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { Transaction, MonthlyBudget, Notification } from '../types';
import TransactionForm from './TransactionForm';
import StatsOverview from './StatsOverview';
import MonthlyCharts from './MonthlyCharts';
import HistoryTable from './HistoryTable';
import BudgetManager from './BudgetManager';
import BudgetPerformance from './BudgetPerformance';
import { 
  Plus, X, Calendar, BarChart3, ClipboardList, ArrowRight, Target, 
  AlertCircle, Clock, History, BellRing, TriangleAlert, Zap, 
  CheckCircle2, ArrowRightCircle, ShoppingBag, Leaf, Fish, 
  Drumstick, Home, Droplets, Car, PlusCircle, LayoutGrid
} from 'lucide-react';
import { storageService } from '../services/googleSheets';

interface DashboardProps {
  activeTab: 'dashboard' | 'analytics' | 'history' | 'budget' | 'bills' | 'settings';
  setActiveTab?: (tab: 'dashboard' | 'analytics' | 'history' | 'budget' | 'bills' | 'settings') => void;
  t: any;
  transactions: Transaction[];
  onAdd: (data: Transaction) => void;
  onUpdate: (id: string, data: Transaction) => void;
  onDelete: (id: string) => void;
  onRefresh: () => void;
  isLoading: boolean;
  formatCurrency: (amount: number) => string;
  notifications?: Notification[];
  latestBalance?: number;
}

const Dashboard: React.FC<DashboardProps> = ({ 
  activeTab, 
  setActiveTab,
  t, 
  transactions, 
  onAdd, 
  onUpdate,
  onDelete,
  onRefresh,
  isLoading,
  formatCurrency,
  notifications = [],
  latestBalance = 0
}) => {
  const [showAddForm, setShowAddForm] = useState(false);
  const [showBudgetForm, setShowBudgetForm] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [budgets, setBudgets] = useState<MonthlyBudget[]>([]);

  useEffect(() => {
    const loadBudgets = async () => {
      const data = await storageService.fetchBudgets();
      setBudgets(data);
    };
    loadBudgets();
  }, [transactions]);

  const currentMonthName = useMemo(() => {
    return new Date().toLocaleString('en-US', { month: 'long', year: 'numeric' });
  }, []);

  const availableMonths = useMemo(() => {
    const monthsSet = new Set<string>();
    transactions.forEach(tx => {
      if (tx.month) monthsSet.add(tx.month.trim());
    });
    monthsSet.add(currentMonthName);
    return Array.from(monthsSet).sort((a, b) => {
      const dateA = new Date(a);
      const dateB = new Date(b);
      return dateB.getTime() - dateA.getTime();
    });
  }, [transactions, currentMonthName]);

  const [selectedMonth, setSelectedMonth] = useState<string>(availableMonths[0] || currentMonthName);

  const activeBudget = useMemo(() => {
    return budgets.find(b => b.month === selectedMonth) || {
      month: selectedMonth,
      limits: { groceries: 0, vegetables: 0, fishEgg: 0, chicken: 0, houseRent: 0, electricity: 0, water: 0, travel: 0, others: 0 }
    };
  }, [budgets, selectedMonth]);

  const currentMonthTransactions = useMemo(() => {
    return transactions
      .filter(tx => tx.month?.trim() === selectedMonth)
      .sort((a, b) => a.date.localeCompare(b.date) || a.timestamp.localeCompare(b.timestamp));
  }, [transactions, selectedMonth]);

  // Category Totals for Quick-View
  const categorySummary = useMemo(() => {
    const categories = [
      { key: 'groceries', label: t.groceries, icon: ShoppingBag, color: 'text-indigo-500', bg: 'bg-indigo-50 dark:bg-indigo-900/20' },
      { key: 'vegetables', label: t.vegetables, icon: Leaf, color: 'text-emerald-500', bg: 'bg-emerald-50 dark:bg-emerald-900/20' },
      { key: 'fishEgg', label: t.fishEgg, icon: Fish, color: 'text-blue-500', bg: 'bg-blue-50 dark:bg-blue-900/20' },
      { key: 'chicken', label: t.chicken, icon: Drumstick, color: 'text-orange-500', bg: 'bg-orange-50 dark:bg-orange-900/20' },
      { key: 'houseRent', label: t.houseRent, icon: Home, color: 'text-rose-500', bg: 'bg-rose-50 dark:bg-rose-900/20' },
      { key: 'electricity', label: t.electricity, icon: Zap, color: 'text-yellow-500', bg: 'bg-yellow-50 dark:bg-yellow-900/20' },
      { key: 'water', label: t.water, icon: Droplets, color: 'text-cyan-500', bg: 'bg-cyan-50 dark:bg-cyan-900/20' },
      { key: 'travel', label: t.travel, icon: Car, color: 'text-purple-500', bg: 'bg-purple-50 dark:bg-purple-900/20' },
      { key: 'others', label: t.others, icon: PlusCircle, color: 'text-slate-500', bg: 'bg-slate-50 dark:bg-slate-800/50' },
    ];

    return categories.map(cat => {
      const total = currentMonthTransactions.reduce((sum, tx) => sum + (Number((tx as any)[cat.key]) || 0), 0);
      const limit = (activeBudget.limits as any)[cat.key] || 0;
      return { ...cat, total, limit };
    });
  }, [currentMonthTransactions, activeBudget, t]);

  // Real-time Budget Health Calculation
  const budgetHealth = useMemo(() => {
    const issues = categorySummary
      .filter(cat => cat.limit > 0 && (cat.total / cat.limit) * 100 >= 80)
      .map(cat => ({
        category: cat.key,
        label: cat.label,
        spent: cat.total,
        limit: cat.limit,
        percentage: (cat.total / cat.limit) * 100,
        status: (cat.total / cat.limit) * 100 >= 100 ? 'over' : 'warning'
      }));

    return issues.sort((a, b) => b.percentage - a.percentage);
  }, [categorySummary]);

  const filteredStats = useMemo(() => {
    const totalSpent = currentMonthTransactions.reduce((sum, tx) => sum + (Number(tx.totalExpenses) || 0), 0);
    const sorted = [...currentMonthTransactions].sort((a, b) => a.date.localeCompare(b.date) || a.timestamp.localeCompare(b.timestamp));
    const firstTx = sorted[0];
    const initialBF = firstTx ? (Number(firstTx.broughtForward) || 0) : 0;
    const totalDailyCash = currentMonthTransactions.reduce((sum, tx) => sum + (Number(tx.dailyCash) || 0), 0);
    const totalAvailableFunds = initialBF + totalDailyCash;
    const currentNetBalance = totalAvailableFunds - totalSpent;
    return { totalSpent, totalReceived: totalAvailableFunds, lastBalance: currentNetBalance };
  }, [currentMonthTransactions]);

  const recentTransactions = useMemo(() => {
    return [...transactions]
      .sort((a, b) => b.date.localeCompare(a.date) || b.timestamp.localeCompare(a.timestamp))
      .slice(0, 5);
  }, [transactions]);

  const activeAlerts = useMemo(() => {
    return notifications
      .filter(n => (n.type === 'bill' || n.type === 'budget') && !n.read)
      .sort((a, b) => {
        const priorityMap = { high: 0, medium: 1, low: 2 };
        return (priorityMap[a.priority] || 3) - (priorityMap[b.priority] || 3);
      })
      .slice(0, 3);
  }, [notifications]);

  const handleEdit = (tx: Transaction) => {
    setEditingTransaction(tx);
    setShowAddForm(true);
  };

  const handleSaveBudget = async (limits: MonthlyBudget['limits']) => {
    await storageService.saveBudget(selectedMonth, limits);
    const updated = await storageService.fetchBudgets();
    setBudgets(updated);
    setShowBudgetForm(false);
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row items-center justify-between gap-4 bg-white dark:bg-slate-900 p-4 rounded-3xl border border-slate-100 dark:border-slate-800 shadow-sm no-print transition-colors">
        <div className="flex items-center gap-3 w-full sm:w-auto">
          <div className="p-2 bg-indigo-50 dark:bg-indigo-900/30 rounded-xl">
            <Calendar className="w-5 h-5 text-indigo-600 dark:text-indigo-400" />
          </div>
          <div className="flex-grow">
            <h2 className="text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest leading-none mb-1">{t.selectMonth}</h2>
            <select 
              value={selectedMonth}
              onChange={(e) => setSelectedMonth(e.target.value)}
              className="bg-transparent font-bold text-lg text-slate-800 dark:text-slate-100 outline-none cursor-pointer hover:text-indigo-600 dark:hover:text-indigo-400 transition-colors"
            >
              {availableMonths.map(m => (
                <option key={m} value={m} className="bg-white dark:bg-slate-900">{m}</option>
              ))}
            </select>
          </div>
        </div>

        <div className="flex items-center gap-2 w-full sm:w-auto">
          <button 
            onClick={() => setShowBudgetForm(true)}
            className="flex-1 sm:flex-none flex items-center justify-center gap-2 px-4 py-3 bg-white dark:bg-slate-900 text-indigo-600 dark:text-indigo-400 rounded-2xl font-bold hover:bg-indigo-50 dark:hover:bg-indigo-900/20 transition-all border border-indigo-100 dark:border-indigo-900 shadow-sm active:scale-95"
          >
            <Target className="w-5 h-5" />
            <span className="sm:inline">{t.manageBudget}</span>
          </button>
          <button 
            onClick={() => setShowAddForm(true)}
            className="flex-1 sm:flex-none bg-indigo-600 text-white px-6 py-3 rounded-2xl font-bold flex items-center justify-center gap-2 shadow-lg shadow-indigo-200 dark:shadow-none hover:bg-indigo-700 active:scale-95 transition-all"
          >
            <Plus className="w-5 h-5" />
            <span className="sm:inline">{t.addRecord}</span>
          </button>
        </div>
      </div>

      {activeTab === 'dashboard' && (
        <>
          {/* Enhanced Budget Watch Banner */}
          {budgetHealth.length > 0 && (
            <div className="animate-in slide-in-from-top-4 duration-500">
              <div className="bg-white dark:bg-slate-900 p-5 rounded-3xl shadow-sm border border-slate-100 dark:border-slate-800 relative overflow-hidden transition-colors">
                <div className={`absolute top-0 left-0 bottom-0 w-1.5 ${budgetHealth.some(h => h.status === 'over') ? 'bg-rose-500 animate-pulse' : 'bg-amber-500'}`} />
                <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                  <div className="flex items-center gap-4">
                    <div className={`p-3 rounded-2xl ${budgetHealth.some(h => h.status === 'over') ? 'bg-rose-50 dark:bg-rose-900/20 text-rose-600' : 'bg-amber-50 dark:bg-amber-900/20 text-amber-600'}`}>
                      {budgetHealth.some(h => h.status === 'over') ? <TriangleAlert className="w-6 h-6" /> : <Zap className="w-6 h-6" />}
                    </div>
                    <div>
                      <h3 className="text-sm font-black text-slate-800 dark:text-slate-100 uppercase tracking-tight">Budget Attention Needed</h3>
                      <div className="flex flex-wrap gap-2 mt-1">
                        {budgetHealth.slice(0, 3).map((h, i) => (
                          <span key={i} className={`text-[10px] font-bold px-2 py-0.5 rounded-full ${h.status === 'over' ? 'bg-rose-100 text-rose-600 dark:bg-rose-900/40' : 'bg-amber-100 text-amber-600 dark:bg-amber-900/40'}`}>
                            {h.label}: {h.percentage.toFixed(0)}%
                          </span>
                        ))}
                      </div>
                    </div>
                  </div>
                  <button 
                    onClick={() => setActiveTab?.('budget')}
                    className="flex items-center gap-2 text-xs font-bold text-indigo-600 dark:text-indigo-400 hover:text-indigo-700 transition-colors bg-indigo-50 dark:bg-indigo-900/30 px-3 py-1.5 rounded-xl shrink-0"
                  >
                    Analysis
                    <ArrowRightCircle className="w-3.5 h-3.5" />
                  </button>
                </div>
              </div>
            </div>
          )}

          {activeAlerts.length > 0 && !budgetHealth.length && (
            <div className="animate-in slide-in-from-top-4 duration-500">
              <div className="bg-indigo-600 text-white p-4 rounded-3xl shadow-xl shadow-indigo-200 dark:shadow-none flex flex-col md:flex-row items-center justify-between gap-4 overflow-hidden relative">
                <div className="absolute top-0 right-0 p-4 opacity-10">
                  <BellRing className="w-24 h-24 rotate-12" />
                </div>
                <div className="flex items-center gap-4 relative z-10">
                  <div className="p-3 bg-white/20 rounded-2xl">
                    <AlertCircle className="w-6 h-6" />
                  </div>
                  <div>
                    <h3 className="font-black text-lg leading-tight uppercase tracking-tight">Active Notifications</h3>
                    <div className="flex flex-col gap-1 mt-1">
                      {activeAlerts.map((n) => (
                        <span key={n.id} className="text-sm font-medium flex items-center gap-2 text-white/90">
                          <span className={`w-2 h-2 rounded-full shrink-0 ${n.priority === 'high' ? 'bg-rose-400 animate-pulse' : (n.priority === 'medium' ? 'bg-amber-400' : 'bg-sky-400')}`} />
                          <span className="font-bold">{n.title}:</span> {n.message}
                        </span>
                      ))}
                    </div>
                  </div>
                </div>
              </div>
            </div>
          )}

          <StatsOverview t={t} stats={filteredStats} formatCurrency={formatCurrency} />

          {/* Enhanced: Category Quick-View Summary with Budget Values */}
          <div className="mt-8 space-y-4">
            <div className="flex items-center gap-2">
              <LayoutGrid className="w-5 h-5 text-indigo-600 dark:text-indigo-400" />
              <h2 className="text-lg font-black text-slate-800 dark:text-slate-100 uppercase tracking-tight">{t.summary}</h2>
            </div>
            <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-5 gap-3">
              {categorySummary.map((cat) => (
                <div key={cat.key} className="bg-white dark:bg-slate-900 p-3 rounded-2xl border border-slate-100 dark:border-slate-800 shadow-sm flex items-center gap-3 transition-all hover:shadow-md group">
                  <div className={`p-2 rounded-xl transition-colors ${cat.bg} shrink-0`}>
                    <cat.icon className={`w-5 h-5 ${cat.color}`} />
                  </div>
                  <div className="min-w-0 flex-grow">
                    <p className="text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest truncate mb-0.5">{cat.label}</p>
                    <div className="flex flex-col">
                      <p className="text-sm font-black text-slate-800 dark:text-slate-100 truncate">{formatCurrency(cat.total)}</p>
                      {cat.limit > 0 && (
                        <p className="text-[9px] font-bold text-slate-400 dark:text-slate-500 truncate mt-0.5">
                          {t.budget}: {formatCurrency(cat.limit)}
                        </p>
                      )}
                    </div>
                    {cat.limit > 0 && (
                      <div className="mt-2 w-full h-1 bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden">
                        <div 
                          className={`h-full transition-all duration-700 ${(cat.total / cat.limit) >= 1 ? 'bg-rose-500' : 'bg-indigo-500'}`}
                          style={{ width: `${Math.min((cat.total / cat.limit) * 100, 100)}%` }}
                        />
                      </div>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </div>

          <div className="mt-10 bg-white dark:bg-slate-900 rounded-3xl border border-slate-100 dark:border-slate-800 shadow-sm overflow-hidden transition-colors">
            <div className="p-6 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between">
              <div className="flex items-center gap-3">
                <ClipboardList className="w-6 h-6 text-indigo-600 dark:text-indigo-400" />
                <h2 className="text-xl font-bold text-slate-800 dark:text-slate-100">{t.recentTransactions}</h2>
              </div>
              <button 
                onClick={() => setActiveTab?.('history')}
                className="flex items-center gap-1 text-sm font-bold text-indigo-600 dark:text-indigo-400 hover:text-indigo-700 dark:hover:text-indigo-300 transition-colors"
              >
                {t.viewAll}
                <ArrowRight className="w-4 h-4" />
              </button>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full text-left min-w-[900px]">
                <thead>
                  <tr className="bg-slate-50 dark:bg-slate-800/50 text-slate-500 dark:text-slate-400 text-[10px] uppercase font-black tracking-widest border-b border-slate-100 dark:border-slate-800">
                    <th className="px-6 py-4">{t.date}</th>
                    <th className="px-6 py-4">{t.broughtForward}</th>
                    <th className="px-6 py-4">{t.dailyCash}</th>
                    <th className="px-6 py-4">{t.totalExpenses}</th>
                    <th className="px-6 py-4 bg-indigo-50/30 dark:bg-indigo-900/10 text-indigo-700 dark:text-indigo-400">{t.totalBalance}</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                  {recentTransactions.map((tx) => (
                    <tr key={tx.id || tx.timestamp} className="hover:bg-slate-50/50 dark:hover:bg-slate-800/50 transition-colors">
                      <td className="px-6 py-4 text-sm font-semibold text-slate-700 dark:text-slate-300">{tx.date.split('-').reverse().join('/')}</td>
                      <td className="px-6 py-4 text-xs font-medium text-slate-400 dark:text-slate-500">{formatCurrency(Number(tx.broughtForward))}</td>
                      <td className="px-6 py-4 text-sm font-bold text-emerald-600 dark:text-emerald-400">{formatCurrency(Number(tx.dailyCash))}</td>
                      <td className="px-6 py-4 text-sm font-bold text-rose-500 dark:text-rose-400">{formatCurrency(Number(tx.totalExpenses))}</td>
                      <td className="px-6 py-4 text-sm font-black text-indigo-600 dark:text-indigo-400 bg-indigo-50/20 dark:bg-indigo-900/5">{formatCurrency(Number(tx.totalBalance))}</td>
                    </tr>
                  ))}
                  {transactions.length === 0 && (
                    <tr>
                      <td colSpan={5} className="px-6 py-12 text-center text-slate-400 dark:text-slate-600 font-medium italic">{t.noData}</td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </>
      )}

      {activeTab === 'analytics' && (
        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div>
            <div className="flex items-center justify-between mb-6">
              <div className="flex items-center gap-3">
                <div className="p-2 bg-indigo-100 dark:bg-indigo-900/30 rounded-xl">
                  <BarChart3 className="w-6 h-6 text-indigo-700 dark:text-indigo-400" />
                </div>
                <h2 className="text-2xl font-black text-slate-800 dark:text-slate-100">{t.charts} - {selectedMonth}</h2>
              </div>
            </div>
            <MonthlyCharts t={t} transactions={currentMonthTransactions} />
          </div>
        </div>
      )}

      {activeTab === 'budget' && (
        <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
          <BudgetPerformance 
            t={t} 
            transactions={transactions} 
            budgets={budgets} 
            formatCurrency={formatCurrency} 
          />
        </div>
      )}

      {activeTab === 'history' && (
        <div className="bg-white dark:bg-slate-900 rounded-3xl shadow-sm border border-slate-100 dark:border-slate-800 overflow-hidden animate-in fade-in slide-in-from-bottom-4 duration-500 transition-colors">
          <div className="p-6 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between no-print">
            <div className="flex items-center gap-3">
               <History className="w-6 h-6 text-indigo-600 dark:text-indigo-400" />
               <h2 className="text-xl font-bold text-slate-800 dark:text-slate-100">{t.history} ({selectedMonth})</h2>
            </div>
          </div>
          <HistoryTable 
            t={t} 
            transactions={currentMonthTransactions} 
            allTransactions={transactions}
            onEdit={handleEdit} 
            onDelete={onDelete} 
            isLoading={isLoading} 
            formatCurrency={formatCurrency}
            budgets={budgets}
          />
        </div>
      )}

      {showAddForm && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 dark:bg-black/70 backdrop-blur-sm no-print">
          <div className="bg-white dark:bg-slate-900 w-full max-w-2xl rounded-3xl shadow-2xl dark:shadow-none overflow-hidden max-h-[90vh] flex flex-col scale-in-center transition-colors">
            <div className="p-6 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between shrink-0">
              <h3 className="text-xl font-bold text-slate-800 dark:text-slate-100">
                {editingTransaction ? t.edit : t.addRecord}
              </h3>
              <button 
                onClick={() => { setShowAddForm(false); setEditingTransaction(null); }}
                className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full transition-colors"
              >
                <X className="w-6 h-6 text-slate-400 dark:text-slate-500" />
              </button>
            </div>
            <div className="p-6 overflow-y-auto">
              <TransactionForm 
                t={t} 
                initialData={editingTransaction}
                latestBalance={latestBalance}
                formatCurrency={formatCurrency}
                onSubmit={(data) => {
                  if (editingTransaction?.id) {
                    onUpdate(editingTransaction.id, data);
                  } else {
                    onAdd(data);
                  }
                  setShowAddForm(false);
                  setEditingTransaction(null);
                }} 
              />
            </div>
          </div>
        </div>
      )}

      {showBudgetForm && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 dark:bg-black/70 backdrop-blur-sm no-print">
          <div className="bg-white dark:bg-slate-900 w-full max-w-lg rounded-3xl shadow-2xl dark:shadow-none overflow-hidden flex flex-col scale-in-center transition-colors max-h-[95vh]">
            <div className="p-6 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between shrink-0">
              <h3 className="text-xl font-bold text-slate-800 dark:text-slate-100">{t.manageBudget}</h3>
              <button 
                onClick={() => setShowBudgetForm(false)}
                className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full transition-colors"
              >
                <X className="w-6 h-6 text-slate-400 dark:text-slate-500" />
              </button>
            </div>
            <div className="p-4 md:p-6 overflow-y-auto">
              <BudgetManager 
                t={t} 
                month={selectedMonth} 
                initialLimits={activeBudget.limits} 
                onSubmit={handleSaveBudget} 
              />
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Dashboard;

import React, { useState, useMemo } from 'react';
import { Transaction, MonthlyBudget } from '../types';
import { Edit2, Trash2, FileSpreadsheet, Printer, Search, X, Calendar as CalendarIcon, Filter, CheckCircle, ArrowRightLeft, TrendingUp, TrendingDown, PieChart, AlertCircle, CheckCircle2 } from 'lucide-react';
import * as XLSX from 'xlsx';

interface HistoryTableProps {
  t: any;
  transactions: Transaction[];
  allTransactions?: Transaction[];
  onEdit: (tx: Transaction) => void;
  onDelete: (id: string) => void;
  isLoading: boolean;
  formatCurrency: (amount: number) => string;
  budgets?: MonthlyBudget[];
}

const HistoryTable: React.FC<HistoryTableProps> = ({ t, transactions, allTransactions, onEdit, onDelete, isLoading, formatCurrency, budgets = [] }) => {
  const [stagedSearch, setStagedSearch] = useState('');
  const [stagedStart, setStagedStart] = useState('');
  const [stagedEnd, setStagedEnd] = useState('');
  const [activeSearch, setActiveSearch] = useState('');
  const [activeStart, setActiveStart] = useState('');
  const [activeEnd, setActiveEnd] = useState('');

  const filteredTransactions = useMemo(() => {
    const lowerSearch = activeSearch.toLowerCase().trim();

    return transactions.filter(tx => {
      if (activeStart && tx.date < activeStart) return false;
      if (activeEnd && tx.date > activeEnd) return false;

      if (lowerSearch) {
        const formattedDate = tx.date.split('-').reverse().join('/'); // dd/mm/yyyy
        if (tx.date.includes(lowerSearch) || formattedDate.includes(lowerSearch)) return true;

        const categories = [
          { key: 'groceries', label: t.groceries },
          { key: 'vegetables', label: t.vegetables },
          { key: 'fishEgg', label: t.fishEgg },
          { key: 'chicken', label: t.chicken },
          { key: 'houseRent', label: t.houseRent },
          { key: 'electricity', label: t.electricity },
          { key: 'water', label: t.water },
          { key: 'travel', label: t.travel },
          { key: 'others', label: t.others },
        ];

        const matchesCategory = categories.some(cat => 
          cat.label.toLowerCase().includes(lowerSearch) && Number((tx as any)[cat.key]) > 0
        );
        if (matchesCategory) return true;

        return (
          tx.totalExpenses.toString().includes(lowerSearch) || 
          tx.dailyCash.toString().includes(lowerSearch) || 
          tx.totalBalance.toString().includes(lowerSearch)
        );
      }
      return true;
    });
  }, [transactions, activeSearch, activeStart, activeEnd, t]);

  const sortedFiltered = useMemo(() => {
    return [...filteredTransactions].sort((a, b) => 
      a.date.localeCompare(b.date) || a.timestamp.localeCompare(b.timestamp)
    );
  }, [filteredTransactions]);

  const summary = useMemo(() => {
    if (sortedFiltered.length === 0) return null;

    const totalIncome = sortedFiltered.reduce((sum, tx) => sum + (Number(tx.dailyCash) || 0), 0);
    const totalExpenses = sortedFiltered.reduce((sum, tx) => sum + (Number(tx.totalExpenses) || 0), 0);
    const startBF = Number(sortedFiltered[0].broughtForward) || 0;
    const endBalance = Number(sortedFiltered[sortedFiltered.length - 1].totalBalance) || 0;

    // Category Totals
    const catKeys = ['groceries', 'vegetables', 'fishEgg', 'chicken', 'houseRent', 'electricity', 'water', 'travel', 'others'];
    const catTotals: Record<string, { actual: number, limit: number }> = {};

    const currentMonthLabel = sortedFiltered[0].month;
    const activeBudget = budgets.find(b => b.month === currentMonthLabel);

    catKeys.forEach(key => {
      catTotals[key] = {
        actual: sortedFiltered.reduce((sum, tx) => sum + (Number((tx as any)[key]) || 0), 0),
        limit: activeBudget ? (activeBudget.limits as any)[key] : 0
      };
    });

    // Budget Comparison
    const budgetAlerts = catKeys.map(key => {
      const { actual: spent, limit } = catTotals[key];
      const isOver = limit > 0 && spent > limit;
      const progress = limit > 0 ? (spent / limit) * 100 : 0;
      return { key, label: (t as any)[key], spent, limit, isOver, progress };
    }).filter(a => a.isOver || (a.limit > 0 && a.progress >= 85));

    return {
      startBF,
      totalIncome,
      totalExpenses,
      endBalance,
      netSavings: totalIncome - totalExpenses,
      catTotals,
      budgetAlerts
    };
  }, [sortedFiltered, budgets, t]);

  const exportAllToExcel = () => {
    const dataToExport = allTransactions || transactions;
    if (dataToExport.length === 0) return;
    const workbook = XLSX.utils.book_new();
    const sortedData = [...dataToExport].sort((a,b) => a.date.localeCompare(b.date) || a.timestamp.localeCompare(b.timestamp));

    // Detailed Transactions Sheet
    const formattedData = sortedData.map(tx => ({
      [t.date]: tx.date,
      [t.broughtForward]: tx.broughtForward,
      [t.dailyCash]: tx.dailyCash,
      [t.groceries]: tx.groceries,
      [t.vegetables]: tx.vegetables,
      [t.fishEgg]: tx.fishEgg,
      [t.chicken]: tx.chicken,
      [t.houseRent]: tx.houseRent,
      [t.electricity]: tx.electricity,
      [t.water]: tx.water,
      [t.travel]: tx.travel,
      [t.others]: tx.others,
      [t.totalExpenses]: tx.totalExpenses,
      [t.totalBalance]: tx.totalBalance,
    }));
    const wsFull = XLSX.utils.json_to_sheet(formattedData);
    XLSX.utils.book_append_sheet(workbook, wsFull, "Transaction Details");

    // Monthly Summary Sheet
    const monthlySummary: any[] = [];
    const months = [...new Set(sortedData.map(tx => tx.month))];
    months.forEach(m => {
      const txsInMonth = sortedData.filter(tx => tx.month === m).sort((a,b) => a.date.localeCompare(b.date) || a.timestamp.localeCompare(b.timestamp));

      const monthIncome = txsInMonth.reduce((acc, curr) => acc + (Number(curr.dailyCash) || 0), 0);
      const monthSpent = txsInMonth.reduce((acc, curr) => acc + (Number(curr.totalExpenses) || 0), 0);
      const startBF = txsInMonth[0] ? txsInMonth[0].broughtForward : 0;
      const endBal = txsInMonth[txsInMonth.length - 1] ? txsInMonth[txsInMonth.length - 1].totalBalance : 0;

      // Category breakdown for summary
      const catTotals: any = {};
      const categories = ['groceries', 'vegetables', 'fishEgg', 'chicken', 'houseRent', 'electricity', 'water', 'travel', 'others'];
      categories.forEach(cat => {
        catTotals[(t as any)[cat]] = txsInMonth.reduce((sum, tx) => sum + (Number((tx as any)[cat]) || 0), 0);
      });

      monthlySummary.push({
        [t.month]: m,
        [t.broughtForward]: startBF,
        [t.totalIncome]: monthIncome,
        [t.totalExpenses]: monthSpent,
        [t.totalBalance]: endBal,
        ...catTotals
      });
    });

    const wsSummary = XLSX.utils.json_to_sheet(monthlySummary);
    XLSX.utils.book_append_sheet(workbook, wsSummary, "Monthly Summary");

    XLSX.writeFile(workbook, `Finance_Report_${new Date().toISOString().split('T')[0]}.xlsx`);
  };

  const clearFilters = () => {
    setStagedSearch(''); setStagedStart(''); setStagedEnd('');
    setActiveSearch(''); setActiveStart(''); setActiveEnd('');
  };

  if (isLoading) return <div className="p-12 text-center text-slate-400">Loading records...</div>;

  return (
    <div className="flex flex-col">
      {/* Monthly Summary Header */}
      {summary && (
        <div className="p-6 bg-slate-50 dark:bg-slate-800/50 border-b border-slate-100 dark:border-slate-800 transition-colors">
          <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-4 mb-6">
            <div className="flex items-center gap-2">
               <PieChart className="w-5 h-5 text-indigo-600 dark:text-indigo-400" />
               <h3 className="font-bold text-slate-700 dark:text-slate-300 uppercase text-xs tracking-widest">{t.summary}</h3>
            </div>

            {/* Budget Alerts within the summary */}
            {summary.budgetAlerts.length > 0 && (
              <div className="flex flex-wrap gap-2">
                {summary.budgetAlerts.map((alert, idx) => (
                  <div key={idx} className={`flex items-center gap-2 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-tight ${alert.isOver ? 'bg-rose-100 text-rose-600 dark:bg-rose-900/30' : 'bg-amber-100 text-amber-600 dark:bg-amber-900/30'}`}>
                    <AlertCircle className="w-3 h-3" />
                    {alert.label}: {alert.isOver ? t.overspent : 'Near Limit'}
                  </div>
                ))}
              </div>
            )}
          </div>

          <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-6">
            <div className="bg-white dark:bg-slate-900 p-4 rounded-2xl border border-slate-100 dark:border-slate-800 shadow-sm">
               <p className="text-[10px] font-black text-slate-400 uppercase mb-1 tracking-wider">{t.broughtForward}</p>
               <p className="text-lg font-black text-indigo-600 dark:text-indigo-400">{formatCurrency(summary.startBF)}</p>
            </div>
            <div className="bg-white dark:bg-slate-900 p-4 rounded-2xl border border-slate-100 dark:border-slate-800 shadow-sm">
               <p className="text-[10px] font-black text-slate-400 uppercase mb-1 tracking-wider">{t.totalIncome}</p>
               <div className="flex items-center gap-2">
                 <TrendingDown className="w-4 h-4 text-emerald-500 rotate-180" />
                 <p className="text-lg font-black text-emerald-600 dark:text-emerald-400">{formatCurrency(summary.totalIncome)}</p>
               </div>
            </div>
            <div className="bg-white dark:bg-slate-900 p-4 rounded-2xl border border-slate-100 dark:border-slate-800 shadow-sm">
               <p className="text-[10px] font-black text-slate-400 uppercase mb-1 tracking-wider">{t.totalExpenses}</p>
               <div className="flex items-center gap-2">
                 <TrendingDown className="w-4 h-4 text-rose-500" />
                 <p className="text-lg font-black text-rose-600 dark:text-rose-400">{formatCurrency(summary.totalExpenses)}</p>
               </div>
            </div>
            <div className="bg-white dark:bg-slate-900 p-4 rounded-2xl border border-indigo-100 dark:border-indigo-900 shadow-sm bg-indigo-50/20 dark:bg-indigo-900/10">
               <p className="text-[10px] font-black text-indigo-400 uppercase mb-1 tracking-wider">{t.totalBalance}</p>
               <p className="text-lg font-black text-indigo-700 dark:text-indigo-300">{formatCurrency(summary.endBalance)}</p>
            </div>
          </div>

          {/* Category-wise Breakdown Summary with Budget Value Comparison */}
          <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-5 gap-3">
             {Object.entries(summary.catTotals).map(([key, value]) => (
               <div key={key} className="bg-white/50 dark:bg-slate-900/50 p-3 rounded-xl border border-slate-100/50 dark:border-slate-800/50">
                  <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest truncate">{(t as any)[key]}</p>
                  <div className="flex flex-col">
                    <p className="text-sm font-bold text-slate-700 dark:text-slate-300">{formatCurrency(value.actual)}</p>
                    {value.limit > 0 && (
                      <p className="text-[8px] font-black text-slate-400 dark:text-slate-500 mt-0.5">
                        {t.budget}: {formatCurrency(value.limit)}
                      </p>
                    )}
                  </div>
               </div>
             ))}
          </div>
        </div>
      )}

      <div className="p-4 md:p-6 border-b border-slate-100 dark:border-slate-800 space-y-4 no-print transition-colors">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">
          <div className="lg:col-span-4 relative group">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 group-focus-within:text-indigo-500 transition-colors" />
            <input 
              type="text" 
              placeholder={t.search} 
              className="w-full pl-11 pr-4 py-3 rounded-2xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 focus:ring-2 focus:ring-indigo-500 outline-none transition-all font-medium text-sm shadow-sm" 
              value={stagedSearch} 
              onChange={(e) => setStagedSearch(e.target.value)} 
              onKeyDown={(e) => e.key === 'Enter' && setActiveSearch(stagedSearch)} 
            />
          </div>
          <div className="lg:col-span-5 flex items-center gap-2">
            <div className="flex-1 relative flex items-center bg-white dark:bg-slate-800 rounded-xl px-3 py-2 border border-slate-200 dark:border-slate-700">
              <CalendarIcon className="w-3.5 h-3.5 text-slate-300 mr-2" />
              <input type="date" className="bg-transparent border-none text-xs font-bold text-slate-700 dark:text-slate-200 outline-none w-full" value={stagedStart} onChange={(e) => setStagedStart(e.target.value)} />
            </div>
            <span className="text-slate-400 font-bold px-1">→</span>
            <div className="flex-1 relative flex items-center bg-white dark:bg-slate-800 rounded-xl px-3 py-2 border border-slate-200 dark:border-slate-700">
              <CalendarIcon className="w-3.5 h-3.5 text-slate-300 mr-2" />
              <input type="date" className="bg-transparent border-none text-xs font-bold text-slate-700 dark:text-slate-200 outline-none w-full" value={stagedEnd} onChange={(e) => setStagedEnd(e.target.value)} />
            </div>
          </div>
          <div className="lg:col-span-3 flex items-end gap-3 h-full">
            <button 
              onClick={() => { setActiveSearch(stagedSearch); setActiveStart(stagedStart); setActiveEnd(stagedEnd); }} 
              className="flex-1 flex items-center justify-center gap-2 bg-indigo-600 text-white font-bold text-sm hover:bg-indigo-700 py-3 rounded-2xl transition-all shadow-lg active:scale-95"
            >
              <Filter className="w-4 h-4" />
              {t.applyFilters}
            </button>
            <button onClick={clearFilters} className="p-3 text-slate-400 hover:text-rose-500 hover:bg-rose-50 dark:hover:bg-rose-900/20 rounded-2xl transition-all border border-slate-200 dark:border-slate-700">
              <X className="w-5 h-5" />
            </button>
          </div>
        </div>
        <div className="flex flex-wrap items-center justify-between gap-4">
          <div className="flex gap-3">
             <button onClick={() => window.print()} className="flex items-center gap-2 bg-white dark:bg-slate-800 text-slate-600 dark:text-slate-300 font-bold text-xs hover:bg-slate-50 dark:hover:bg-slate-700 border border-slate-200 dark:border-slate-700 px-5 py-2.5 rounded-xl transition-all"><Printer className="w-3.5 h-3.5" />{t.printReport}</button>
             <button onClick={exportAllToExcel} className="flex items-center gap-2 bg-emerald-600 text-white font-bold text-xs hover:bg-emerald-700 px-5 py-2.5 rounded-xl transition-all"><FileSpreadsheet className="w-3.5 h-3.5" />{t.exportExcel}</button>
          </div>
        </div>
      </div>

      <div className="overflow-x-auto">
        <table className="w-full text-left min-w-[1400px] border-collapse">
          <thead>
            <tr className="bg-slate-50 dark:bg-slate-800/50 text-slate-500 dark:text-slate-400 text-[10px] uppercase font-black tracking-widest border-b border-slate-200 dark:border-slate-800">
              <th className="px-6 py-4">{t.date}</th>
              <th className="px-6 py-4">{t.broughtForward}</th>
              <th className="px-6 py-4">{t.dailyCash}</th>
              <th className="px-4 py-4">{t.groceries}</th>
              <th className="px-4 py-4">{t.vegetables}</th>
              <th className="px-4 py-4">{t.fishEgg}</th>
              <th className="px-4 py-4">{t.chicken}</th>
              <th className="px-4 py-4">{t.houseRent}</th>
              <th className="px-4 py-4">{t.electricity}</th>
              <th className="px-4 py-4">{t.water}</th>
              <th className="px-4 py-4">{t.travel}</th>
              <th className="px-4 py-4">{t.others}</th>
              <th className="px-6 py-4">{t.totalExpenses}</th>
              <th className="px-6 py-4 bg-indigo-50/30 dark:bg-indigo-900/10 text-indigo-700 dark:text-indigo-400">{t.totalBalance}</th>
              <th className="px-6 py-4 text-center no-print">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100 dark:divide-slate-800 text-sm">
            {sortedFiltered.map((tx) => (
              <tr key={tx.id || tx.timestamp} className="hover:bg-slate-50/50 dark:hover:bg-slate-800/50 transition-colors">
                <td className="px-6 py-4 font-semibold text-slate-700 dark:text-slate-300">{tx.date.split('-').reverse().join('/')}</td>
                <td className="px-6 py-4 font-bold text-indigo-500 dark:text-indigo-400">{formatCurrency(Number(tx.broughtForward))}</td>
                <td className="px-6 py-4 font-bold text-emerald-600 dark:text-emerald-400">{formatCurrency(Number(tx.dailyCash))}</td>
                <td className="px-4 py-4 text-slate-600 dark:text-slate-400">{Number(tx.groceries || 0).toLocaleString()}</td>
                <td className="px-4 py-4 text-slate-600 dark:text-slate-400">{Number(tx.vegetables || 0).toLocaleString()}</td>
                <td className="px-4 py-4 text-slate-600 dark:text-slate-400">{Number(tx.fishEgg || 0).toLocaleString()}</td>
                <td className="px-4 py-4 text-slate-600 dark:text-slate-400">{Number(tx.chicken || 0).toLocaleString()}</td>
                <td className="px-4 py-4 text-slate-600 dark:text-slate-400">{Number(tx.houseRent || 0).toLocaleString()}</td>
                <td className="px-4 py-4 text-slate-600 dark:text-slate-400">{Number(tx.electricity || 0).toLocaleString()}</td>
                <td className="px-4 py-4 text-slate-600 dark:text-slate-400">{Number(tx.water || 0).toLocaleString()}</td>
                <td className="px-4 py-4 text-slate-600 dark:text-slate-400">{Number(tx.travel || 0).toLocaleString()}</td>
                <td className="px-4 py-4 text-slate-600 dark:text-slate-400">{Number(tx.others || 0).toLocaleString()}</td>
                <td className="px-6 py-4 font-bold text-rose-500 dark:text-rose-400">{formatCurrency(Number(tx.totalExpenses))}</td>
                <td className="px-6 py-4 font-black text-indigo-600 dark:text-indigo-400 bg-indigo-50/20 dark:bg-indigo-900/5">{formatCurrency(Number(tx.totalBalance))}</td>
                <td className="px-6 py-4 no-print whitespace-nowrap">
                  <div className="flex items-center justify-center gap-2">
                    <button onClick={() => onEdit(tx)} className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-all"><Edit2 className="w-4 h-4" /></button>
                    <button onClick={() => tx.id && onDelete(tx.id)} className="p-2 text-slate-400 hover:text-rose-600 hover:bg-rose-50 rounded-lg transition-all"><Trash2 className="w-4 h-4" /></button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        {sortedFiltered.length === 0 && (
          <div className="p-20 text-center flex flex-col items-center gap-4 text-slate-400">
             <Filter className="w-12 h-12 opacity-10" />
             <p className="font-bold italic">{t.noResults}</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default HistoryTable;

import React, { useState, useMemo } from 'react';
import { Transaction, MonthlyBudget } from '../types';
import { Edit2, Trash2, FileSpreadsheet, Printer, Search, X, Calendar as CalendarIcon, Filter, CheckCircle, ArrowRightLeft, TrendingUp, TrendingDown, PieChart, AlertCircle, CheckCircle2 } from 'lucide-react';
import * as XLSX from 'xlsx';

interface HistoryTableProps {
  t: any;
  transactions: Transaction[];
  allTransactions?: Transaction[];
  onEdit: (tx: Transaction) => void;
  onDelete: (id: string) => void;
  isLoading: boolean;
  formatCurrency: (amount: number) => string;
  budgets?: MonthlyBudget[];
}

const HistoryTable: React.FC<HistoryTableProps> = ({ t, transactions, allTransactions, onEdit, onDelete, isLoading, formatCurrency, budgets = [] }) => {
  const [stagedSearch, setStagedSearch] = useState('');
  const [stagedStart, setStagedStart] = useState('');
  const [stagedEnd, setStagedEnd] = useState('');
  const [activeSearch, setActiveSearch] = useState('');
  const [activeStart, setActiveStart] = useState('');
  const [activeEnd, setActiveEnd] = useState('');

  const filteredTransactions = useMemo(() => {
    const lowerSearch = activeSearch.toLowerCase().trim();

    return transactions.filter(tx => {
      if (activeStart && tx.date < activeStart) return false;
      if (activeEnd && tx.date > activeEnd) return false;

      if (lowerSearch) {
        const formattedDate = tx.date.split('-').reverse().join('/'); // dd/mm/yyyy
        if (tx.date.includes(lowerSearch) || formattedDate.includes(lowerSearch)) return true;

        const categories = [
          { key: 'groceries', label: t.groceries },
          { key: 'vegetables', label: t.vegetables },
          { key: 'fishEgg', label: t.fishEgg },
          { key: 'chicken', label: t.chicken },
          { key: 'houseRent', label: t.houseRent },
          { key: 'electricity', label: t.electricity },
          { key: 'water', label: t.water },
          { key: 'travel', label: t.travel },
          { key: 'others', label: t.others },
        ];

        const matchesCategory = categories.some(cat => 
          cat.label.toLowerCase().includes(lowerSearch) && Number((tx as any)[cat.key]) > 0
        );
        if (matchesCategory) return true;

        return (
          tx.totalExpenses.toString().includes(lowerSearch) || 
          tx.dailyCash.toString().includes(lowerSearch) || 
          tx.totalBalance.toString().includes(lowerSearch)
        );
      }
      return true;
    });
  }, [transactions, activeSearch, activeStart, activeEnd, t]);

  const sortedFiltered = useMemo(() => {
    return [...filteredTransactions].sort((a, b) => 
      a.date.localeCompare(b.date) || a.timestamp.localeCompare(b.timestamp)
    );
  }, [filteredTransactions]);

  const summary = useMemo(() => {
    if (sortedFiltered.length === 0) return null;

    const totalIncome = sortedFiltered.reduce((sum, tx) => sum + (Number(tx.dailyCash) || 0), 0);
    const totalExpenses = sortedFiltered.reduce((sum, tx) => sum + (Number(tx.totalExpenses) || 0), 0);
    const startBF = Number(sortedFiltered[0].broughtForward) || 0;
    const endBalance = Number(sortedFiltered[sortedFiltered.length - 1].totalBalance) || 0;

    // Category Totals
    const catKeys = ['groceries', 'vegetables', 'fishEgg', 'chicken', 'houseRent', 'electricity', 'water', 'travel', 'others'];
    const catTotals: Record<string, { actual: number, limit: number }> = {};

    const currentMonthLabel = sortedFiltered[0].month;
    const activeBudget = budgets.find(b => b.month === currentMonthLabel);

    catKeys.forEach(key => {
      catTotals[key] = {
        actual: sortedFiltered.reduce((sum, tx) => sum + (Number((tx as any)[key]) || 0), 0),
        limit: activeBudget ? (activeBudget.limits as any)[key] : 0
      };
    });

    // Budget Comparison
    const budgetAlerts = catKeys.map(key => {
      const { actual: spent, limit } = catTotals[key];
      const isOver = limit > 0 && spent > limit;
      const progress = limit > 0 ? (spent / limit) * 100 : 0;
      return { key, label: (t as any)[key], spent, limit, isOver, progress };
    }).filter(a => a.isOver || (a.limit > 0 && a.progress >= 85));

    return {
      startBF,
      totalIncome,
      totalExpenses,
      endBalance,
      netSavings: totalIncome - totalExpenses,
      catTotals,
      budgetAlerts
    };
  }, [sortedFiltered, budgets, t]);

  const exportAllToExcel = () => {
    const dataToExport = allTransactions || transactions;
    if (dataToExport.length === 0) return;
    const workbook = XLSX.utils.book_new();
    const sortedData = [...dataToExport].sort((a,b) => a.date.localeCompare(b.date) || a.timestamp.localeCompare(b.timestamp));

    // Detailed Transactions Sheet
    const formattedData = sortedData.map(tx => ({
      [t.date]: tx.date,
      [t.broughtForward]: tx.broughtForward,
      [t.dailyCash]: tx.dailyCash,
      [t.groceries]: tx.groceries,
      [t.vegetables]: tx.vegetables,
      [t.fishEgg]: tx.fishEgg,
      [t.chicken]: tx.chicken,
      [t.houseRent]: tx.houseRent,
      [t.electricity]: tx.electricity,
      [t.water]: tx.water,
      [t.travel]: tx.travel,
      [t.others]: tx.others,
      [t.totalExpenses]: tx.totalExpenses,
      [t.totalBalance]: tx.totalBalance,
    }));
    const wsFull = XLSX.utils.json_to_sheet(formattedData);
    XLSX.utils.book_append_sheet(workbook, wsFull, "Transaction Details");

    // Monthly Summary Sheet
    const monthlySummary: any[] = [];
    const months = [...new Set(sortedData.map(tx => tx.month))];
    months.forEach(m => {
      const txsInMonth = sortedData.filter(tx => tx.month === m).sort((a,b) => a.date.localeCompare(b.date) || a.timestamp.localeCompare(b.timestamp));

      const monthIncome = txsInMonth.reduce((acc, curr) => acc + (Number(curr.dailyCash) || 0), 0);
      const monthSpent = txsInMonth.reduce((acc, curr) => acc + (Number(curr.totalExpenses) || 0), 0);
      const startBF = txsInMonth[0] ? txsInMonth[0].broughtForward : 0;
      const endBal = txsInMonth[txsInMonth.length - 1] ? txsInMonth[txsInMonth.length - 1].totalBalance : 0;

      // Category breakdown for summary
      const catTotals: any = {};
      const categories = ['groceries', 'vegetables', 'fishEgg', 'chicken', 'houseRent', 'electricity', 'water', 'travel', 'others'];
      categories.forEach(cat => {
        catTotals[(t as any)[cat]] = txsInMonth.reduce((sum, tx) => sum + (Number((tx as any)[cat]) || 0), 0);
      });

      monthlySummary.push({
        [t.month]: m,
        [t.broughtForward]: startBF,
        [t.totalIncome]: monthIncome,
        [t.totalExpenses]: monthSpent,
        [t.totalBalance]: endBal,
        ...catTotals
      });
    });

    const wsSummary = XLSX.utils.json_to_sheet(monthlySummary);
    XLSX.utils.book_append_sheet(workbook, wsSummary, "Monthly Summary");

    XLSX.writeFile(workbook, `Finance_Report_${new Date().toISOString().split('T')[0]}.xlsx`);
  };

  const clearFilters = () => {
    setStagedSearch(''); setStagedStart(''); setStagedEnd('');
    setActiveSearch(''); setActiveStart(''); setActiveEnd('');
  };

  if (isLoading) return <div className="p-12 text-center text-slate-400">Loading records...</div>;

  return (
    <div className="flex flex-col">
      {/* Monthly Summary Header */}
      {summary && (
        <div className="p-6 bg-slate-50 dark:bg-slate-800/50 border-b border-slate-100 dark:border-slate-800 transition-colors">
          <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-4 mb-6">
            <div className="flex items-center gap-2">
               <PieChart className="w-5 h-5 text-indigo-600 dark:text-indigo-400" />
               <h3 className="font-bold text-slate-700 dark:text-slate-300 uppercase text-xs tracking-widest">{t.summary}</h3>
            </div>

            {/* Budget Alerts within the summary */}
            {summary.budgetAlerts.length > 0 && (
              <div className="flex flex-wrap gap-2">
                {summary.budgetAlerts.map((alert, idx) => (
                  <div key={idx} className={`flex items-center gap-2 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-tight ${alert.isOver ? 'bg-rose-100 text-rose-600 dark:bg-rose-900/30' : 'bg-amber-100 text-amber-600 dark:bg-amber-900/30'}`}>
                    <AlertCircle className="w-3 h-3" />
                    {alert.label}: {alert.isOver ? t.overspent : 'Near Limit'}
                  </div>
                ))}
              </div>
            )}
          </div>

          <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-6">
            <div className="bg-white dark:bg-slate-900 p-4 rounded-2xl border border-slate-100 dark:border-slate-800 shadow-sm">
               <p className="text-[10px] font-black text-slate-400 uppercase mb-1 tracking-wider">{t.broughtForward}</p>
               <p className="text-lg font-black text-indigo-600 dark:text-indigo-400">{formatCurrency(summary.startBF)}</p>
            </div>
            <div className="bg-white dark:bg-slate-900 p-4 rounded-2xl border border-slate-100 dark:border-slate-800 shadow-sm">
               <p className="text-[10px] font-black text-slate-400 uppercase mb-1 tracking-wider">{t.totalIncome}</p>
               <div className="flex items-center gap-2">
                 <TrendingDown className="w-4 h-4 text-emerald-500 rotate-180" />
                 <p className="text-lg font-black text-emerald-600 dark:text-emerald-400">{formatCurrency(summary.totalIncome)}</p>
               </div>
            </div>
            <div className="bg-white dark:bg-slate-900 p-4 rounded-2xl border border-slate-100 dark:border-slate-800 shadow-sm">
               <p className="text-[10px] font-black text-slate-400 uppercase mb-1 tracking-wider">{t.totalExpenses}</p>
               <div className="flex items-center gap-2">
                 <TrendingDown className="w-4 h-4 text-rose-500" />
                 <p className="text-lg font-black text-rose-600 dark:text-rose-400">{formatCurrency(summary.totalExpenses)}</p>
               </div>
            </div>
            <div className="bg-white dark:bg-slate-900 p-4 rounded-2xl border border-indigo-100 dark:border-indigo-900 shadow-sm bg-indigo-50/20 dark:bg-indigo-900/10">
               <p className="text-[10px] font-black text-indigo-400 uppercase mb-1 tracking-wider">{t.totalBalance}</p>
               <p className="text-lg font-black text-indigo-700 dark:text-indigo-300">{formatCurrency(summary.endBalance)}</p>
            </div>
          </div>

          {/* Category-wise Breakdown Summary with Budget Value Comparison */}
          {/* Fix: Explicitly cast Object.entries to resolve property access errors on type 'unknown' */}
          <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-5 gap-3">
             {(Object.entries(summary.catTotals) as [string, { actual: number, limit: number }][]).map(([key, value]) => (
               <div key={key} className="bg-white/50 dark:bg-slate-900/50 p-3 rounded-xl border border-slate-100/50 dark:border-slate-800/50">
                  <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest truncate">{(t as any)[key]}</p>
                  <div className="flex flex-col">
                    <p className="text-sm font-bold text-slate-700 dark:text-slate-300">{formatCurrency(value.actual)}</p>
                    {value.limit > 0 && (
                      <p className="text-[8px] font-black text-slate-400 dark:text-slate-500 mt-0.5">
                        {t.budget}: {formatCurrency(value.limit)}
                      </p>
                    )}
                  </div>
               </div>
             ))}
          </div>
        </div>
      )}

      <div className="p-4 md:p-6 border-b border-slate-100 dark:border-slate-800 space-y-4 no-print transition-colors">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">
          <div className="lg:col-span-4 relative group">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 group-focus-within:text-indigo-500 transition-colors" />
            <input 
              type="text" 
              placeholder={t.search} 
              className="w-full pl-11 pr-4 py-3 rounded-2xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 focus:ring-2 focus:ring-indigo-500 outline-none transition-all font-medium text-sm shadow-sm" 
              value={stagedSearch} 
              onChange={(e) => setStagedSearch(e.target.value)} 
              onKeyDown={(e) => e.key === 'Enter' && setActiveSearch(stagedSearch)} 
            />
          </div>
          <div className="lg:col-span-5 flex items-center gap-2">
            <div className="flex-1 relative flex items-center bg-white dark:bg-slate-800 rounded-xl px-3 py-2 border border-slate-200 dark:border-slate-700">
              <CalendarIcon className="w-3.5 h-3.5 text-slate-300 mr-2" />
              <input type="date" className="bg-transparent border-none text-xs font-bold text-slate-700 dark:text-slate-200 outline-none w-full" value={stagedStart} onChange={(e) => setStagedStart(e.target.value)} />
            </div>
            <span className="text-slate-400 font-bold px-1">→</span>
            <div className="flex-1 relative flex items-center bg-white dark:bg-slate-800 rounded-xl px-3 py-2 border border-slate-200 dark:border-slate-700">
              <CalendarIcon className="w-3.5 h-3.5 text-slate-300 mr-2" />
              <input type="date" className="bg-transparent border-none text-xs font-bold text-slate-700 dark:text-slate-200 outline-none w-full" value={stagedEnd} onChange={(e) => setStagedEnd(e.target.value)} />
            </div>
          </div>
          <div className="lg:col-span-3 flex items-end gap-3 h-full">
            <button 
              onClick={() => { setActiveSearch(stagedSearch); setActiveStart(stagedStart); setActiveEnd(stagedEnd); }} 
              className="flex-1 flex items-center justify-center gap-2 bg-indigo-600 text-white font-bold text-sm hover:bg-indigo-700 py-3 rounded-2xl transition-all shadow-lg active:scale-95"
            >
              <Filter className="w-4 h-4" />
              {t.applyFilters}
            </button>
            <button onClick={clearFilters} className="p-3 text-slate-400 hover:text-rose-500 hover:bg-rose-50 dark:hover:bg-rose-900/20 rounded-2xl transition-all border border-slate-200 dark:border-slate-700">
              <X className="w-5 h-5" />
            </button>
          </div>
        </div>
        <div className="flex flex-wrap items-center justify-between gap-4">
          <div className="flex gap-3">
             <button onClick={() => window.print()} className="flex items-center gap-2 bg-white dark:bg-slate-800 text-slate-600 dark:text-slate-300 font-bold text-xs hover:bg-slate-50 dark:hover:bg-slate-700 border border-slate-200 dark:border-slate-700 px-5 py-2.5 rounded-xl transition-all"><Printer className="w-3.5 h-3.5" />{t.printReport}</button>
             <button onClick={exportAllToExcel} className="flex items-center gap-2 bg-emerald-600 text-white font-bold text-xs hover:bg-emerald-700 px-5 py-2.5 rounded-xl transition-all"><FileSpreadsheet className="w-3.5 h-3.5" />{t.exportExcel}</button>
          </div>
        </div>
      </div>

      <div className="overflow-x-auto">
        <table className="w-full text-left min-w-[1400px] border-collapse">
          <thead>
            <tr className="bg-slate-50 dark:bg-slate-800/50 text-slate-500 dark:text-slate-400 text-[10px] uppercase font-black tracking-widest border-b border-slate-200 dark:border-slate-800">
              <th className="px-6 py-4">{t.date}</th>
              <th className="px-6 py-4">{t.broughtForward}</th>
              <th className="px-6 py-4">{t.dailyCash}</th>
              <th className="px-4 py-4">{t.groceries}</th>
              <th className="px-4 py-4">{t.vegetables}</th>
              <th className="px-4 py-4">{t.fishEgg}</th>
              <th className="px-4 py-4">{t.chicken}</th>
              <th className="px-4 py-4">{t.houseRent}</th>
              <th className="px-4 py-4">{t.electricity}</th>
              <th className="px-4 py-4">{t.water}</th>
              <th className="px-4 py-4">{t.travel}</th>
              <th className="px-4 py-4">{t.others}</th>
              <th className="px-6 py-4">{t.totalExpenses}</th>
              <th className="px-6 py-4 bg-indigo-50/30 dark:bg-indigo-900/10 text-indigo-700 dark:text-indigo-400">{t.totalBalance}</th>
              <th className="px-6 py-4 text-center no-print">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100 dark:divide-slate-800 text-sm">
            {sortedFiltered.map((tx) => (
              <tr key={tx.id || tx.timestamp} className="hover:bg-slate-50/50 dark:hover:bg-slate-800/50 transition-colors">
                <td className="px-6 py-4 font-semibold text-slate-700 dark:text-slate-300">{tx.date.split('-').reverse().join('/')}</td>
                <td className="px-6 py-4 font-bold text-indigo-500 dark:text-indigo-400">{formatCurrency(Number(tx.broughtForward))}</td>
                <td className="px-6 py-4 font-bold text-emerald-600 dark:text-emerald-400">{formatCurrency(Number(tx.dailyCash))}</td>
                <td className="px-4 py-4 text-slate-600 dark:text-slate-400">{Number(tx.groceries || 0).toLocaleString()}</td>
                <td className="px-4 py-4 text-slate-600 dark:text-slate-400">{Number(tx.vegetables || 0).toLocaleString()}</td>
                <td className="px-4 py-4 text-slate-600 dark:text-slate-400">{Number(tx.fishEgg || 0).toLocaleString()}</td>
                <td className="px-4 py-4 text-slate-600 dark:text-slate-400">{Number(tx.chicken || 0).toLocaleString()}</td>
                <td className="px-4 py-4 text-slate-600 dark:text-slate-400">{Number(tx.houseRent || 0).toLocaleString()}</td>
                <td className="px-4 py-4 text-slate-600 dark:text-slate-400">{Number(tx.electricity || 0).toLocaleString()}</td>
                <td className="px-4 py-4 text-slate-600 dark:text-slate-400">{Number(tx.water || 0).toLocaleString()}</td>
                <td className="px-4 py-4 text-slate-600 dark:text-slate-400">{Number(tx.travel || 0).toLocaleString()}</td>
                <td className="px-4 py-4 text-slate-600 dark:text-slate-400">{Number(tx.others || 0).toLocaleString()}</td>
                <td className="px-6 py-4 font-bold text-rose-500 dark:text-rose-400">{formatCurrency(Number(tx.totalExpenses))}</td>
                <td className="px-6 py-4 font-black text-indigo-600 dark:text-indigo-400 bg-indigo-50/20 dark:bg-indigo-900/5">{formatCurrency(Number(tx.totalBalance))}</td>
                <td className="px-6 py-4 no-print whitespace-nowrap">
                  <div className="flex items-center justify-center gap-2">
                    <button onClick={() => onEdit(tx)} className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-all"><Edit2 className="w-4 h-4" /></button>
                    <button onClick={() => tx.id && onDelete(tx.id)} className="p-2 text-slate-400 hover:text-rose-600 hover:bg-rose-50 rounded-lg transition-all"><Trash2 className="w-4 h-4" /></button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        {sortedFiltered.length === 0 && (
          <div className="p-20 text-center flex flex-col items-center gap-4 text-slate-400">
             <Filter className="w-12 h-12 opacity-10" />
             <p className="font-bold italic">{t.noResults}</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default HistoryTable;

import React, { useState, useEffect } from 'react';
import { Transaction } from '../types';
import { AlertCircle, Sparkles, Loader2, CheckCircle, RefreshCcw } from 'lucide-react';
import { GoogleGenAI, Type } from "@google/genai";

interface TransactionFormProps {
  t: any;
  initialData?: Transaction | null;
  latestBalance?: number;
  onSubmit: (data: Transaction) => void;
  formatCurrency: (amount: number) => string;
}

const TransactionForm: React.FC<TransactionFormProps> = ({ t, initialData, latestBalance = 0, onSubmit, formatCurrency }) => {
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    groceries: '' as any,
    vegetables: '' as any,
    fishEgg: '' as any,
    chicken: '' as any,
    houseRent: '' as any,
    electricity: '' as any,
    water: '' as any,
    travel: '' as any,
    others: '' as any,
    dailyCash: '' as any,
    broughtForward: '' as any,
  });

  const [dateError, setDateError] = useState<string | null>(null);
  const [aiText, setAiText] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [aiStatus, setAiStatus] = useState<'idle' | 'success' | 'error'>('idle');

  useEffect(() => {
    if (initialData) {
      setFormData({
        date: initialData.date,
        groceries: initialData.groceries || '',
        vegetables: initialData.vegetables || '',
        fishEgg: initialData.fishEgg || '',
        chicken: initialData.chicken || '',
        houseRent: initialData.houseRent || '',
        electricity: initialData.electricity || '',
        water: initialData.water || '',
        travel: initialData.travel || '',
        others: initialData.others || '',
        dailyCash: initialData.dailyCash || '',
        broughtForward: initialData.broughtForward || '',
      });
    } else {
      setFormData(prev => ({
        ...prev,
        broughtForward: latestBalance === 0 ? '' : latestBalance
      }));
    }
  }, [initialData, latestBalance]);

  const handleSmartEntry = async () => {
    if (!aiText.trim()) return;
    setIsProcessing(true);
    setAiStatus('idle');

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Parse this spending description and extract the amounts for these categories: 
        groceries, vegetables, fishEgg, chicken, houseRent, electricity, water, travel, others, and dailyCash.
        Input text (can be English or Sinhala): "${aiText}"
        Return as JSON only.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              groceries: { type: Type.NUMBER },
              vegetables: { type: Type.NUMBER },
              fishEgg: { type: Type.NUMBER },
              chicken: { type: Type.NUMBER },
              houseRent: { type: Type.NUMBER },
              electricity: { type: Type.NUMBER },
              water: { type: Type.NUMBER },
              travel: { type: Type.NUMBER },
              others: { type: Type.NUMBER },
              dailyCash: { type: Type.NUMBER },
            }
          }
        },
      });

      const result = JSON.parse(response.text || '{}');

      setFormData(prev => ({
        ...prev,
        groceries: result.groceries || prev.groceries,
        vegetables: result.vegetables || prev.vegetables,
        fishEgg: result.fishEgg || prev.fishEgg,
        chicken: result.chicken || prev.chicken,
        houseRent: result.houseRent || prev.houseRent,
        electricity: result.electricity || prev.electricity,
        water: result.water || prev.water,
        travel: result.travel || prev.travel,
        others: result.others || prev.others,
        dailyCash: result.dailyCash || prev.dailyCash,
      }));

      setAiStatus('success');
      setAiText('');
      setTimeout(() => setAiStatus('idle'), 3000);
    } catch (error) {
      console.error("AI Entry error:", error);
      setAiStatus('error');
    } finally {
      setIsProcessing(false);
    }
  };

  const validateDate = (dateString: string) => {
    const selectedDate = new Date(dateString);
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    selectedDate.setHours(0, 0, 0, 0);

    if (selectedDate > today) {
      setDateError(t.futureDateError);
      return false;
    } else {
      setDateError(null);
      return true;
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value, type } = e.target;
    if (name === 'date') validateDate(value);
    setFormData(prev => ({
      ...prev,
      [name]: type === 'number' ? (value === '' ? '' : parseFloat(value)) : value
    }));
  };

  const val = (v: any) => {
    const n = parseFloat(v);
    return isNaN(n) ? 0 : n;
  };

  const totalExpenses = 
    val(formData.groceries) + 
    val(formData.vegetables) + 
    val(formData.fishEgg) + 
    val(formData.chicken) + 
    val(formData.houseRent) +
    val(formData.electricity) +
    val(formData.water) +
    val(formData.travel) +
    val(formData.others);

  const totalBalance = val(formData.broughtForward) + val(formData.dailyCash) - totalExpenses;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!validateDate(formData.date)) return;

    const dateObj = new Date(formData.date);
    const monthName = dateObj.toLocaleString('en-US', { month: 'long', year: 'numeric' });

    onSubmit({
      ...formData,
      groceries: val(formData.groceries),
      vegetables: val(formData.vegetables),
      fishEgg: val(formData.fishEgg),
      chicken: val(formData.chicken),
      houseRent: val(formData.houseRent),
      electricity: val(formData.electricity),
      water: val(formData.water),
      travel: val(formData.travel),
      others: val(formData.others),
      dailyCash: val(formData.dailyCash),
      broughtForward: val(formData.broughtForward),
      month: monthName,
      totalExpenses: totalExpenses,
      totalBalance: totalBalance,
      timestamp: new Date().toISOString()
    });
  };

  return (
    <div className="space-y-6">
      {/* Smart AI Entry Section */}
      <div className="bg-indigo-600 p-6 rounded-3xl shadow-xl shadow-indigo-100 dark:shadow-none transition-all">
        <div className="flex items-center gap-2 mb-4">
          <Sparkles className="w-5 h-5 text-indigo-200" />
          <h3 className="text-white font-black uppercase tracking-tight text-sm">{t.smartEntry}</h3>
        </div>
        <div className="relative group">
          <textarea
            className="w-full bg-white/10 border border-white/20 rounded-2xl p-4 text-white placeholder-white/40 outline-none focus:ring-2 focus:ring-white/30 transition-all font-medium min-h-[80px] resize-none pr-12"
            placeholder={t.smartEntryPlaceholder}
            value={aiText}
            onChange={(e) => setAiText(e.target.value)}
            disabled={isProcessing}
            onKeyDown={(e) => {
              if (e.key === 'Enter' && !e.shiftKey) {
                e.preventDefault();
                handleSmartEntry();
              }
            }}
          />
          <button
            type="button"
            onClick={handleSmartEntry}
            disabled={isProcessing || !aiText.trim()}
            className="absolute right-3 bottom-3 p-2 bg-white text-indigo-600 rounded-xl hover:scale-105 active:scale-95 transition-all disabled:opacity-50 disabled:scale-100 shadow-lg"
          >
            {isProcessing ? <Loader2 className="w-5 h-5 animate-spin" /> : <RefreshCcw className="w-5 h-5" />}
          </button>
        </div>

        {aiStatus === 'success' && (
          <div className="mt-3 flex items-center gap-2 text-indigo-100 text-xs font-bold animate-in fade-in slide-in-from-top-1">
            <CheckCircle className="w-4 h-4" />
            {t.entrySuccess}
          </div>
        )}
        {aiStatus === 'error' && (
          <div className="mt-3 flex items-center gap-2 text-rose-200 text-xs font-bold animate-in fade-in slide-in-from-top-1">
            <AlertCircle className="w-4 h-4" />
            {t.entryError}
          </div>
        )}
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          <div className="space-y-1">
            <label className="block text-sm font-semibold text-slate-700 dark:text-slate-300 mb-1">{t.date}</label>
            <input
              type="date"
              name="date"
              required
              className={`w-full px-4 py-2.5 rounded-xl border ${dateError ? 'border-rose-500 ring-1 ring-rose-500' : 'border-slate-200 dark:border-slate-700'} bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 focus:ring-2 focus:ring-indigo-500 outline-none transition-all`}
              value={formData.date}
              onChange={handleChange}
            />
            {dateError && (
              <div className="flex items-center gap-1.5 text-rose-500 text-xs font-bold animate-in fade-in slide-in-from-top-1">
                <AlertCircle className="w-3.5 h-3.5" />
                {dateError}
              </div>
            )}
          </div>
          <div>
            <label className="block text-sm font-semibold text-slate-700 dark:text-slate-300 mb-1">{t.broughtForward}</label>
            <input
              type="number"
              name="broughtForward"
              placeholder="0"
              className="w-full px-4 py-2.5 rounded-xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 focus:ring-2 focus:ring-indigo-500 outline-none transition-all font-bold text-indigo-600 dark:text-indigo-400"
              value={formData.broughtForward}
              onChange={handleChange}
            />
          </div>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
          <div>
            <label className="block text-sm font-semibold mb-1 text-emerald-600 dark:text-emerald-400">{t.dailyCash}</label>
            <input
              type="number"
              name="dailyCash"
              placeholder="0"
              className="w-full px-4 py-2.5 rounded-xl border border-emerald-200 dark:border-emerald-900 bg-emerald-50 dark:bg-emerald-900/10 font-bold transition-all focus:ring-2 focus:ring-emerald-500 outline-none text-emerald-800 dark:text-emerald-100"
              value={formData.dailyCash}
              onChange={handleChange}
            />
          </div>
          {[
            { name: 'groceries', label: t.groceries },
            { name: 'vegetables', label: t.vegetables },
            { name: 'fishEgg', label: t.fishEgg },
            { name: 'chicken', label: t.chicken },
            { name: 'houseRent', label: t.houseRent },
            { name: 'electricity', label: t.electricity },
            { name: 'water', label: t.water },
            { name: 'travel', label: t.travel },
            { name: 'others', label: t.others },
          ].map(field => (
            <div key={field.name}>
              <label className="block text-sm font-semibold mb-1 text-slate-700 dark:text-slate-300">{field.label}</label>
              <input
                type="number"
                name={field.name}
                placeholder="0"
                className="w-full px-4 py-2.5 rounded-xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 transition-all focus:ring-2 focus:ring-indigo-500 outline-none font-medium"
                value={(formData as any)[field.name]}
                onChange={handleChange}
              />
            </div>
          ))}
        </div>

        <div className="p-6 bg-slate-50 dark:bg-slate-800/50 rounded-2xl flex flex-wrap gap-8 items-center justify-center border border-slate-100 dark:border-slate-800 transition-colors">
          <div className="text-center">
            <p className="text-xs text-slate-400 dark:text-slate-500 uppercase tracking-wider font-bold">{t.totalExpenses}</p>
            <p className="text-2xl font-black text-rose-600 dark:text-rose-400">{formatCurrency(totalExpenses)}</p>
          </div>
          <div className="text-center">
            <p className="text-xs text-slate-400 dark:text-slate-500 uppercase tracking-wider font-bold">{t.totalBalance}</p>
            <p className="text-2xl font-black text-indigo-600 dark:text-indigo-400">{formatCurrency(totalBalance)}</p>
          </div>
        </div>

        <button
          type="submit"
          disabled={!!dateError}
          className={`w-full ${dateError ? 'bg-slate-300 cursor-not-allowed' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-200'} text-white py-4 rounded-xl font-bold shadow-lg dark:shadow-none active:scale-[0.99] transition-all`}
        >
          {t.save}
        </button>
      </form>
    </div>
  );
};

