  const handleEdit = (tx: Transaction) => {
    setEditingTransaction(tx);
    setShowAddForm(true);
  };

  const handleSaveBudget = async (limits: MonthlyBudget['limits']) => {
    await storageService.saveBudget(selectedMonth, limits);
    const updated = await storageService.fetchBudgets();
    setBudgets(updated);
    setShowBudgetForm(false);
  };

  return (
    <div className="space-y-4 md:space-y-6">
      <div className="flex flex-col sm:flex-row items-center justify-between gap-3 bg-white dark:bg-slate-900 p-3 md:p-4 rounded-2xl md:rounded-3xl border border-slate-100 dark:border-slate-800 shadow-sm no-print transition-colors">
        <div className="flex items-center gap-2 w-full sm:w-auto">
          <div className="p-2 bg-indigo-50 dark:bg-indigo-900/30 rounded-lg">
            <Calendar className="w-4 h-4 text-indigo-600 dark:text-indigo-400" />
          </div>
          <div className="flex-grow min-w-0">
            <h2 className="text-[9px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest leading-none mb-0.5 truncate">{t.selectMonth}</h2>
            <select 
              value={selectedMonth}
              onChange={(e) => setSelectedMonth(e.target.value)}
              className="bg-transparent font-bold text-base text-slate-800 dark:text-slate-100 outline-none cursor-pointer hover:text-indigo-600 dark:hover:text-indigo-400 transition-colors w-full appearance-none"
            >
              {availableMonths.map(m => (
                <option key={m} value={m} className="bg-white dark:bg-slate-900 text-sm">{m}</option>
              ))}
            </select>
          </div>
        </div>

        <div className="flex items-center gap-2 w-full sm:w-auto">
          <button 
            onClick={() => setShowBudgetForm(true)}
            className="flex-1 sm:flex-none flex items-center justify-center gap-2 px-3 py-2.5 bg-white dark:bg-slate-900 text-indigo-600 dark:text-indigo-400 rounded-xl font-bold text-xs hover:bg-indigo-50 dark:hover:bg-indigo-900/20 transition-all border border-indigo-100 dark:border-indigo-900 shadow-sm active:scale-95"
          >
            <Target className="w-4 h-4" />
            <span>{t.manageBudget}</span>
          </button>
          <button 
            onClick={() => setShowAddForm(true)}
            className="flex-1 sm:flex-none bg-indigo-600 text-white px-4 py-2.5 rounded-xl font-bold text-xs flex items-center justify-center gap-2 shadow-lg shadow-indigo-200 dark:shadow-none hover:bg-indigo-700 active:scale-95 transition-all"
          >
            <Plus className="w-4 h-4" />
            <span>{t.addRecord}</span>
          </button>
        </div>
      </div>

      {activeTab === 'dashboard' && (
        <>
          {/* Enhanced Budget Watch Banner */}
          {budgetHealth.length > 0 && (
            <div className="animate-in slide-in-from-top-4 duration-500">
              <div className="bg-white dark:bg-slate-900 p-4 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-800 relative overflow-hidden transition-colors">
                <div className={`absolute top-0 left-0 bottom-0 w-1 ${budgetHealth.some(h => h.status === 'over') ? 'bg-rose-500 animate-pulse' : 'bg-amber-500'}`} />
                <div className="flex flex-col md:flex-row md:items-center justify-between gap-3">
                  <div className="flex items-center gap-3">
                    <div className={`p-2 rounded-xl ${budgetHealth.some(h => h.status === 'over') ? 'bg-rose-50 dark:bg-rose-900/20 text-rose-600' : 'bg-amber-50 dark:bg-amber-900/20 text-amber-600'}`}>
                      {budgetHealth.some(h => h.status === 'over') ? <TriangleAlert className="w-5 h-5" /> : <Zap className="w-5 h-5" />}
                    </div>
                    <div>
                      <h3 className="text-xs font-black text-slate-800 dark:text-slate-100 uppercase tracking-tight">Budget Attention</h3>
                      <div className="flex flex-wrap gap-1 mt-0.5">
                        {budgetHealth.slice(0, 2).map((h, i) => (
                          <span key={i} className={`text-[8px] font-bold px-1.5 py-0.5 rounded-full ${h.status === 'over' ? 'bg-rose-100 text-rose-600 dark:bg-rose-900/40' : 'bg-amber-100 text-amber-600 dark:bg-amber-900/40'}`}>
                            {h.label}: {h.percentage.toFixed(0)}%
                          </span>
                        ))}
                      </div>
                    </div>
                  </div>
                  <button 
                    onClick={() => setActiveTab?.('budget')}
                    className="flex items-center gap-1.5 text-[10px] font-bold text-indigo-600 dark:text-indigo-400 hover:text-indigo-700 transition-colors bg-indigo-50 dark:bg-indigo-900/30 px-2.5 py-1 rounded-lg shrink-0 w-fit"
                  >
                    Analysis
                    <ArrowRightCircle className="w-3 h-3" />
                  </button>
                </div>
              </div>
            </div>
          )}

          <StatsOverview t={t} stats={filteredStats} formatCurrency={formatCurrency} />

          {/* Enhanced: Category Quick-View Summary with Budget Values */}
          <div className="mt-6 space-y-3">
            <div className="flex items-center gap-2">
              <LayoutGrid className="w-4 h-4 text-indigo-600 dark:text-indigo-400" />
              <h2 className="text-base font-black text-slate-800 dark:text-slate-100 uppercase tracking-tight">{t.summary}</h2>
            </div>
            <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-5 gap-2">
              {categorySummary.map((cat) => (
                <div key={cat.key} className="bg-white dark:bg-slate-900 p-2.5 rounded-xl border border-slate-100 dark:border-slate-800 shadow-sm flex items-center gap-2.5 transition-all hover:shadow-md group">
                  <div className={`p-1.5 rounded-lg transition-colors ${cat.bg} shrink-0`}>
                    <cat.icon className={`w-4 h-4 ${cat.color}`} />
                  </div>
                  <div className="min-w-0 flex-grow">
                    <p className="text-[8px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest truncate mb-0.5">{cat.label}</p>
                    <div className="flex flex-col">
                      <p className="text-xs font-black text-slate-800 dark:text-slate-100 truncate">{formatCurrency(cat.total)}</p>
                      {cat.limit > 0 && (
                        <p className="text-[7px] font-bold text-slate-400 dark:text-slate-500 truncate">
                          {t.budget}: {formatCurrency(cat.limit)}
                        </p>
                      )}
                    </div>
                    {cat.limit > 0 && (
                      <div className="mt-1.5 w-full h-0.5 bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden">
                        <div 
                          className={`h-full transition-all duration-700 ${(cat.total / cat.limit) >= 1 ? 'bg-rose-500' : 'bg-indigo-500'}`}
                          style={{ width: `${Math.min((cat.total / cat.limit) * 100, 100)}%` }}
                        />
                      </div>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </div>

          <div className="mt-8 bg-white dark:bg-slate-900 rounded-2xl border border-slate-100 dark:border-slate-800 shadow-sm overflow-hidden transition-colors">
            <div className="p-4 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between">
              <div className="flex items-center gap-2">
                <ClipboardList className="w-5 h-5 text-indigo-600 dark:text-indigo-400" />
                <h2 className="text-lg font-bold text-slate-800 dark:text-slate-100">{t.recentTransactions}</h2>
              </div>
              <button 
                onClick={() => setActiveTab?.('history')}
                className="flex items-center gap-1 text-[11px] font-bold text-indigo-600 dark:text-indigo-400 hover:text-indigo-700 dark:hover:text-indigo-300 transition-colors"
              >
                {t.viewAll}
                <ArrowRight className="w-3 h-3" />
              </button>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full text-left min-w-[500px]">
                <thead>
                  <tr className="bg-slate-50 dark:bg-slate-800/50 text-slate-500 dark:text-slate-400 text-[8px] uppercase font-black tracking-widest border-b border-slate-100 dark:border-slate-800">
                    <th className="px-4 py-3">{t.date}</th>
                    <th className="px-4 py-3">{t.dailyCash}</th>
                    <th className="px-4 py-3">{t.totalExpenses}</th>
                    <th className="px-4 py-3 bg-indigo-50/30 dark:bg-indigo-900/10 text-indigo-700 dark:text-indigo-400">{t.totalBalance}</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                  {recentTransactions.map((tx) => (
                    <tr key={tx.id || tx.timestamp} className="hover:bg-slate-50/50 dark:hover:bg-slate-800/50 transition-colors text-xs">
                      <td className="px-4 py-3 font-semibold text-slate-700 dark:text-slate-300">{tx.date.split('-').reverse().join('/')}</td>
                      <td className="px-4 py-3 font-bold text-emerald-600 dark:text-emerald-400">{formatCurrency(Number(tx.dailyCash))}</td>
                      <td className="px-4 py-3 font-bold text-rose-500 dark:text-rose-400">{formatCurrency(Number(tx.totalExpenses))}</td>
                      <td className="px-4 py-3 font-black text-indigo-600 dark:text-indigo-400 bg-indigo-50/20 dark:bg-indigo-900/5">{formatCurrency(Number(tx.totalBalance))}</td>
                    </tr>
                  ))}
                  {transactions.length === 0 && (
                    <tr>
                      <td colSpan={4} className="px-4 py-10 text-center text-slate-400 dark:text-slate-600 font-medium italic text-xs">{t.noData}</td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </>
      )}

      {activeTab === 'analytics' && (
        <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div>
            <div className="flex items-center justify-between mb-4">
              <div className="flex items-center gap-2">
                <div className="p-1.5 bg-indigo-100 dark:bg-indigo-900/30 rounded-lg">
                  <BarChart3 className="w-5 h-5 text-indigo-700 dark:text-indigo-400" />
                </div>
                <h2 className="text-xl font-black text-slate-800 dark:text-slate-100">{t.charts}</h2>
              </div>
            </div>
            <MonthlyCharts t={t} transactions={currentMonthTransactions} />
          </div>
        </div>
      )}

      {activeTab === 'budget' && (
        <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
          <BudgetPerformance 
            t={t} 
            transactions={transactions} 
            budgets={budgets} 
            formatCurrency={formatCurrency} 
          />
        </div>
      )}

      {activeTab === 'history' && (
        <div className="bg-white dark:bg-slate-900 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-800 overflow-hidden animate-in fade-in slide-in-from-bottom-4 duration-500 transition-colors">
          <div className="p-4 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between no-print">
            <div className="flex items-center gap-2">
               <History className="w-5 h-5 text-indigo-600 dark:text-indigo-400" />
               <h2 className="text-lg font-bold text-slate-800 dark:text-slate-100">{t.history}</h2>
            </div>
          </div>
          <HistoryTable 
            t={t} 
            transactions={currentMonthTransactions} 
            allTransactions={transactions}
            onEdit={handleEdit} 
            onDelete={onDelete} 
            isLoading={isLoading} 
            formatCurrency={formatCurrency}
            budgets={budgets}
          />
        </div>
      )}

      {showAddForm && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/60 dark:bg-black/70 backdrop-blur-sm no-print">
          <div className="bg-white dark:bg-slate-900 w-full max-w-2xl rounded-2xl md:rounded-3xl shadow-2xl dark:shadow-none overflow-hidden max-h-[90vh] flex flex-col scale-in-center transition-colors">
            <div className="p-4 md:p-6 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between shrink-0">
              <h3 className="text-lg font-bold text-slate-800 dark:text-slate-100">
                {editingTransaction ? t.edit : t.addRecord}
              </h3>
              <button 
                onClick={() => { setShowAddForm(false); setEditingTransaction(null); }}
                className="p-1.5 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full transition-colors"
              >
                <X className="w-5 h-5 text-slate-400 dark:text-slate-500" />
              </button>
            </div>
            <div className="p-4 md:p-6 overflow-y-auto">
              <TransactionForm 
                t={t} 
                initialData={editingTransaction}
                getStartingBalance={getStartingBalance}
                formatCurrency={formatCurrency}
                onSubmit={(data) => {
                  if (editingTransaction?.id) {
                    onUpdate(editingTransaction.id, data);
                  } else {
                    onAdd(data);
                  }
                  setShowAddForm(false);
                  setEditingTransaction(null);
                }} 
              />
            </div>
          </div>
        </div>
      )}

      {showBudgetForm && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/60 dark:bg-black/70 backdrop-blur-sm no-print">
          <div className="bg-white dark:bg-slate-900 w-full max-w-lg rounded-2xl md:rounded-3xl shadow-2xl dark:shadow-none overflow-hidden flex flex-col scale-in-center transition-colors max-h-[95vh]">
            <div className="p-4 md:p-6 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between shrink-0">
              <h3 className="text-lg font-bold text-slate-800 dark:text-slate-100">{t.manageBudget}</h3>
              <button 
                onClick={() => setShowBudgetForm(false)}
                className="p-1.5 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full transition-colors"
              >
                <X className="w-5 h-5 text-slate-400 dark:text-slate-500" />
              </button>
            </div>
            <div className="p-3 md:p-6 overflow-y-auto">
              <BudgetManager 
                t={t} 
                month={selectedMonth} 
                initialLimits={activeBudget.limits} 
                onSubmit={handleSaveBudget} 
              />
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { Transaction } from '../types';
import { AlertCircle, Sparkles, Loader2, CheckCircle, RefreshCcw } from 'lucide-react';
import { GoogleGenAI, Type } from "@google/genai";

interface TransactionFormProps {
  t: any;
  initialData?: Transaction | null;
  getStartingBalance: (date: string) => number;
  onSubmit: (data: Transaction) => void;
  formatCurrency: (amount: number) => string;
}

const TransactionForm: React.FC<TransactionFormProps> = ({ t, initialData, getStartingBalance, onSubmit, formatCurrency }) => {
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    groceries: '' as any,
    vegetables: '' as any,
    fishEgg: '' as any,
    chicken: '' as any,
    houseRent: '' as any,
    electricity: '' as any,
    water: '' as any,
    travel: '' as any,
    others: '' as any,
    dailyCash: '' as any,
    broughtForward: '' as any,
  });

  const [dateError, setDateError] = useState<string | null>(null);
  const [aiText, setAiText] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [aiStatus, setAiStatus] = useState<'idle' | 'success' | 'error'>('idle');

  useEffect(() => {
    if (initialData) {
      setFormData({
        date: initialData.date,
        groceries: initialData.groceries || '',
        vegetables: initialData.vegetables || '',
        fishEgg: initialData.fishEgg || '',
        chicken: initialData.chicken || '',
        houseRent: initialData.houseRent || '',
        electricity: initialData.electricity || '',
        water: initialData.water || '',
        travel: initialData.travel || '',
        others: initialData.others || '',
        dailyCash: initialData.dailyCash || '',
        broughtForward: initialData.broughtForward || '',
      });
    } else {
      const bf = getStartingBalance(formData.date);
      setFormData(prev => ({
        ...prev,
        broughtForward: bf === 0 ? '' : bf
      }));
    }
  }, [initialData, getStartingBalance, formData.date]);

  const handleSmartEntry = async () => {
    if (!aiText.trim()) return;
    setIsProcessing(true);
    setAiStatus('idle');

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Parse this spending description and extract the amounts for these categories: 
        groceries, vegetables, fishEgg, chicken, houseRent, electricity, water, travel, others, and dailyCash.
        Input text (can be English or Sinhala): "${aiText}"
        Return as JSON only.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              groceries: { type: Type.NUMBER },
              vegetables: { type: Type.NUMBER },
              fishEgg: { type: Type.NUMBER },
              chicken: { type: Type.NUMBER },
              houseRent: { type: Type.NUMBER },
              electricity: { type: Type.NUMBER },
              water: { type: Type.NUMBER },
              travel: { type: Type.NUMBER },
              others: { type: Type.NUMBER },
              dailyCash: { type: Type.NUMBER },
            }
          }
        },
      });

      const result = JSON.parse(response.text || '{}');

      setFormData(prev => ({
        ...prev,
        groceries: result.groceries || prev.groceries,
        vegetables: result.vegetables || prev.vegetables,
        fishEgg: result.fishEgg || prev.fishEgg,
        chicken: result.chicken || prev.chicken,
        houseRent: result.houseRent || prev.houseRent,
        electricity: result.electricity || prev.electricity,
        water: result.water || prev.water,
        travel: result.travel || prev.travel,
        others: result.others || prev.others,
        dailyCash: result.dailyCash || prev.dailyCash,
      }));

      setAiStatus('success');
      setAiText('');
      setTimeout(() => setAiStatus('idle'), 3000);
    } catch (error) {
      console.error("AI Entry error:", error);
      setAiStatus('error');
    } finally {
      setIsProcessing(false);
    }
  };

  const validateDate = (dateString: string) => {
    const selectedDate = new Date(dateString);
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    selectedDate.setHours(0, 0, 0, 0);

    if (selectedDate > today) {
      setDateError(t.futureDateError);
      return false;
    } else {
      setDateError(null);
      return true;
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value, type } = e.target;
    if (name === 'date') validateDate(value);
    setFormData(prev => ({
      ...prev,
      [name]: type === 'number' ? (value === '' ? '' : parseFloat(value)) : value
    }));
  };

  const val = (v: any) => {
    const n = parseFloat(v);
    return isNaN(n) ? 0 : n;
  };

  const totalExpenses = 
    val(formData.groceries) + 
    val(formData.vegetables) + 
    val(formData.fishEgg) + 
    val(formData.chicken) + 
    val(formData.houseRent) +
    val(formData.electricity) +
    val(formData.water) +
    val(formData.travel) +
    val(formData.others);

  const totalBalance = val(formData.broughtForward) + val(formData.dailyCash) - totalExpenses;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!validateDate(formData.date)) return;

    const dateObj = new Date(formData.date);
    const monthName = dateObj.toLocaleString('en-US', { month: 'long', year: 'numeric' });

    onSubmit({
      ...formData,
      groceries: val(formData.groceries),
      vegetables: val(formData.vegetables),
      fishEgg: val(formData.fishEgg),
      chicken: val(formData.chicken),
      houseRent: val(formData.houseRent),
      electricity: val(formData.electricity),
      water: val(formData.water),
      travel: val(formData.travel),
      others: val(formData.others),
      dailyCash: val(formData.dailyCash),
      broughtForward: val(formData.broughtForward),
      month: monthName,
      totalExpenses: totalExpenses,
      totalBalance: totalBalance,
      timestamp: new Date().toISOString()
    });
  };

  return (
    <div className="space-y-6">
      {/* Smart AI Entry Section */}
      <div className="bg-indigo-600 p-6 rounded-3xl shadow-xl shadow-indigo-100 dark:shadow-none transition-all">
        <div className="flex items-center gap-2 mb-4">
          <Sparkles className="w-5 h-5 text-indigo-200" />
          <h3 className="text-white font-black uppercase tracking-tight text-sm">{t.smartEntry}</h3>
        </div>
        <div className="relative group">
          <textarea
            className="w-full bg-white/10 border border-white/20 rounded-2xl p-4 text-white placeholder-white/40 outline-none focus:ring-2 focus:ring-white/30 transition-all font-medium min-h-[80px] resize-none pr-12"
            placeholder={t.smartEntryPlaceholder}
            value={aiText}
            onChange={(e) => setAiText(e.target.value)}
            disabled={isProcessing}
            onKeyDown={(e) => {
              if (e.key === 'Enter' && !e.shiftKey) {
                e.preventDefault();
                handleSmartEntry();
              }
            }}
          />
          <button
            type="button"
            onClick={handleSmartEntry}
            disabled={isProcessing || !aiText.trim()}
            className="absolute right-3 bottom-3 p-2 bg-white text-indigo-600 rounded-xl hover:scale-105 active:scale-95 transition-all disabled:opacity-50 disabled:scale-100 shadow-lg"
          >
            {isProcessing ? <Loader2 className="w-5 h-5 animate-spin" /> : <RefreshCcw className="w-5 h-5" />}
          </button>
        </div>

        {aiStatus === 'success' && (
          <div className="mt-3 flex items-center gap-2 text-indigo-100 text-xs font-bold animate-in fade-in slide-in-from-top-1">
            <CheckCircle className="w-4 h-4" />
            {t.entrySuccess}
          </div>
        )}
        {aiStatus === 'error' && (
          <div className="mt-3 flex items-center gap-2 text-rose-200 text-xs font-bold animate-in fade-in slide-in-from-top-1">
            <AlertCircle className="w-4 h-4" />
            {t.entryError}
          </div>
        )}
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          <div className="space-y-1">
            <label className="block text-sm font-semibold text-slate-700 dark:text-slate-300 mb-1">{t.date}</label>
            <input
              type="date"
              name="date"
              required
              className={`w-full px-4 py-2.5 rounded-xl border ${dateError ? 'border-rose-500 ring-1 ring-rose-500' : 'border-slate-200 dark:border-slate-700'} bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 focus:ring-2 focus:ring-indigo-500 outline-none transition-all`}
              value={formData.date}
              onChange={handleChange}
            />
            {dateError && (
              <div className="flex items-center gap-1.5 text-rose-500 text-xs font-bold animate-in fade-in slide-in-from-top-1">
                <AlertCircle className="w-3.5 h-3.5" />
                {dateError}
              </div>
            )}
          </div>
          <div>
            <label className="block text-sm font-semibold text-slate-700 dark:text-slate-300 mb-1">{t.broughtForward}</label>
            <input
              type="number"
              name="broughtForward"
              placeholder="0"
              className="w-full px-4 py-2.5 rounded-xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 focus:ring-2 focus:ring-indigo-500 outline-none transition-all font-bold text-indigo-600 dark:text-indigo-400"
              value={formData.broughtForward}
              onChange={handleChange}
            />
          </div>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
          <div>
            <label className="block text-sm font-semibold mb-1 text-emerald-600 dark:text-emerald-400">{t.dailyCash}</label>
            <input
              type="number"
              name="dailyCash"
              placeholder="0"
              className="w-full px-4 py-2.5 rounded-xl border border-emerald-200 dark:border-emerald-900 bg-emerald-50 dark:bg-emerald-900/10 font-bold transition-all focus:ring-2 focus:ring-emerald-500 outline-none text-emerald-800 dark:text-emerald-100"
              value={formData.dailyCash}
              onChange={handleChange}
            />
          </div>
          {[
            { name: 'groceries', label: t.groceries },
            { name: 'vegetables', label: t.vegetables },
            { name: 'fishEgg', label: t.fishEgg },
            { name: 'chicken', label: t.chicken },
            { name: 'houseRent', label: t.houseRent },
            { name: 'electricity', label: t.electricity },
            { name: 'water', label: t.water },
            { name: 'travel', label: t.travel },
            { name: 'others', label: t.others },
          ].map(field => (
            <div key={field.name}>
              <label className="block text-sm font-semibold mb-1 text-slate-700 dark:text-slate-300">{field.label}</label>
              <input
                type="number"
                name={field.name}
                placeholder="0"
                className="w-full px-4 py-2.5 rounded-xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 transition-all focus:ring-2 focus:ring-indigo-500 outline-none font-medium"
                value={(formData as any)[field.name]}
                onChange={handleChange}
              />
            </div>
          ))}
        </div>

        <div className="p-6 bg-slate-50 dark:bg-slate-800/50 rounded-2xl flex flex-wrap gap-8 items-center justify-center border border-slate-100 dark:border-slate-800 transition-colors">
          <div className="text-center">
            <p className="text-xs text-slate-400 dark:text-slate-500 uppercase tracking-wider font-bold">{t.totalExpenses}</p>
            <p className="text-2xl font-black text-rose-600 dark:text-rose-400">{formatCurrency(totalExpenses)}</p>
          </div>
          <div className="text-center">
            <p className="text-xs text-slate-400 dark:text-slate-500 uppercase tracking-wider font-bold">{t.totalBalance}</p>
            <p className="text-2xl font-black text-indigo-600 dark:text-indigo-400">{formatCurrency(totalBalance)}</p>
          </div>
        </div>

        <button
          type="submit"
          disabled={!!dateError}
          className={`w-full ${dateError ? 'bg-slate-300 cursor-not-allowed' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-200'} text-white py-4 rounded-xl font-bold shadow-lg dark:shadow-none active:scale-[0.99] transition-all`}
        >
          {t.save}
        </button>
      </form>
    </div>
  );
};

