import { storageService } from '../services/googleSheets';
import { Plus, CreditCard, Trash2, Calendar, DollarSign, X, TrendingUp, ReceiptText, CheckCircle2 } from 'lucide-react';

interface BillManagerProps {
  t: any;
  formatCurrency: (amount: number) => string;
  transactions: Transaction[];
  onRefresh?: () => void;
}

const CATEGORY_COLORS: Record<string, { dot: string; bg: string; text: string }> = {
  groceries: { dot: 'bg-indigo-500', bg: 'bg-indigo-50 dark:bg-indigo-900/20', text: 'text-indigo-600 dark:text-indigo-400' },
  vegetables: { dot: 'bg-emerald-500', bg: 'bg-emerald-50 dark:bg-emerald-900/20', text: 'text-emerald-600 dark:text-emerald-400' },
  fishEgg: { dot: 'bg-blue-500', bg: 'bg-blue-50 dark:bg-blue-900/20', text: 'text-blue-600 dark:text-blue-400' },
  chicken: { dot: 'bg-orange-500', bg: 'bg-orange-50 dark:bg-orange-900/20', text: 'text-orange-600 dark:text-orange-400' },
  houseRent: { dot: 'bg-rose-500', bg: 'bg-rose-50 dark:bg-rose-900/20', text: 'text-rose-600 dark:text-rose-400' },
  electricity: { dot: 'bg-yellow-500', bg: 'bg-yellow-50 dark:bg-yellow-900/20', text: 'text-yellow-600 dark:text-yellow-400' },
  water: { dot: 'bg-cyan-500', bg: 'bg-cyan-50 dark:bg-cyan-900/20', text: 'text-cyan-600 dark:text-cyan-400' },
  travel: { dot: 'bg-purple-500', bg: 'bg-purple-50 dark:bg-purple-900/20', text: 'text-purple-600 dark:text-purple-400' },
  others: { dot: 'bg-slate-500', bg: 'bg-slate-50 dark:bg-slate-800/50', text: 'text-slate-600 dark:text-slate-400' },
};

const BillManager: React.FC<BillManagerProps> = ({ t, formatCurrency, transactions, onRefresh }) => {
  const [bills, setBills] = useState<Bill[]>([]);
  const [showAdd, setShowAdd] = useState(false);
  const [newBill, setNewBill] = useState<Partial<Bill>>({ dueDay: new Date().getDate(), category: 'others' });
  const [isNameManuallyEdited, setIsNameManuallyEdited] = useState(false);

  useEffect(() => {
    storageService.fetchBills().then(setBills);
  }, []);

  const currentMonthLabel = useMemo(() => {
    return new Date().toLocaleString('en-US', { month: 'long', year: 'numeric' });
  }, []);

  const monthlySpendingSummary = useMemo(() => {
    const currentMonthTxs = transactions.filter(tx => tx.month === currentMonthLabel);

    // Aggregating actual spending by category
    const actualByCategory: Record<string, number> = {
      groceries: 0, vegetables: 0, fishEgg: 0, chicken: 0,
      houseRent: 0, electricity: 0, water: 0, travel: 0, others: 0
    };

    currentMonthTxs.forEach(tx => {
      Object.keys(actualByCategory).forEach(cat => {
        actualByCategory[cat] += (tx as any)[cat] || 0;
      });
    });

    // Aggregating bill estimates by category
    const billEstimatesByCategory: Record<string, number> = {
      groceries: 0, vegetables: 0, fishEgg: 0, chicken: 0,
      houseRent: 0, electricity: 0, water: 0, travel: 0, others: 0
    };

    bills.forEach(bill => {
      if (billEstimatesByCategory[bill.category] !== undefined) {
        billEstimatesByCategory[bill.category] += bill.amount;
      } else {
        billEstimatesByCategory.others += bill.amount;
      }
    });

    return Object.keys(actualByCategory)
      .map(cat => ({
        category: cat,
        label: t[cat as keyof typeof t] || cat,
        actual: actualByCategory[cat],
        estimate: billEstimatesByCategory[cat]
      }))
      .filter(item => item.actual > 0 || item.estimate > 0)
      .sort((a, b) => b.actual - a.actual);
  }, [transactions, bills, currentMonthLabel, t]);

  const handleCategoryChange = (category: string) => {
    const updates: Partial<Bill> = { category };

    // Auto-fill name if not manually edited or if name is empty
    if (!isNameManuallyEdited || !newBill.name) {
      updates.name = t[category as keyof typeof t] || category;
    }

    setNewBill(prev => ({ ...prev, ...updates }));
  };

  const handleSave = async () => {
    if (!newBill.name || !newBill.amount) return;
    const bill: Bill = {
      id: crypto.randomUUID(),
      name: newBill.name,
      amount: Number(newBill.amount),
      dueDay: Number(newBill.dueDay),
      category: newBill.category || 'others'
    };
    await storageService.saveBill(bill);
    setBills([...bills, bill]);
    setShowAdd(false);
    resetForm();
    if (onRefresh) onRefresh();
  };

  const resetForm = () => {
    setNewBill({ dueDay: new Date().getDate(), category: 'others' });
    setIsNameManuallyEdited(false);
  };

  const handleDelete = async (id: string) => {
    if (window.confirm(t.confirmDelete)) {
      await storageService.deleteBill(id);
      setBills(bills.filter(b => b.id !== id));
      if (onRefresh) onRefresh();
    }
  };

  const handlePayBill = async (bill: Bill) => {
    const updatedBill: Bill = {
      ...bill,
      lastPaidMonth: currentMonthLabel
    };
    await storageService.saveBill(updatedBill);
    setBills(prev => prev.map(b => b.id === bill.id ? updatedBill : b));
    if (onRefresh) onRefresh();
  };

  const getDummyDateString = (day: number = 1) => {
    const now = new Date();
    const date = new Date(now.getFullYear(), now.getMonth(), day);
    return date.toISOString().split('T')[0];
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      {/* Page Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-indigo-100 dark:bg-indigo-900/30 rounded-xl">
            <CreditCard className="w-6 h-6 text-indigo-700 dark:text-indigo-400" />
          </div>
          <h2 className="text-2xl font-black text-slate-800 dark:text-slate-100">{t.bills}</h2>
        </div>
        <button 
          onClick={() => setShowAdd(true)}
          className="flex items-center gap-2 px-6 py-3 bg-indigo-600 text-white rounded-2xl font-bold shadow-lg shadow-indigo-200 dark:shadow-none hover:bg-indigo-700 active:scale-95 transition-all"
        >
          <Plus className="w-5 h-5" />
          {t.addBill}
        </button>
      </div>

      {/* Monthly Spending Section */}
      <div className="bg-white dark:bg-slate-900 rounded-3xl border border-slate-100 dark:border-slate-800 p-6 shadow-sm overflow-hidden transition-colors">
        <div className="flex items-center gap-3 mb-6">
          <div className="p-2 bg-emerald-100 dark:bg-emerald-900/30 rounded-xl">
            <TrendingUp className="w-5 h-5 text-emerald-600 dark:text-emerald-400" />
          </div>
          <div>
            <h3 className="text-lg font-bold text-slate-800 dark:text-slate-100">Monthly Spending Summary</h3>
            <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">{currentMonthLabel}</p>
          </div>
        </div>

        {monthlySpendingSummary.length > 0 ? (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
            {monthlySpendingSummary.map(item => (
              <div key={item.category} className="p-4 bg-slate-50 dark:bg-slate-800/40 rounded-2xl border border-slate-100 dark:border-slate-700/30">
                <div className="flex justify-between items-start mb-2">
                  <span className="text-xs font-black uppercase text-slate-400 tracking-wider flex items-center gap-2">
                    <span className={`w-2 h-2 rounded-full ${CATEGORY_COLORS[item.category]?.dot || 'bg-slate-400'}`} />
                    {item.label}
                  </span>
                  {item.estimate > 0 && item.actual > item.estimate && (
                    <span className="text-[10px] font-black text-rose-500 bg-rose-50 dark:bg-rose-950/30 px-2 py-0.5 rounded-full">Exceeded Bill</span>
                  )}
                </div>
                <div className="flex items-baseline gap-2 mb-3">
                  <span className="text-xl font-black text-slate-800 dark:text-slate-100">{formatCurrency(item.actual)}</span>
                  {item.estimate > 0 && (
                    <span className="text-xs text-slate-400 font-bold">/ {formatCurrency(item.estimate)}</span>
                  )}
                </div>
                {item.estimate > 0 && (
                  <div className="w-full h-1.5 bg-slate-200 dark:bg-slate-700 rounded-full overflow-hidden">
                    <div 
                      className={`h-full transition-all duration-700 ${item.actual > item.estimate ? 'bg-rose-500' : 'bg-emerald-500'}`}
                      style={{ width: `${Math.min((item.actual / item.estimate) * 100, 100)}%` }}
                    />
                  </div>
                )}
              </div>
            ))}
          </div>
        ) : (
          <div className="py-10 text-center text-slate-400 italic flex flex-col items-center gap-2">
            <ReceiptText className="w-8 h-8 opacity-20" />
            <p>No spending recorded for this month yet.</p>
          </div>
        )}
      </div>

      {/* Bill List Section */}
      <div className="space-y-4">
        <h3 className="text-lg font-bold text-slate-800 dark:text-slate-100 flex items-center gap-2">
          <ReceiptText className="w-5 h-5 text-indigo-600" />
          Scheduled & Recurring
        </h3>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {bills.map(bill => {
            const isPaidThisMonth = bill.lastPaidMonth === currentMonthLabel;
            const categoryStyle = CATEGORY_COLORS[bill.category] || CATEGORY_COLORS.others;
            return (
              <div 
                key={bill.id} 
                className={`bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-100 dark:border-slate-800 shadow-sm relative group overflow-hidden transition-all duration-300 ${isPaidThisMonth ? 'opacity-60 bg-slate-50 dark:bg-slate-800/20' : ''}`}
              >
                <div className={`absolute top-0 left-0 w-1.5 h-full transition-all ${isPaidThisMonth ? 'bg-emerald-500' : categoryStyle.dot}`} />
                <div className="flex justify-between items-start mb-4 pl-2">
                  <div>
                    <h3 className={`font-black text-slate-800 dark:text-slate-100 text-lg uppercase tracking-tight flex items-center gap-2 ${isPaidThisMonth ? 'line-through decoration-slate-400' : ''}`}>
                      <span className={`w-2 h-2 rounded-full ${isPaidThisMonth ? 'bg-emerald-500' : categoryStyle.dot}`} />
                      {bill.name}
                    </h3>
                    <p className={`text-[10px] font-black uppercase tracking-widest ${isPaidThisMonth ? 'text-slate-400' : categoryStyle.text}`}>
                      {t[bill.category as keyof typeof t] || bill.category}
                    </p>
                  </div>
                  <button 
                    onClick={() => handleDelete(bill.id)}
                    className="p-2 text-slate-300 dark:text-slate-600 hover:text-rose-500 dark:hover:text-rose-400 hover:bg-rose-50 dark:hover:bg-rose-900/30 rounded-xl transition-all"
                  >
                    <Trash2 className="w-4 h-4" />
                  </button>
                </div>

                <div className="flex items-center gap-6 pl-2 mb-6">
                  <div className="flex flex-col">
                    <span className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-1">{t.date}</span>
                    <div className={`flex items-center gap-2 font-black ${isPaidThisMonth ? 'text-slate-400' : 'text-indigo-600 dark:text-indigo-400'}`}>
                      <Calendar className="w-4 h-4" />
                      <span>Day {bill.dueDay} / Month</span>
                    </div>
                  </div>
                  <div className="flex flex-col">
                    <span className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-1">Amount</span>
                    <div className={`flex items-center gap-2 font-black ${isPaidThisMonth ? 'text-slate-400' : 'text-slate-800 dark:text-slate-100'}`}>
                      <DollarSign className="w-4 h-4 text-slate-300 dark:text-slate-700" />
                      <span>{formatCurrency(bill.amount)}</span>
                    </div>
                  </div>
                </div>

                <div className="pl-2">
                  {isPaidThisMonth ? (
                    <div className="flex items-center gap-2 text-emerald-600 dark:text-emerald-400 font-black text-sm uppercase tracking-widest bg-emerald-50 dark:bg-emerald-950/30 py-2 px-4 rounded-xl w-fit">
                      <CheckCircle2 className="w-4 h-4" />
                      {t.paid}
                    </div>
                  ) : (
                    <button 
                      onClick={() => handlePayBill(bill)}
                      className={`w-full flex items-center justify-center gap-2 text-white font-bold text-xs uppercase tracking-widest py-3 rounded-xl transition-all shadow-md active:scale-95 ${categoryStyle.dot} filter saturate-[1.2] brightness-[0.9] hover:brightness-[1.1]`}
                    >
                      <CheckCircle2 className="w-4 h-4" />
                      {t.payBill}
                    </button>
                  )}
                </div>
              </div>
            );
          })}

          {bills.length === 0 && (
            <div className="col-span-full py-20 bg-slate-50/50 dark:bg-slate-900/50 rounded-3xl border-2 border-dashed border-slate-200 dark:border-slate-800 flex flex-col items-center justify-center text-slate-400 dark:text-slate-600 gap-4 transition-colors">
               <CreditCard className="w-12 h-12 opacity-10" />
               <p className="font-bold italic">{t.noData}</p>
            </div>
          )}
        </div>
      </div>

      {showAdd && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 dark:bg-black/70 backdrop-blur-sm">
          <div className="bg-white dark:bg-slate-900 w-full max-w-md rounded-3xl shadow-2xl dark:shadow-none overflow-hidden animate-in zoom-in-95 duration-200 transition-colors">
            <div className="p-6 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between">
              <h3 className="text-xl font-bold text-slate-800 dark:text-slate-100">{t.addBill}</h3>
              <button onClick={() => { setShowAdd(false); resetForm(); }} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full transition-colors">
                <X className="w-6 h-6 text-slate-400 dark:text-slate-500" />
              </button>
            </div>
            <div className="p-6 space-y-4">
              <div>
                <label className="block text-xs font-black text-slate-400 dark:text-slate-500 uppercase mb-2">Category</label>
                <select 
                  className="w-full px-4 py-3 rounded-2xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 focus:ring-2 focus:ring-indigo-500 outline-none font-bold"
                  value={newBill.category || 'others'}
                  onChange={e => handleCategoryChange(e.target.value)}
                >
                  <option value="groceries">{t.groceries}</option>
                  <option value="vegetables">{t.vegetables}</option>
                  <option value="fishEgg">{t.fishEgg}</option>
                  <option value="chicken">{t.chicken}</option>
                  <option value="houseRent">{t.houseRent}</option>
                  <option value="electricity">{t.electricity}</option>
                  <option value="water">{t.water}</option>
                  <option value="travel">{t.travel}</option>
                  <option value="others">{t.others}</option>
                </select>
              </div>

              <div>
                <label className="block text-xs font-black text-slate-400 dark:text-slate-500 uppercase mb-2">Bill Name</label>
                <input 
                  type="text" 
                  className="w-full px-4 py-3 rounded-2xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 focus:ring-2 focus:ring-indigo-500 outline-none font-bold"
                  value={newBill.name || ''}
                  onChange={e => {
                    setNewBill({...newBill, name: e.target.value});
                    setIsNameManuallyEdited(true);
                  }}
                  placeholder="e.g. Internet Bill"
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-black text-slate-400 dark:text-slate-500 uppercase mb-2">Amount</label>
                  <input 
                    type="number" 
                    className="w-full px-4 py-3 rounded-2xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 focus:ring-2 focus:ring-indigo-500 outline-none font-bold"
                    value={newBill.amount ?? ''}
                    onChange={e => setNewBill({...newBill, amount: e.target.value === '' ? undefined : Number(e.target.value)})}
                  />
                </div>
                <div>
                  <label className="block text-xs font-black text-slate-400 dark:text-slate-500 uppercase mb-2">Recurring Due Day</label>
                  <div className="relative">
                    <input 
                      type="date" 
                      className="w-full px-4 py-3 rounded-2xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 focus:ring-2 focus:ring-indigo-500 outline-none font-bold text-sm"
                      value={getDummyDateString(newBill.dueDay)}
                      onChange={e => {
                        const date = new Date(e.target.value);
                        if (!isNaN(date.getTime())) {
                          setNewBill({...newBill, dueDay: date.getDate()});
                        }
                      }}
                    />
                    <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-indigo-500">
                       <span className="text-xs font-black">Day {newBill.dueDay}</span>
                    </div>
                  </div>
                </div>
              </div>

              <button 
                onClick={handleSave}
                className="w-full bg-indigo-600 text-white py-4 rounded-2xl font-bold shadow-lg shadow-indigo-200 dark:shadow-none hover:bg-indigo-700 mt-4 transition-all"
              >
                {t.save}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default BillManager;

import React, { useState, useMemo } from 'react';
import { Transaction, MonthlyBudget } from '../types';
import { Edit2, Trash2, FileSpreadsheet, Printer, Search, X, Calendar as CalendarIcon, Filter, PieChart, AlertCircle, TrendingDown } from 'lucide-react';
import * as XLSX from 'xlsx';

interface HistoryTableProps {
  t: any;
  transactions: Transaction[];
  allTransactions?: Transaction[];
  onEdit: (tx: Transaction) => void;
  onDelete: (id: string) => void;
  isLoading: boolean;
  formatCurrency: (amount: number) => string;
  budgets?: MonthlyBudget[];
}

const HistoryTable: React.FC<HistoryTableProps> = ({ t, transactions, allTransactions = [], onEdit, onDelete, isLoading, formatCurrency, budgets = [] }) => {
  const [stagedSearch, setStagedSearch] = useState('');
  const [stagedStart, setStagedStart] = useState('');
  const [stagedEnd, setStagedEnd] = useState('');
  const [activeSearch, setActiveSearch] = useState('');
  const [activeStart, setActiveStart] = useState('');
  const [activeEnd, setActiveEnd] = useState('');

  // Use allTransactions as the source for filtering so that search and date ranges
  // work across the entire database, not just the currently selected month.
  const filteredTransactions = useMemo(() => {
    const lowerSearch = activeSearch.toLowerCase().trim();
    const source = (activeSearch || activeStart || activeEnd) ? allTransactions : transactions;

    return source.filter(tx => {
      // Date Range Filtering
      if (activeStart && tx.date < activeStart) return false;
      if (activeEnd && tx.date > activeEnd) return false;

      // Text Search Filtering
      if (lowerSearch) {
        const formattedDate = tx.date.split('-').reverse().join('/'); // dd/mm/yyyy
        const dateMatch = tx.date.includes(lowerSearch) || formattedDate.includes(lowerSearch);
        if (dateMatch) return true;

        const categories = [
          { key: 'groceries', label: t.groceries },
          { key: 'vegetables', label: t.vegetables },
          { key: 'fishEgg', label: t.fishEgg },
          { key: 'chicken', label: t.chicken },
          { key: 'houseRent', label: t.houseRent },
          { key: 'electricity', label: t.electricity },
          { key: 'water', label: t.water },
          { key: 'travel', label: t.travel },
          { key: 'others', label: t.others },
        ];

        const matchesCategory = categories.some(cat => 
          cat.label.toLowerCase().includes(lowerSearch) && Number((tx as any)[cat.key]) > 0
        );
        if (matchesCategory) return true;

        const numericMatch = 
          tx.totalExpenses.toString().includes(lowerSearch) || 
          tx.dailyCash.toString().includes(lowerSearch) || 
          tx.totalBalance.toString().includes(lowerSearch);

        return numericMatch;
      }
      return true;
    });
  }, [transactions, allTransactions, activeSearch, activeStart, activeEnd, t]);

  const sortedFiltered = useMemo(() => {
    return [...filteredTransactions].sort((a, b) => 
      a.date.localeCompare(b.date) || (a.timestamp || '').localeCompare(b.timestamp || '')
    );
  }, [filteredTransactions]);

  const summary = useMemo(() => {
    if (sortedFiltered.length === 0) return null;

    const totalIncome = sortedFiltered.reduce((sum, tx) => sum + (Number(tx.dailyCash) || 0), 0);
    const totalExpenses = sortedFiltered.reduce((sum, tx) => sum + (Number(tx.totalExpenses) || 0), 0);

    const startBF = Number(sortedFiltered[0].broughtForward) || 0;
    const endBalance = startBF + totalIncome - totalExpenses;

    const catKeys = ['groceries', 'vegetables', 'fishEgg', 'chicken', 'houseRent', 'electricity', 'water', 'travel', 'others'];
    const catTotals: Record<string, { actual: number, limit: number }> = {};

    // We only show budget alerts if the view is filtered to a single month
    const monthsInView = new Set(sortedFiltered.map(tx => tx.month));
    const isSingleMonth = monthsInView.size === 1;
    const currentMonthLabel = Array.from(monthsInView)[0];
    const activeBudget = isSingleMonth ? budgets.find(b => b.month === currentMonthLabel) : null;

    catKeys.forEach(key => {
      catTotals[key] = {
        actual: sortedFiltered.reduce((sum, tx) => sum + (Number((tx as any)[key]) || 0), 0),
        limit: activeBudget ? (activeBudget.limits as any)[key] : 0
      };
    });

    const budgetAlerts = isSingleMonth ? catKeys.map(key => {
      const { actual: spent, limit } = catTotals[key];
      const isOver = limit > 0 && spent > limit;
      const progress = limit > 0 ? (spent / limit) * 100 : 0;
      return { key, label: (t as any)[key], spent, limit, isOver, progress };
    }).filter(a => a.isOver || (a.limit > 0 && a.progress >= 85)) : [];

    return {
      startBF,
      totalIncome,
      totalExpenses,
      endBalance,
      isSingleMonth,
      currentMonthLabel,
      catTotals,
      budgetAlerts
    };
  }, [sortedFiltered, budgets, t]);

  const exportToExcel = () => {
    if (sortedFiltered.length === 0) return;
    const workbook = XLSX.utils.book_new();

    const formattedData = sortedFiltered.map(tx => ({
      [t.date]: tx.date,
      [t.broughtForward]: tx.broughtForward,
      [t.dailyCash]: tx.dailyCash,
      [t.groceries]: tx.groceries,
      [t.vegetables]: tx.vegetables,
      [t.fishEgg]: tx.fishEgg,
      [t.chicken]: tx.chicken,
      [t.houseRent]: tx.houseRent,
      [t.electricity]: tx.electricity,
      [t.water]: tx.water,
      [t.travel]: tx.travel,
      [t.others]: tx.others,
      [t.totalExpenses]: tx.totalExpenses,
      [t.totalBalance]: tx.totalBalance,
    }));

    const ws = XLSX.utils.json_to_sheet(formattedData);
    XLSX.utils.book_append_sheet(workbook, ws, "Filtered Transactions");
    XLSX.writeFile(workbook, `Filtered_Report_${new Date().toISOString().split('T')[0]}.xlsx`);
  };

  const clearFilters = () => {
    setStagedSearch(''); setStagedStart(''); setStagedEnd('');
    setActiveSearch(''); setActiveStart(''); setActiveEnd('');
  };

  if (isLoading) return <div className="p-12 text-center text-slate-400">Loading records...</div>;

  return (
    <div className="flex flex-col">
      {/* Dynamic Summary Section */}
      {summary && (
        <div className="p-4 md:p-6 bg-slate-50 dark:bg-slate-800/50 border-b border-slate-100 dark:border-slate-800 transition-colors">
          <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-4 mb-4 md:mb-6">
            <div className="flex items-center gap-2">
               <PieChart className="w-5 h-5 text-indigo-600 dark:text-indigo-400" />
               <h3 className="font-bold text-slate-700 dark:text-slate-300 uppercase text-xs tracking-widest">
                 {summary.isSingleMonth ? `${summary.currentMonthLabel} ${t.summary}` : 'Filtered View Summary'}
               </h3>
            </div>

            {summary.budgetAlerts.length > 0 && (
              <div className="flex flex-wrap gap-2">
                {summary.budgetAlerts.map((alert, idx) => (
                  <div key={idx} className={`flex items-center gap-2 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-tight ${alert.isOver ? 'bg-rose-100 text-rose-600 dark:bg-rose-900/30' : 'bg-amber-100 text-amber-600 dark:bg-amber-900/30'}`}>
                    <AlertCircle className="w-3 h-3" />
                    {alert.label}: {alert.isOver ? t.overspent : 'Near Limit'}
                  </div>
                ))}
              </div>
            )}
          </div>

          <div className="grid grid-cols-2 lg:grid-cols-4 gap-3 md:gap-4 mb-4 md:mb-6">
            <div className="bg-white dark:bg-slate-900 p-3 md:p-4 rounded-xl md:rounded-2xl border border-slate-100 dark:border-slate-800 shadow-sm">
               <p className="text-[10px] font-black text-slate-400 uppercase mb-1 tracking-wider">{t.broughtForward}</p>
               <p className="text-sm md:text-lg font-black text-indigo-600 dark:text-indigo-400">{formatCurrency(summary.startBF)}</p>
            </div>
            <div className="bg-white dark:bg-slate-900 p-3 md:p-4 rounded-xl md:rounded-2xl border border-slate-100 dark:border-slate-800 shadow-sm">
               <p className="text-[10px] font-black text-slate-400 uppercase mb-1 tracking-wider">{t.totalIncome}</p>
               <div className="flex items-center gap-1 md:gap-2">
                 <TrendingDown className="w-3 md:w-4 h-3 md:h-4 text-emerald-500 rotate-180" />
                 <p className="text-sm md:text-lg font-black text-emerald-600 dark:text-emerald-400">{formatCurrency(summary.totalIncome)}</p>
               </div>
            </div>
            <div className="bg-white dark:bg-slate-900 p-3 md:p-4 rounded-xl md:rounded-2xl border border-slate-100 dark:border-slate-800 shadow-sm">
               <p className="text-[10px] font-black text-slate-400 uppercase mb-1 tracking-wider">{t.totalExpenses}</p>
               <div className="flex items-center gap-1 md:gap-2">
                 <TrendingDown className="w-3 md:w-4 h-3 md:h-4 text-rose-500" />
                 <p className="text-sm md:text-lg font-black text-rose-600 dark:text-rose-400">{formatCurrency(summary.totalExpenses)}</p>
               </div>
            </div>
            <div className="bg-white dark:bg-slate-900 p-3 md:p-4 rounded-xl md:rounded-2xl border border-indigo-100 dark:border-indigo-900 shadow-sm bg-indigo-50/20 dark:bg-indigo-900/10">
               <p className="text-[10px] font-black text-indigo-400 uppercase mb-1 tracking-wider">{t.totalBalance}</p>
               <p className="text-sm md:text-lg font-black text-indigo-700 dark:text-indigo-300">{formatCurrency(summary.endBalance)}</p>
            </div>
          </div>

          <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-5 gap-2 md:gap-3">
             {Object.entries(summary.catTotals).map(([key, value]) => (
               <div key={key} className="bg-white/50 dark:bg-slate-900/50 p-2 md:p-3 rounded-lg md:rounded-xl border border-slate-100/50 dark:border-slate-800/50">
                  <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest truncate">{(t as any)[key]}</p>
                  <div className="flex flex-col">
                    <p className="text-xs md:text-sm font-bold text-slate-700 dark:text-slate-300">{formatCurrency(value.actual)}</p>
                    {value.limit > 0 && (
