import React, { useState, useEffect } from 'react';
import { Transaction } from '../types';
import { AlertCircle, Calculator } from 'lucide-react';

interface TransactionFormProps {
  t: any;
  initialData?: Transaction | null;
  getStartingBalance: (date: string) => number;
  onSubmit: (data: Transaction) => void;
  formatCurrency: (amount: number) => string;
}

const TransactionForm: React.FC<TransactionFormProps> = ({ t, initialData, getStartingBalance, onSubmit, formatCurrency }) => {
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    groceries: '' as any,
    vegetables: '' as any,
    fishEgg: '' as any,
    chicken: '' as any,
    houseRent: '' as any,
    electricity: '' as any,
    water: '' as any,
    travel: '' as any,
    others: '' as any,
    dailyCash: '' as any,
    broughtForward: '' as any,
  });

  const [dateError, setDateError] = useState<string | null>(null);
  const [isCalculated, setIsCalculated] = useState(false);

  // Synchronize Brought Forward whenever the date or initialData changes.
  useEffect(() => {
    if (initialData) {
      // Editing existing transaction
      setFormData({
        date: initialData.date,
        groceries: initialData.groceries || '',
        vegetables: initialData.vegetables || '',
        fishEgg: initialData.fishEgg || '',
        chicken: initialData.chicken || '',
        houseRent: initialData.houseRent || '',
        electricity: initialData.electricity || '',
        water: initialData.water || '',
        travel: initialData.travel || '',
        others: initialData.others || '',
        dailyCash: initialData.dailyCash || '',
        broughtForward: initialData.broughtForward,
      });
      setIsCalculated(false);
    } else {
      // Adding new transaction - calculate opening balance reactively
      const bf = getStartingBalance(formData.date);
      setFormData(prev => ({
        ...prev,
        broughtForward: Number(bf) || 0
      }));
      setIsCalculated(true);
    }
  }, [initialData, getStartingBalance, formData.date]);

  const validateDate = (dateString: string) => {
    const selectedDate = new Date(dateString);
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    selectedDate.setHours(0, 0, 0, 0);

    if (selectedDate > today) {
      setDateError(t.futureDateError);
      return false;
    } else {
      setDateError(null);
      return true;
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value, type } = e.target;
    if (name === 'date') validateDate(value);

    // If user manually edits the Brought Forward, mark it as no longer auto-calculated
    if (name === 'broughtForward') setIsCalculated(false);

    setFormData(prev => ({
      ...prev,
      [name]: type === 'number' ? (value === '' ? '' : Number(value)) : value
    }));
  };

  const val = (v: any) => {
    const n = Number(v);
    return isNaN(n) ? 0 : n;
  };

  const totalExpenses = 
    val(formData.groceries) + 
    val(formData.vegetables) + 
    val(formData.fishEgg) + 
    val(formData.chicken) + 
    val(formData.houseRent) +
    val(formData.electricity) +
    val(formData.water) +
    val(formData.travel) +
    val(formData.others);

  const totalBalance = val(formData.broughtForward) + val(formData.dailyCash) - totalExpenses;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!validateDate(formData.date)) return;

    const dateObj = new Date(formData.date);
    const monthName = dateObj.toLocaleString('en-US', { month: 'long', year: 'numeric' });

    onSubmit({
      ...formData,
      groceries: val(formData.groceries),
      vegetables: val(formData.vegetables),
      fishEgg: val(formData.fishEgg),
      chicken: val(formData.chicken),
      houseRent: val(formData.houseRent),
      electricity: val(formData.electricity),
      water: val(formData.water),
      travel: val(formData.travel),
      others: val(formData.others),
      dailyCash: val(formData.dailyCash),
      broughtForward: val(formData.broughtForward),
      month: monthName,
      totalExpenses: totalExpenses,
      totalBalance: totalBalance,
      timestamp: initialData?.timestamp || new Date().toISOString()
    });
  };

  return (
    <div className="space-y-6">
      <form onSubmit={handleSubmit} className="space-y-6">
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          <div className="space-y-1">
            <label className="block text-sm font-semibold text-slate-700 dark:text-slate-300 mb-1">{t.date}</label>
            <input
              type="date"
              name="date"
              required
              className={`w-full px-4 py-2.5 rounded-xl border ${dateError ? 'border-rose-500 ring-1 ring-rose-500' : 'border-slate-200 dark:border-slate-700'} bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 focus:ring-2 focus:ring-indigo-500 outline-none transition-all font-medium`}
              value={formData.date}
              onChange={handleChange}
            />
            {dateError && (
              <div className="flex items-center gap-1.5 text-rose-500 text-xs font-bold animate-in fade-in slide-in-from-top-1">
                <AlertCircle className="w-3.5 h-3.5" />
                {dateError}
              </div>
            )}
          </div>
          <div>
            <div className="flex items-center justify-between mb-1">
              <label className="block text-sm font-semibold text-slate-700 dark:text-slate-300">{t.broughtForward}</label>
              {isCalculated && (
                <span className="flex items-center gap-1 text-[10px] font-black text-indigo-500 dark:text-indigo-400 uppercase tracking-tight animate-in fade-in duration-300">
                  <Calculator className="w-2.5 h-2.5" />
                  Auto-Synced
                </span>
              )}
            </div>
            <input
              type="number"
              name="broughtForward"
              placeholder="0"
              className={`w-full px-4 py-2.5 rounded-xl border ${isCalculated ? 'border-indigo-100 dark:border-indigo-900 bg-indigo-50/20 dark:bg-indigo-900/10' : 'border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800'} text-slate-800 dark:text-slate-100 focus:ring-2 focus:ring-indigo-500 outline-none transition-all font-bold text-indigo-600 dark:text-indigo-400`}
              value={formData.broughtForward === '' ? '' : formData.broughtForward}
              onChange={handleChange}
            />
          </div>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
          <div>
            <label className="block text-sm font-semibold mb-1 text-emerald-600 dark:text-emerald-400">{t.dailyCash}</label>
            <input
              type="number"
              name="dailyCash"
              placeholder="0"
              className="w-full px-4 py-2.5 rounded-xl border border-emerald-200 dark:border-emerald-900 bg-emerald-50 dark:bg-emerald-900/10 font-bold transition-all focus:ring-2 focus:ring-emerald-500 outline-none text-emerald-800 dark:text-emerald-100"
              value={formData.dailyCash === '' ? '' : formData.dailyCash}
              onChange={handleChange}
            />
          </div>
          {[
            { name: 'groceries', label: t.groceries },
            { name: 'vegetables', label: t.vegetables },
            { name: 'fishEgg', label: t.fishEgg },
            { name: 'chicken', label: t.chicken },
            { name: 'houseRent', label: t.houseRent },
            { name: 'electricity', label: t.electricity },
            { name: 'water', label: t.water },
            { name: 'travel', label: t.travel },
            { name: 'others', label: t.others },
          ].map(field => (
            <div key={field.name}>
              <label className="block text-sm font-semibold mb-1 text-slate-700 dark:text-slate-300">{field.label}</label>
              <input
                type="number"
                name={field.name}
                placeholder="0"
                className="w-full px-4 py-2.5 rounded-xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 transition-all focus:ring-2 focus:ring-indigo-500 outline-none font-medium"
                value={(formData as any)[field.name] === '' ? '' : (formData as any)[field.name]}
                onChange={handleChange}
              />
            </div>
          ))}
        </div>

        <div className="p-6 bg-slate-50 dark:bg-slate-800/50 rounded-2xl flex flex-wrap gap-8 items-center justify-center border border-slate-100 dark:border-slate-800 transition-colors shadow-inner">
          <div className="text-center">
            <p className="text-xs text-slate-400 dark:text-slate-500 uppercase tracking-widest font-bold mb-1">{t.totalExpenses}</p>
            <p className="text-2xl font-black text-rose-600 dark:text-rose-400">{formatCurrency(totalExpenses)}</p>
          </div>
          <div className="text-center">
            <p className="text-xs text-slate-400 dark:text-slate-500 uppercase tracking-widest font-bold mb-1">{t.totalBalance}</p>
            <p className="text-2xl font-black text-indigo-600 dark:text-indigo-400">{formatCurrency(totalBalance)}</p>
          </div>
        </div>

        <button
          type="submit"
          disabled={!!dateError}
          className={`w-full ${dateError ? 'bg-slate-300 cursor-not-allowed' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-200'} text-white py-4 rounded-xl font-bold shadow-lg dark:shadow-none active:scale-[0.99] transition-all`}
        >
          {t.save}
        </button>
      </form>
    </div>
  );
};

export default TransactionForm;

import React, { useState, useEffect, useMemo } from 'react';
import { Bill, Transaction } from '../types';
import { storageService } from '../services/googleSheets';
import { Plus, CreditCard, Trash2, Calendar, DollarSign, X, TrendingUp, ReceiptText, CheckCircle2, Search, Filter, ArrowUpDown } from 'lucide-react';

interface BillManagerProps {
  t: any;
  formatCurrency: (amount: number) => string;
  transactions: Transaction[];
  onRefresh?: () => void;
}

const CATEGORY_COLORS: Record<string, { dot: string; bg: string; text: string }> = {
  groceries: { dot: 'bg-indigo-500', bg: 'bg-indigo-50 dark:bg-indigo-900/20', text: 'text-indigo-600 dark:text-indigo-400' },
  vegetables: { dot: 'bg-emerald-500', bg: 'bg-emerald-50 dark:bg-emerald-900/20', text: 'text-emerald-600 dark:text-emerald-400' },
  fishEgg: { dot: 'bg-blue-500', bg: 'bg-blue-50 dark:bg-blue-900/20', text: 'text-blue-600 dark:text-blue-400' },
  chicken: { dot: 'bg-orange-500', bg: 'bg-orange-50 dark:bg-orange-900/20', text: 'text-orange-600 dark:text-orange-400' },
  houseRent: { dot: 'bg-rose-500', bg: 'bg-rose-50 dark:bg-rose-900/20', text: 'text-rose-600 dark:text-rose-400' },
  electricity: { dot: 'bg-yellow-500', bg: 'bg-yellow-50 dark:bg-yellow-900/20', text: 'text-yellow-600 dark:text-yellow-400' },
  water: { dot: 'bg-cyan-500', bg: 'bg-cyan-50 dark:bg-cyan-900/20', text: 'text-cyan-600 dark:text-cyan-400' },
  travel: { dot: 'bg-purple-500', bg: 'bg-purple-50 dark:bg-purple-900/20', text: 'text-purple-600 dark:text-purple-400' },
  others: { dot: 'bg-slate-500', bg: 'bg-slate-50 dark:bg-slate-800/50', text: 'text-slate-600 dark:text-slate-400' },
};

const BillManager: React.FC<BillManagerProps> = ({ t, formatCurrency, transactions, onRefresh }) => {
  const [bills, setBills] = useState<Bill[]>([]);
  const [showAdd, setShowAdd] = useState(false);
  const [newBill, setNewBill] = useState<Partial<Bill>>({ dueDay: new Date().getDate(), category: 'others' });
  const [isNameManuallyEdited, setIsNameManuallyEdited] = useState(false);

  // Search and Filter State
  const [searchTerm, setSearchTerm] = useState('');
  const [categoryFilter, setCategoryFilter] = useState('all');
  const [sortBy, setSortBy] = useState<'day' | 'name' | 'amount'>('day');

  useEffect(() => {
    storageService.fetchBills().then(setBills);
  }, []);

  const currentMonthLabel = useMemo(() => {
    return new Date().toLocaleString('en-US', { month: 'long', year: 'numeric' });
  }, []);

  const filteredBills = useMemo(() => {
    return bills
      .filter(bill => {
        const matchesSearch = bill.name.toLowerCase().includes(searchTerm.toLowerCase());
        const matchesCategory = categoryFilter === 'all' || bill.category === categoryFilter;
        return matchesSearch && matchesCategory;
      })
      .sort((a, b) => {
        if (sortBy === 'day') return a.dueDay - b.dueDay;
        if (sortBy === 'amount') return b.amount - a.amount;
        return a.name.localeCompare(b.name);
      });
  }, [bills, searchTerm, categoryFilter, sortBy]);

  const monthlySpendingSummary = useMemo(() => {
    const currentMonthTxs = transactions.filter(tx => tx.month === currentMonthLabel);

    // Aggregating actual spending by category
    const actualByCategory: Record<string, number> = {
      groceries: 0, vegetables: 0, fishEgg: 0, chicken: 0,
      houseRent: 0, electricity: 0, water: 0, travel: 0, others: 0
    };

    currentMonthTxs.forEach(tx => {
      Object.keys(actualByCategory).forEach(cat => {
        actualByCategory[cat] += (tx as any)[cat] || 0;
      });
    });

    // Aggregating bill estimates by category
    const billEstimatesByCategory: Record<string, number> = {
      groceries: 0, vegetables: 0, fishEgg: 0, chicken: 0,
      houseRent: 0, electricity: 0, water: 0, travel: 0, others: 0
    };

    bills.forEach(bill => {
      if (billEstimatesByCategory[bill.category] !== undefined) {
        billEstimatesByCategory[bill.category] += bill.amount;
      } else {
        billEstimatesByCategory.others += bill.amount;
      }
    });

    return Object.keys(actualByCategory)
      .map(cat => ({
        category: cat,
        label: t[cat as keyof typeof t] || cat,
        actual: actualByCategory[cat],
        estimate: billEstimatesByCategory[cat]
      }))
      .filter(item => item.actual > 0 || item.estimate > 0)
      .sort((a, b) => b.actual - a.actual);
  }, [transactions, bills, currentMonthLabel, t]);

  const handleCategoryChange = (category: string) => {
    const updates: Partial<Bill> = { category };

    // Auto-fill name if not manually edited or if name is empty
    if (!isNameManuallyEdited || !newBill.name) {
      updates.name = t[category as keyof typeof t] || category;
    }

    setNewBill(prev => ({ ...prev, ...updates }));
  };

  const handleSave = async () => {
    if (!newBill.name || !newBill.amount) return;
    const bill: Bill = {
      id: crypto.randomUUID(),
      name: newBill.name,
      amount: Number(newBill.amount),
      dueDay: Number(newBill.dueDay),
      category: newBill.category || 'others'
    };
    await storageService.saveBill(bill);
    setBills([...bills, bill]);
    setShowAdd(false);
    resetForm();
    if (onRefresh) onRefresh();
  };

  const resetForm = () => {
    setNewBill({ dueDay: new Date().getDate(), category: 'others' });
    setIsNameManuallyEdited(false);
  };

  const handleDelete = async (id: string) => {
    if (window.confirm(t.confirmDelete)) {
      await storageService.deleteBill(id);
      setBills(bills.filter(b => b.id !== id));
      if (onRefresh) onRefresh();
    }
  };

  const handlePayBill = async (bill: Bill) => {
    const updatedBill: Bill = {
      ...bill,
      lastPaidMonth: currentMonthLabel
    };
    await storageService.saveBill(updatedBill);
    setBills(prev => prev.map(b => b.id === bill.id ? updatedBill : b));
    if (onRefresh) onRefresh();
  };

  const getDummyDateString = (day: number = 1) => {
    const now = new Date();
    const date = new Date(now.getFullYear(), now.getMonth(), day);
    return date.toISOString().split('T')[0];
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      {/* Page Header */}
      <div className="flex flex-col sm:flex-row items-center justify-between gap-4">
        <div className="flex items-center gap-3 w-full sm:w-auto">
          <div className="p-2 bg-indigo-100 dark:bg-indigo-900/30 rounded-xl">
            <CreditCard className="w-6 h-6 text-indigo-700 dark:text-indigo-400" />
          </div>
          <h2 className="text-2xl font-black text-slate-800 dark:text-slate-100">{t.bills}</h2>
        </div>
        <button 
          onClick={() => setShowAdd(true)}
          className="w-full sm:w-auto flex items-center justify-center gap-2 px-6 py-3 bg-indigo-600 text-white rounded-2xl font-bold shadow-lg shadow-indigo-200 dark:shadow-none hover:bg-indigo-700 active:scale-95 transition-all"
        >
          <Plus className="w-5 h-5" />
          {t.addBill}
        </button>
      </div>

      {/* Monthly Spending Section */}
      <div className="bg-white dark:bg-slate-900 rounded-3xl border border-slate-100 dark:border-slate-800 p-6 shadow-sm overflow-hidden transition-colors">
        <div className="flex items-center gap-3 mb-6">
          <div className="p-2 bg-emerald-100 dark:bg-emerald-900/30 rounded-xl">
            <TrendingUp className="w-5 h-5 text-emerald-600 dark:text-emerald-400" />
          </div>
          <div>
            <h3 className="text-lg font-bold text-slate-800 dark:text-slate-100">Monthly Spending Summary</h3>
            <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">{currentMonthLabel}</p>
          </div>
        </div>

        {monthlySpendingSummary.length > 0 ? (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
            {monthlySpendingSummary.map(item => (
              <div key={item.category} className="p-4 bg-slate-50 dark:bg-slate-800/40 rounded-2xl border border-slate-100 dark:border-slate-700/30">
                <div className="flex justify-between items-start mb-2">
                  <span className="text-xs font-black uppercase text-slate-400 tracking-wider flex items-center gap-2">
                    <span className={`w-2 h-2 rounded-full ${CATEGORY_COLORS[item.category]?.dot || 'bg-slate-400'}`} />
                    {item.label}
                  </span>
                  {item.estimate > 0 && item.actual > item.estimate && (
                    <span className="text-[10px] font-black text-rose-500 bg-rose-50 dark:bg-rose-950/30 px-2 py-0.5 rounded-full">Exceeded Bill</span>
                  )}
                </div>
                <div className="flex items-baseline gap-2 mb-3">
                  <span className="text-xl font-black text-slate-800 dark:text-slate-100">{formatCurrency(item.actual)}</span>
                  {item.estimate > 0 && (
                    <span className="text-xs text-slate-400 font-bold">/ {formatCurrency(item.estimate)}</span>
                  )}
                </div>
                {item.estimate > 0 && (
                  <div className="w-full h-1.5 bg-slate-200 dark:bg-slate-700 rounded-full overflow-hidden">
                    <div 
                      className={`h-full transition-all duration-700 ${item.actual > item.estimate ? 'bg-rose-500' : 'bg-emerald-500'}`}
                      style={{ width: `${Math.min((item.actual / item.estimate) * 100, 100)}%` }}
                    />
                  </div>
                )}
              </div>
            ))}
          </div>
        ) : (
          <div className="py-10 text-center text-slate-400 italic flex flex-col items-center gap-2">
            <ReceiptText className="w-8 h-8 opacity-20" />
            <p>No spending recorded for this month yet.</p>
          </div>
        )}
      </div>

      {/* Bill List Toolbar (Search & Filter) */}
      <div className="flex flex-col lg:flex-row gap-4 no-print">
        <div className="relative flex-grow">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
          <input 
            type="text" 
            placeholder={t.search} 
            className="w-full pl-11 pr-4 py-3 rounded-2xl border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 text-slate-800 dark:text-slate-100 focus:ring-2 focus:ring-indigo-500 outline-none transition-all font-medium text-sm shadow-sm"
            value={searchTerm}
            onChange={e => setSearchTerm(e.target.value)}
          />
        </div>
        <div className="flex gap-2">
          <div className="relative flex-1 sm:flex-none min-w-[140px]">
            <Filter className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
            <select 
              className="w-full pl-11 pr-8 py-3 rounded-2xl border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 text-slate-800 dark:text-slate-100 focus:ring-2 focus:ring-indigo-500 outline-none transition-all font-bold text-xs appearance-none shadow-sm cursor-pointer"
              value={categoryFilter}
              onChange={e => setCategoryFilter(e.target.value)}
            >
              <option value="all">All Categories</option>
              <option value="groceries">{t.groceries}</option>
              <option value="vegetables">{t.vegetables}</option>
              <option value="fishEgg">{t.fishEgg}</option>
              <option value="chicken">{t.chicken}</option>
              <option value="houseRent">{t.houseRent}</option>
              <option value="electricity">{t.electricity}</option>
              <option value="water">{t.water}</option>
              <option value="travel">{t.travel}</option>
              <option value="others">{t.others}</option>
            </select>
          </div>
          <div className="relative flex-1 sm:flex-none min-w-[140px]">
            <ArrowUpDown className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
            <select 
              className="w-full pl-11 pr-8 py-3 rounded-2xl border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 text-slate-800 dark:text-slate-100 focus:ring-2 focus:ring-indigo-500 outline-none transition-all font-bold text-xs appearance-none shadow-sm cursor-pointer"
              value={sortBy}
              onChange={e => setSortBy(e.target.value as any)}
            >
              <option value="day">Sort by Day</option>
              <option value="name">Sort by Name</option>
              <option value="amount">Sort by Amount</option>
            </select>
          </div>
        </div>
      </div>

      {/* Bill List Section */}
      <div className="space-y-4">
        <h3 className="text-lg font-bold text-slate-800 dark:text-slate-100 flex items-center gap-2">
          <ReceiptText className="w-5 h-5 text-indigo-600" />
          Scheduled & Recurring
        </h3>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {filteredBills.map(bill => {
            const isPaidThisMonth = bill.lastPaidMonth === currentMonthLabel;
            const categoryStyle = CATEGORY_COLORS[bill.category] || CATEGORY_COLORS.others;
            return (
              <div 
                key={bill.id} 
                className={`bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-100 dark:border-slate-800 shadow-sm relative group overflow-hidden transition-all duration-300 ${isPaidThisMonth ? 'opacity-60 bg-slate-50 dark:bg-slate-800/20' : ''}`}
              >
                <div className={`absolute top-0 left-0 w-1.5 h-full transition-all ${isPaidThisMonth ? 'bg-emerald-500' : categoryStyle.dot}`} />
                <div className="flex justify-between items-start mb-4 pl-2">
                  <div>
                    <h3 className={`font-black text-slate-800 dark:text-slate-100 text-lg uppercase tracking-tight flex items-center gap-2 ${isPaidThisMonth ? 'line-through decoration-slate-400' : ''}`}>
                      <span className={`w-2 h-2 rounded-full ${isPaidThisMonth ? 'bg-emerald-500' : categoryStyle.dot}`} />
                      {bill.name}
                    </h3>
                    <p className={`text-[10px] font-black uppercase tracking-widest ${isPaidThisMonth ? 'text-slate-400' : categoryStyle.text}`}>
                      {t[bill.category as keyof typeof t] || bill.category}
                    </p>
                  </div>
                  <button 
                    onClick={() => handleDelete(bill.id)}
                    className="p-2 text-slate-300 dark:text-slate-600 hover:text-rose-500 dark:hover:text-rose-400 hover:bg-rose-50 dark:hover:bg-rose-900/30 rounded-xl transition-all"
                  >
                    <Trash2 className="w-4 h-4" />
                  </button>
                </div>

                <div className="flex items-center gap-6 pl-2 mb-6">
                  <div className="flex flex-col">
                    <span className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-1">{t.date}</span>
                    <div className={`flex items-center gap-2 font-black ${isPaidThisMonth ? 'text-slate-400' : 'text-indigo-600 dark:text-indigo-400'}`}>
                      <Calendar className="w-4 h-4" />
                      <span>Day {bill.dueDay} / Month</span>
                    </div>
                  </div>
                  <div className="flex flex-col">
                    <span className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-1">Amount</span>
                    <div className={`flex items-center gap-2 font-black ${isPaidThisMonth ? 'text-slate-400' : 'text-slate-800 dark:text-slate-100'}`}>
                      <DollarSign className="w-4 h-4 text-slate-300 dark:text-slate-700" />
                      <span>{formatCurrency(bill.amount)}</span>
                    </div>
                  </div>
                </div>

                <div className="pl-2">
                  {isPaidThisMonth ? (
                    <div className="flex items-center gap-2 text-emerald-600 dark:text-emerald-400 font-black text-sm uppercase tracking-widest bg-emerald-50 dark:bg-emerald-950/30 py-2 px-4 rounded-xl w-fit">
                      <CheckCircle2 className="w-4 h-4" />
                      {t.paid}
                    </div>
                  ) : (
                    <button 
                      onClick={() => handlePayBill(bill)}
                      className={`w-full flex items-center justify-center gap-2 text-white font-bold text-xs uppercase tracking-widest py-3 rounded-xl transition-all shadow-md active:scale-95 ${categoryStyle.dot} filter saturate-[1.2] brightness-[0.9] hover:brightness-[1.1]`}
                    >
                      <CheckCircle2 className="w-4 h-4" />
                      {t.payBill}
                    </button>
                  )}
                </div>
              </div>
            );
          })}

          {filteredBills.length === 0 && (
            <div className="col-span-full py-20 bg-slate-50/50 dark:bg-slate-900/50 rounded-3xl border-2 border-dashed border-slate-200 dark:border-slate-800 flex flex-col items-center justify-center text-slate-400 dark:text-slate-600 gap-4 transition-colors">
               {bills.length > 0 ? (
                 <>
                   <Search className="w-12 h-12 opacity-10" />
                   <p className="font-bold italic">{t.noResults}</p>
                 </>
               ) : (
                 <>
                   <CreditCard className="w-12 h-12 opacity-10" />
                   <p className="font-bold italic">{t.noData}</p>
                 </>
               )}
            </div>
          )}
        </div>
      </div>

      {showAdd && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 dark:bg-black/70 backdrop-blur-sm">
          <div className="bg-white dark:bg-slate-900 w-full max-w-md rounded-3xl shadow-2xl dark:shadow-none overflow-hidden animate-in zoom-in-95 duration-200 transition-colors">
            <div className="p-6 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between">
              <h3 className="text-xl font-bold text-slate-800 dark:text-slate-100">{t.addBill}</h3>
              <button onClick={() => { setShowAdd(false); resetForm(); }} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full transition-colors">
                <X className="w-6 h-6 text-slate-400 dark:text-slate-500" />
              </button>
            </div>
            <div className="p-6 space-y-4">
              <div>
                <label className="block text-xs font-black text-slate-400 dark:text-slate-500 uppercase mb-2">Category</label>
                <select 
                  className="w-full px-4 py-3 rounded-2xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 focus:ring-2 focus:ring-indigo-500 outline-none font-bold"
                  value={newBill.category || 'others'}
                  onChange={e => handleCategoryChange(e.target.value)}
                >
                  <option value="groceries">{t.groceries}</option>
                  <option value="vegetables">{t.vegetables}</option>
                  <option value="fishEgg">{t.fishEgg}</option>
                  <option value="chicken">{t.chicken}</option>
                  <option value="houseRent">{t.houseRent}</option>
                  <option value="electricity">{t.electricity}</option>
                  <option value="water">{t.water}</option>
                  <option value="travel">{t.travel}</option>
                  <option value="others">{t.others}</option>
                </select>
              </div>

              <div>
                <label className="block text-xs font-black text-slate-400 dark:text-slate-500 uppercase mb-2">Bill Name</label>
                <input 
                  type="text" 
                  className="w-full px-4 py-3 rounded-2xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 focus:ring-2 focus:ring-indigo-500 outline-none font-bold"
                  value={newBill.name || ''}
                  onChange={e => {
                    setNewBill({...newBill, name: e.target.value});
                    setIsNameManuallyEdited(true);
                  }}
                  placeholder="e.g. Internet Bill"
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-black text-slate-400 dark:text-slate-500 uppercase mb-2">Amount</label>
                  <input 
                    type="number" 
                    className="w-full px-4 py-3 rounded-2xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 focus:ring-2 focus:ring-indigo-500 outline-none font-bold"
                    value={newBill.amount ?? ''}
                    onChange={e => setNewBill({...newBill, amount: e.target.value === '' ? undefined : Number(e.target.value)})}
                  />
                </div>
                <div>
                  <label className="block text-xs font-black text-slate-400 dark:text-slate-500 uppercase mb-2">Recurring Due Day</label>
                  <div className="relative">
                    <input 
                      type="date" 
                      className="w-full px-4 py-3 rounded-2xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-100 focus:ring-2 focus:ring-indigo-500 outline-none font-bold text-sm"
                      value={getDummyDateString(newBill.dueDay)}
                      onChange={e => {
                        const date = new Date(e.target.value);
                        if (!isNaN(date.getTime())) {
                          setNewBill({...newBill, dueDay: date.getDate()});
                        }
                      }}
                    />
                    <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-indigo-500">
                       <span className="text-xs font-black">Day {newBill.dueDay}</span>
                    </div>
                  </div>
                </div>
              </div>

              <button 
                onClick={handleSave}
                className="w-full bg-indigo-600 text-white py-4 rounded-2xl font-bold shadow-lg shadow-indigo-200 dark:shadow-none hover:bg-indigo-700 mt-4 transition-all"
              >
                {t.save}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default BillManager;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { Transaction, Language, CurrencySettings, Notification, MonthlyBudget, Bill } from './types';
import { translations } from './translations';
import { storageService } from './services/googleSheets';
import Dashboard from './components/Dashboard';
import SettingsPage from './components/SettingsPage';
import NotificationDrawer from './components/NotificationDrawer';
import BillManager from './components/BillManager';
import { Globe, Wallet, LayoutDashboard, History, BarChart3, Target, Settings, Bell, CreditCard, Sun, Moon } from 'lucide-react';

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>(() => (localStorage.getItem('lang') as Language) || 'en');
  const [isDark, setIsDark] = useState(() => localStorage.getItem('theme') === 'dark');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'analytics' | 'history' | 'budget' | 'settings' | 'bills'>('dashboard');
  const [isLoading, setIsLoading] = useState(false);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [isNotificationOpen, setIsNotificationOpen] = useState(false);
  const [currencySettings, setCurrencySettings] = useState<CurrencySettings>({
    symbol: 'LKR',
    position: 'before'
  });

  const t = translations[lang];

  useEffect(() => {
    localStorage.setItem('lang', lang);
  }, [lang]);

  useEffect(() => {
    if (isDark) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [isDark]);

  const formatCurrency = useCallback((amount: number) => {
    // Force two decimal places for all currency amounts
    const formattedAmount = amount.toLocaleString(undefined, { 
      minimumFractionDigits: 2, 
      maximumFractionDigits: 2 
    });
    return currencySettings.position === 'before' 
      ? `${currencySettings.symbol} ${formattedAmount}`
      : `${formattedAmount} ${currencySettings.symbol}`;
  }, [currencySettings]);

  /**
   * Recalculates the entire transaction history to ensure balance continuity.
   * Every record's BF is strictly derived from the previous record's total balance.
   */
  const recalculateChain = useCallback((txs: Transaction[]) => {
    if (txs.length === 0) return [];

    // Sort strictly by date, then by timestamp
    const sorted = [...txs].sort((a, b) => {
      const dateDiff = a.date.localeCompare(b.date);
      if (dateDiff !== 0) return dateDiff;
      return (a.timestamp || '').localeCompare(b.timestamp || '');
    });

    const categories = ['groceries', 'vegetables', 'fishEgg', 'chicken', 'houseRent', 'electricity', 'water', 'travel', 'others'];

    let runningBalance = 0;
    return sorted.map((tx, index) => {
      // For the very first entry, we use its own BF if it exists, otherwise 0.
      // For all subsequent entries, the BF is the closing balance (runningBalance) of the previous entry.
      const bf = index === 0 ? Number(tx.broughtForward || 0) : runningBalance;

      const income = Number(tx.dailyCash || 0);
      const expense = categories.reduce((sum, cat) => sum + (Number((tx as any)[cat]) || 0), 0);
      const totalBalance = bf + income - expense;

      runningBalance = totalBalance;

      return {
        ...tx,
        broughtForward: bf,
        totalExpenses: expense,
        totalBalance: totalBalance
      };
    });
  }, []);

  /**
   * Finds the closing balance of the last recorded date BEFORE the target date.
   */
  const getStartingBalance = useCallback((targetDate: string) => {
    if (!transactions || transactions.length === 0) return 0;

    const sorted = [...transactions].sort((a, b) => {
      const d = a.date.localeCompare(b.date);
      if (d !== 0) return d;
      return (a.timestamp || '').localeCompare(b.timestamp || '');
    });

    // Find the absolute latest transaction that occurred before the targetDate
    const lastValidEntry = [...sorted].reverse().find(tx => tx.date < targetDate);

    if (lastValidEntry) {
      return Number(lastValidEntry.totalBalance || 0);
    }

    // If no entries exist before this date, and an entry already exists on this date,
    // we return its Brought Forward value to keep consistency.
    const sameDayEntry = sorted.find(tx => tx.date === targetDate);
    if (sameDayEntry) return Number(sameDayEntry.broughtForward || 0);

    return 0;
  }, [transactions]);

  const generateNotifications = useCallback(async (txs: Transaction[]) => {
    const budgets = await storageService.fetchBudgets();
    const bills = await storageService.fetchBills();
    const now = new Date();
    const currentMonthLabel = now.toLocaleString('en-US', { month: 'long', year: 'numeric' });
    const currentMonthTxs = txs.filter(tx => tx.month === currentMonthLabel);
    const budget = budgets.find(b => b.month === currentMonthLabel);
    const newNotifications: Notification[] = [];

    if (budget) {
      const categories = ['groceries', 'vegetables', 'fishEgg', 'chicken', 'houseRent', 'electricity', 'water', 'travel', 'others'];
      categories.forEach(cat => {
        const limit = (budget.limits as any)[cat];
        const spent = currentMonthTxs.reduce((sum, tx) => sum + ((tx as any)[cat] || 0), 0);
        if (limit > 0 && spent / limit >= 0.85) {
          newNotifications.push({
            id: `budget-${cat}-${currentMonthLabel}`,
            type: 'budget',
            title: t.lowBudgetAlert,
            message: t.lowBudgetMsg.replace('{percent}', Math.round((spent/limit)*100).toString()).replace('{category}', (t as any)[cat]),
            timestamp: now.toISOString(),
            read: false,
            priority: spent >= limit ? 'high' : 'medium'
          });
        }
      });
    }

    bills.forEach(bill => {
      const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
      let dueDate = new Date(now.getFullYear(), now.getMonth(), bill.dueDay);
      if (dueDate < today) {
        dueDate = new Date(now.getFullYear(), now.getMonth() + 1, bill.dueDay);
      }
      const diffTime = dueDate.getTime() - today.getTime();
      const daysLeft = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

      if (daysLeft >= 0 && daysLeft <= 7) {
        newNotifications.push({
          id: `bill-${bill.id}-${dueDate.toISOString().split('T')[0]}`,
          type: 'bill',
          title: bill.name,
          message: daysLeft === 0 ? t.dueToday : t.billDueIn.replace('{days}', daysLeft.toString()),
          timestamp: now.toISOString(),
          read: false,
          priority: daysLeft === 0 ? 'high' : (daysLeft <= 3 ? 'medium' : 'low')
        });
      }
    });

    setNotifications(prev => {
      const existingIds = new Set(prev.map(n => n.id));
      const added = newNotifications.filter(n => !existingIds.has(n.id));
      return [...added, ...prev].slice(0, 30);
    });
  }, [t]);

  const loadData = useCallback(async () => {
    setIsLoading(true);
    try {
      const data = await storageService.fetchTransactions();
      const rebalanced = recalculateChain(data);
      setTransactions(rebalanced);
      await generateNotifications(rebalanced);

      const savedCurrency = localStorage.getItem('currency_settings');
      if (savedCurrency) setCurrencySettings(JSON.parse(savedCurrency));
    } catch (err) {
      console.error("Failed to load data", err);
    } finally {
      setIsLoading(false);
    }
  }, [generateNotifications, recalculateChain]);

  const onAddTransaction = useCallback(async (data: Transaction) => {
    const freshTransactions = await storageService.fetchTransactions();
    // Search for an existing entry for this specific date
    const existingIndex = freshTransactions.findIndex(tx => tx.date === data.date);

    let newList;
    if (existingIndex !== -1) {
      const existing = freshTransactions[existingIndex];
      const categories = ['groceries', 'vegetables', 'fishEgg', 'chicken', 'houseRent', 'electricity', 'water', 'travel', 'others'];

      // When merging, we sum everything but keep the original BF to preserve chain integrity
      const merged: Transaction = {
        ...existing,
        dailyCash: Number(existing.dailyCash || 0) + Number(data.dailyCash || 0),
        timestamp: new Date().toISOString() // Update timestamp to reflect newest activity
      };

      categories.forEach(cat => {
        (merged as any)[cat] = Number((existing as any)[cat] || 0) + Number((data as any)[cat] || 0);
      });

      newList = [...freshTransactions];
      newList[existingIndex] = merged;
    } else {
      // New date - create fresh entry
      newList = [...freshTransactions, { ...data, id: crypto.randomUUID(), timestamp: new Date().toISOString() }];
    }

    // Always rebalance the entire chain before saving to ensure any insertion or update propagates correctly
    const rebalanced = recalculateChain(newList);
    await storageService.saveAllTransactions(rebalanced);
    loadData();
  }, [loadData, recalculateChain]);

  const onUpdateTransaction = useCallback(async (id: string, data: Transaction) => {
    const freshTransactions = await storageService.fetchTransactions();
    const updatedList = freshTransactions.map(tx => tx.id === id ? { ...data, id } : tx);
    const rebalanced = recalculateChain(updatedList);
    await storageService.saveAllTransactions(rebalanced);
    loadData();
  }, [loadData, recalculateChain]);

  const onDeleteTransaction = useCallback(async (id: string) => {
    if (window.confirm(t.confirmDelete)) {
      const freshTransactions = await storageService.fetchTransactions();
      const updatedList = freshTransactions.filter(tx => tx.id !== id);
      const rebalanced = recalculateChain(updatedList);
      await storageService.saveAllTransactions(rebalanced);
      loadData();
    }
  }, [loadData, t.confirmDelete, recalculateChain]);

  useEffect(() => {
    loadData();
  }, [loadData]);

  const navItems = [
    { id: 'dashboard', label: t.dashboard, icon: LayoutDashboard },
    { id: 'analytics', label: t.charts, icon: BarChart3 },
    { id: 'budget', label: t.budget, icon: Target },
    { id: 'bills', label: t.bills, icon: CreditCard },
    { id: 'history', label: t.history, icon: History },
    { id: 'settings', label: t.settings, icon: Settings },
  ];

  return (
    <div className="min-h-screen bg-slate-50 dark:bg-slate-950 pb-24 md:pb-0 font-sans transition-colors duration-300">
      <nav className="hidden md:flex flex-col fixed h-full w-64 bg-white dark:bg-slate-900 border-r border-slate-200 dark:border-slate-800 p-6 z-20 no-print transition-colors">
        <div className="flex items-center gap-3 mb-10">
          <div className="p-2 bg-indigo-600 rounded-xl shadow-lg shadow-indigo-200 dark:shadow-none">
            <Wallet className="w-6 h-6 text-white" />
          </div>
          <h1 className="font-bold text-lg text-slate-800 dark:text-slate-100 leading-tight">{t.title}</h1>
        </div>

        <div className="space-y-2 flex-grow">
          {navItems.map(tab => (
            <button 
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium transition-all ${activeTab === tab.id ? 'bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400 shadow-sm' : 'text-slate-500 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800 hover:text-slate-800 dark:hover:text-slate-200'}`}
            >
              <tab.icon className="w-5 h-5" />
              {tab.label}
            </button>
          ))}
        </div>

        <div className="mt-auto space-y-2 border-t border-slate-100 dark:border-slate-800 pt-6">
          <button onClick={() => setIsDark(!isDark)} className="w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium text-slate-500 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800 transition-all">
            {isDark ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
            {isDark ? t.lightMode : t.darkMode}
          </button>
          <button onClick={() => setLang(lang === 'en' ? 'si' : 'en')} className="w-full flex items-center gap-3 px-4 py-3 text-slate-500 dark:text-slate-400 hover:text-indigo-600 dark:hover:text-indigo-400 font-medium transition-colors">
            <Globe className="w-5 h-5" />
            {t.language}
          </button>
        </div>
      </nav>

      <nav className="md:hidden fixed bottom-0 left-0 right-0 bg-white/80 dark:bg-slate-900/80 backdrop-blur-lg border-t border-slate-200 dark:border-slate-800 px-2 py-3 z-50 no-print flex justify-around items-center transition-colors">
        {navItems.map(tab => (
          <button 
            key={tab.id}
            onClick={() => setActiveTab(tab.id as any)}
            className={`flex flex-col items-center gap-1 transition-all flex-1 min-w-0 ${activeTab === tab.id ? 'text-indigo-600 dark:text-indigo-400' : 'text-slate-400 dark:text-slate-500'}`}
          >
            <tab.icon className={`w-5 h-5 ${activeTab === tab.id ? 'scale-110' : 'scale-100'}`} />
            <span className="text-[9px] font-bold uppercase tracking-tight truncate w-full text-center">{tab.label}</span>
          </button>
        ))}
      </nav>

      <header className="md:hidden bg-white dark:bg-slate-900 border-b border-slate-200 dark:border-slate-800 px-4 py-2 flex items-center justify-between sticky top-0 z-30 no-print transition-colors shadow-sm">
        <div className="flex items-center gap-2">
          <Wallet className="w-5 h-5 text-indigo-600 dark:text-indigo-400" />
          <h1 className="font-bold text-xs text-slate-800 dark:text-slate-100 truncate max-w-[150px]">{t.title}</h1>
        </div>
        <div className="flex items-center gap-1">
          <button onClick={() => setIsNotificationOpen(true)} className="p-2 relative text-slate-500 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-lg">
            <Bell className="w-4 h-4" />
            {notifications.filter(n => !n.read).length > 0 && <span className="absolute top-1.5 right-1.5 w-1.5 h-1.5 bg-rose-500 rounded-full"></span>}
          </button>
          <button onClick={() => setIsDark(!isDark)} className="p-2 text-slate-500 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-lg">
            {isDark ? <Sun className="w-4 h-4" /> : <Moon className="w-4 h-4" />}
          </button>
        </div>
      </header>

      <main className="md:pl-64 min-h-screen">
        <div className="max-w-6xl mx-auto p-3 md:p-8">
          {activeTab === 'settings' && (
            <SettingsPage 
              t={t} 
              lang={lang}
              onLanguageChange={setLang}
              settings={currencySettings} 
              isDark={isDark}
              onToggleDark={() => setIsDark(!isDark)}
              onSave={(s) => { setCurrencySettings(s); localStorage.setItem('currency_settings', JSON.stringify(s)); }} 
            />
          )}
          {activeTab === 'bills' && <BillManager t={t} formatCurrency={formatCurrency} transactions={transactions} onRefresh={loadData} />}
          {activeTab !== 'settings' && activeTab !== 'bills' && (
            <Dashboard 
              activeTab={activeTab} 
              setActiveTab={setActiveTab}
              t={t} 
              transactions={transactions} 
              onAdd={onAddTransaction}
              onUpdate={onUpdateTransaction}
              onDelete={onDeleteTransaction}
              onRefresh={loadData}
              isLoading={isLoading}
              formatCurrency={formatCurrency}
              notifications={notifications}
              getStartingBalance={getStartingBalance}
            />
          )}
        </div>
      </main>

      <NotificationDrawer 
        isOpen={isNotificationOpen} 
        onClose={() => setIsNotificationOpen(false)} 
        notifications={notifications}
        onRead={(id) => setNotifications(prev => prev.map(n => n.id === id ? {...n, read: true} : n))}
        onReadAll={() => setNotifications(prev => prev.map(n => ({...n, read: true})))}
        t={t}
      />
    </div>
  );
};

